const TOPICS = [{"n":1,"l":"الف","t":"اللہ تعالیٰ کی توحید","p":"30","s":"الاخلاص","sn":112,"r":"1","a":"1-4","ar":"قُلۡ هُوَ اللّٰهُ اَحَدٌۚ اَللّٰهُ الصَّمَدُۚ لَمۡ يَلِدۡ ۙ وَلَمۡ يُوۡلَدۡۙ وَلَمۡ يَكُنۡ لَّهٗ كُفُوًا اَحَدٌ","u":"تو کہہ وہ اللہ ایک ہے اللہ بے نیاز ہے نہ کسی کو جنا نہ کسی سے جنا اور نہیں اُس کے جوڑ کا کوئی"},{"n":2,"l":"الف","t":"اللہ تعالیٰ کی صفات","p":"28","s":"الحشر","sn":59,"r":"3","a":"22-24","ar":"هُوَ اللّٰهُ الَّذِيۡ لَا٘ اِلٰهَ اِلَّا هُوَۚ عٰلِمُ الۡغَيۡبِ وَالشَّهَادَةِۚ هُوَ الرَّحۡمٰنُ الرَّحِيۡمُ هُوَ اللّٰهُ الَّذِيۡ لَا٘ اِلٰهَ اِلَّا هُوَۚ اَلۡمَلِكُ الۡقُدُّوۡسُ السَّلٰمُ الۡمُؤۡمِنُ الۡمُهَيۡمِنُ الۡعَزِيۡزُ الۡجَبَّارُ الۡمُتَكَبِّرُؕ سُبۡحٰنَ اللّٰهِ عَمَّا يُشۡرِكُوۡنَ هُوَ اللّٰهُ الۡخَالِقُ الۡبَارِئُ الۡمُصَوِّرُ لَهُ الۡاَسۡمَآءُ الۡحُسۡنٰيؕ يُسَبِّحُ لَهٗ مَا فِي السَّمٰوٰتِ وَالۡاَرۡضِۚ وَهُوَ الۡعَزِيۡزُ الۡحَكِيۡمُ","u":"وہ اللہ ہے جس کے سوائے بندگی نہیں کسی کی جانتا ہے جو پوشیدہ ہے اور جو ظاہر ہے وہ ہے بڑا مہربان رحم والا وہ اللہ ہے جس کے سوائے بندگی نہیں کسی کی وہ بادشاہ ہے پاک ذات سب عیبوں سے سالم امان دینے والا پناہ میں لینے والا زبردست دباؤ والا صاحب عظمت پاک ہے اللہ اُنکے شریک بتلانے سے وہ اللہ ہے بنانے والا نکال کھڑا کرنے والا صورت کھینچنے والا اُسی کے ہیں سب نام خاصے (عمدہ) پاکی بول رہا ہے اُسکی جو کچھ ہے آسمانوں میں اور زمین میں اور وہی ہے زبردست حکمتوں والا"},{"n":3,"l":"الف","t":"ایمانیات (ارکانِ ایمان)","p":"3","s":"البقرہ","sn":2,"r":"40","a":"285","ar":"اٰمَنَ الرَّسُوۡلُ بِمَا٘ اُنۡزِلَ اِلَيۡهِ مِنۡ رَّبِّهٖ وَالۡمُؤۡمِنُوۡنَؕ كُلٌّ اٰمَنَ بِاللّٰهِ وَمَلٰٓئِكَتِهٖ وَكُتُبِهٖ وَرُسُلِهٖ لَا نُفَرِّقُ بَيۡنَ اَحَدٍ مِّنۡ رُّسُلِهٖ وَقَالُوۡا سَمِعۡنَا وَاَطَعۡنَا غُفۡرَانَكَ رَبَّنَا وَاِلَيۡكَ الۡمَصِيۡرُ","u":"مان لیا رسول نے جو کچھ اترا اس پر اس کے رب کی طرف سے اور مسلمانوں نے بھی سب نے مانا اللہ کو اور اس کے فرشتوں کو اور اس کی کتابوں کو اور اس کے رسولوں کو کہتے ہیں کہ ہم جدا نہیں کرتے کسی کو اس کے پیغمبروں میں سے اور کہہ اٹھے کہ ہم نےسنا اور قبول کیا تیری بخشش چاہتے ہیں اے ہمارے رب اور تیری ہی طرف لوٹ کر جانا ہے"},{"n":4,"l":"الف","t":"اخلاص فی العمل","p":"30","s":"البینہ","sn":98,"r":"1","a":"5","ar":"وَمَا٘ اُمِرُوۡ٘ا اِلَّا لِيَعۡبُدُوا اللّٰهَ مُخۡلِصِيۡنَ لَهُ الدِّيۡنَ ۙ حُنَفَآءَ وَيُقِيۡمُوا الصَّلٰوةَ وَيُؤۡتُوا الزَّكٰوةَ وَذٰلِكَ دِيۡنُ الۡقَيِّمَةِؕ","u":"اور انکو حکم یہی ہوا کہ بندگی کریں اللہ کی خالص کر کے اُسکے واسطے بندگی ابراہیم کی راہ پر اور قائم رکھیں نماز اور دیں زکوٰۃ اور یہ ہے راہ مضبوط لوگوں کی"},{"n":5,"l":"الف","t":"آخرت پر ایمان","p":"1","s":"البقرہ","sn":2,"r":"1","a":"4","ar":"وَالَّذِيۡنَ يُؤۡمِنُوۡنَ بِمَا٘ اُنۡزِلَ اِلَيۡكَ وَمَا٘ اُنۡزِلَ مِنۡ قَبۡلِكَۚ وَبِالۡاٰخِرَةِ هُمۡ يُوۡقِنُوۡنَؕ","u":"اور وہ لوگ جو ایمان لائے اس پر کہ جو کچھ نازل ہوا تیری طرف اور اس پر کہ جو کچھ نازل ہوا تجھ سے پہلے اور آخرت کو وہ یقینی جانتے ہیں"},{"n":6,"l":"الف","t":"انبیاء پر ایمان","p":"1","s":"البقرہ","sn":2,"r":"16","a":"136","ar":"قُوۡلُوۡ٘ا اٰمَنَّا بِاللّٰهِ وَمَا٘ اُنۡزِلَ اِلَيۡنَا وَمَا٘ اُنۡزِلَ اِلٰ٘ي اِبۡرٰهٖمَ وَاِسۡمٰعِيۡلَ وَاِسۡحٰقَ وَيَعۡقُوۡبَ وَالۡاَسۡبَاطِ وَمَا٘ اُوۡتِيَ مُوۡسٰي وَعِيۡسٰي وَمَا٘ اُوۡتِيَ النَّبِيُّوۡنَ مِنۡ رَّبِّهِمۡۚ لَا نُفَرِّقُ بَيۡنَ اَحَدٍ مِّنۡهُمۡؗ وَنَحۡنُ لَهٗ مُسۡلِمُوۡنَ","u":"تم کہہ دو کہ ہم ایمان لائے اللہ پر اور جو اترا ہم پر اور جو اترا ابراہیم اور اسمٰعیل اور اسحٰق اور یعقوب اور اس کی اولاد پر اور جو ملا موسٰی کو اور عیسٰی کو اور جو ملا دوسرے پیغمبروں کو انکے رب کی طرف سے ہم فرق نہیں کرتے ان سب میں سے ایک میں بھی اور ہم اسی پروردگار کے فرمانبردار ہیں"},{"n":7,"l":"الف","t":"استغفار کی فضیلت","p":"4","s":"آلِ عمران","sn":3,"r":"14","a":"135","ar":"وَالَّذِيۡنَ اِذَا فَعَلُوۡا فَاحِشَةً اَوۡ ظَلَمُوۡ٘ا اَنۡفُسَهُمۡ ذَكَرُوا اللّٰهَ فَاسۡتَغۡفَرُوۡا لِذُنُوۡبِهِمۡ وَمَنۡ يَّغۡفِرُ الذُّنُوۡبَ اِلَّا اللّٰهُ وَلَمۡ يُصِرُّوۡا عَلٰي مَا فَعَلُوۡا وَهُمۡ يَعۡلَمُوۡنَ","u":"اور وہ لوگ کہ جب کر بیٹھیں کچھ کھلا گناہ یا برا کام کریں اپنے حق میں تو یاد کریں اللہ کو اور بخشش مانگیں اپنے گناہوں کی اور کون ہے گناہ بخشنے والا سوا اللہ کے اور اڑتے نہیں اپنے کئے پر اور وہ جانتے ہیں"},{"n":8,"l":"الف","t":"اطاعتِ رسول صلی اللہ علیہ وسلم","p":"5","s":"النساء","sn":4,"r":"11","a":"80","ar":"مَنۡ يُّطِعِ الرَّسُوۡلَ فَقَدۡ اَطَاعَ اللّٰهَۚ وَمَنۡ تَوَلّٰي فَمَا٘ اَرۡسَلۡنٰكَ عَلَيۡهِمۡ حَفِيۡظًاؕ","u":"جس نے حکم مانا رسول کا اس نے حکم مانا اللہ کا اور جو الٹا پھرا تو ہم نے تجھ نہیں بھیجا ان پر نگہبان"},{"n":9,"l":"الف","t":"احسان کا درجہ","p":"14","s":"النحل","sn":16,"r":"13","a":"90","ar":"اِنَّ اللّٰهَ يَاۡمُرُ بِالۡعَدۡلِ وَالۡاِحۡسَانِ وَاِيۡتَآئِ ذِي الۡقُرۡبٰي وَيَنۡهٰي عَنِ الۡفَحۡشَآءِ وَالۡمُنۡكَرِ وَالۡبَغۡيِۚ يَعِظُكُمۡ لَعَلَّكُمۡ تَذَكَّرُوۡنَ","u":"اللہ حکم کرتا ہے انصاف کرنے کا اور بھلائی کرنے کا اور قرابت والوں کے (کو) دینے کا اور منع کرتا ہے بے حیائی سے اور نامعقول کام سے اور سرکشی سے تم کو سمجھاتا ہے تاکہ تم یاد رکھو"},{"n":10,"l":"الف","t":"ابلیس کی گمراہی اور انسان دشمنی","p":"8","s":"الاعراف","sn":7,"r":"2","a":"16-17","ar":"قَالَ فَبِمَا٘ اَغۡوَيۡتَنِيۡ لَاَقۡعُدَنَّ لَهُمۡ صِرَاطَكَ الۡمُسۡتَقِيۡمَۙ ثُمَّ لَاٰتِيَنَّهُمۡ مِّنۭۡ بَيۡنِ اَيۡدِيۡهِمۡ وَمِنۡ خَلۡفِهِمۡ وَعَنۡ اَيۡمَانِهِمۡ وَعَنۡ شَمَآئِلِهِمۡؕ وَلَا تَجِدُ اَكۡثَرَهُمۡ شٰكِرِيۡنَ","u":"بولا تو جیسا تو نے مجھے گمراہ کیا ہے میں بھی ضرور بیٹھوں گا انکی تاک میں تیری سیدھی راہ پر پھر ان پر آؤں گا ان کے آگے سے اور پیچھے سے اور دائیں سے اور بائیں سے اور نہ پائے گا تو اکثروں کو ان میں شکرگذار"},{"n":11,"l":"الف","t":"آدم علیہ السلام کی تخلیق و قصہ","p":"1","s":"البقرہ","sn":2,"r":"4","a":"30-31","ar":"وَاِذۡ قَالَ رَبُّكَ لِلۡمَلٰٓئِكَةِ اِنِّيۡ جَاعِلٌ فِي الۡاَرۡضِ خَلِيۡفَةًؕ قَالُوۡ٘ا اَتَجۡعَلُ فِيۡهَا مَنۡ يُّفۡسِدُ فِيۡهَا وَيَسۡفِكُ الدِّمَآءَۚ وَنَحۡنُ نُسَبِّحُ بِحَمۡدِكَ وَنُقَدِّسُ لَكَؕ قَالَ اِنِّيۡ٘ اَعۡلَمُ مَا لَا تَعۡلَمُوۡنَ وَعَلَّمَ اٰدَمَ الۡاَسۡمَآءَ كُلَّهَا ثُمَّ عَرَضَهُمۡ عَلَي الۡمَلٰٓئِكَةِ فَقَالَ اَنۭۡ بِـُٔوۡنِيۡ بِاَسۡمَآءِ هٰ٘ؤُلَآءِ اِنۡ كُنۡتُمۡ صٰدِقِيۡنَ","u":"اور جب کہا تیرے رب نے فرشتوں کو کہ میں بنانیوالا ہوں زمین میں ایک نائبکہا فرشتوں نے کیا قائم کرتا ہے تو زمین میں اسکو جو فساد کرے اس میں اور خون بہائے اور ہم پڑھتے رہتے ہیں تیری خوبیاں اور یاد کرتے ہیں تیری پاک ذات کو فرمایا بیشک مجھ کو معلوم ہے جو تم نہیں جانتے اور سکھلا دیے اللہ نے آدم کو نام سب چیزوں کے پھر سامنے کیا ان سب چیزوں کو فرشتوں کے پھر فرمایا بتاؤ مجھ کو نام ان کے اگر تم سچے ہو"},{"n":12,"l":"الف","t":"ابراہیم علیہ السلام کا قصہ","p":"7","s":"الانعام","sn":6,"r":"9","a":"75-79","ar":"وَكَذٰلِكَ نُرِيۡ٘ اِبۡرٰهِيۡمَ مَلَكُوۡتَ السَّمٰوٰتِ وَالۡاَرۡضِ وَلِيَكُوۡنَ مِنَ الۡمُوۡقِنِيۡنَ فَلَمَّا جَنَّ عَلَيۡهِ الَّيۡلُ رَاٰ كَوۡكَبًاۚ قَالَ هٰذَا رَبِّيۡۚ فَلَمَّا٘ اَفَلَ قَالَ لَا٘ اُحِبُّ الۡاٰفِلِيۡنَ فَلَمَّا رَاَ الۡقَمَرَ بَازِغًا قَالَ هٰذَا رَبِّيۡۚ فَلَمَّا٘ اَفَلَ قَالَ لَئِنۡ لَّمۡ يَهۡدِنِيۡ رَبِّيۡ لَاَكُوۡنَنَّ مِنَ الۡقَوۡمِ الضَّآلِّيۡنَ فَلَمَّا رَاَ الشَّمۡسَ بَازِغَةً قَالَ هٰذَا رَبِّيۡ هٰذَا٘ اَكۡبَرُۚ فَلَمَّا٘ اَفَلَتۡ قَالَ يٰقَوۡمِ اِنِّيۡ بَرِيۡٓءٌ مِّمَّا تُشۡرِكُوۡنَ اِنِّيۡ وَجَّهۡتُ وَجۡهِيَ لِلَّذِيۡ فَطَرَ السَّمٰوٰتِ وَالۡاَرۡضَ حَنِيۡفًا وَّمَا٘ اَنَا مِنَ الۡمُشۡرِكِيۡنَۚ","u":"اور اسی طرح ہم دکھانے لگے ابراہیم کو عجائبات آسمانوں اور زمینوں کے اور تاکہ اس کو یقین آ جاوے پھر جب اندھیرا کر لیا اس پر رات نے دیکھا اس نے ایک ستارہ بولا یہ ہے رب میرا پھر جب وہ غائب ہو گیا تو بولا میں پسند نہیں کرتا غائب ہو جانے والوں کو پھر جب دیکھا چاند چمکتا ہوا بولا یہ ہے رب میرا پھر جب وہ غائب ہو گیا بولا اگر نہ ہدایت کرے گا مجھ کو رب میرا تو بیشک میں رہوں گا گمراہ لوگوں میں پھر جب دیکھا سورج جھلکھتا ہوا بولا یہ ہے رب میرا یہ سب سے بڑا ہے پھر جب وہ غائب ہو گیا بولا اے میری قوم میں بیزار ہوں ان سے جن کو تم شریک کرتے ہو میں نے متوجہ کر لیا اپنے منہ کو اسی کی طرف جس نے بنائے آسمان اور زمین سب سے یکسو ہو کر اور میں نہیں ہوں شرک کرنے والا"},{"n":13,"l":"الف","t":"ابراہیم علیہ السلام کی دعائیں","p":"13","s":"ابراہیم","sn":14,"r":"6","a":"35-41","ar":"وَاِذۡ قَالَ اِبۡرٰهِيۡمُ رَبِّ اجۡعَلۡ هٰذَا الۡبَلَدَ اٰمِنًا وَّاجۡنُبۡنِيۡ وَبَنِيَّ اَنۡ نَّعۡبُدَ الۡاَصۡنَامَؕ رَبِّ اِنَّهُنَّ اَضۡلَلۡنَ كَثِيۡرًا مِّنَ النَّاسِۚ فَمَنۡ تَبِعَنِيۡ فَاِنَّهٗ مِنِّيۡۚ وَمَنۡ عَصَانِيۡ فَاِنَّكَ غَفُوۡرٌ رَّحِيۡمٌ رَبَّنَا٘ اِنِّيۡ٘ اَسۡكَنۡتُ مِنۡ ذُرِّيَّتِيۡ بِوَادٍ غَيۡرِ ذِيۡ زَرۡعٍ عِنۡدَ بَيۡتِكَ الۡمُحَرَّمِۙ رَبَّنَا لِيُقِيۡمُوا الصَّلٰوةَ فَاجۡعَلۡ اَفۡـِٕدَةً مِّنَ النَّاسِ تَهۡوِيۡ٘ اِلَيۡهِمۡ وَارۡزُقۡهُمۡ مِّنَ الثَّمَرٰتِ لَعَلَّهُمۡ يَشۡكُرُوۡنَ رَبَّنَا٘ اِنَّكَ تَعۡلَمُ مَا نُخۡفِيۡ وَمَا نُعۡلِنُؕ وَمَا يَخۡفٰي عَلَي اللّٰهِ مِنۡ شَيۡءٍ فِي الۡاَرۡضِ وَلَا فِي السَّمَآءِ اَلۡحَمۡدُ لِلّٰهِ الَّذِيۡ وَهَبَ لِيۡ عَلَي الۡكِبَرِ اِسۡمٰعِيۡلَ وَاِسۡحٰقَؕ اِنَّ رَبِّيۡ لَسَمِيۡعُ الدُّعَآءِ رَبِّ اجۡعَلۡنِيۡ مُقِيۡمَ الصَّلٰوةِ وَمِنۡ ذُرِّيَّتِيۡۖ رَبَّنَا وَتَقَبَّلۡ دُعَآءِ رَبَّنَا اغۡفِرۡ لِيۡ وَلِوَالِدَيَّ وَلِلۡمُؤۡمِنِيۡنَ يَوۡمَ يَقُوۡمُ الۡحِسَابُ","u":"اور جس وقت کہا ابراہیم نے اے رب کر دے اس شہر کو امن والا اور دور کر مجھ کو اور میری اولاد کو اس بات سے کہ ہم پوجیں مورتوں کو اے رب انہوں نے گمراہ کیا (گمراہی میں ڈالا) بہت لوگوں کو سو جس نے پیروی کی میری (جو کوئی میرے رستہ پر چلا) وہ تو میرا ہے اور جس نے میرا کہنا نہ مانا سو تو بخشنے والا مہربان ہے اے رب میں نے بسایا ہے اپنی ایک اولاد کو میدان میں کہ جہاں کھیتی نہیں تیرے محترم (حرمت والے) گھر کے پاس اے رب ہمارے تاکہ قائم رکھیں نماز کو سو رکھ بعض لوگوں کے دل کہ مائل (جھکتے رہیں ) ہوں ان کی طرف اور روزی دے انکو میووں سے شاید وہ شکر کریں اے رب ہمارے تو تو جانتا ہے جو کچھ ہم کرتے ہیں چھپا کر اور جو کچھ کرتے ہیں دکھا کر (کھول کر) اور مخفی نہیں اللہ پر کوئی چیز زمین میں نہ آسمان میں شکر ہے اللہ کا جس نے بخشا مجھ کو اتنی بڑی عمر میں اسمٰعیل اور اسحٰق بیشک میرا رب سنتا ہے دعا کو اے رب میرے کر مجھ کو کہ قائم رکھوں نماز اور میری اولاد میں سے بھی اے رب میرے اور قبول کر میری دعا اے ہمارے رب بخش مجھ کو اور میرے ماں باپ کو اور سب ایمان والوں کو جس دن قائم ہو حساب"},{"n":14,"l":"الف","t":"ایوب علیہ السلام کا صبر","p":"17","s":"الانبیاء","sn":21,"r":"6","a":"83-84","ar":"وَاَيُّوۡبَ اِذۡ نَادٰي رَبَّهٗ٘ اَنِّيۡ مَسَّنِيَ الضُّرُّ وَاَنۡتَ اَرۡحَمُ الرّٰحِمِيۡنَۚۖ فَاسۡتَجَبۡنَا لَهٗ فَكَشَفۡنَا مَا بِهٖ مِنۡ ضُرٍّ وَّاٰتَيۡنٰهُ اَهۡلَهٗ وَمِثۡلَهُمۡ مَّعَهُمۡ رَحۡمَةً مِّنۡ عِنۡدِنَا وَذِكۡرٰي لِلۡعٰبِدِيۡنَ","u":"اور ایوب کو جس وقت پکارا اُس نے اپنے رب کو کہ مجھ پر پڑی ہے تکلیف اور تو ہے سب رحم والوں سے رحم کرنے والا پھر ہم نے سن لی اُسکی فریاد سو دور کر دی جو اُس پر تھی تکلیف اور عطا کئے اُسکو اسکے گھر والے اور اتنے ہی اور اُنکے ساتھ رحمت اپنی طرف سے اور نصیحت بندگی کرنے والوں کو"},{"n":15,"l":"الف","t":"اسراف و فضول خرچی کی ممانعت","p":"15","s":"بنی اسرائیل (الاسراء)","sn":17,"r":"3","a":"26-27","ar":"وَاٰتِ ذَا الۡقُرۡبٰي حَقَّهٗ وَالۡمِسۡكِيۡنَ وَابۡنَ السَّبِيۡلِ وَلَا تُبَذِّرۡ تَبۡذِيۡرًا اِنَّ الۡمُبَذِّرِيۡنَ كَانُوۡ٘ا اِخۡوَانَ الشَّيٰطِيۡنِؕ وَكَانَ الشَّيۡطٰنُ لِرَبِّهٖ كَفُوۡرًا","u":"اور دے قرابت والے کو اس کا حق اور محتاج کو اور مسافر کو اور مت اڑا بیجا (فضول) بےشک اڑانے والے بھائی ہیں شیطانوں کے اور شیطان ہے اپنے رب کا ناشکر"},{"n":16,"l":"الف","t":"امن و سلامتی کی تعلیم","p":"10","s":"الانفال","sn":8,"r":"8","a":"61","ar":"وَاِنۡ جَنَحُوۡا لِلسَّلۡمِ فَاجۡنَحۡ لَهَا وَتَوَكَّلۡ عَلَي اللّٰهِؕ اِنَّهٗ هُوَ السَّمِيۡعُ الۡعَلِيۡمُ","u":"اور اگر وہ جھکیں صلح کی طرف تو تو بھی جھک اسی طرف اور بھروسہ کر اللہ پر بیشک وہی ہے سننے والا جاننے والا"},{"n":17,"l":"الف","t":"اولاد کی تربیت","p":"28","s":"التحریم","sn":66,"r":"1","a":"6","ar":"يٰ٘اَيُّهَا الَّذِيۡنَ اٰمَنُوۡا قُوۡ٘ا اَنۡفُسَكُمۡ وَاَهۡلِيۡكُمۡ نَارًا وَّقُوۡدُهَا النَّاسُ وَالۡحِجَارَةُ عَلَيۡهَا مَلٰٓئِكَةٌ غِلَاظٌ شِدَادٌ لَّا يَعۡصُوۡنَ اللّٰهَ مَا٘ اَمَرَهُمۡ وَيَفۡعَلُوۡنَ مَا يُؤۡمَرُوۡنَ","u":"اے ایمان والو بچاؤ اپنی جان کو اور اپنے گھر والوں کو اُس آگ سے جسکی چھپٹیاں ہیں آدمی اور پتھر اُس پر مقرر ہیں فرشتے تندخو زبردست نافرمانی نہیں کرتے اللہ کی جو بات فرمائے اُنکو اور وہی کام کرتے ہیں جو اُنکو حکم ہو"},{"n":18,"l":"الف","t":"ادب و احترامِ والدین","p":"15","s":"بنی اسرائیل (الاسراء)","sn":17,"r":"3","a":"23-24","ar":"وَقَضٰي رَبُّكَ اَلَّا تَعۡبُدُوۡ٘ا اِلَّا٘ اِيَّاهُ وَبِالۡوَالِدَيۡنِ اِحۡسَانًاؕ اِمَّا يَبۡلُغَنَّ عِنۡدَكَ الۡكِبَرَ اَحَدُهُمَا٘ اَوۡ كِلٰهُمَا فَلَا تَقُلۡ لَّهُمَا٘ اُفٍّ وَّلَا تَنۡهَرۡهُمَا وَقُلۡ لَّهُمَا قَوۡلًا كَرِيۡمًا وَاخۡفِضۡ لَهُمَا جَنَاحَ الذُّلِّ مِنَ الرَّحۡمَةِ وَقُلۡ رَّبِّ ارۡحَمۡهُمَا كَمَا رَبَّيٰنِيۡ صَغِيۡرًاؕ","u":"اور حکم کر چکا تیرا رب کہ نہ پوجو اس کے سوائے اور ماں باپ کے ساتھ بھلائی کرو اگر پہنچ جائے تیرے سامنے بڑھاپے کو ایک ان میں سے یا دونوں تو نہ کہہ ان کو ہوں اور نہ جھڑک ان کو اور کہہ ان سے بات ادب کی اور جھکا دے ان کے آگے کندھے عاجزی کر کر نیازمندی سے اور کہہ اے رب ان پر رحم کر جیسا پالا انہوں نے مجھ کو چھوٹا سا"},{"n":19,"l":"الف","t":"امانت داری","p":"5","s":"النساء","sn":4,"r":"8","a":"58","ar":"اِنَّ اللّٰهَ يَاۡمُرُكُمۡ اَنۡ تُؤَدُّوا الۡاَمٰنٰتِ اِلٰ٘ي اَهۡلِهَاۙ وَاِذَا حَكَمۡتُمۡ بَيۡنَ النَّاسِ اَنۡ تَحۡكُمُوۡا بِالۡعَدۡلِؕ اِنَّ اللّٰهَ نِعِمَّا يَعِظُكُمۡ بِهٖؕ اِنَّ اللّٰهَ كَانَ سَمِيۡعًاۭ بَصِيۡرًا","u":"بیشک اللہ تم کو فرماتا ہے کہ پہنچا دو امانتیں امانت والوں کو اور جب فیصلہ کرنے لگو لوگوں میں تو فیصلہ کرو انصاف سے اللہ اچھی نصیحت کرتا ہے تم کو بیشک اللہ ہے سننے والا دیکھنے والا"},{"n":20,"l":"الف","t":"ارکانِ اسلام","p":"1","s":"البقرہ","sn":2,"r":"5","a":"43","ar":"وَاَقِيۡمُوا الصَّلٰوةَ وَاٰتُوا الزَّكٰوةَ وَارۡكَعُوۡا مَعَ الرّٰكِعِيۡنَ","u":"اور قائم کرو نماز اور دیا کرو زکوٰۃ اور جھکو نماز میں جھکنے والوں کے ساتھ"},{"n":21,"l":"الف","t":"اخوتِ اسلامی (بھائی چارہ)","p":"26","s":"الحجرات","sn":49,"r":"1","a":"10","ar":"اِنَّمَا الۡمُؤۡمِنُوۡنَ اِخۡوَةٌ فَاَصۡلِحُوۡا بَيۡنَ اَخَوَيۡكُمۡۚ وَاتَّقُوا اللّٰهَ لَعَلَّكُمۡ تُرۡحَمُوۡنَ","u":"مسلمان ہو ہیں سو بھائی ہیں سو ملاپ کرا دو اپنے دو بھائیوں میں اور ڈرتے رہو اللہ سے تاکہ تم پر رحم ہو"},{"n":22,"l":"الف","t":"استقامت علی الدین","p":"24","s":"فصلت","sn":41,"r":"4","a":"30","ar":"اِنَّ الَّذِيۡنَ قَالُوۡا رَبُّنَا اللّٰهُ ثُمَّ اسۡتَقَامُوۡا تَتَنَزَّلُ عَلَيۡهِمُ الۡمَلٰٓئِكَةُ اَلَّا تَخَافُوۡا وَلَا تَحۡزَنُوۡا وَاَبۡشِرُوۡا بِالۡجَنَّةِ الَّتِيۡ كُنۡتُمۡ تُوۡعَدُوۡنَ","u":"تحقیق جنہوں نے کہا رب ہمارا اللہ ہے پھر اس پر قائم رہے ان پر اترتے ہیں فرشتے کہ تم مت ڈرو اور نہ غم کھاؤ اور خوشخبری سنو اس بہشت کی جس کا تم سے وعدہ تھا"},{"n":23,"l":"الف","t":"انسان کی تخلیق کے مراحل","p":"18","s":"المؤمنون","sn":23,"r":"1","a":"12-14","ar":"وَلَقَدۡ خَلَقۡنَا الۡاِنۡسَانَ مِنۡ سُلٰلَةٍ مِّنۡ طِيۡنٍۚ ثُمَّ جَعَلۡنٰهُ نُطۡفَةً فِيۡ قَرَارٍ مَّكِيۡنٍ ثُمَّ خَلَقۡنَا النُّطۡفَةَ عَلَقَةً فَخَلَقۡنَا الۡعَلَقَةَ مُضۡغَةً فَخَلَقۡنَا الۡمُضۡغَةَ عِظٰمًا فَكَسَوۡنَا الۡعِظٰمَ لَحۡمًا ثُمَّ اَنۡشَاۡنٰهُ خَلۡقًا اٰخَرَؕ فَتَبٰرَكَ اللّٰهُ اَحۡسَنُ الۡخٰلِقِيۡنَؕ","u":"اور ہم نے بنایا آدمی کو چنی ہوئی مٹی سے پھر ہم نے رکھا اُسکو پانی کی بوند کر کے ایک جمے ہوئے ٹھکانہ میں پھر بنایا اس بوند سے لہو جما ہوا پھر بنائی اس لہو جمے ہوئے سے گوشت کی بوٹی پھر بنائیں اُس بوٹی سےہڈیاں پھر پہنایا ہڈیوں پر گوشت پھر اٹھا کھڑا کیا اسکو ایک نئی صورت میں سو بڑی برکت اللہ کی جو سب سے بہتر بنانے والا ہے"},{"n":24,"l":"الف","t":"اصحابِ کہف کا قصہ","p":"15","s":"الکہف","sn":18,"r":"1","a":"9-12","ar":"اَمۡ حَسِبۡتَ اَنَّ اَصۡحٰبَ الۡكَهۡفِ وَالرَّقِيۡمِ كَانُوۡا مِنۡ اٰيٰتِنَا عَجَبًا اِذۡ اَوَي الۡفِتۡيَةُ اِلَي الۡكَهۡفِ فَقَالُوۡا رَبَّنَا٘ اٰتِنَا مِنۡ لَّدُنۡكَ رَحۡمَةً وَّهَيِّئۡ لَنَا مِنۡ اَمۡرِنَا رَشَدًا فَضَرَبۡنَا عَلٰ٘ي اٰذَانِهِمۡ فِي الۡكَهۡفِ سِنِيۡنَ عَدَدًاۙ ثُمَّ بَعَثۡنٰهُمۡ لِنَعۡلَمَ اَيُّ الۡحِزۡبَيۡنِ اَحۡصٰي لِمَا لَبِثُوۡ٘ا اَمَدًا","u":"کیا تو خیال کرتا ہے کہ غار اور کھوہ کے رہنے والے ہماری قدرتوں میں عجب اچنبھا تھے جب جا بیٹھے وہ جوان پہاڑ کی کھو میں پھر بولے اے رب دے ہم کو اپنے پاس سے بخشش اور پوری کر دے ہمارے کام کی درستی پھر تھپک دئے ہم نے ان کے کان اس کھوہ میں چند برس گنتی کے پھر ہم نے ان کو اٹھایا کہ معلوم کریں دو فرقوں میں کس نے یاد رکھی ہے جتنی مدت وہ رہے"},{"n":25,"l":"الف","t":"اصحابِ فیل کا واقعہ","p":"30","s":"الفیل","sn":105,"r":"1","a":"1-5","ar":"اَلَمۡ تَرَ كَيۡفَ فَعَلَ رَبُّكَ بِاَصۡحٰبِ الۡفِيۡلِؕ اَلَمۡ يَجۡعَلۡ كَيۡدَهُمۡ فِيۡ تَضۡلِيۡلٍۙ وَّاَرۡسَلَ عَلَيۡهِمۡ طَيۡرًا اَبَابِيۡلَۙ تَرۡمِيۡهِمۡ بِحِجَارَةٍ مِّنۡ سِجِّيۡلٍۙ فَجَعَلَهُمۡ كَعَصۡفٍ مَّاۡكُوۡلٍ","u":"کیا تو نے نہ دیکھا کیسا کیا تیرے رب نے ہاتھی والوں کے ساتھ کیا نہیں کر دیا اُن کا داؤ غلط اور بھیجے اُن پر اڑتے جانور ٹکڑیاں ٹکڑیاں پھینکتے تھے اُن پر پتھریاں کنکر کی پھر کر ڈالا اُنکو جیسے بھس کھایا ہوا"},{"n":26,"l":"الف","t":"اصحابِ اخدود کا واقعہ","p":"30","s":"البروج","sn":85,"r":"1","a":"4-8","ar":"قُتِلَ اَصۡحٰبُ الۡاُخۡدُوۡدِۙ النَّارِ ذَاتِ الۡوَقُوۡدِۙ اِذۡ هُمۡ عَلَيۡهَا قُعُوۡدٌۙ وَّهُمۡ عَلٰي مَا يَفۡعَلُوۡنَ بِالۡمُؤۡمِنِيۡنَ شُهُوۡدٌؕ وَمَا نَقَمُوۡا مِنۡهُمۡ اِلَّا٘ اَنۡ يُّؤۡمِنُوۡا بِاللّٰهِ الۡعَزِيۡزِ الۡحَمِيۡدِۙ","u":"مارے گئے کھائیاں کھودنے والے آگ ہے بہت ایندھن والی جب وہ اس پر بیٹھے اور جو کچھ وہ کرتے مسلمانوں کے ساتھ اپنی آنکھوں سے دیکھتے اور اُن سے بدلا نہ لیتے تھے مگر اسی بات کہ وہ یقین لائے اللہ پر جو زبردست ہے تعریفوں والا"},{"n":27,"l":"الف","t":"ازواجِ مطہرات کا مقام","p":"21","s":"الاحزاب","sn":33,"r":"1","a":"6","ar":"اَلنَّبِيُّ اَوۡلٰي بِالۡمُؤۡمِنِيۡنَ مِنۡ اَنۡفُسِهِمۡ وَاَزۡوَاجُهٗ٘ اُمَّهٰتُهُمۡؕ وَاُولُوا الۡاَرۡحَامِ بَعۡضُهُمۡ اَوۡلٰي بِبَعۡضٍ فِيۡ كِتٰبِ اللّٰهِ مِنَ الۡمُؤۡمِنِيۡنَ وَالۡمُهٰجِرِيۡنَ اِلَّا٘ اَنۡ تَفۡعَلُوۡ٘ا اِلٰ٘ي اَوۡلِيٰٓـِٕكُمۡ مَّعۡرُوۡفًاؕ كَانَ ذٰلِكَ فِي الۡكِتٰبِ مَسۡطُوۡرًا","u":"نبی سے لگاؤ ہے ایمان والوں کو زیادہ اپنی جان سے اور اسکی عورتیں انکی مائیں ہیں اور قرابت والے ایک دوسرے سے لگاؤ رکھتے ہیں اللہ کے حکم میں زیادہ سب ایمان والوں اور ہجرت کرنے والوں سے مگر یہ کہ کرنا چاہو اپنے رفیقوں سے احسان یہ ہے کتاب میں لکھا ہوا"},{"n":28,"l":"الف","t":"اعمالِ صالحہ کی جزا","p":"14","s":"النحل","sn":16,"r":"13","a":"97","ar":"مَنۡ عَمِلَ صَالِحًا مِّنۡ ذَكَرٍ اَوۡ اُنۡثٰي وَهُوَ مُؤۡمِنٌ فَلَنُحۡيِيَنَّهٗ حَيٰوةً طَيِّبَةًۚ وَلَنَجۡزِيَنَّهُمۡ اَجۡرَهُمۡ بِاَحۡسَنِ مَا كَانُوۡا يَعۡمَلُوۡنَ","u":"جس نے کیا نیک کام مرد ہو یا عورت ہو اور وہ ایمان پر ہے تو اس کو ہم زندگی دیں گے ایک اچھی زندگی اور بدلے میں دیں گے ان کو حق ان کا بہتر کاموں پر جو کرتے تھے"},{"n":29,"l":"الف","t":"ادائے امانت","p":"9","s":"الانفال","sn":8,"r":"3","a":"27","ar":"يٰ٘اَيُّهَا الَّذِيۡنَ اٰمَنُوۡا لَا تَخُوۡنُوا اللّٰهَ وَالرَّسُوۡلَ وَتَخُوۡنُوۡ٘ا اَمٰنٰتِكُمۡ وَاَنۡتُمۡ تَعۡلَمُوۡنَ","u":"اے ایمان والو خیانت نہ کرو اللہ سے اور رسول سے اور خیانت نہ کرو آپس کی امانتوں میں جان کر"},{"n":30,"l":"الف","t":"انسانوں کی برابری (تقویٰ کے سوا)","p":"26","s":"الحجرات","sn":49,"r":"2","a":"13","ar":"يٰ٘اَيُّهَا النَّاسُ اِنَّا خَلَقۡنٰكُمۡ مِّنۡ ذَكَرٍ وَّاُنۡثٰي وَجَعَلۡنٰكُمۡ شُعُوۡبًا وَّقَبَآئِلَ لِتَعَارَفُوۡاؕ اِنَّ اَكۡرَمَكُمۡ عِنۡدَ اللّٰهِ اَتۡقٰىكُمۡؕ اِنَّ اللّٰهَ عَلِيۡمٌ خَبِيۡرٌ","u":"اے آدمیو ہم نے تم کو بنایا ایک مرد اور ایک عورت سےاور رکھیں تمہاری ذاتیں اور قبیلے تاکہ آپس کی پہچان ہو تحقیق عزت اللہ کے یہاں اسکی کو بڑی جسکو ادب بڑا اللہ سب کچھ جانتا ہے خبردار"},{"n":31,"l":"الف","t":"اہلِ کتاب سے متعلق احکام","p":"6","s":"المائدہ","sn":5,"r":"1","a":"5","ar":"اَلۡيَوۡمَ اُحِلَّ لَكُمُ الطَّيِّبٰتُؕ وَطَعَامُ الَّذِيۡنَ اُوۡتُوا الۡكِتٰبَ حِلٌّ لَّكُمۡ وَطَعَامُكُمۡ حِلٌّ لَّهُمۡؗ وَالۡمُحۡصَنٰتُ مِنَ الۡمُؤۡمِنٰتِ وَالۡمُحۡصَنٰتُ مِنَ الَّذِيۡنَ اُوۡتُوا الۡكِتٰبَ مِنۡ قَبۡلِكُمۡ اِذَا٘ اٰتَيۡتُمُوۡهُنَّ اُجُوۡرَهُنَّ مُحۡصِنِيۡنَ غَيۡرَ مُسٰفِحِيۡنَ وَلَا مُتَّخِذِيۡ٘ اَخۡدَانٍؕ وَمَنۡ يَّكۡفُرۡ بِالۡاِيۡمَانِ فَقَدۡ حَبِطَ عَمَلُهٗؗ وَهُوَ فِي الۡاٰخِرَةِ مِنَ الۡخٰسِرِيۡنَ","u":"آج حلال ہوئیں تم کو سب ستھری چیزیں اور اہل کتاب کا کھانا تم کو حلال ہے اور تمہارا کھانا ان کو حلال ہے اور حلال ہیں تم کو پاکدامن عورتیں مسلمان اور پاکدامن عورتیں ان میں سےجن کو دی گئ کتاب تم سے پہلےجب دو ان کو مہر ان کے قید میں لانے کو نہ مستی نکالنے کو اور نہ چھپی آشنائی کرنے کو اور جو منکر ہوا ایمان سے تو ضائع ہوئی محنت اس کی اور آخرت میں وہ ٹوٹے والوں میں ہے"},{"n":32,"l":"الف","t":"ادائیگیِ قرض کی اہمیت","p":"3","s":"البقرہ","sn":2,"r":"39","a":"282","ar":"يٰ٘اَيُّهَا الَّذِيۡنَ اٰمَنُوۡ٘ا اِذَا تَدَايَنۡتُمۡ بِدَيۡنٍ اِلٰ٘ي اَجَلٍ مُّسَمًّي فَاكۡتُبُوۡهُؕ وَلۡيَكۡتُبۡ بَّيۡنَكُمۡ كَاتِبٌۭ بِالۡعَدۡلِ وَلَا يَاۡبَ كَاتِبٌ اَنۡ يَّكۡتُبَ كَمَا عَلَّمَهُ اللّٰهُ فَلۡيَكۡتُبۡۚ وَلۡيُمۡلِلِ الَّذِيۡ عَلَيۡهِ الۡحَقُّ وَلۡيَتَّقِ اللّٰهَ رَبَّهٗ وَلَا يَبۡخَسۡ مِنۡهُ شَيۡـًٔاؕ فَاِنۡ كَانَ الَّذِيۡ عَلَيۡهِ الۡحَقُّ سَفِيۡهًا اَوۡ ضَعِيۡفًا اَوۡ لَا يَسۡتَطِيۡعُ اَنۡ يُّمِلَّ هُوَ فَلۡيُمۡلِلۡ وَلِيُّهٗ بِالۡعَدۡلِؕ وَاسۡتَشۡهِدُوۡا شَهِيۡدَيۡنِ مِنۡ رِّجَالِكُمۡۚ فَاِنۡ لَّمۡ يَكُوۡنَا رَجُلَيۡنِ فَرَجُلٌ وَّامۡرَاَتٰنِ مِمَّنۡ تَرۡضَوۡنَ مِنَ الشُّهَدَآءِ اَنۡ تَضِلَّ اِحۡدٰىهُمَا فَتُذَكِّرَ اِحۡدٰىهُمَا الۡاُخۡرٰيؕ وَلَا يَاۡبَ الشُّهَدَآءُ اِذَا مَا دُعُوۡاؕ وَلَا تَسۡـَٔمُوۡ٘ا اَنۡ تَكۡتُبُوۡهُ صَغِيۡرًا اَوۡ كَبِيۡرًا اِلٰ٘ي اَجَلِهٖؕ ذٰلِكُمۡ اَقۡسَطُ عِنۡدَ اللّٰهِ وَاَقۡوَمُ لِلشَّهَادَةِ وَاَدۡنٰ٘ي اَلَّا تَرۡتَابُوۡ٘ا اِلَّا٘ اَنۡ تَكُوۡنَ تِجَارَةً حَاضِرَةً تُدِيۡرُوۡنَهَا بَيۡنَكُمۡ فَلَيۡسَ عَلَيۡكُمۡ جُنَاحٌ اَلَّا تَكۡتُبُوۡهَاؕ وَاَشۡهِدُوۡ٘ا اِذَا تَبَايَعۡتُمۡ وَلَا يُضَآرَّ كَاتِبٌ وَّلَا شَهِيۡدٌ ؕ وَاِنۡ تَفۡعَلُوۡا فَاِنَّهٗ فُسُوۡقٌۭ بِكُمۡؕ وَاتَّقُوا اللّٰهَؕ وَيُعَلِّمُكُمُ اللّٰهُؕ وَاللّٰهُ بِكُلِّ شَيۡءٍ عَلِيۡمٌ","u":"اے ایمان والو جب تم آپس میں معاملہ کرو ادھار کا کسی وقت مقرر تک تو اس کو لکھ لیا کرو اور چاہئے کہ لکھ دے تمہارے درمیان کوئی لکھنے والا انصاف سے اور انکار نہ کرے لکھنے والا اس سے کہ لکھ دیوے جیسا سکھایا اس کو اللہ نے سو اس کو چاہئے کہ لکھ دے اور بتلاتا جاوے وہ شخص کہ جس پر قرض ہے اور ڈرے اللہ سے جو اس کا رب ہے اور کم نہ کرے اس میں سےکچھ پھر اگر وہ شخص کہ جس پر قرض ہے بے عقل ہے یا ضعیف ہے یا آپ نہیں بتلا سکتا تو بتلاوے کارگذار اس کا انصاف سے اور گواہ کرو دو شاہد اپنے مردوں میں سے پھر اگر نہ ہوں دو مرد تو ایک مرد اور دو عورتیں ان لوگوں میں سے کہ جن کو تم پسند کرتے ہو گواہوں میں تاکہ اگر بھول جائے ایک ان میں سے تو یاد دلاوے اس کو وہ دوسری اور انکار نہ کریں گواہ جس وقت بلائے جاویں اور کاہلی نہ کرو اس کے لکھنے سے چھوٹا ہو معاملہ یا بڑا اس کی میعاد تک اس میں پورا انصاف ہے اللہ کے نزدیک اور بہت درست رکھنے والا ہے گواہی کو اور نزدیک ہے کہ شبہ میں نہ پڑو مگر یہ کہ سودا ہو ہاتھوں ہاتھ لیتے دیتے ہو اس کو آپس میں تو تم پر کچھ گناہ نہیں اگر اس کو نہ لکھو اور گواہ کر لیا کرو جب تم سودا کرو اور نقصان نہ کرےلکھنے والا اور نہ گواہ اور اگر ایسا کرو تو یہ گناہ کی بات ہے تمہارے اندر اور ڈرتے رہو اللہ سے اور اللہ تم کو سکھلاتا ہے اور اللہ ہر ایک چیز کو جانتا ہے"},{"n":33,"l":"الف","t":"اجتماعی دعا کے آداب","p":"8","s":"الاعراف","sn":7,"r":"7","a":"55","ar":"اُدۡعُوۡا رَبَّكُمۡ تَضَرُّعًا وَّخُفۡيَةًؕ اِنَّهٗ لَا يُحِبُّ الۡمُعۡتَدِيۡنَۚ","u":"پکارو اپنے رب کو گڑگڑا کر اور چپکے چپکے اس کو خوش نہیں آتے حد سے بڑھنے والے"},{"n":34,"l":"الف","t":"اہلِ ایمان کی علامات","p":"9","s":"الانفال","sn":8,"r":"1","a":"2-4","ar":"اِنَّمَا الۡمُؤۡمِنُوۡنَ الَّذِيۡنَ اِذَا ذُكِرَ اللّٰهُ وَجِلَتۡ قُلُوۡبُهُمۡ وَاِذَا تُلِيَتۡ عَلَيۡهِمۡ اٰيٰتُهٗ زَادَتۡهُمۡ اِيۡمَانًا وَّعَلٰي رَبِّهِمۡ يَتَوَكَّلُوۡنَۚۙ الَّذِيۡنَ يُقِيۡمُوۡنَ الصَّلٰوةَ وَمِمَّا رَزَقۡنٰهُمۡ يُنۡفِقُوۡنَؕ اُولٰٓئِكَ هُمُ الۡمُؤۡمِنُوۡنَ حَقًّاؕ لَهُمۡ دَرَجٰتٌ عِنۡدَ رَبِّهِمۡ وَمَغۡفِرَةٌ وَّرِزۡقٌ كَرِيۡمٌۚ","u":"ایمان والے وہی ہیں کہ جب نام آئے اللہ کا تو ڈر جائیں ان کے دل اور جب پڑھا جائے ان پر اس کا کلام تو زیادہ ہو جاتا ہےان کا ایمان اور وہ اپنے رب پر بھروسا رکھتے ہیں وہ لوگ جو کہ قائم رکھتے ہیں نماز کو اور ہم نے جو انکو روزی دی ہے اس میں سے خرچ کرتے ہیں وہی ہیں سچے ایمان والے انکے لئے درجے ہیں اپنے رب کے پاس اور معافی اور روزی عزت کی"},{"n":35,"l":"الف","t":"انفاق فی سبیل اللہ","p":"3","s":"البقرہ","sn":2,"r":"36","a":"261","ar":"مَثَلُ الَّذِيۡنَ يُنۡفِقُوۡنَ اَمۡوَالَهُمۡ فِيۡ سَبِيۡلِ اللّٰهِ كَمَثَلِ حَبَّةٍ اَنۭۡ بَتَتۡ سَبۡعَ سَنَابِلَ فِيۡ كُلِّ سُنۭۡ بُلَةٍ مِّائَةُ حَبَّةٍؕ وَاللّٰهُ يُضٰعِفُ لِمَنۡ يَّشَآءُؕ وَاللّٰهُ وَاسِعٌ عَلِيۡمٌ","u":"مثال ان لوگوں کی جو خرچ کرتے ہیں اپنے مال اللہ کی راہ میں ایسی ہے کہ جیسے ایک دانہ اس سے اگیں سات بالیں ہر بال میں سو سو دانے اور اللہ بڑھاتا ہے جس کے واسطے چاہے اور اللہ بینہایت بخشش کرنے والا ہے سب کچھ جانتا ہے"},{"n":36,"l":"الف","t":"آدابِ گفتگو","p":"22","s":"الاحزاب","sn":33,"r":"9","a":"70","ar":"يٰ٘اَيُّهَا الَّذِيۡنَ اٰمَنُوا اتَّقُوا اللّٰهَ وَقُوۡلُوۡا قَوۡلًا سَدِيۡدًاۙ","u":"اے ایمان والو ڈرتے رہو اللہ سے اور کہو بات سیدھی"},{"n":37,"l":"الف","t":"اجر و ثواب میں اضافہ","p":"8","s":"الانعام","sn":6,"r":"20","a":"160","ar":"مَنۡ جَآءَ بِالۡحَسَنَةِ فَلَهٗ عَشۡرُ اَمۡثَالِهَاۚ وَمَنۡ جَآءَ بِالسَّيِّئَةِ فَلَا يُجۡزٰ٘ي اِلَّا مِثۡلَهَا وَهُمۡ لَا يُظۡلَمُوۡنَ","u":"جو کوئی لاتا ہے ایک نیکی تو اسکے لئے اس کا دس گنا ہے اور جو کوئی لاتا ہے ایک برائی سو سزا پائے گا اسی کے برابر اور ان پر ظلم نہ ہو گا"},{"n":38,"l":"الف","t":"استقامت بوقتِ مصیبت","p":"2","s":"البقرہ","sn":2,"r":"19","a":"155-157","ar":"وَلَنَبۡلُوَنَّكُمۡ بِشَيۡءٍ مِّنَ الۡخَوۡفِ وَالۡجُوۡعِ وَنَقۡصٍ مِّنَ الۡاَمۡوَالِ وَالۡاَنۡفُسِ وَالثَّمَرٰتِؕ وَبَشِّرِ الصّٰبِرِيۡنَۙ الَّذِيۡنَ اِذَا٘ اَصَابَتۡهُمۡ مُّصِيۡبَةٌۙ قَالُوۡ٘ا اِنَّا لِلّٰهِ وَاِنَّا٘ اِلَيۡهِ رٰجِعُوۡنَؕ اُولٰٓئِكَ عَلَيۡهِمۡ صَلَوٰتٌ مِّنۡ رَّبِّهِمۡ وَرَحۡمَةٌ وَاُولٰٓئِكَ هُمُ الۡمُهۡتَدُوۡنَ","u":"اور البتہ ہم آزمائیں گے تم کو تھوڑے سے ڈر سے اور بھوک سے اور نقصان سے مالوں کے اور جانوں کے اور میووں کے اور خوشخبری دے ان صبر کرنے والوں کو کہ جب پہنچے ان کو کچھ مصیبت تو کہیں ہم تو اللہ ہی کا مال ہیں اور ہم اسی کی طرف لوٹ کر جانے والے ہیں ایسے ہی لوگوں پر عنایتیں ہیں اپنے رب کی اور مہربانی اور وہی ہیں سیدھی راہ پر"},{"n":39,"l":"الف","t":"ام موسیٰ علیہا السلام کا تذکرہ","p":"20","s":"القصص","sn":28,"r":"1","a":"7","ar":"وَاَوۡحَيۡنَا٘ اِلٰ٘ي اُمِّ مُوۡسٰ٘ي اَنۡ اَرۡضِعِيۡهِۚ فَاِذَا خِفۡتِ عَلَيۡهِ فَاَلۡقِيۡهِ فِي الۡيَمِّ وَلَا تَخَافِيۡ وَلَا تَحۡزَنِيۡۚ اِنَّا رَآدُّوۡهُ اِلَيۡكِ وَجَاعِلُوۡهُ مِنَ الۡمُرۡسَلِيۡنَ","u":"اور ہم نے حکم بھیجا موسٰی کی ماں کو کہ اس کو دودھ پلاتی رہ پھر جب تجھ کو ڈر ہو اس کا تو ڈال دے اسکو دریا میں اور نہ خطرہ کر اور نہ غمگین ہو ہم پھر پہنچا دیں گے اسکو تیری طرف اور کریں گے اس کو رسولوں سے"},{"n":40,"l":"الف","t":"ایفائے عہد","p":"15","s":"بنی اسرائیل (الاسراء)","sn":17,"r":"4","a":"34","ar":"وَلَا تَقۡرَبُوۡا مَالَ الۡيَتِيۡمِ اِلَّا بِالَّتِيۡ هِيَ اَحۡسَنُ حَتّٰي يَبۡلُغَ اَشُدَّهٗ وَاَوۡفُوۡا بِالۡعَهۡدِۚ اِنَّ الۡعَهۡدَ كَانَ مَسۡـُٔوۡلًا","u":"اور پاس نہ جاؤ یتیم کے مال کے مگر جس طرح کہ بہتر ہو جب تک کہ وہ پہنچے اپنی جوانی کو اور پورا کرو عہد کو بیشک عہد کی پوچھ ہو گی"},{"n":41,"l":"الف","t":"انسانی کرامت","p":"15","s":"بنی اسرائیل (الاسراء)","sn":17,"r":"7","a":"70","ar":"وَلَقَدۡ كَرَّمۡنَا بَنِيۡ٘ اٰدَمَ وَحَمَلۡنٰهُمۡ فِي الۡبَرِّ وَالۡبَحۡرِ وَرَزَقۡنٰهُمۡ مِّنَ الطَّيِّبٰتِ وَفَضَّلۡنٰهُمۡ عَلٰي كَثِيۡرٍ مِّمَّنۡ خَلَقۡنَا تَفۡضِيۡلًا","u":"اور ہم نےعزت دی ہے آدم کی اولاد کو اور سواری دی ان کو جنگل اور دریا میں اور روزی دی ہم نے ان کو ستھری چیزوں سے اور بڑھا دیا ان کو بہتوں سے جن کو پیدا کیا ہم نے بڑائی دے کر"},{"n":42,"l":"ب","t":"بخشش و مغفرتِ الٰہی","p":"24","s":"الزمر","sn":39,"r":"6","a":"53","ar":"قُلۡ يٰعِبَادِيَ الَّذِيۡنَ اَسۡرَفُوۡا عَلٰ٘ي اَنۡفُسِهِمۡ لَا تَقۡنَطُوۡا مِنۡ رَّحۡمَةِ اللّٰهِؕ اِنَّ اللّٰهَ يَغۡفِرُ الذُّنُوۡبَ جَمِيۡعًاؕ اِنَّهٗ هُوَ الۡغَفُوۡرُ الرَّحِيۡمُ","u":"کہہ دے اے بندو میرے جنہوں نے کہ زیادتی کہ ہے اپنی جان پر آس مت توڑو اللہ کی مہربانی سے بیشک اللہ بخشتا ہے سب گناہ وہ جو ہے وہی ہے گناہ معاف کرنے والا مہربان"},{"n":43,"l":"ب","t":"برکت کا تصور","p":"9","s":"الاعراف","sn":7,"r":"12","a":"96","ar":"وَلَوۡ اَنَّ اَهۡلَ الۡقُرٰ٘ي اٰمَنُوۡا وَاتَّقَوۡا لَفَتَحۡنَا عَلَيۡهِمۡ بَرَكٰتٍ مِّنَ السَّمَآءِ وَالۡاَرۡضِ وَلٰكِنۡ كَذَّبُوۡا فَاَخَذۡنٰهُمۡ بِمَا كَانُوۡا يَكۡسِبُوۡنَ","u":"اور اگر بستیوں والے ایمان لاتے اور پرہیزگاری کرتے تو ہم کھول دیتے ان پر نعمتیں آسمان اور زمین سے لیکن جھٹلایا انہوں نے پس پکڑا ہم نے ان کو ان کے اعمال کےبدلے"},{"n":44,"l":"ب","t":"بدگمانی کی ممانعت","p":"26","s":"الحجرات","sn":49,"r":"2","a":"12","ar":"يٰ٘اَيُّهَا الَّذِيۡنَ اٰمَنُوا اجۡتَنِبُوۡا كَثِيۡرًا مِّنَ الظَّنِّؗ اِنَّ بَعۡضَ الظَّنِّ اِثۡمٌ وَّلَا تَجَسَّسُوۡا وَلَا يَغۡتَبۡ بَّعۡضُكُمۡ بَعۡضًاؕ اَيُحِبُّ اَحَدُكُمۡ اَنۡ يَّاۡكُلَ لَحۡمَ اَخِيۡهِ مَيۡتًا فَكَرِهۡتُمُوۡهُؕ وَاتَّقُوا اللّٰهَؕ اِنَّ اللّٰهَ تَوَّابٌ رَّحِيۡمٌ","u":"اے ایمان والو بچتے رہو بہت تہمتیں کرنے سے مقرر بعضی تہمت گناہ ہے اور بھید نہ ٹٹولو کسی کا اور برا نہ کہیو پیٹھ پیچھے ایک دوسرے کو بھلا خوش لگتا ہے تم میں کسی کو کہ کھائے گوشت اپنے بھائی کا جو مردہ ہو سو گھن آتا ہے تم کو اس سے اور ڈرتے رہو اللہ سے بیشک اللہ معاف کرنے والا ہے مہربان"},{"n":45,"l":"ب","t":"بخل کی مذمت","p":"4","s":"آلِ عمران","sn":3,"r":"18","a":"180","ar":"وَلَا يَحۡسَبَنَّ الَّذِيۡنَ يَبۡخَلُوۡنَ بِمَا٘ اٰتٰىهُمُ اللّٰهُ مِنۡ فَضۡلِهٖ هُوَ خَيۡرًا لَّهُمۡؕ بَلۡ هُوَ شَرٌّ لَّهُمۡؕ سَيُطَوَّقُوۡنَ مَا بَخِلُوۡا بِهٖ يَوۡمَ الۡقِيٰمَةِؕ وَلِلّٰهِ مِيۡرَاثُ السَّمٰوٰتِ وَالۡاَرۡضِؕ وَاللّٰهُ بِمَا تَعۡمَلُوۡنَ خَبِيۡرٌ","u":"اور نہ خیال کریں وہ لوگ جو بخل کرتے ہیں اس چیز پر جو اللہ نے انکو دی ہے اپنے فضل سے کہ یہ بخل بہتر ہے انکے حق میں بلکہ یہ بہت برا ہے انکے حق میں طوق بنا کر ڈالا جائے گا انکے گلوں میں وہ مال جس میں بخل کیا تھا قیامت کے دن اور اللہ وارث ہے آسمان اور زمین کا اور اللہ جو کرتے ہو سو جانتا ہے"},{"n":46,"l":"ب","t":"بھائی چارہ اور اتحاد","p":"4","s":"آلِ عمران","sn":3,"r":"11","a":"103","ar":"وَاعۡتَصِمُوۡا بِحَبۡلِ اللّٰهِ جَمِيۡعًا وَّلَا تَفَرَّقُوۡا وَاذۡكُرُوۡا نِعۡمَتَ اللّٰهِ عَلَيۡكُمۡ اِذۡ كُنۡتُمۡ اَعۡدَآءً فَاَلَّفَ بَيۡنَ قُلُوۡبِكُمۡ فَاَصۡبَحۡتُمۡ بِنِعۡمَتِهٖ٘ اِخۡوَانًاۚ وَكُنۡتُمۡ عَلٰي شَفَا حُفۡرَةٍ مِّنَ النَّارِ فَاَنۡقَذَكُمۡ مِّنۡهَاؕ كَذٰلِكَ يُبَيِّنُ اللّٰهُ لَكُمۡ اٰيٰتِهٖ لَعَلَّكُمۡ تَهۡتَدُوۡنَ","u":"اور مضبوط پکڑو رسی اللہ کی سب مل کر اور پھوٹ نہ ڈالو اور یاد کرو احسان اللہ کا اپنے اوپر جب کہ تھے تم آپس میں دشمن پھر الفت دی تمہارے دلوں میں اب ہو گئے اس کے فضل سے بھائی اور تم تھے کنارے پر ایک آگ کے گڑھے کے پھر تم کو اس سے نجات دی اسی طرح کھولتا ہے اللہ تم پر آیتیں تاکہ تم راہ پاؤ"},{"n":47,"l":"ب","t":"بیعتِ رضوان","p":"26","s":"الفتح","sn":48,"r":"3","a":"18","ar":"لَقَدۡ رَضِيَ اللّٰهُ عَنِ الۡمُؤۡمِنِيۡنَ اِذۡ يُبَايِعُوۡنَكَ تَحۡتَ الشَّجَرَةِ فَعَلِمَ مَا فِيۡ قُلُوۡبِهِمۡ فَاَنۡزَلَ السَّكِيۡنَةَ عَلَيۡهِمۡ وَاَثَابَهُمۡ فَتۡحًا قَرِيۡبًاۙ","u":"تحقیق اللہ خوش ہوا ایمان والوں سے جب بیعت کرنے لگے تجھ سے اس درخت کے نیچے پھر معلوم کیا جو اُنکے جی میں تھا پھر اتارا اُن پر اطمینان اور انعام دیا اُنکو ایک فتح نزدیک"},{"n":48,"l":"ب","t":"غزوۂ بدر کا تذکرہ","p":"4","s":"آلِ عمران","sn":3,"r":"13","a":"123","ar":"وَلَقَدۡ نَصَرَكُمُ اللّٰهُ بِبَدۡرٍ وَّاَنۡتُمۡ اَذِلَّةٌۚ فَاتَّقُوا اللّٰهَ لَعَلَّكُمۡ تَشۡكُرُوۡنَ","u":"اور تمہاری مدد کر چکا ہے اللہ بدر کی لڑائی میں اور تم کمزور تھے سو ڈرتے رہو اللہ سے تاکہ تم احسان مانو"},{"n":49,"l":"ب","t":"بنی اسرائیل کے واقعات و انعامات","p":"1","s":"البقرہ","sn":2,"r":"6","a":"47","ar":"يٰبَنِيۡ٘ اِسۡرَآءِيۡلَ اذۡكُرُوۡا نِعۡمَتِيَ الَّتِيۡ٘ اَنۡعَمۡتُ عَلَيۡكُمۡ وَاَنِّيۡ فَضَّلۡتُكُمۡ عَلَي الۡعٰلَمِيۡنَ","u":"اے بنی اسرائیل یاد کرو میرے احسان جو میں نے تم پر کئے اور اسکو کہ میں نے تم کو بڑائی دی تمام عالم پر"},{"n":50,"l":"ب","t":"بہتان کی حرمت","p":"5","s":"النساء","sn":4,"r":"16","a":"112","ar":"وَمَنۡ يَّكۡسِبۡ خَطِيۡٓـَٔةً اَوۡ اِثۡمًا ثُمَّ يَرۡمِ بِهٖ بَرِيۡٓـًٔا فَقَدِ احۡتَمَلَ بُهۡتَانًا وَّاِثۡمًا مُّبِيۡنًا","u":"اور جو کوئی کرے خطا یا گناہ پھر تمہت لگاوے کسی بے گناہ پر تو اس نے اپنے سر دھرا طوفان اور گناہ صریح"},{"n":51,"l":"ب","t":"بیت اللہ کی تعمیر","p":"1","s":"البقرہ","sn":2,"r":"15","a":"127","ar":"وَاِذۡ يَرۡفَعُ اِبۡرٰهٖمُ الۡقَوَاعِدَ مِنَ الۡبَيۡتِ وَاِسۡمٰعِيۡلُؕ رَبَّنَا تَقَبَّلۡ مِنَّاؕ اِنَّكَ اَنۡتَ السَّمِيۡعُ الۡعَلِيۡمُ","u":"اور یاد کرو جب اٹھاتے تھے ابراہیم بنیادیں خانہ کعبہ کی اور اسمٰعیل اور دعا کرتے تھے اے پروردگار ہمارے قبول کر ہم سے بیشک تو ہی ہے سننے والا جاننے والا"},{"n":52,"l":"ب","t":"باہمی صلح کی ترغیب","p":"5","s":"النساء","sn":4,"r":"19","a":"128","ar":"وَاِنِ امۡرَاَةٌ خَافَتۡ مِنۭۡ بَعۡلِهَا نُشُوۡزًا اَوۡ اِعۡرَاضًا فَلَا جُنَاحَ عَلَيۡهِمَا٘ اَنۡ يُّصۡلِحَا بَيۡنَهُمَا صُلۡحًاؕ وَالصُّلۡحُ خَيۡرٌؕ وَاُحۡضِرَتِ الۡاَنۡفُسُ الشُّحَّؕ وَاِنۡ تُحۡسِنُوۡا وَتَتَّقُوۡا فَاِنَّ اللّٰهَ كَانَ بِمَا تَعۡمَلُوۡنَ خَبِيۡرًا","u":"اور اگر کوئی عورت ڈرے اپنے خاوند کے لڑنے سے یا جی پھر جانے سو تو کچھ گناہ نہیں دونوں پر کہ کر لیں آپس میں کسی طرح صلح اور صلح خوب چیز ہے اور دلوں کے سامنے موجود ہے حرص اور اگر تم نیکی کرو اور پرہیزگاری کرو تو اللہ کو تمہارے سب کاموں کی خبر ہے"},{"n":53,"l":"ب","t":"بیوہ اور مطلقہ کے حقوق","p":"2","s":"البقرہ","sn":2,"r":"31","a":"241","ar":"وَلِلۡمُطَلَّقٰتِ مَتَاعٌۭ بِالۡمَعۡرُوۡفِؕ حَقًّا عَلَي الۡمُتَّقِيۡنَ","u":"اور طلاق دی ہوئی عورتوں کے واسطے خرچ دینا ہے قاعدہ کے موافق لازم ہے پرہیزگاروں پر"},{"n":54,"l":"ب","t":"بدعہدی کی مذمت","p":"1","s":"البقرہ","sn":2,"r":"3","a":"27","ar":"الَّذِيۡنَ يَنۡقُضُوۡنَ عَهۡدَ اللّٰهِ مِنۭۡ بَعۡدِ مِيۡثَاقِهٖ وَيَقۡطَعُوۡنَ مَا٘ اَمَرَ اللّٰهُ بِهٖ٘ اَنۡ يُّوۡصَلَ وَيُفۡسِدُوۡنَ فِي الۡاَرۡضِؕ اُولٰٓئِكَ هُمُ الۡخٰسِرُوۡنَ","u":"جو توڑتے ہیں خدا کے معاہدہ کو مضبوط کرنے کے بعد اور قطع کرتے ہیں اس چیز کو جس کو اللہ نے فرمایا ملانے کو اور فساد کرتے ہیں ملک میں وہی ہیں ٹوٹے والے"},{"n":55,"l":"ب","t":"باہمی مشاورت کی برکات","p":"25","s":"الشوریٰ","sn":42,"r":"4","a":"38","ar":"وَالَّذِيۡنَ اسۡتَجَابُوۡا لِرَبِّهِمۡ وَاَقَامُوا الصَّلٰوةَ وَاَمۡرُهُمۡ شُوۡرٰي بَيۡنَهُمۡ وَمِمَّا رَزَقۡنٰهُمۡ يُنۡفِقُوۡنَۚ","u":"اور جنہوں نے کہ حکم مانا اپنے رب کا اور قائم کیا نماز کو اور کام کرتے ہیں مشورہ سے آپس کے اور ہمارا دیا کچھ خرچ کرتے ہیں"},{"n":56,"l":"ب","t":"بیت المقدس کا تذکرہ","p":"15","s":"بنی اسرائیل (الاسراء)","sn":17,"r":"1","a":"1","ar":"سُبۡحٰنَ الَّذِيۡ٘ اَسۡرٰي بِعَبۡدِهٖ لَيۡلًا مِّنَ الۡمَسۡجِدِ الۡحَرَامِ اِلَي الۡمَسۡجِدِ الۡاَقۡصَا الَّذِيۡ بٰرَكۡنَا حَوۡلَهٗ لِنُرِيَهٗ مِنۡ اٰيٰتِنَاؕ اِنَّهٗ هُوَ السَّمِيۡعُ الۡبَصِيۡرُ","u":"پاک ذات ہے جو لے گیا اپنے بندہ کو راتوں رات مسجد حرام سے مسجد اقصٰی تک جس کو گھیر رکھا ہے ہماری برکت نے تاکہ دکھلائیں اُسکو کچھ اپنی قدرت کے نمونے وہی ہے سننے والا دیکھنے والا"},{"n":57,"l":"ب","t":"بزرگوں کا احترام","p":"5","s":"النساء","sn":4,"r":"6","a":"36","ar":"وَاعۡبُدُوا اللّٰهَ وَلَا تُشۡرِكُوۡا بِهٖ شَيۡـًٔا وَّبِالۡوَالِدَيۡنِ اِحۡسَانًا وَّبِذِي الۡقُرۡبٰي وَالۡيَتٰمٰي وَالۡمَسٰكِيۡنِ وَالۡجَارِ ذِي الۡقُرۡبٰي وَالۡجَارِ الۡجُنُبِ وَالصَّاحِبِ بِالۡجَنۭۡ بِ وَابۡنِ السَّبِيۡلِۙ وَمَا مَلَكَتۡ اَيۡمَانُكُمۡؕ اِنَّ اللّٰهَ لَا يُحِبُّ مَنۡ كَانَ مُخۡتَالًا فَخُوۡرَاۙ","u":"اور بندگی کرو اللہ کی اور شریک نہ کرو اس کا کسی کو اور ماں باپ کے ساتھ نیکی کرو اور قرابت والوں کے ساتھ اور یتیموں اور فقیروں اور ہمسایہ قریب اور ہمسایہ اجنبی اور پاس بیٹھنے والےاور مسافر کے ساتھ اور اپنے ہاتھ کے مال یعنی غلام باندیوں کے ساتھ بیشک اللہ کو پسند نہیں آتا اترانے والا بڑائی کرنے والا"},{"n":58,"l":"ب","t":"بیعتِ عقبہ کا تذکرہ","p":"26","s":"الفتح","sn":48,"r":"1","a":"10","ar":"اِنَّ الَّذِيۡنَ يُبَايِعُوۡنَكَ اِنَّمَا يُبَايِعُوۡنَ اللّٰهَؕ يَدُ اللّٰهِ فَوۡقَ اَيۡدِيۡهِمۡۚ فَمَنۡ نَّكَثَ فَاِنَّمَا يَنۡكُثُ عَلٰي نَفۡسِهٖۚ وَمَنۡ اَوۡفٰي بِمَا عٰهَدَ عَلَيۡهُ اللّٰهَ فَسَيُؤۡتِيۡهِ اَجۡرًا عَظِيۡمًا","u":"تحقیق جو لوگ بیعت کرتے ہیں تجھ سے وہ بیعت کرتے ہیں اللہ سے اللہ کا ہاتھ ہے اوپر اُنکے ہاتھ کے پھر جو کوئی قول توڑےسو توڑتا ہے اپنے نقصان کو اور جو کوئی پورا کرے اس چیز کو جس پر اقرار کیا اللہ سے تو وہ اس کو دے گا بدلہ بہت بڑا"},{"n":59,"l":"پ","t":"پاکیزگی و طہارت","p":"2","s":"البقرہ","sn":2,"r":"28","a":"222","ar":"وَيَسۡـَٔلُوۡنَكَ عَنِ الۡمَحِيۡضِؕ قُلۡ هُوَ اَذًيۙ فَاعۡتَزِلُوا النِّسَآءَ فِي الۡمَحِيۡضِۙ وَلَا تَقۡرَبُوۡهُنَّ حَتّٰي يَطۡهُرۡنَۚ فَاِذَا تَطَهَّرۡنَ فَاۡتُوۡهُنَّ مِنۡ حَيۡثُ اَمَرَكُمُ اللّٰهُؕ اِنَّ اللّٰهَ يُحِبُّ التَّوَّابِيۡنَ وَيُحِبُّ الۡمُتَطَهِّرِيۡنَ","u":"اور تجھ سے پوچھتے ہیں حکم حیض کا کہدے وہ گندگی ہے سو تم الگ رہو عورتوں سے حیض کے وقت اور نزدیک نہ ہو ان کے جب تک پاک نہ ہوویں پھر جب خوب پاک ہو جاویں تو جاؤ ان کے پاس جہاں سے حکم دیا تم کو اللہ نے بیشک اللہ کو پسند آتے ہیں توبہ کرنے والے اور پسند آتے ہیں گندگی سے بچنے والے"},{"n":60,"l":"پ","t":"پردہ و حجاب کا حکم","p":"22","s":"الاحزاب","sn":33,"r":"8","a":"59","ar":"يٰ٘اَيُّهَا النَّبِيُّ قُلۡ لِّاَزۡوَاجِكَ وَبَنٰتِكَ وَنِسَآءِ الۡمُؤۡمِنِيۡنَ يُدۡنِيۡنَ عَلَيۡهِنَّ مِنۡ جَلَابِيۡبِهِنَّؕ ذٰلِكَ اَدۡنٰ٘ي اَنۡ يُّعۡرَفۡنَ فَلَا يُؤۡذَيۡنَؕ وَكَانَ اللّٰهُ غَفُوۡرًا رَّحِيۡمًا","u":"اے نبی کہہ دے اپنی عورتوں کو اور اپنی بیٹیوں کو اور مسلمانوں کی عورتوں کو نیچے لٹکا لیں اپنے اوپر تھوڑی سی اپنی چادریں اس میں بہت قریب ہے کہ پہچانی پڑیں تو کوئی انکو نہ ستائے اور ہے اللہ بخشنے والا مہربان"},{"n":61,"l":"پ","t":"پڑوسی کے حقوق","p":"5","s":"النساء","sn":4,"r":"6","a":"36","ar":"وَاعۡبُدُوا اللّٰهَ وَلَا تُشۡرِكُوۡا بِهٖ شَيۡـًٔا وَّبِالۡوَالِدَيۡنِ اِحۡسَانًا وَّبِذِي الۡقُرۡبٰي وَالۡيَتٰمٰي وَالۡمَسٰكِيۡنِ وَالۡجَارِ ذِي الۡقُرۡبٰي وَالۡجَارِ الۡجُنُبِ وَالصَّاحِبِ بِالۡجَنۭۡ بِ وَابۡنِ السَّبِيۡلِۙ وَمَا مَلَكَتۡ اَيۡمَانُكُمۡؕ اِنَّ اللّٰهَ لَا يُحِبُّ مَنۡ كَانَ مُخۡتَالًا فَخُوۡرَاۙ","u":"اور بندگی کرو اللہ کی اور شریک نہ کرو اس کا کسی کو اور ماں باپ کے ساتھ نیکی کرو اور قرابت والوں کے ساتھ اور یتیموں اور فقیروں اور ہمسایہ قریب اور ہمسایہ اجنبی اور پاس بیٹھنے والےاور مسافر کے ساتھ اور اپنے ہاتھ کے مال یعنی غلام باندیوں کے ساتھ بیشک اللہ کو پسند نہیں آتا اترانے والا بڑائی کرنے والا"},{"n":62,"l":"پ","t":"پیمانہ پورا کرنے کا حکم","p":"15","s":"بنی اسرائیل (الاسراء)","sn":17,"r":"4","a":"35","ar":"وَاَوۡفُوا الۡكَيۡلَ اِذَا كِلۡتُمۡ وَزِنُوۡا بِالۡقِسۡطَاسِ الۡمُسۡتَقِيۡمِؕ ذٰلِكَ خَيۡرٌ وَّاَحۡسَنُ تَاۡوِيۡلًا","u":"اور پورا بھر دو ماپ جب ماپ کر دینے لگو اور تولو سیدھی ترازو سے یہ بہتر ہے اور اچھا ہے اس کا انجام"},{"n":63,"l":"پ","t":"پیغمبروں کی جدوجہد","p":"26","s":"الاحقاف","sn":46,"r":"4","a":"35","ar":"فَاصۡبِرۡ كَمَا صَبَرَ اُولُوا الۡعَزۡمِ مِنَ الرُّسُلِ وَلَا تَسۡتَعۡجِلۡ لَّهُمۡؕ كَاَنَّهُمۡ يَوۡمَ يَرَوۡنَ مَا يُوۡعَدُوۡنَۙ لَمۡ يَلۡبَثُوۡ٘ا اِلَّا سَاعَةً مِّنۡ نَّهَارٍؕ بَلٰغٌۚ فَهَلۡ يُهۡلَكُ اِلَّا الۡقَوۡمُ الۡفٰسِقُوۡنَ","u":"سو تو ٹھہرا رہ جیسے ٹھہرے رہے ہیں ہمت والے رسول اور جلدی نہ کر انکے معاملہ میں یہ لوگ جس دن دیکھ لیں گے اس چیز کو جس کا ان سےوعدہ ہے جیسے ڈھیل نہ پائی تھی مگر ایک گھڑی دن کی یہ پہنچا دینا ہے اب وہی غارت ہوں گے جو لوگ نافرمان ہیں"},{"n":64,"l":"پ","t":"پاکیزہ رزق کی تلاش","p":"2","s":"البقرہ","sn":2,"r":"21","a":"168","ar":"يٰ٘اَيُّهَا النَّاسُ كُلُوۡا مِمَّا فِي الۡاَرۡضِ حَلٰلًا طَيِّبًاؗ وَّلَا تَتَّبِعُوۡا خُطُوٰتِ الشَّيۡطٰنِؕ اِنَّهٗ لَكُمۡ عَدُوٌّ مُّبِيۡنٌ","u":"اے لوگو کھاؤ زمین کی چیزوں میں سے حلال پاکیزہ اور پیروی نہ کرو شیطان کی بیشک وہ تمہارا دشمن ہے صریح"},{"n":65,"l":"ت","t":"توبہ کی قبولیت","p":"4","s":"النساء","sn":4,"r":"3","a":"17-18","ar":"اِنَّمَا التَّوۡبَةُ عَلَي اللّٰهِ لِلَّذِيۡنَ يَعۡمَلُوۡنَ السُّوۡٓءَ بِجَهَالَةٍ ثُمَّ يَتُوۡبُوۡنَ مِنۡ قَرِيۡبٍ فَاُولٰٓئِكَ يَتُوۡبُ اللّٰهُ عَلَيۡهِمۡؕ وَكَانَ اللّٰهُ عَلِيۡمًا حَكِيۡمًا وَلَيۡسَتِ التَّوۡبَةُ لِلَّذِيۡنَ يَعۡمَلُوۡنَ السَّيِّاٰتِۚ حَتّٰ٘ي اِذَا حَضَرَ اَحَدَهُمُ الۡمَوۡتُ قَالَ اِنِّيۡ تُبۡتُ الۡـٰٔنَ وَلَا الَّذِيۡنَ يَمُوۡتُوۡنَ وَهُمۡ كُفَّارٌؕ اُولٰٓئِكَ اَعۡتَدۡنَا لَهُمۡ عَذَابًا اَلِيۡمًا","u":"توبہ قبول کرنی اللہ کو ضرور تو انکی ہے جو کرتے ہیں برا کام جہالت سے پھر توبہ کرتے ہیں جلدی سے تو ان کو اللہ معاف کر دیتا ہے اور اللہ سب کچھ جاننے والا ہے حکمت والا اور ایسوں کی توبہ نہیں جو کئے جاتے ہیں برے کام یہاں تک کہ جب سامنے آ جائے ان میں سے کسی کے موت تو کہنے لگا میں توبہ کرتا ہوں اب اور نہ ایسوں کی توبہ جو کہ مرتے ہیں حالت کفر میں ان کے لئے تو ہم نے تیار کیا ہے عذاب دردناک"},{"n":66,"l":"ت","t":"تقویٰ کی فضیلت","p":"28","s":"الطلاق","sn":65,"r":"1","a":"2-3","ar":"فَاِذَا بَلَغۡنَ اَجَلَهُنَّ فَاَمۡسِكُوۡهُنَّ بِمَعۡرُوۡفٍ اَوۡ فَارِقُوۡهُنَّ بِمَعۡرُوۡفٍ وَّاَشۡهِدُوۡا ذَوَيۡ عَدۡلٍ مِّنۡكُمۡ وَاَقِيۡمُوا الشَّهَادَةَ لِلّٰهِؕ ذٰلِكُمۡ يُوۡعَظُ بِهٖ مَنۡ كَانَ يُؤۡمِنُ بِاللّٰهِ وَالۡيَوۡمِ الۡاٰخِرِ ؕ وَمَنۡ يَّتَّقِ اللّٰهَ يَجۡعَلۡ لَّهٗ مَخۡرَجًاۙ وَّيَرۡزُقۡهُ مِنۡ حَيۡثُ لَا يَحۡتَسِبُؕ وَمَنۡ يَّتَوَكَّلۡ عَلَي اللّٰهِ فَهُوَ حَسۡبُهٗؕ اِنَّ اللّٰهَ بَالِغُ اَمۡرِهٖؕ قَدۡ جَعَلَ اللّٰهُ لِكُلِّ شَيۡءٍ قَدۡرًا","u":"پھر جب پہنچیں اپنے وعدہ کو تو رکھ لو اُنکو دستور کے موافق یا چھوڑ دو اُنکو دستور کے موافق اور گواہ کر لو دو معتبر اپنے میں کے اور سیدھی ادا کرو گواہی اللہ کے واسطے یہ بات جو ہے اس سے سمجھ جائے گا جو کوئی یقین رکھتا ہو گا اللہ پر اور پچھلے دن پر اور جو کوئی ڈرتا ہے اللہ سے وہ کر دے اُس کا گذارہ اور روزی دے اُسکو جہاں سے اُسکو خیال بھی نہ ہو اور جو کوئی بھروسہ رکھے اللہ پر تو وہ اُسکو کافی ہے تحقیق اللہ پورا کر لیتا ہے اپنا کام اللہ نےرکھا ہے ہر چیز کا اندازہ"},{"n":67,"l":"ت","t":"توکل علی اللہ","p":"4","s":"آلِ عمران","sn":3,"r":"17","a":"159","ar":"فَبِمَا رَحۡمَةٍ مِّنَ اللّٰهِ لِنۡتَ لَهُمۡۚ وَلَوۡ كُنۡتَ فَظًّا غَلِيۡظَ الۡقَلۡبِ لَانۡفَضُّوۡا مِنۡ حَوۡلِكَ فَاعۡفُ عَنۡهُمۡ وَاسۡتَغۡفِرۡ لَهُمۡ وَشَاوِرۡهُمۡ فِي الۡاَمۡرِۚ فَاِذَا عَزَمۡتَ فَتَوَكَّلۡ عَلَي اللّٰهِؕ اِنَّ اللّٰهَ يُحِبُّ الۡمُتَوَكِّلِيۡنَ","u":"سو کچھ اللہ ہی کی رحمت ہے جو تو نرم دل مل گیا ان کو اور اگر تو ہوتا تندخو سخت دل تو متفرق ہو جاتے تیرے پاس سے سو تو ان کو معاف کر اور ان کے واسطے بخشش مانگ اور ان سے مشورہ لے کام میں پھر جب قصد کر چکا تو اس کام کا تو پھر بھروسہ کر اللہ پر اللہ کو محبت ہے توکل والوں سے"},{"n":68,"l":"ت","t":"تکبر کی مذمت","p":"21","s":"لقمان","sn":31,"r":"2","a":"18","ar":"وَلَا تُصَعِّرۡ خَدَّكَ لِلنَّاسِ وَلَا تَمۡشِ فِي الۡاَرۡضِ مَرَحًاؕ اِنَّ اللّٰهَ لَا يُحِبُّ كُلَّ مُخۡتَالٍ فَخُوۡرٍۚ","u":"اور اپنے گال مت پھلا لوگوں کی طرف اور مت چل زمین پر اتراتا بیشک اللہ کو نہیں بھاتا کوئی اتراتا بڑائیاں کرنے والا"},{"n":69,"l":"ت","t":"تواضع و انکساری","p":"19","s":"الفرقان","sn":25,"r":"6","a":"63","ar":"وَعِبَادُ الرَّحۡمٰنِ الَّذِيۡنَ يَمۡشُوۡنَ عَلَي الۡاَرۡضِ هَوۡنًا وَّاِذَا خَاطَبَهُمُ الۡجٰهِلُوۡنَ قَالُوۡا سَلٰمًا","u":"اور بندے رحمٰن کے وہ ہیں جو چلتے ہیں زمین پر دبے پاؤں اور جب بات کرنے لگیں ان سے بے سمجھ لوگ تو کہیں صاحب سلامت"},{"n":70,"l":"ت","t":"تلاوتِ قرآن کا حکم","p":"20","s":"العنکبوت","sn":29,"r":"5","a":"45","ar":"اُتۡلُ مَا٘ اُوۡحِيَ اِلَيۡكَ مِنَ الۡكِتٰبِ وَاَقِمِ الصَّلٰوةَؕ اِنَّ الصَّلٰوةَ تَنۡهٰي عَنِ الۡفَحۡشَآءِ وَالۡمُنۡكَرِؕ وَلَذِكۡرُ اللّٰهِ اَكۡبَرُؕ وَاللّٰهُ يَعۡلَمُ مَا تَصۡنَعُوۡنَ","u":"تو پڑھ جو اتری تیری طرف کتاب اور قائم رکھ نماز بیشک نماز روکتی ہے بیحیائی اور بری بات سے اور اللہ کی یاد ہے سب سے بڑی اور اللہ کو خبر ہے جو تم کرتے ہو"},{"n":71,"l":"ت","t":"تجارت کے اسلامی احکام","p":"5","s":"النساء","sn":4,"r":"5","a":"29","ar":"يٰ٘اَيُّهَا الَّذِيۡنَ اٰمَنُوۡا لَا تَاۡكُلُوۡ٘ا اَمۡوَالَكُمۡ بَيۡنَكُمۡ بِالۡبَاطِلِ اِلَّا٘ اَنۡ تَكُوۡنَ تِجَارَةً عَنۡ تَرَاضٍ مِّنۡكُمۡ وَلَا تَقۡتُلُوۡ٘ا اَنۡفُسَكُمۡؕ اِنَّ اللّٰهَ كَانَ بِكُمۡ رَحِيۡمًا","u":"اے ایمان والو نہ کھاؤ مال ایک دوسرے کے آپس میں ناحق مگر یہ کہ تجارت ہو آپس کی خوشی سے اور نہ خون کرو آپس میں بیشک اللہ تم پر مہربان ہے"},{"n":72,"l":"ت","t":"تعددِ ازواج کا حکم","p":"4","s":"النساء","sn":4,"r":"1","a":"3","ar":"وَاِنۡ خِفۡتُمۡ اَلَّا تُقۡسِطُوۡا فِي الۡيَتٰمٰي فَانۡكِحُوۡا مَا طَابَ لَكُمۡ مِّنَ النِّسَآءِ مَثۡنٰي وَثُلٰثَ وَرُبٰعَۚ فَاِنۡ خِفۡتُمۡ اَلَّا تَعۡدِلُوۡا فَوَاحِدَةً اَوۡ مَا مَلَكَتۡ اَيۡمَانُكُمۡؕ ذٰلِكَ اَدۡنٰ٘ي اَلَّا تَعُوۡلُوۡاؕ","u":"اور اگر ڈرو کہ انصاف نہ کر سکو گے یتیم لڑکیوں کے حق میں تو نکاح کر لو جو اور عورتیں تم کو خوش آویں دو دو تین تین چار چار پھر اگر ڈرو کہ ان میں انصاف نہ کر سکو گے تو ایک ہی نکاح کرو یا لونڈی جو اپنا مال ہے اس میں امید ہے کہ ایک طرف نہ جھک پڑو گے"},{"n":73,"l":"ت","t":"تہجد کی فضیلت","p":"15","s":"بنی اسرائیل (الاسراء)","sn":17,"r":"9","a":"79","ar":"وَمِنَ الَّيۡلِ فَتَهَجَّدۡ بِهٖ نَافِلَةً لَّكَۖ عَسٰ٘ي اَنۡ يَّبۡعَثَكَ رَبُّكَ مَقَامًا مَّحۡمُوۡدًا","u":"اور کچھ رات جاگتا رہ قرآن کے ساتھ یہ زیادتی ہے تیرے لئے قریب ہے کہ کھڑا کر دے تجھ کو تیرا رب مقام محمود میں"},{"n":74,"l":"ت","t":"تعزیرات و حدودِ الٰہی","p":"2","s":"البقرہ","sn":2,"r":"29","a":"229","ar":"اَلطَّلَاقُ مَرَّتٰنِ فَاِمۡسَاكٌۭ بِمَعۡرُوۡفٍ اَوۡ تَسۡرِيۡحٌۭ بِاِحۡسَانٍؕ وَلَا يَحِلُّ لَكُمۡ اَنۡ تَاۡخُذُوۡا مِمَّا٘ اٰتَيۡتُمُوۡهُنَّ شَيۡـًٔا اِلَّا٘ اَنۡ يَّخَافَا٘ اَلَّا يُقِيۡمَا حُدُوۡدَ اللّٰهِؕ فَاِنۡ خِفۡتُمۡ اَلَّا يُقِيۡمَا حُدُوۡدَ اللّٰهِۙ فَلَا جُنَاحَ عَلَيۡهِمَا فِيۡمَا افۡتَدَتۡ بِهٖؕ تِلۡكَ حُدُوۡدُ اللّٰهِ فَلَا تَعۡتَدُوۡهَاۚ وَمَنۡ يَّتَعَدَّ حُدُوۡدَ اللّٰهِ فَاُولٰٓئِكَ هُمُ الظّٰلِمُوۡنَ","u":"طلاق رجعی ہے دو بار تک اسکے بعد رکھ لینا موافق دستور کے یا چھوڑ دینا بھلی طرح سے اور تم کو روا نہیں کہ لے لو کچھ اپنا دیا ہوا عورتوں سے مگر جبکہ خاوند عورت دونوں ڈریں اس بات سے کہ قائم نہ رکھ سکیں گے حکم اللہ کا پھر اگر تم لوگ ڈرو اس بات سے کہ وہ دونوں قائم نہ رکھ سکیں گے اللہ کا حکم تو کچھ گناہ نہیں دونوں پر اس میں کہ عورت بدلہ دیکر چھوٹ جاوے یہ اللہ کی باندھی ہوئی حدیں ہیں سو ان سے آگے مت بڑھو اور جو کوئی بڑھ چلے اللہ کی باندھی ہوئی حدوں سےسو وہی لوگ ہیں ظالم"},{"n":75,"l":"ت","t":"تعاون و باہمی امداد","p":"6","s":"المائدہ","sn":5,"r":"1","a":"2","ar":"يٰ٘اَيُّهَا الَّذِيۡنَ اٰمَنُوۡا لَا تُحِلُّوۡا شَعَآئِرَ اللّٰهِ وَلَا الشَّهۡرَ الۡحَرَامَ وَلَا الۡهَدۡيَ وَلَا الۡقَلَآئِدَ وَلَا٘ آٰمِّيۡنَ الۡبَيۡتَ الۡحَرَامَ يَبۡتَغُوۡنَ فَضۡلًا مِّنۡ رَّبِّهِمۡ وَرِضۡوَانًاؕ وَاِذَا حَلَلۡتُمۡ فَاصۡطَادُوۡاؕ وَلَا يَجۡرِمَنَّكُمۡ شَنَاٰنُ قَوۡمٍ اَنۡ صَدُّوۡكُمۡ عَنِ الۡمَسۡجِدِ الۡحَرَامِ اَنۡ تَعۡتَدُوۡاۘ وَتَعَاوَنُوۡا عَلَي الۡبِرِّ وَالتَّقۡوٰي وَلَا تَعَاوَنُوۡا عَلَي الۡاِثۡمِ وَالۡعُدۡوَانِ وَاتَّقُوا اللّٰهَؕ اِنَّ اللّٰهَ شَدِيۡدُ الۡعِقَابِ","u":"اے ایمان والو حلال نہ سمجھو اللہ کی نشانیوں کو اور نہ ادب والے مہینہ کو اور نہ اس جانور کو جو نیاز کعبہ کی ہو اور نہ جنکے گلے میں پٹا ڈال کر لیجاویں کعبہ کو اور نہ آنے والوں کو حرمت والے گھر کی طرف جو ڈھونڈتے ہیں فضل اپنے رب کا اور اسکی خوشی اور جب احرام سے نکلو تو شکار کر لو اور باعث نہ ہو تم کو اس قوم کی دشمنی جو کہ تم کو روکتی تھی حرمت والی مسجد سے اس پر کہ زیادتی کرنے لگو اور آپس میں مدد کرو نیک کام پر اور پرہیزگاری پر اور مدد نہ کرو گناہ پر اور ظلم پر اور ڈرتے رہو اللہ سے بیشک اللہ کا عذاب سخت ہے"},{"n":76,"l":"ت","t":"توحیدِ ربوبیت و الوہیت","p":"7","s":"الانعام","sn":6,"r":"13","a":"102","ar":"ذٰلِكُمُ اللّٰهُ رَبُّكُمۡۚ لَا٘ اِلٰهَ اِلَّا هُوَۚ خَالِقُ كُلِّ شَيۡءٍ فَاعۡبُدُوۡهُۚ وَهُوَ عَلٰي كُلِّ شَيۡءٍ وَّكِيۡلٌ","u":"یہ اللہ تمہارا رب ہے نہیں ہے کوئی معبود سوا اسکے پیدا کرنے والا ہر چیز کا سو تم اسی کی عبادت کرو اور وہ ہرچیز پر کارساز ہے"},{"n":77,"l":"ت","t":"تقدیر پر ایمان","p":"27","s":"القمر","sn":54,"r":"3","a":"49","ar":"اِنَّا كُلَّ شَيۡءٍ خَلَقۡنٰهُ بِقَدَرٍ","u":"ہم نے ہر چیز بنائی پہلے ٹھہرا کر"},{"n":78,"l":"ت","t":"تفکر و تدبر کی دعوت","p":"4","s":"آلِ عمران","sn":3,"r":"20","a":"190-191","ar":"اِنَّ فِيۡ خَلۡقِ السَّمٰوٰتِ وَالۡاَرۡضِ وَاخۡتِلَافِ الَّيۡلِ وَالنَّهَارِ لَاٰيٰتٍ لِّاُولِي الۡاَلۡبَابِۚۖ الَّذِيۡنَ يَذۡكُرُوۡنَ اللّٰهَ قِيٰمًا وَّقُعُوۡدًا وَّعَلٰي جُنُوۡبِهِمۡ وَيَتَفَكَّرُوۡنَ فِيۡ خَلۡقِ السَّمٰوٰتِ وَالۡاَرۡضِۚ رَبَّنَا مَا خَلَقۡتَ هٰذَا بَاطِلًاۚ سُبۡحٰنَكَ فَقِنَا عَذَابَ النَّارِ","u":"بیشک آسمان اور زمین کا بنانا اور رات اور دن کا آنا جانا اس میں نشانیاں ہیں عقل والوں کو وہ جو یاد کرتے ہیں اللہ کو کھڑے اور بیٹھے اور کروٹ پر لیٹے اور فکر کرتے ہیں آسمان اور زمین کی پیدائش میں کہتے ہیں اے رب ہمارے تو نے یہ عبث نہیں بنایا تو پاک ہے سب عیبوں سے ہم کو بچا دوزخ کے عذاب سے"},{"n":79,"l":"ت","t":"تکریمِ انسانیت","p":"30","s":"التین","sn":95,"r":"1","a":"4","ar":"لَقَدۡ خَلَقۡنَا الۡاِنۡسَانَ فِيۡ٘ اَحۡسَنِ تَقۡوِيۡمٍؗ","u":"ہم نے بنایا آدمی خوب سے اندازے پر"},{"n":80,"l":"ت","t":"تنگ دستی میں صبر","p":"2","s":"البقرہ","sn":2,"r":"22","a":"177","ar":"لَيۡسَ الۡبِرَّ اَنۡ تُوَلُّوۡا وُجُوۡهَكُمۡ قِبَلَ الۡمَشۡرِقِ وَالۡمَغۡرِبِ وَلٰكِنَّ الۡبِرَّ مَنۡ اٰمَنَ بِاللّٰهِ وَالۡيَوۡمِ الۡاٰخِرِ وَالۡمَلٰٓئِكَةِ وَالۡكِتٰبِ وَالنَّبِيّٖنَۚ وَاٰتَي الۡمَالَ عَلٰي حُبِّهٖ ذَوِي الۡقُرۡبٰي وَالۡيَتٰمٰي وَالۡمَسٰكِيۡنَ وَابۡنَ السَّبِيۡلِۙ وَالسَّآئِلِيۡنَ وَفِي الرِّقَابِۚ وَاَقَامَ الصَّلٰوةَ وَاٰتَي الزَّكٰوةَۚ وَالۡمُوۡفُوۡنَ بِعَهۡدِهِمۡ اِذَا عٰهَدُوۡاۚ وَالصّٰبِرِيۡنَ فِي الۡبَاۡسَآءِ وَالضَّرَّآءِ وَحِيۡنَ الۡبَاۡسِؕ اُولٰٓئِكَ الَّذِيۡنَ صَدَقُوۡاؕ وَاُولٰٓئِكَ هُمُ الۡمُتَّقُوۡنَ","u":"نیکی کچھ یہی نہیں کہ منہ کرو اپنا مشرق کی طرف یا مغرب کی لیکن بڑی نیکی تو یہ ہے جو کوئی ایمان لائے اللہ پر اور قیامت کے دن پر اور فرشتوں پر اور سب کتابوں پر اور پیغمبروں پر اور دے مال اس کی محبت پر رشتہ داروں کو اور یتیموں کو اور محتاجوں کو اور مسافروں کو اور مانگنے والوں کو اور گردنیں چھڑانے میں اور قائم رکھے نماز اور دیا کرے زکوٰۃ اور پورا کرنے والے اپنے اقرار کو جب عہد کریں اور صبر کرنے والے سختی میں اور تکلیف میں اور لڑائی کے وقت یہی لوگ ہیں سچے اور یہی ہیں پرہیزگار"},{"n":81,"l":"ت","t":"تیمم کے احکام","p":"6","s":"المائدہ","sn":5,"r":"2","a":"6","ar":"يٰ٘اَيُّهَا الَّذِيۡنَ اٰمَنُوۡ٘ا اِذَا قُمۡتُمۡ اِلَي الصَّلٰوةِ فَاغۡسِلُوۡا وُجُوۡهَكُمۡ وَاَيۡدِيَكُمۡ اِلَي الۡمَرَافِقِ وَامۡسَحُوۡا بِرُءُوۡسِكُمۡ وَاَرۡجُلَكُمۡ اِلَي الۡكَعۡبَيۡنِؕ وَاِنۡ كُنۡتُمۡ جُنُبًا فَاطَّهَّرُوۡاؕ وَاِنۡ كُنۡتُمۡ مَّرۡضٰ٘ي اَوۡ عَلٰي سَفَرٍ اَوۡ جَآءَ اَحَدٌ مِّنۡكُمۡ مِّنَ الۡغَآئِطِ اَوۡ لٰمَسۡتُمُ النِّسَآءَ فَلَمۡ تَجِدُوۡا مَآءً فَتَيَمَّمُوۡا صَعِيۡدًا طَيِّبًا فَامۡسَحُوۡا بِوُجُوۡهِكُمۡ وَاَيۡدِيۡكُمۡ مِّنۡهُؕ مَا يُرِيۡدُ اللّٰهُ لِيَجۡعَلَ عَلَيۡكُمۡ مِّنۡ حَرَجٍ وَّلٰكِنۡ يُّرِيۡدُ لِيُطَهِّرَكُمۡ وَلِيُتِمَّ نِعۡمَتَهٗ عَلَيۡكُمۡ لَعَلَّكُمۡ تَشۡكُرُوۡنَ","u":"اے ایمان والو جب تم اٹھو نماز کو تو دھو لو اپنے منہ اور ہاتھ کہنیوں تک اور مل لو اپنے سر کو اور پاؤں ٹخنوں تک اور اگر تم کو جنابت ہو تو خوب طرح پاک ہو اور اگر تم بیمار ہو یا سفر میں یا کوئی تم میں آیا ہے جائے ضرور سے یا پاس گئے ہو عورتوں کے پھر نہ پاؤ تم پانی تو قصد کرو مٹی پاک کا اور مل لو اپنے منہ اور ہاتھ اس سے اللہ نہیں چاہتا کہ تم پر تنگی کرے لیکن چاہتا ہے کہ تم کو پاک کرے اور پورا کرے اپنا احسان تم پر تاکہ تم احسان مانو"},{"n":82,"l":"ت","t":"تعویذ و ٹونے ٹوٹکوں سے اجتناب","p":"30","s":"الفلق","sn":113,"r":"1","a":"1-5","ar":"قُلۡ اَعُوۡذُ بِرَبِّ الۡفَلَقِۙ مِنۡ شَرِّ مَا خَلَقَۙ وَمِنۡ شَرِّ غَاسِقٍ اِذَا وَقَبَۙ وَمِنۡ شَرِّ النَّفّٰثٰتِ فِي الۡعُقَدِۙ وَمِنۡ شَرِّ حَاسِدٍ اِذَا حَسَدَ","u":"تو کہہ میں پناہ میں آیا صبح کے رب کی ہر چیز کی بدی سے جو اُس نے بنائی اور بدی سے اندھیرے کی جب سمٹ آئے اور بدی سے عورتوں کی جو گرہوں میں پھونک ماریں اور بدی سے برا چاہنے والے کی جب لگے ٹوک لگانے"},{"n":83,"l":"ت","t":"تجسس کی ممانعت","p":"26","s":"الحجرات","sn":49,"r":"2","a":"12","ar":"يٰ٘اَيُّهَا الَّذِيۡنَ اٰمَنُوا اجۡتَنِبُوۡا كَثِيۡرًا مِّنَ الظَّنِّؗ اِنَّ بَعۡضَ الظَّنِّ اِثۡمٌ وَّلَا تَجَسَّسُوۡا وَلَا يَغۡتَبۡ بَّعۡضُكُمۡ بَعۡضًاؕ اَيُحِبُّ اَحَدُكُمۡ اَنۡ يَّاۡكُلَ لَحۡمَ اَخِيۡهِ مَيۡتًا فَكَرِهۡتُمُوۡهُؕ وَاتَّقُوا اللّٰهَؕ اِنَّ اللّٰهَ تَوَّابٌ رَّحِيۡمٌ","u":"اے ایمان والو بچتے رہو بہت تہمتیں کرنے سے مقرر بعضی تہمت گناہ ہے اور بھید نہ ٹٹولو کسی کا اور برا نہ کہیو پیٹھ پیچھے ایک دوسرے کو بھلا خوش لگتا ہے تم میں کسی کو کہ کھائے گوشت اپنے بھائی کا جو مردہ ہو سو گھن آتا ہے تم کو اس سے اور ڈرتے رہو اللہ سے بیشک اللہ معاف کرنے والا ہے مہربان"},{"n":84,"l":"ت","t":"تحفہ و ہدیہ کی ترغیب","p":"29","s":"الانسان","sn":76,"r":"1","a":"8","ar":"وَيُطۡعِمُوۡنَ الطَّعَامَ عَلٰي حُبِّهٖ مِسۡكِيۡنًا وَّيَتِيۡمًا وَّاَسِيۡرًا","u":"اور کھلاتے ہیں کھانا اُسکی محبت پر محتاج کو اور یتیم کو اور قیدی کو"},{"n":85,"l":"ت","t":"تنہائی میں اللہ کی نگرانی کا احساس","p":"26","s":"قٓ","sn":50,"r":"2","a":"16","ar":"وَلَقَدۡ خَلَقۡنَا الۡاِنۡسَانَ وَنَعۡلَمُ مَا تُوَسۡوِسُ بِهٖ نَفۡسُهٗۚۖ وَنَحۡنُ اَقۡرَبُ اِلَيۡهِ مِنۡ حَبۡلِ الۡوَرِيۡدِ","u":"اور البتہ ہم نے بنایا انسان کو اور ہم جانتےہیں جو باتیں آتی رہتی ہیں اُسکے جی میں اور ہم اُس سے نزدیک ہیں دھڑکتی رگ سے زیادہ"},{"n":86,"l":"ت","t":"تطہیرِ قلب","p":"19","s":"الشعراء","sn":26,"r":"5","a":"88-89","ar":"يَوۡمَ لَا يَنۡفَعُ مَالٌ وَّلَا بَنُوۡنَۙ اِلَّا مَنۡ اَتَي اللّٰهَ بِقَلۡبٍ سَلِيۡمٍؕ","u":"جس دن نہ کام آئے کوئی مال اور نہ بیٹے مگر جو کوئی آیا اللہ کے پاس لیکر دل چنگا"},{"n":87,"l":"ت","t":"ترکِ گناہ کے فوائد","p":"28","s":"التحریم","sn":66,"r":"2","a":"8","ar":"يٰ٘اَيُّهَا الَّذِيۡنَ اٰمَنُوۡا تُوۡبُوۡ٘ا اِلَي اللّٰهِ تَوۡبَةً نَّصُوۡحًاؕ عَسٰي رَبُّكُمۡ اَنۡ يُّكَفِّرَ عَنۡكُمۡ سَيِّاٰتِكُمۡ وَيُدۡخِلَكُمۡ جَنّٰتٍ تَجۡرِيۡ مِنۡ تَحۡتِهَا الۡاَنۡهٰرُۙ يَوۡمَ لَا يُخۡزِي اللّٰهُ النَّبِيَّ وَالَّذِيۡنَ اٰمَنُوۡا مَعَهٗۚ نُوۡرُهُمۡ يَسۡعٰي بَيۡنَ اَيۡدِيۡهِمۡ وَبِاَيۡمَانِهِمۡ يَقُوۡلُوۡنَ رَبَّنَا٘ اَتۡمِمۡ لَنَا نُوۡرَنَا وَاغۡفِرۡ لَنَاۚ اِنَّكَ عَلٰي كُلِّ شَيۡءٍ قَدِيۡرٌ","u":"اے ایمان والو توبہ کرو اللہ کی طرف صاف دل کی توبہ امید ہے تمہارا رب اتار دے تم پر سے تمہاری برائیاں اور داخل کرے تم کو باغوں میں جنکے نیچے بہتی ہیں نہریں جس دن کہ اللہ ذلیل نہ کرے گا نبی کو اور اُن لوگوں کو جو یقین لاتے ہیں اُسکے ساتھ اُنکی روشنی دوڑتی ہے اُنکے آگے اور اُنکے داہنے کہتے ہیں اے رب ہمارے پوری کر دے ہماری روشنی اور معاف کر ہم کو بیشک تو سب کچھ کر سکتا ہے"},{"n":88,"l":"ت","t":"تخلیقِ کائنات کے مراحل","p":"24","s":"فصلت","sn":41,"r":"2","a":"9-12","ar":"قُلۡ اَئِنَّكُمۡ لَتَكۡفُرُوۡنَ بِالَّذِيۡ خَلَقَ الۡاَرۡضَ فِيۡ يَوۡمَيۡنِ وَتَجۡعَلُوۡنَ لَهٗ٘ اَنۡدَادًاؕ ذٰلِكَ رَبُّ الۡعٰلَمِيۡنَۚ وَجَعَلَ فِيۡهَا رَوَاسِيَ مِنۡ فَوۡقِهَا وَبٰرَكَ فِيۡهَا وَقَدَّرَ فِيۡهَا٘ اَقۡوَاتَهَا فِيۡ٘ اَرۡبَعَةِ اَيَّامٍؕ سَوَآءً لِّلسَّآئِلِيۡنَ ثُمَّ اسۡتَوٰ٘ي اِلَي السَّمَآءِ وَهِيَ دُخَانٌ فَقَالَ لَهَا وَلِلۡاَرۡضِ ائۡتِيَا طَوۡعًا اَوۡ كَرۡهًاؕ قَالَتَا٘ اَتَيۡنَا طَآئِعِيۡنَ فَقَضٰىهُنَّ سَبۡعَ سَمٰوَاتٍ فِيۡ يَوۡمَيۡنِ وَاَوۡحٰي فِيۡ كُلِّ سَمَآءٍ اَمۡرَهَا وَزَيَّنَّا السَّمَآءَ الدُّنۡيَا بِمَصَابِيۡحَۖ وَحِفۡظًاؕ ذٰلِكَ تَقۡدِيۡرُ الۡعَزِيۡزِ الۡعَلِيۡمِ","u":"تو کہہ کیا تم منکر ہو اس سے جس نے بنائی زمین دو دن میں اور برابر کرتے ہو اسکے ساتھ اوروں کو وہ ہے رب جہان کا اور رکھے اس میں بھاری پہاڑ اوپر سے اور برکت رکھی اسکے اندر اور ٹھہرائیں اُسمیں خوراکیں اُسکی چار دن میں پورا ہوا پوچھنے والوں کو پھر چڑھا آسمان کو اور وہ دھواں ہو رہا تھا پھر کہا اسکو اور زمین کو آؤ تم دونوں خوشی سے یا زور سے وہ بولے ہم آئے خوشی سے پھر کر دیے وہ سات آسمان دو دن میں اور اتارا ہر آسمان میں حکم اُس کا اور رونق دی ہم نے سب سے ورلے آسمان کو چراغوں سے اور محفوظ کر دیا یہ سادھا ہوا ہے زبردست خبردار کا"},{"n":89,"l":"ت","t":"تنزیہِ باری تعالیٰ","p":"25","s":"الشوریٰ","sn":42,"r":"2","a":"11","ar":"فَاطِرُ السَّمٰوٰتِ وَالۡاَرۡضِؕ جَعَلَ لَكُمۡ مِّنۡ اَنۡفُسِكُمۡ اَزۡوَاجًا وَّمِنَ الۡاَنۡعَامِ اَزۡوَاجًاۚ يَذۡرَؤُكُمۡ فِيۡهِؕ لَيۡسَ كَمِثۡلِهٖ شَيۡءٌۚ وَهُوَ السَّمِيۡعُ الۡبَصِيۡرُ","u":"بنا نکالنے والا آسمانوں کا اور زمین کا بنا دیے تمہارے واسطے تمہی میں سے جوڑے اور چوپایوں میں سے جوڑے بکھیرتا ہے تمکو اسی طرح نہیں ہے اس کی طرح کا سا کوئی اور وہی ہے سننے والا دیکھنے والا"},{"n":90,"l":"ٹ","t":"ٹھوس وعدوں کی پاسداری","p":"28","s":"الصف","sn":61,"r":"1","a":"2-3","ar":"يٰ٘اَيُّهَا الَّذِيۡنَ اٰمَنُوۡا لِمَ تَقُوۡلُوۡنَ مَا لَا تَفۡعَلُوۡنَ كَبُرَ مَقۡتًا عِنۡدَ اللّٰهِ اَنۡ تَقُوۡلُوۡا مَا لَا تَفۡعَلُوۡنَ","u":"اے ایمان والو کیوں کہتے ہو منہ سے جو نہیں کرتے بڑی بیزاری کی بات ہے اللہ کے یہاں کہ کہو وہ چیز جو نہ کرو"},{"n":91,"l":"ث","t":"ثوابِ اعمال","p":"30","s":"الزلزلہ","sn":99,"r":"1","a":"7-8","ar":"فَمَنۡ يَّعۡمَلۡ مِثۡقَالَ ذَرَّةٍ خَيۡرًا يَّرَهٗؕ وَمَنۡ يَّعۡمَلۡ مِثۡقَالَ ذَرَّةٍ شَرًّا يَّرَهٗ","u":"سو جس نے کی ذرہ بھر بھلائی وہ دیکھ لے گا اُسے اور جس نے کی ذرہ بھر برائی دیکھ لے گا اُسے"},{"n":92,"l":"ث","t":"ثباتِ قدم فی الدین","p":"13","s":"ابراہیم","sn":14,"r":"4","a":"27","ar":"يُثَبِّتُ اللّٰهُ الَّذِيۡنَ اٰمَنُوۡا بِالۡقَوۡلِ الثَّابِتِ فِي الۡحَيٰوةِ الدُّنۡيَا وَفِي الۡاٰخِرَةِۚ وَيُضِلُّ اللّٰهُ الظّٰلِمِيۡنَۙ وَيَفۡعَلُ اللّٰهُ مَا يَشَآءُ","u":"مضبوط کرتا ہے اللہ ایمان والوں کو مضبوط بات سے دنیا کی زندگی میں اور آخرت میں اور بچلا (راہ بھلا دیتا ہے) دیتا ہے اللہ بے انصافوں کو اور کرتا ہے اللہ جو چاہے"},{"n":93,"l":"ج","t":"جنت کی صفات و نعمتیں","p":"26","s":"محمد","sn":47,"r":"2","a":"15","ar":"مَثَلُ الۡجَنَّةِ الَّتِيۡ وُعِدَ الۡمُتَّقُوۡنَؕ فِيۡهَا٘ اَنۡهٰرٌ مِّنۡ مَّآءٍ غَيۡرِ اٰسِنٍۚ وَاَنۡهٰرٌ مِّنۡ لَّبَنٍ لَّمۡ يَتَغَيَّرۡ طَعۡمُهٗۚ وَاَنۡهٰرٌ مِّنۡ خَمۡرٍ لَّذَّةٍ لِّلشّٰرِبِيۡنَ ۚ وَاَنۡهٰرٌ مِّنۡ عَسَلٍ مُّصَفًّيؕ وَلَهُمۡ فِيۡهَا مِنۡ كُلِّ الثَّمَرٰتِ وَمَغۡفِرَةٌ مِّنۡ رَّبِّهِمۡؕ كَمَنۡ هُوَ خَالِدٌ فِي النَّارِ وَسُقُوۡا مَآءً حَمِيۡمًا فَقَطَّعَ اَمۡعَآءَهُمۡ","u":"احوال اس بہشت کا جس کا وعدہ ہوا ہے ڈرنے والوں سے اس میں نہریں ہیں پانی کی جو بو نہیں کر گیا اور نہریں ہیں دودھ کی جس کا مزہ نہیں پھرا اور نہریں ہیں شراب کی جس میں مزہ ہے پینے والوں کے واسطے اور نہریں ہیں شہد کی جھاگ اترا ہوا اور انکے لئے وہاں سب طرح کے میوےہیں اور معافی ہے انکے رب سے یہ برابر ہے اسکے جو سدا رہے آگ میں اور پلایا جائے انکو کھولتا پانی تو کاٹ نکالے انکی آنتیں"},{"n":94,"l":"ج","t":"جہنم کی ہولناکی","p":"29","s":"الحاقہ","sn":69,"r":"1","a":"30-32","ar":"خُذُوۡهُ فَغُلُّوۡهُۙ ثُمَّ الۡجَحِيۡمَ صَلُّوۡهُۙ ثُمَّ فِيۡ سِلۡسِلَةٍ ذَرۡعُهَا سَبۡعُوۡنَ ذِرَاعًا فَاسۡلُكُوۡهُؕ","u":"اُسکو پکڑو پھر طوق ڈالو پھر آگ کے ڈھیر میں اسکو ڈالو پھر ایک زنجیر میں جس کا طول ستر گز ہے اُسکو جکڑ دو"},{"n":95,"l":"ج","t":"جہاد فی سبیل اللہ","p":"11","s":"التوبہ","sn":9,"r":"14","a":"111","ar":"اِنَّ اللّٰهَ اشۡتَرٰي مِنَ الۡمُؤۡمِنِيۡنَ اَنۡفُسَهُمۡ وَاَمۡوَالَهُمۡ بِاَنَّ لَهُمُ الۡجَنَّةَؕ يُقَاتِلُوۡنَ فِيۡ سَبِيۡلِ اللّٰهِ فَيَقۡتُلُوۡنَ وَيُقۡتَلُوۡنَ وَعۡدًا عَلَيۡهِ حَقًّا فِي التَّوۡرٰىةِ وَالۡاِنۡجِيۡلِ وَالۡقُرۡاٰنِؕ وَمَنۡ اَوۡفٰي بِعَهۡدِهٖ مِنَ اللّٰهِ فَاسۡتَبۡشِرُوۡا بِبَيۡعِكُمُ الَّذِيۡ بَايَعۡتُمۡ بِهٖؕ وَذٰلِكَ هُوَ الۡفَوۡزُ الۡعَظِيۡمُ","u":"اللہ نے خرید لی مسلمانوں سے ان کی جان اور ان کا مال اس قیمت پر کہ انکے لئے جنت ہے لڑتے ہیں اللہ کی راہ میں پھر مارتے ہیں اور مرتے ہیں وعدہ ہو چکا اسکے ذمہ پر سچا توریت اور انجیل اور قرآن میں اور کون ہے قول کا پورا اللہ سے زیادہ سو خوشیاں کرو اس معاملہ پر جو تم نے کیا ہے اس سے اور یہ یہی ہے بڑی کامیابی"},{"n":96,"l":"ج","t":"جھوٹ کی ممانعت","p":"17","s":"الحج","sn":22,"r":"4","a":"30","ar":"ذٰلِكَ وَمَنۡ يُّعَظِّمۡ حُرُمٰتِ اللّٰهِ فَهُوَ خَيۡرٌ لَّهٗ عِنۡدَ رَبِّهٖؕ وَاُحِلَّتۡ لَكُمُ الۡاَنۡعَامُ اِلَّا مَا يُتۡلٰي عَلَيۡكُمۡ فَاجۡتَنِبُوا الرِّجۡسَ مِنَ الۡاَوۡثَانِ وَاجۡتَنِبُوۡا قَوۡلَ الزُّوۡرِۙ","u":"یہ سن چکے اور جو کوئی بڑائی رکھے اللہ کی حرمتوں کی سو وہ بہتر ہے آُسکے لئے اپنے رب کے پاس اور حلال ہیں تمکو چوپائے مگر جو تمکو سناتےہیں سو بچتے رہو بتوں کی گندگی سے اور بچتے رہو جھوٹی بات سے"},{"n":97,"l":"ج","t":"جادو کی حقیقت","p":"1","s":"البقرہ","sn":2,"r":"12","a":"102","ar":"وَاتَّبَعُوۡا مَا تَتۡلُوا الشَّيٰطِيۡنُ عَلٰي مُلۡكِ سُلَيۡمٰنَۚ وَمَا كَفَرَ سُلَيۡمٰنُ وَلٰكِنَّ الشَّيٰطِيۡنَ كَفَرُوۡا يُعَلِّمُوۡنَ النَّاسَ السِّحۡرَ وَمَا٘ اُنۡزِلَ عَلَي الۡمَلَكَيۡنِ بِبَابِلَ هَارُوۡتَ وَمَارُوۡتَؕ وَمَا يُعَلِّمٰنِ مِنۡ اَحَدٍ حَتّٰي يَقُوۡلَا٘ اِنَّمَا نَحۡنُ فِتۡنَةٌ فَلَا تَكۡفُرۡؕ فَيَتَعَلَّمُوۡنَ مِنۡهُمَا مَا يُفَرِّقُوۡنَ بِهٖ بَيۡنَ الۡمَرۡءِ وَزَوۡجِهٖؕ وَمَا هُمۡ بِضَآرِّيۡنَ بِهٖ مِنۡ اَحَدٍ اِلَّا بِاِذۡنِ اللّٰهِؕ وَيَتَعَلَّمُوۡنَ مَا يَضُرُّهُمۡ وَلَا يَنۡفَعُهُمۡؕ وَلَقَدۡ عَلِمُوۡا لَمَنِ اشۡتَرٰىهُ مَا لَهٗ فِي الۡاٰخِرَةِ مِنۡ خَلَاقٍؕ وَلَبِئۡسَ مَا شَرَوۡا بِهٖ٘ اَنۡفُسَهُمۡؕ لَوۡ كَانُوۡا يَعۡلَمُوۡنَ","u":"اور پیچھے ہو لئے اس علم کے جو پڑتے تھے شیطان سلیمان کی بادشاہت کے وقت اور کفر نہیں کیا سلیمان نے لیکن شیطانوں نے کفر کیا کہ سکھلاتے تھے لوگوں کو جادو اور اس علم کے پیچھے ہو لئے جو اترا دو فرشتوں پر شہر بابل میں جن کا نام ہاروت اور ماروت ہے اور نہیں سکھاتے تھے وہ دونوں فرشتے کسی کو جب تک یہ نہ کہدیتے کہ ہم تو آزمائش کے لئے ہیں سو تو کافر مت ہو پھر ان سے سیکھتے وہ جادو جس سے جدائی ڈالتے ہیں مرد میں اور اسکی عورت میں اور وہ اس سے نقصان نہیں کر سکتے کس کا بغیر حکم اللہ کے اور سیکھتے ہیں وہ چیز جو نقصان کرے ان کا اور فائدہ نہ کرے اور وہ خوب جان چکے ہیں کہ جس نے اختیار کیا جادو کو نہیں اس کے لئے آخرت میں کچھ حصہ اور بہت ہی بری چیز ہے جسکے بدلے بیچا انہوں نے اپنے آپکو اگر ان کو سمجھ ہوتی"},{"n":98,"l":"ج","t":"جمعہ کی فضیلت","p":"28","s":"الجمعہ","sn":62,"r":"2","a":"9","ar":"يٰ٘اَيُّهَا الَّذِيۡنَ اٰمَنُوۡ٘ا اِذَا نُوۡدِيَ لِلصَّلٰوةِ مِنۡ يَّوۡمِ الۡجُمُعَةِ فَاسۡعَوۡا اِلٰي ذِكۡرِ اللّٰهِ وَذَرُوا الۡبَيۡعَؕ ذٰلِكُمۡ خَيۡرٌ لَّكُمۡ اِنۡ كُنۡتُمۡ تَعۡلَمُوۡنَ","u":"اے ایمان والو جب اذان ہو نماز کی جمعہ کے دن تو دوڑو اللہ کی یاد کو اور چھوڑ دو خرید و فروخت یہ بہتر ہے تمہارے حق میں اگر تم کو سمجھ ہے"},{"n":99,"l":"ج","t":"جنات کا تذکرہ","p":"27","s":"الذاریات","sn":51,"r":"3","a":"56","ar":"وَمَا خَلَقۡتُ الۡجِنَّ وَالۡاِنۡسَ اِلَّا لِيَعۡبُدُوۡنِ","u":"اور میں نے جو بنائے جن اور آدمی سو اپنی بندگی کو"},{"n":100,"l":"ج","t":"جواب دہی کا تصور (یومِ حساب)","p":"17","s":"الانبیاء","sn":21,"r":"4","a":"47","ar":"وَنَضَعُ الۡمَوَازِيۡنَ الۡقِسۡطَ لِيَوۡمِ الۡقِيٰمَةِ فَلَا تُظۡلَمُ نَفۡسٌ شَيۡـًٔاؕ وَاِنۡ كَانَ مِثۡقَالَ حَبَّةٍ مِّنۡ خَرۡدَلٍ اَتَيۡنَا بِهَاؕ وَكَفٰي بِنَا حٰسِبِيۡنَ","u":"اور رکھیں گے ہم ترازوئیں انصاف کی قیامت کے دن پھر ظلم نہ ہو گا کسی جی پر ایک ذرہ اور اگر ہو گا برابر رائی کے دانہ کی تو ہم لے آئیں گے اُسکو اور ہم کافی ہیں حساب کرنے کو"},{"n":101,"l":"ج","t":"جانوروں کے حقوق","p":"7","s":"الانعام","sn":6,"r":"4","a":"38","ar":"وَمَا مِنۡ دَآبَّةٍ فِي الۡاَرۡضِ وَلَا طٰٓئِرٍ يَّطِيۡرُ بِجَنَاحَيۡهِ اِلَّا٘ اُمَمٌ اَمۡثَالُكُمۡؕ مَا فَرَّطۡنَا فِي الۡكِتٰبِ مِنۡ شَيۡءٍ ثُمَّ اِلٰي رَبِّهِمۡ يُحۡشَرُوۡنَ","u":"اور نہیں ہے کوئی چلنے والا زمین میں اور نہ کوئی پرندہ کہ اڑتا ہے اپنے دو بازوؤں سے مگر ہر ایک امت ہے تمہاری طرح ہم نےنہیں چھوڑی لکھنے میں کوئی چیز پھر سب اپنے رب کے سامنے جمع ہوں گے"},{"n":102,"l":"ج","t":"جنگی قیدیوں کے حقوق","p":"26","s":"محمد","sn":47,"r":"1","a":"4","ar":"فَاِذَا لَقِيۡتُمُ الَّذِيۡنَ كَفَرُوۡا فَضَرۡبَ الرِّقَابِؕ حَتّٰ٘ي اِذَا٘ اَثۡخَنۡتُمُوۡهُمۡ فَشُدُّوا الۡوَثَاقَۙ فَاِمَّا مَنًّاۭ بَعۡدُ وَاِمَّا فِدَآءً حَتّٰي تَضَعَ الۡحَرۡبُ اَوۡزَارَهَا ۚۛ ذٰلِكَؕۛ وَلَوۡ يَشَآءُ اللّٰهُ لَانۡتَصَرَ مِنۡهُمۡۙ وَلٰكِنۡ لِّيَبۡلُوَا۠ بَعۡضَكُمۡ بِبَعۡضٍؕ وَالَّذِيۡنَ قُتِلُوۡا فِيۡ سَبِيۡلِ اللّٰهِ فَلَنۡ يُّضِلَّ اَعۡمَالَهُمۡ","u":"سو جب تم مقابل ہو منکروں کے تو مارو گردنیں یہاں تک کہ جب خوب قتل کر چکو انکو تو مضبوط باندھ لو قید پھر یا احسان کیجیو اور یا معاوضہ لیجیو جب تک کہ رکھ دے لڑائی اپنے ہتھیار یہ سن چکے اور اگر چاہے اللہ تو بدلا لے ان سے پر جانچنا چاہتا ہے تمہارے ایک سے دوسرے کو اور جو لوگ مارے گئے اللہ کی راہ میں تو نہ ضائع کرے گا وہ انکے کئے کام"},{"n":103,"l":"ج","t":"جسمانی صحت کی اہمیت","p":"8","s":"الاعراف","sn":7,"r":"3","a":"31","ar":"يٰبَنِيۡ٘ اٰدَمَ خُذُوۡا زِيۡنَتَكُمۡ عِنۡدَ كُلِّ مَسۡجِدٍ وَّكُلُوۡا وَاشۡرَبُوۡا وَلَا تُسۡرِفُوۡاۚؕ اِنَّهٗ لَا يُحِبُّ الۡمُسۡرِفِيۡنَ","u":"اے اولاد آدم کی لے لو اپنی آرائش ہر نماز کے وقت اور کھاؤ اور پیئو اور بیجا خرچ نہ کرو اس کو خوش نہیں آتے بیجا خرچ کرنے والے"},{"n":104,"l":"ج","t":"جزاء و سزا کا اصول","p":"27","s":"النجم","sn":53,"r":"2","a":"31","ar":"وَلِلّٰهِ مَا فِي السَّمٰوٰتِ وَمَا فِي الۡاَرۡضِۙ لِيَجۡزِيَ الَّذِيۡنَ اَسَآءُوۡا بِمَا عَمِلُوۡا وَيَجۡزِيَ الَّذِيۡنَ اَحۡسَنُوۡا بِالۡحُسۡنٰيۚ","u":"اور اللہ کا ہے جو کچھ ہے آسمانوں میں اور زمین میں تاکہ وہ بدلا دے برائی والوں کو اُنکے کئے کا اور بدلا دے بھلائی والوں کو بھلائی سے"},{"n":105,"l":"ج","t":"جنگی اخلاقیات","p":"2","s":"البقرہ","sn":2,"r":"24","a":"190","ar":"وَقَاتِلُوۡا فِيۡ سَبِيۡلِ اللّٰهِ الَّذِيۡنَ يُقَاتِلُوۡنَكُمۡ وَلَا تَعۡتَدُوۡاؕ اِنَّ اللّٰهَ لَا يُحِبُّ الۡمُعۡتَدِيۡنَ","u":"اور لڑو اللہ کی راہ میں ان لگوں سے جو لڑتے ہیں تم سے اور کسی پر زیادتی مت کرو بیشک اللہ تعالیٰ ناپسند کرتا ہے زیادتی کرنے والوں کو"},{"n":106,"l":"ج","t":"جسمانی و روحانی پاکیزگی","p":"11","s":"التوبہ","sn":9,"r":"13","a":"108","ar":"لَا تَقُمۡ فِيۡهِ اَبَدًاؕ لَمَسۡجِدٌ اُسِّسَ عَلَي التَّقۡوٰي مِنۡ اَوَّلِ يَوۡمٍ اَحَقُّ اَنۡ تَقُوۡمَ فِيۡهِؕ فِيۡهِ رِجَالٌ يُّحِبُّوۡنَ اَنۡ يَّتَطَهَّرُوۡاؕ وَاللّٰهُ يُحِبُّ الۡمُطَّهِّرِيۡنَ","u":"تو نہ کھڑا ہو اس میں کبھی البتہ وہ مسجد جسکی بنیاد دھری گئ پرہیزگاری پر اول دن سے وہ لائق ہے کہ تو کھڑا ہو اسمیں اس میں ایسےلوگ ہیں جو دوست رکھتے ہیں پاک رہنے کو اور اللہ دوست رکھتا ہے پاک رہنے والوں کو"},{"n":107,"l":"ج","t":"جزیہ کا حکم","p":"10","s":"التوبہ","sn":9,"r":"4","a":"29","ar":"قَاتِلُوا الَّذِيۡنَ لَا يُؤۡمِنُوۡنَ بِاللّٰهِ وَلَا بِالۡيَوۡمِ الۡاٰخِرِ وَلَا يُحَرِّمُوۡنَ مَا حَرَّمَ اللّٰهُ وَرَسُوۡلُهٗ وَلَا يَدِيۡنُوۡنَ دِيۡنَ الۡحَقِّ مِنَ الَّذِيۡنَ اُوۡتُوا الۡكِتٰبَ حَتّٰي يُعۡطُوا الۡجِزۡيَةَ عَنۡ يَّدٍ وَّهُمۡ صٰغِرُوۡنَ","u":"لڑو ان لوگوں سے جو ایمان نہیں لاتے اللہ پر اور نہ آخرت کے دن پر اور نہ حرام جانتے ہیں اسکو جس کو حرام کیا اللہ نے اور اسکے رسول نے اور نہ قبول کرتے ہیں دین سچا ان لوگوں میں سے جو کہ اہل کتاب ہیں یہاں تک کہ وہ جزیہ دیں اپنے ہاتھ سے ذلیل ہو کر"},{"n":108,"l":"ج","t":"جوامع الکلم (اعجازِ بیانِ قرآن)","p":"15","s":"بنی اسرائیل (الاسراء)","sn":17,"r":"10","a":"88","ar":"قُلۡ لَّئِنِ اجۡتَمَعَتِ الۡاِنۡسُ وَالۡجِنُّ عَلٰ٘ي اَنۡ يَّاۡتُوۡا بِمِثۡلِ هٰذَا الۡقُرۡاٰنِ لَا يَاۡتُوۡنَ بِمِثۡلِهٖ وَلَوۡ كَانَ بَعۡضُهُمۡ لِبَعۡضٍ ظَهِيۡرًا","u":"کہہ اگر جمع ہوں آدمی اور جن اس پر کہ لائیں ایسا قرآن ہر گز نہ لائیں گے ایسا قرآن اور پڑے مدد کیا کریں ایک دوسرے کی"},{"n":109,"l":"چ","t":"چاند اور سورج کا نظام","p":"27","s":"الرحمٰن","sn":55,"r":"1","a":"5","ar":"اَلشَّمۡسُ وَالۡقَمَرُ بِحُسۡبَانٍۙ","u":"سورج اور چاند کیلئے ایک حساب ہے"},{"n":110,"l":"چ","t":"چاند کی منزلیں","p":"23","s":"یٰسٓ","sn":36,"r":"3","a":"39","ar":"وَالۡقَمَرَ قَدَّرۡنٰهُ مَنَازِلَ حَتّٰي عَادَ كَالۡعُرۡجُوۡنِ الۡقَدِيۡمِ","u":"اور چاند کو ہم نے بانٹ دی ہیں منزلیں یہاں تک کہ پھر آ رہا ہے جیسے ٹہنی پرانی"},{"n":111,"l":"ح","t":"حلال و حرام کے احکام","p":"6","s":"المائدہ","sn":5,"r":"1","a":"3","ar":"حُرِّمَتۡ عَلَيۡكُمُ الۡمَيۡتَةُ وَالدَّمُ وَلَحۡمُ الۡخِنۡزِيۡرِ وَمَا٘ اُهِلَّ لِغَيۡرِ اللّٰهِ بِهٖ وَالۡمُنۡخَنِقَةُ وَالۡمَوۡقُوۡذَةُ وَالۡمُتَرَدِّيَةُ وَالنَّطِيۡحَةُ وَمَا٘ اَكَلَ السَّبُعُ اِلَّا مَا ذَكَّيۡتُمۡ وَمَا ذُبِحَ عَلَي النُّصُبِ وَاَنۡ تَسۡتَقۡسِمُوۡا بِالۡاَزۡلَامِؕ ذٰلِكُمۡ فِسۡقٌؕ اَلۡيَوۡمَ يَئِسَ الَّذِيۡنَ كَفَرُوۡا مِنۡ دِيۡنِكُمۡ فَلَا تَخۡشَوۡهُمۡ وَاخۡشَوۡنِؕ اَلۡيَوۡمَ اَكۡمَلۡتُ لَكُمۡ دِيۡنَكُمۡ وَاَتۡمَمۡتُ عَلَيۡكُمۡ نِعۡمَتِيۡ وَرَضِيۡتُ لَكُمُ الۡاِسۡلَامَ دِيۡنًاؕ فَمَنِ اضۡطُرَّ فِيۡ مَخۡمَصَةٍ غَيۡرَ مُتَجَانِفٍ لِّاِثۡمٍۙ فَاِنَّ اللّٰهَ غَفُوۡرٌ رَّحِيۡمٌ","u":"حرام ہوا تم پر مردہ جانور اور لہو اور گوشت سور کا اور جس جانور پر نام پکارا جائے اللہ کے سوا کسی اور کا اور جو مر گیا ہو گلا گھونٹنے سے یاچوٹ سے یا اونچے سے گر کر یا سینگ مارنے سے اور جس کو کھایا ہو درندہ نے مگر جس کو تم نےذبح کر لیا اور حرام ہے جو ذبح ہوا کسی تھان پر اور یہ کہ تقسیم کرو جوئے کے تیروں سے یہ گناہ کا کام ہے آج ناامید ہو گئے کافر تمہارے دین سے سو ان سے مت ڈرو اور مجھ سے ڈرو آج میں پورا کر چکا تمہارے لئے دین تمہارا اور پورا کیا تم پر میں نے احسان اپنا اور پسند کیا میں نے تمہارے واسطےاسلام کو دین پھر جو کوئی لاچار ہو جاوے بھوک میں لیکن گناہ پر مائل نہ ہو تو اللہ بخشنے والا مہربان ہے"},{"n":112,"l":"ح","t":"حقوق العباد","p":"15","s":"بنی اسرائیل (الاسراء)","sn":17,"r":"3","a":"26","ar":"وَاٰتِ ذَا الۡقُرۡبٰي حَقَّهٗ وَالۡمِسۡكِيۡنَ وَابۡنَ السَّبِيۡلِ وَلَا تُبَذِّرۡ تَبۡذِيۡرًا","u":"اور دے قرابت والے کو اس کا حق اور محتاج کو اور مسافر کو اور مت اڑا بیجا (فضول)"},{"n":113,"l":"ح","t":"حج کے احکام","p":"4","s":"آلِ عمران","sn":3,"r":"10","a":"97","ar":"فِيۡهِ اٰيٰتٌۭ بَيِّنٰتٌ مَّقَامُ اِبۡرٰهِيۡمَ ۚ وَمَنۡ دَخَلَهٗ كَانَ اٰمِنًاؕ وَلِلّٰهِ عَلَي النَّاسِ حِجُّ الۡبَيۡتِ مَنِ اسۡتَطَاعَ اِلَيۡهِ سَبِيۡلًاؕ وَمَنۡ كَفَرَ فَاِنَّ اللّٰهَ غَنِيٌّ عَنِ الۡعٰلَمِيۡنَ","u":"اس میں نشانیاں ہیں ظاہر جیسے مقام ابراہیم اور جو اس کے اندر آیا اس کو امن ملا اور اللہ کا حق ہے لوگوں پر حج کرنا اس گھر کا جو شخص قدرت رکھتا ہو اسکی طرف راہ چلنے کی اور جو نہ مانے تو پھر اللہ پروا نہیں رکھتا جہان کے لوگوں کی"},{"n":114,"l":"ح","t":"حسنِ سلوک بوالدین","p":"21","s":"لقمان","sn":31,"r":"2","a":"14","ar":"وَوَصَّيۡنَا الۡاِنۡسَانَ بِوَالِدَيۡهِۚ حَمَلَتۡهُ اُمُّهٗ وَهۡنًا عَلٰي وَهۡنٍ وَّفِصٰلُهٗ فِيۡ عَامَيۡنِ اَنِ اشۡكُرۡ لِيۡ وَلِوَالِدَيۡكَؕ اِلَيَّ الۡمَصِيۡرُ","u":"اور ہم نے تاکید کر دی انسان کو اسکے ماں باپ کے واسطے پیٹ میں رکھا اس کو اسکی ماں نے تھک تھک کر اور دودھ چھڑانا ہے اس کا دو برس میں کہ حق مان میرا اور اپنے ماں باپ کا آخر مجھی تک آنا ہے"},{"n":115,"l":"ح","t":"حیا کی اہمیت","p":"18","s":"النور","sn":24,"r":"4","a":"30","ar":"قُلۡ لِّلۡمُؤۡمِنِيۡنَ يَغُضُّوۡا مِنۡ اَبۡصَارِهِمۡ وَيَحۡفَظُوۡا فُرُوۡجَهُمۡؕ ذٰلِكَ اَزۡكٰي لَهُمۡؕ اِنَّ اللّٰهَ خَبِيۡرٌۭ بِمَا يَصۡنَعُوۡنَ","u":"کہہ دے ایمان والوں کو نیچی رکھیں ذری اپنی آنکھیں اور تھامتے رہیں اپنے ستر کو اس میں خوب ستھرائی ہے انکے لئے بیشک اللہ کو خبر ہے جو کچھ کرتےہیں"},{"n":116,"l":"ح","t":"حسد کی مذمت","p":"30","s":"الفلق","sn":113,"r":"1","a":"5","ar":"وَمِنۡ شَرِّ حَاسِدٍ اِذَا حَسَدَ","u":"اور بدی سے برا چاہنے والے کی جب لگے ٹوک لگانے"},{"n":117,"l":"ح","t":"حکمت کا تصور","p":"3","s":"البقرہ","sn":2,"r":"37","a":"269","ar":"يُّؤۡتِي الۡحِكۡمَةَ مَنۡ يَّشَآءُۚ وَمَنۡ يُّؤۡتَ الۡحِكۡمَةَ فَقَدۡ اُوۡتِيَ خَيۡرًا كَثِيۡرًاؕ وَمَا يَذَّكَّرُ اِلَّا٘ اُولُوا الۡاَلۡبَابِ","u":"عنایت کرتا ہے سمجھ جس کسی کو چاہے اور جس کو سمجھ ملی اس کو بڑی خوبی ملی اور نصیحت وہی قبول کرتے ہیں جو عقل والے ہیں"},{"n":118,"l":"ح","t":"حضرت محمد صلی اللہ علیہ وسلم کی صفاتِ کریمہ","p":"29","s":"القلم","sn":68,"r":"1","a":"4","ar":"وَاِنَّكَ لَعَلٰي خُلُقٍ عَظِيۡمٍ","u":"اور تو پیدا ہوا ہے بڑے خلق پر"},{"n":119,"l":"ح","t":"حضرت محمد صلی اللہ علیہ وسلم کا تذکرہ بطور رحمت اللعالمین","p":"17","s":"الانبیاء","sn":21,"r":"7","a":"107","ar":"وَمَا٘ اَرۡسَلۡنٰكَ اِلَّا رَحۡمَةً لِّلۡعٰلَمِيۡنَ","u":"اور تجھ کو جو ہم نے بھیجا سو مہربانی کر کر جہاں کے لوگوں پر"},{"n":120,"l":"ح","t":"حضرت محمد صلی اللہ علیہ وسلم سے محبت و اطاعت","p":"3","s":"آلِ عمران","sn":3,"r":"4","a":"31","ar":"قُلۡ اِنۡ كُنۡتُمۡ تُحِبُّوۡنَ اللّٰهَ فَاتَّبِعُوۡنِيۡ يُحۡبِبۡكُمُ اللّٰهُ وَيَغۡفِرۡ لَكُمۡ ذُنُوۡبَكُمۡؕ وَاللّٰهُ غَفُوۡرٌ رَّحِيۡمٌ","u":"تو کہہ اگر تم محبت رکھتے ہو اللہ کی تو میری راہ چلو تاکہ محبت کرے تم سے اللہ اور بخشے گناہ تمہارے اور اللہ بخشنے والا مہربان ہے"},{"n":121,"l":"ح","t":"حلال رزق کی اہمیت","p":"18","s":"المؤمنون","sn":23,"r":"4","a":"51","ar":"يٰ٘اَيُّهَا الرُّسُلُ كُلُوۡا مِنَ الطَّيِّبٰتِ وَاعۡمَلُوۡا صَالِحًاؕ اِنِّيۡ بِمَا تَعۡمَلُوۡنَ عَلِيۡمٌؕ","u":"اے رسولو کھاؤ ستھری چیزیں اور کام کرو بھلا جو تم کرتے ہو میں جانتا ہوں"},{"n":122,"l":"ح","t":"حقِ زوجین","p":"2","s":"البقرہ","sn":2,"r":"28","a":"228","ar":"وَالۡمُطَلَّقٰتُ يَتَرَبَّصۡنَ بِاَنۡفُسِهِنَّ ثَلٰثَةَ قُرُوۡٓءٍؕ وَلَا يَحِلُّ لَهُنَّ اَنۡ يَّكۡتُمۡنَ مَا خَلَقَ اللّٰهُ فِيۡ٘ اَرۡحَامِهِنَّ اِنۡ كُنَّ يُؤۡمِنَّ بِاللّٰهِ وَالۡيَوۡمِ الۡاٰخِرِؕ وَبُعُوۡلَتُهُنَّ اَحَقُّ بِرَدِّهِنَّ فِيۡ ذٰلِكَ اِنۡ اَرَادُوۡ٘ا اِصۡلَاحًاؕ وَلَهُنَّ مِثۡلُ الَّذِيۡ عَلَيۡهِنَّ بِالۡمَعۡرُوۡفِ وَلِلرِّجَالِ عَلَيۡهِنَّ دَرَجَةٌؕ وَاللّٰهُ عَزِيۡزٌ حَكِيۡمٌ","u":"اور طلاق والی عورتیں انتظار میں رکھیں اپنے آپ کو تین حیض تک اور ان کو حلال نہیں کہ چھپا رکھیں جو پیدا کیا اللہ نے ان کے پیٹ میں اگر وہ ایمان رکھتی ہیں اللہ پر اور پچھلے دن پر اور ان کے خاوند حق رکھتے ہیں انکے لوٹا لینے کا اس مدت میں اگر چاہیں سلوک سے رہنا اور عورتوں کا بھی حق ہے جیسا کہ مردوں کا ان پر حق ہے دستور کے موافق اور مردوں کو عورتوں پر فضیلت ہے اور اللہ زبردست ہے تدبیر والا"},{"n":123,"l":"ح","t":"حلال کمائی سے اولاد کی پرورش","p":"4","s":"النساء","sn":4,"r":"1","a":"9","ar":"وَلۡيَخۡشَ الَّذِيۡنَ لَوۡ تَرَكُوۡا مِنۡ خَلۡفِهِمۡ ذُرِّيَّةً ضِعٰفًا خَافُوۡا عَلَيۡهِمۡ فَلۡيَتَّقُوا اللّٰهَ وَلۡيَقُوۡلُوۡا قَوۡلًا سَدِيۡدًا","u":"اور چاہئے کہ ڈریں وہ لوگ کہ اگر چھوڑی ہے اپنے پیچھے اولاد ضعیف تو ان پر اندیشہ کریں یعنی ہمارے پیچھے ایسا ہی حال انکا ہو گا تو چاہئے کہ ڈریں اللہ سے اور کہیں بات سیدھی"},{"n":124,"l":"ح","t":"حضرت اسماعیل علیہ السلام کا قصہ","p":"23","s":"الصافات","sn":37,"r":"3","a":"102","ar":"فَلَمَّا بَلَغَ مَعَهُ السَّعۡيَ قَالَ يٰبُنَيَّ اِنِّيۡ٘ اَرٰي فِي الۡمَنَامِ اَنِّيۡ٘ اَذۡبَحُكَ فَانۡظُرۡ مَاذَا تَرٰيؕ قَالَ يٰ٘اَبَتِ افۡعَلۡ مَا تُؤۡمَرُؗ سَتَجِدُنِيۡ٘ اِنۡ شَآءَ اللّٰهُ مِنَ الصّٰبِرِيۡنَ","u":"پھر جب پہنچا اس کے ساتھ دوڑنے کو کہا اے بیٹے میں دیکھتا ہوں خواب میں کہ تجھ کو ذبح کرتا ہوں پھر دیکھ تو تو کیا دیکھتا ہے بولا اے باپ کر ڈال جو تجھ کو حکم ہوتا ہے تو مجھکو کو پائے گا اگر اللہ نے چاہا سہارنے والا"},{"n":125,"l":"ح","t":"حضرت اسحاق علیہ السلام کا تذکرہ","p":"23","s":"الصافات","sn":37,"r":"3","a":"112-113","ar":"وَبَشَّرۡنٰهُ بِاِسۡحٰقَ نَبِيًّا مِّنَ الصّٰلِحِيۡنَ وَبٰرَكۡنَا عَلَيۡهِ وَعَلٰ٘ي اِسۡحٰقَؕ وَمِنۡ ذُرِّيَّتِهِمَا مُحۡسِنٌ وَّظَالِمٌ لِّنَفۡسِهٖ مُبِيۡنٌ","u":"اور خوشخبری دی ہم نے اسکو اسحٰق کی جو نبی ہو گا نیک بختوں میں اور برکت دی ہم نے اس پر اسحٰق پر اور دونوں کی اولاد میں نیکی والے ہیں اور بدکار بھی ہیں اپنے حق میں صریح"},{"n":126,"l":"ح","t":"حضرت یعقوب علیہ السلام کا تذکرہ","p":"13","s":"یوسف","sn":12,"r":"10","a":"86","ar":"قَالَ اِنَّمَا٘ اَشۡكُوۡا بَثِّيۡ وَحُزۡنِيۡ٘ اِلَي اللّٰهِ وَاَعۡلَمُ مِنَ اللّٰهِ مَا لَا تَعۡلَمُوۡنَ","u":"بولا میں تو کھولتا ہوں اپنا اضطراب اور غم اللہ کے سامنے اور جانتا ہوں اللہ کی طرف سے جو تم نہیں جانتے"},{"n":127,"l":"ح","t":"حضرت ادریس علیہ السلام کا تذکرہ","p":"16","s":"مریم","sn":19,"r":"4","a":"56-57","ar":"وَاذۡكُرۡ فِي الۡكِتٰبِ اِدۡرِيۡسَؗ اِنَّهٗ كَانَ صِدِّيۡقًا نَّبِيًّاۙ وَّرَفَعۡنٰهُ مَكَانًا عَلِيًّا","u":"اور مذکور کر کتاب میں ادریس کا وہ تھا سچا نبی اور اٹھا لیا ہم نے اسکو ایک اونچے مکان پر"},{"n":128,"l":"ح","t":"حضرت ذکریا علیہ السلام کا قصہ","p":"16","s":"مریم","sn":19,"r":"1","a":"4-6","ar":"قَالَ رَبِّ اِنِّيۡ وَهَنَ الۡعَظۡمُ مِنِّيۡ وَاشۡتَعَلَ الرَّاۡسُ شَيۡبًا وَّلَمۡ اَكُنۭۡ بِدُعَآئِكَ رَبِّ شَقِيًّا وَاِنِّيۡ خِفۡتُ الۡمَوَالِيَ مِنۡ وَّرَآءِيۡ وَكَانَتِ امۡرَاَتِيۡ عَاقِرًا فَهَبۡ لِيۡ مِنۡ لَّدُنۡكَ وَلِيًّاۙ يَّرِثُنِيۡ وَيَرِثُ مِنۡ اٰلِ يَعۡقُوۡبَ وَاجۡعَلۡهُ رَبِّ رَضِيًّا","u":"بولا اے میرے رب بوڑھی ہو گئیں میری ہڈیاں اور شعلہ نکلا سر سے بڑھاپے کا اور تجھ سے مانگ کر اے رب میں کبھی محروم نہیں رہا اور میں ڈرتا ہوں بھائی بندوں سے اپنے پیچھے اور عورت میری بانجھ ہے سو بخش تو مجھ کو اپنے پاس سے ایک کام اٹھانے والا جو میری جگہ بیٹھے اور یعقوب کی اولاد کی اور کر اُسکو اے رب من مانتا"},{"n":129,"l":"ح","t":"حضرت یحییٰ علیہ السلام کا تذکرہ","p":"16","s":"مریم","sn":19,"r":"1","a":"12-13","ar":"يٰيَحۡيٰي خُذِ الۡكِتٰبَ بِقُوَّةٍؕ وَاٰتَيۡنٰهُ الۡحُكۡمَ صَبِيًّاۙ وَّحَنَانًا مِّنۡ لَّدُنَّا وَزَكٰوةًؕ وَكَانَ تَقِيًّاۙ","u":"اے یحیٰی اٹھا لے کتاب زور سے اور دیا ہم نے اُسکو حکم کرنا لڑکا پن میں اور شوق دیا اپنی طرف سے اورستھرائی اور تھا پرہیز گار"},{"n":130,"l":"ح","t":"حضرت الیاس علیہ السلام کا تذکرہ","p":"23","s":"الصافات","sn":37,"r":"4","a":"123-124","ar":"وَاِنَّ اِلۡيَاسَ لَمِنَ الۡمُرۡسَلِيۡنَؕ اِذۡ قَالَ لِقَوۡمِهٖ٘ اَلَا تَتَّقُوۡنَ","u":"اور تحقیق الیاس ہے رسولوں میں جب اس نے کہا اپنی قوم کو کیا تم کو ڈر نہیں"},{"n":131,"l":"ح","t":"حضرت الیسع علیہ السلام کا تذکرہ","p":"23","s":"صٓ","sn":38,"r":"4","a":"48","ar":"وَاذۡكُرۡ اِسۡمٰعِيۡلَ وَالۡيَسَعَ وَذَا الۡكِفۡلِؕ وَكُلٌّ مِّنَ الۡاَخۡيَارِؕ","u":"اور یاد کر اسمٰعیل کو اور الیسع کو اور ذوالکفل کو اور ہر ایک تھا خوبی والا"},{"n":132,"l":"ح","t":"حضرت ذوالکفل علیہ السلام کا تذکرہ","p":"17","s":"الانبیاء","sn":21,"r":"6","a":"85-86","ar":"وَاِسۡمٰعِيۡلَ وَاِدۡرِيۡسَ وَذَا الۡكِفۡلِؕ كُلٌّ مِّنَ الصّٰبِرِيۡنَۙۚۖ وَاَدۡخَلۡنٰهُمۡ فِيۡ رَحۡمَتِنَاؕ اِنَّهُمۡ مِّنَ الصّٰلِحِيۡنَ","u":"اور اسمٰعیل اور ادریس اور ذوالکفل کو یہ سب ہیں صبر والے اور لے لیا ہم نے اُنکو اپنی رحمت میں وہ ہیں نیک بختوں میں"},{"n":133,"l":"ح","t":"حضرت سلیمان علیہ السلام کی حکمرانی","p":"19","s":"النمل","sn":27,"r":"2","a":"16","ar":"وَوَرِثَ سُلَيۡمٰنُ دَاوٗدَ وَقَالَ يٰ٘اَيُّهَا النَّاسُ عُلِّمۡنَا مَنۡطِقَ الطَّيۡرِ وَاُوۡتِيۡنَا مِنۡ كُلِّ شَيۡءٍؕ اِنَّ هٰذَا لَهُوَ الۡفَضۡلُ الۡمُبِيۡنُ","u":"اور قائم مقام ہوا سلیمان داؤد کا اور بولے اے لوگو ہم کو سکھائی ہے بولی اڑتے جانوروں کی اور دیا ہم کو ہر چیز میں سے بیشک یہی ہے فضیلت صریح"},{"n":134,"l":"ح","t":"حسنِ معاشرت","p":"4","s":"النساء","sn":4,"r":"3","a":"19","ar":"يٰ٘اَيُّهَا الَّذِيۡنَ اٰمَنُوۡا لَا يَحِلُّ لَكُمۡ اَنۡ تَرِثُوا النِّسَآءَ كَرۡهًاؕ وَلَا تَعۡضُلُوۡهُنَّ لِتَذۡهَبُوۡا بِبَعۡضِ مَا٘ اٰتَيۡتُمُوۡهُنَّ اِلَّا٘ اَنۡ يَّاۡتِيۡنَ بِفَاحِشَةٍ مُّبَيِّنَةٍۚ وَعَاشِرُوۡهُنَّ بِالۡمَعۡرُوۡفِۚ فَاِنۡ كَرِهۡتُمُوۡهُنَّ فَعَسٰ٘ي اَنۡ تَكۡرَهُوۡا شَيۡـًٔا وَّيَجۡعَلَ اللّٰهُ فِيۡهِ خَيۡرًا كَثِيۡرًا","u":"اے ایمان والو حلال نہیں تم کو کہ میراث میں لے لو عورتوں کو زبردستی اور نہ روکے رکھو ان کو اس واسطے کہ لے لو ان سے کچھ اپنا دیا ہوا مگر کہ وہ کریں بے حیائی صریح اور گذران کرو عورتوں کے ساتھ اچھی طرح پھر اگر وہ تم کو نہ بھاویں تو شاید تم کو پسند نہ آوے ایک چیز اور اللہ نے رکھی ہو اس میں بہت خوبی"},{"n":135,"l":"ح","t":"حضرت ہارون علیہ السلام کا تذکرہ","p":"16","s":"طٰہ","sn":20,"r":"2","a":"29-32","ar":"وَاجۡعَلۡ لِّيۡ وَزِيۡرًا مِّنۡ اَهۡلِيۡۙ هٰرُوۡنَ اَخِيۙ اشۡدُدۡ بِهٖ٘ اَزۡرِيۡۙ وَاَشۡرِكۡهُ فِيۡ٘ اَمۡرِيۡۙ","u":"اور دےمجھ کو ایک کام بٹانے والا میرے گھر کا ہارون میرا بھائی اُس سے مضبوط کر میری کمر اور شریک کر اُسکو میرے کام میں"},{"n":136,"l":"ح","t":"حلم و بردباری","p":"4","s":"آلِ عمران","sn":3,"r":"14","a":"134","ar":"الَّذِيۡنَ يُنۡفِقُوۡنَ فِي السَّرَّآءِ وَالضَّرَّآءِ وَالۡكٰظِمِيۡنَ الۡغَيۡظَ وَالۡعَافِيۡنَ عَنِ النَّاسِؕ وَاللّٰهُ يُحِبُّ الۡمُحۡسِنِيۡنَۚ","u":"جو خرچ کئے جاتے ہیں خوشی میں اور تکلیف میں اور دبا لیتےہیں غصہ اور معاف کرتے ہیں لوگوں کو اور اللہ چاہتا ہے نیکی کرنے والوں کو"},{"n":137,"l":"ح","t":"حضرت آسیہ علیہا السلام کا کردار","p":"28","s":"التحریم","sn":66,"r":"2","a":"11","ar":"وَضَرَبَ اللّٰهُ مَثَلًا لِّلَّذِيۡنَ اٰمَنُوا امۡرَاَتَ فِرۡعَوۡنَۘ اِذۡ قَالَتۡ رَبِّ ابۡنِ لِيۡ عِنۡدَكَ بَيۡتًا فِي الۡجَنَّةِ وَنَجِّنِيۡ مِنۡ فِرۡعَوۡنَ وَعَمَلِهٖ وَنَجِّنِيۡ مِنَ الۡقَوۡمِ الظّٰلِمِيۡنَۙ","u":"اور اللہ نے بتلائی ایک مثل ایمان والوں کے لئے عورت فرعون کی جب بولی اے رب بنا میرے واسطے اپنے پاس ایک گھر بہشت میں اور بچا نکال مجھ کو فرعون سے اور اُسکے کام سے اور بچا نکال مجھ کو ظالم لوگوں سے"},{"n":138,"l":"خ","t":"خوفِ خدا","p":"30","s":"النازعات","sn":79,"r":"2","a":"40-41","ar":"وَاَمَّا مَنۡ خَافَ مَقَامَ رَبِّهٖ وَنَهَي النَّفۡسَ عَنِ الۡهَوٰيۙ فَاِنَّ الۡجَنَّةَ هِيَ الۡمَاۡوٰيؕ","u":"اور جو کوئی ڈرا ہو اپنے رب کے سامنے کھڑے ہونے سے اور روکا ہو اُس نے جی کو خواہش سے سو بہشت ہے اُس کا ٹھکانہ"},{"n":139,"l":"خ","t":"خیانت کی مذمت","p":"5","s":"النساء","sn":4,"r":"16","a":"107","ar":"وَلَا تُجَادِلۡ عَنِ الَّذِيۡنَ يَخۡتَانُوۡنَ اَنۡفُسَهُمۡؕ اِنَّ اللّٰهَ لَا يُحِبُّ مَنۡ كَانَ خَوَّانًا اَثِيۡمًاۚۙ","u":"اور مت جھگڑ ان کی طرف سے جو اپنے جی میں دغا رکھتے ہیں اللہ کو پسند نہیں جو کوئی ہو دغاباز گنہگار"},{"n":140,"l":"خ","t":"خود کشی کی حرمت","p":"5","s":"النساء","sn":4,"r":"5","a":"29","ar":"يٰ٘اَيُّهَا الَّذِيۡنَ اٰمَنُوۡا لَا تَاۡكُلُوۡ٘ا اَمۡوَالَكُمۡ بَيۡنَكُمۡ بِالۡبَاطِلِ اِلَّا٘ اَنۡ تَكُوۡنَ تِجَارَةً عَنۡ تَرَاضٍ مِّنۡكُمۡ وَلَا تَقۡتُلُوۡ٘ا اَنۡفُسَكُمۡؕ اِنَّ اللّٰهَ كَانَ بِكُمۡ رَحِيۡمًا","u":"اے ایمان والو نہ کھاؤ مال ایک دوسرے کے آپس میں ناحق مگر یہ کہ تجارت ہو آپس کی خوشی سے اور نہ خون کرو آپس میں بیشک اللہ تم پر مہربان ہے"},{"n":141,"l":"خ","t":"خلافت و امانتِ زمین","p":"22","s":"الاحزاب","sn":33,"r":"9","a":"72","ar":"اِنَّا عَرَضۡنَا الۡاَمَانَةَ عَلَي السَّمٰوٰتِ وَالۡاَرۡضِ وَالۡجِبَالِ فَاَبَيۡنَ اَنۡ يَّحۡمِلۡنَهَا وَاَشۡفَقۡنَ مِنۡهَا وَحَمَلَهَا الۡاِنۡسَانُؕ اِنَّهٗ كَانَ ظَلُوۡمًا جَهُوۡلًاۙ","u":"ہم نے دکھلائی امانت آسمانوں کو اور زمین کو اور پہاڑوں کو پھر کسی نے قبول نہ کیا کہ اس کو اٹھائیں اورا س سے ڈر گئے اور اٹھا لیا اس کو انسان نے یہ ہے بڑا بے ترس نادان"},{"n":142,"l":"خ","t":"خضر علیہ السلام کا واقعہ","p":"15","s":"الکہف","sn":18,"r":"9","a":"65-66","ar":"فَوَجَدَا عَبۡدًا مِّنۡ عِبَادِنَا٘ اٰتَيۡنٰهُ رَحۡمَةً مِّنۡ عِنۡدِنَا وَعَلَّمۡنٰهُ مِنۡ لَّدُنَّا عِلۡمًا قَالَ لَهٗ مُوۡسٰي هَلۡ اَتَّبِعُكَ عَلٰ٘ي اَنۡ تُعَلِّمَنِ مِمَّا عُلِّمۡتَ رُشۡدًا","u":"پھر پایا ایک بندہ ہمارے بندوں میں کا جس کو دی تھی ہم نے رحمت اپنے پاس سے اور سکھلایا تھا اپنے پاس سے ایک علم کہا اس کو موسٰی نے کہے تو تیرے ساتھ رہوں اس بات پر کہ مجھ کو سکھلا دے کچھ جو تجھ کو سکھلائی ہے بھلی راہ"},{"n":143,"l":"خ","t":"خمر (شراب) کی حرمت","p":"7","s":"المائدہ","sn":5,"r":"12","a":"90-91","ar":"يٰ٘اَيُّهَا الَّذِيۡنَ اٰمَنُوۡ٘ا اِنَّمَا الۡخَمۡرُ وَالۡمَيۡسِرُ وَالۡاَنۡصَابُ وَالۡاَزۡلَامُ رِجۡسٌ مِّنۡ عَمَلِ الشَّيۡطٰنِ فَاجۡتَنِبُوۡهُ لَعَلَّكُمۡ تُفۡلِحُوۡنَ اِنَّمَا يُرِيۡدُ الشَّيۡطٰنُ اَنۡ يُّوۡقِعَ بَيۡنَكُمُ الۡعَدَاوَةَ وَالۡبَغۡضَآءَ فِي الۡخَمۡرِ وَالۡمَيۡسِرِ وَيَصُدَّكُمۡ عَنۡ ذِكۡرِ اللّٰهِ وَعَنِ الصَّلٰوةِۚ فَهَلۡ اَنۡتُمۡ مُّنۡتَهُوۡنَ","u":"اے ایمان والو یہ جو ہے شراب اور جوا اور بت اور پانسے سب گندے کام ہیں شیطان کے سو ان سے بچتے رہو تاکہ تم نجات پاؤ شیطان تو یہی چاہتا ہے کہ ڈالے تم میں دشمنی اور بیر بذریعہ شراب اور جوئے کے اور روکےتم کو اللہ کی یاد سے اور نماز سے سو اب بھی تم باز آؤ گے"},{"n":144,"l":"خ","t":"خوش اخلاقی","p":"9","s":"الاعراف","sn":7,"r":"24","a":"199","ar":"خُذِ الۡعَفۡوَ وَاۡمُرۡ بِالۡعُرۡفِ وَاَعۡرِضۡ عَنِ الۡجٰهِلِيۡنَ","u":"عادت کر درگذر کی اور حکم کر نیک کام کرنے کا اور کنارہ کر جاہلوں سے"},{"n":145,"l":"خ","t":"خشوع فی الصلاۃ","p":"18","s":"المؤمنون","sn":23,"r":"1","a":"1-2","ar":"قَدۡ اَفۡلَحَ الۡمُؤۡمِنُوۡنَۙ الَّذِيۡنَ هُمۡ فِيۡ صَلَاتِهِمۡ خٰشِعُوۡنَۙ","u":"کام نکال لے گئے ایمان والے جو اپنی نماز میں جھکنے والے ہیں"},{"n":146,"l":"خ","t":"خوابوں کی تعبیر (قصۂ یوسف کی روشنی میں)","p":"12","s":"یوسف","sn":12,"r":"1","a":"4-5","ar":"اِذۡ قَالَ يُوۡسُفُ لِاَبِيۡهِ يٰ٘اَبَتِ اِنِّيۡ رَاَيۡتُ اَحَدَ عَشَرَ كَوۡكَبًا وَّالشَّمۡسَ وَالۡقَمَرَ رَاَيۡتُهُمۡ لِيۡ سٰجِدِيۡنَ قَالَ يٰبُنَيَّ لَا تَقۡصُصۡ رُءۡيَاكَ عَلٰ٘ي اِخۡوَتِكَ فَيَكِيۡدُوۡا لَكَ كَيۡدًاؕ اِنَّ الشَّيۡطٰنَ لِلۡاِنۡسَانِ عَدُوٌّ مُّبِيۡنٌ","u":"جس وقت کہا یوسف نے اپنے باپ سے اے باپ میں نے دیکھا خواب میں گیارہ ستاروں کو اور سورج کو اور چاند کو دیکھا میں نے انکو اپنے واسطے سجدہ کرتے ہوئے کہا اے بیٹے مت بیان کرنا خواب اپنا اپنے بھائیوں کے آگے پھر وہ بنائیں گے تیرے واسطے کچھ فریب البتہ شیطان ہے انسان کا صریح دشمن"},{"n":147,"l":"خ","t":"خدمتِ خلق کی ترغیب","p":"29","s":"الانسان","sn":76,"r":"1","a":"8-9","ar":"وَيُطۡعِمُوۡنَ الطَّعَامَ عَلٰي حُبِّهٖ مِسۡكِيۡنًا وَّيَتِيۡمًا وَّاَسِيۡرًا اِنَّمَا نُطۡعِمُكُمۡ لِوَجۡهِ اللّٰهِ لَا نُرِيۡدُ مِنۡكُمۡ جَزَآءً وَّلَا شُكُوۡرًا","u":"اور کھلاتے ہیں کھانا اُسکی محبت پر محتاج کو اور یتیم کو اور قیدی کو ہم جو تم کو کھلاتے ہیں سو خالص اللہ کی خوشی چاہنے کو نہ تم سے ہم چاہیں گے بدلا اور نہ چاہیں گے شکرگذاری"},{"n":148,"l":"خ","t":"خاتم النبیین صلی اللہ علیہ وسلم کا مقام","p":"22","s":"الاحزاب","sn":33,"r":"5","a":"40","ar":"مَا كَانَ مُحَمَّدٌ اَبَا٘ اَحَدٍ مِّنۡ رِّجَالِكُمۡ وَلٰكِنۡ رَّسُوۡلَ اللّٰهِ وَخَاتَمَ النَّبِيّٖنَؕ وَكَانَ اللّٰهُ بِكُلِّ شَيۡءٍ عَلِيۡمًا","u":"محمد باپ نہیں کسی کا تمہارے مردوں میں سے لیکن رسول ہے اللہ کا اور مہر سب نبیوں پر اور ہے اللہ سب چیزوں کو جاننے والا"},{"n":149,"l":"خ","t":"خوشحالی میں شکر اور آزمائش میں صبر","p":"21","s":"لقمان","sn":31,"r":"3","a":"31","ar":"اَلَمۡ تَرَ اَنَّ الۡفُلۡكَ تَجۡرِيۡ فِي الۡبَحۡرِ بِنِعۡمَتِ اللّٰهِ لِيُرِيَكُمۡ مِّنۡ اٰيٰتِهٖؕ اِنَّ فِيۡ ذٰلِكَ لَاٰيٰتٍ لِّكُلِّ صَبَّارٍ شَكُوۡرٍ","u":"تو نے نہ دیکھا کہ جہاز چلتے ہیں سمندر میں اللہ کی نعمت لے کر تاکہ دکھلائے تمکو کچھ اپنی قدرتیں البتہ اس میں نشانیاں ہیں ہر ایک تحمل کرنے والے احسان ماننے والے کے واسطے"},{"n":150,"l":"خ","t":"خوشخبری اور انذار کا اسلوبِ دعوت","p":"22","s":"الاحزاب","sn":33,"r":"6","a":"45-46","ar":"يٰ٘اَيُّهَا النَّبِيُّ اِنَّا٘ اَرۡسَلۡنٰكَ شَاهِدًا وَّمُبَشِّرًا وَّنَذِيۡرًاۙ وَّدَاعِيًا اِلَي اللّٰهِ بِاِذۡنِهٖ وَسِرَاجًا مُّنِيۡرًا","u":"اے نبی ہم نے تجھ کو بھیجا بتانے والا اور خوشخبری سنانے والا اور ڈرانے والا اور بلانے والا للہ کی طرف اسکے حکم سے اور چمکتا ہوا چراغ"},{"n":151,"l":"خ","t":"خیر کے کاموں میں جلدی کرنا","p":"2","s":"البقرہ","sn":2,"r":"18","a":"148","ar":"وَلِكُلٍّ وِّجۡهَةٌ هُوَ مُوَلِّيۡهَا فَاسۡتَبِقُوا الۡخَيۡرٰتِؕؔ اَيۡنَ مَا تَكُوۡنُوۡا يَاۡتِ بِكُمُ اللّٰهُ جَمِيۡعًاؕ اِنَّ اللّٰهَ عَلٰي كُلِّ شَيۡءٍ قَدِيۡرٌ","u":"اور ہر کسی کے واسطے ایک جانب ہے یعنی قبلہ کہ وہ منہ کرتا ہے اس طرف سو تم سبقت کرو نیکیوں میں جہاں کہیں تم ہو گے کر لائے گا تم کو اللہ اکٹھا بیشک اللہ ہر چیز کر سکتا ہے"},{"n":152,"l":"خ","t":"خدمتِ والدین بڑھاپے میں","p":"26","s":"الاحقاف","sn":46,"r":"2","a":"15","ar":"وَوَصَّيۡنَا الۡاِنۡسَانَ بِوَالِدَيۡهِ اِحۡسٰنًاؕ حَمَلَتۡهُ اُمُّهٗ كُرۡهًا وَّوَضَعَتۡهُ كُرۡهًاؕ وَحَمۡلُهٗ وَفِصٰلُهٗ ثَلٰثُوۡنَ شَهۡرًاؕ حَتّٰ٘ي اِذَا بَلَغَ اَشُدَّهٗ وَبَلَغَ اَرۡبَعِيۡنَ سَنَةًۙ قَالَ رَبِّ اَوۡزِعۡنِيۡ٘ اَنۡ اَشۡكُرَ نِعۡمَتَكَ الَّتِيۡ٘ اَنۡعَمۡتَ عَلَيَّ وَعَلٰي وَالِدَيَّ وَاَنۡ اَعۡمَلَ صَالِحًا تَرۡضٰىهُ وَاَصۡلِحۡ لِيۡ فِيۡ ذُرِّيَّتِيۡۚؕ اِنِّيۡ تُبۡتُ اِلَيۡكَ وَاِنِّيۡ مِنَ الۡمُسۡلِمِيۡنَ","u":"اور ہم نے حکم کر دیا انسان کو اپنے ماں باپ سے بھلائی کا پیٹ میں رکھا اسکو اسکی ماں نے تکلیف سے اور جنا اسکو تکلیف سے اور حمل میں رہنا اس کا اور دودھ چھوڑنا تیس مہینے میں ہے یہاں تک کہ جب پہنچا اپنی قوت کو اور پہنچ گیا چالیس برس کو کہنے لگا اے رب میرے میری قسمت میں کر کہ شکر کروں تیرے احسان کا جو تو نے مجھ پر کیا اور میرے ماں باپ پر اور یہ کہ کروں نیک کام جس سے تو راضی ہو اور مجھ کو دے نیک اولاد میری میں نے توبہ کی تیری طرف اور میں ہوں حکم بردار"},{"n":153,"l":"د","t":"دعا کی اہمیت و آداب","p":"24","s":"غافر","sn":40,"r":"6","a":"60","ar":"وَقَالَ رَبُّكُمُ ادۡعُوۡنِيۡ٘ اَسۡتَجِبۡ لَكُمۡؕ اِنَّ الَّذِيۡنَ يَسۡتَكۡبِرُوۡنَ عَنۡ عِبَادَتِيۡ سَيَدۡخُلُوۡنَ جَهَنَّمَ دٰخِرِيۡنَ","u":"اور کہتا ہے تمہارا رب مجھ کو پکارو کہ پہنچوں تمہاری پکار کو بیشک جو لوگ تکبر کرتے ہیں میری بندگی سے اب داخل ہوں گے دوزخ میں ذلیل ہو کر"},{"n":154,"l":"د","t":"دنیا کی بے ثباتی","p":"27","s":"الحدید","sn":57,"r":"3","a":"20","ar":"اِعۡلَمُوۡ٘ا اَنَّمَا الۡحَيٰوةُ الدُّنۡيَا لَعِبٌ وَّلَهۡوٌ وَّزِيۡنَةٌ وَّتَفَاخُرٌۭ بَيۡنَكُمۡ وَتَكَاثُرٌ فِي الۡاَمۡوَالِ وَالۡاَوۡلَادِؕ كَمَثَلِ غَيۡثٍ اَعۡجَبَ الۡكُفَّارَ نَبَاتُهٗ ثُمَّ يَهِيۡجُ فَتَرٰىهُ مُصۡفَرًّا ثُمَّ يَكُوۡنُ حُطَامًاؕ وَفِي الۡاٰخِرَةِ عَذَابٌ شَدِيۡدٌۙ وَّمَغۡفِرَةٌ مِّنَ اللّٰهِ وَرِضۡوَانٌؕ وَمَا الۡحَيٰوةُ الدُّنۡيَا٘ اِلَّا مَتَاعُ الۡغُرُوۡرِ","u":"جان رکھو کہ دنیا کی زندگانی یہی ہے کھیل اور تماشا اور بناؤ اور بڑائیاں کرنی آپس میں اور بہتایت ڈھونڈنی مال کی اور اولاد کی جیسے حالت ایک مینہ کی جو خوش لگا کسانوں کو اُس کا سبزہ پھر زور پر آتا ہے پھر تو دیکھے زرد ہو گیا پھر ہو جاتا ہے روندا ہوا گھاس اور آخرت میں سخب عذاب ہے اور معافی بھی ہے اللہ سے اور رضامندی اور دنیا کی زندگانی تو یہی ہے مال دغا کا"},{"n":155,"l":"د","t":"داؤد علیہ السلام کا قصہ","p":"22","s":"سبأ","sn":34,"r":"2","a":"10","ar":"وَلَقَدۡ اٰتَيۡنَا دَاوٗدَ مِنَّا فَضۡلًاؕ يٰجِبَالُ اَوِّبِيۡ مَعَهٗ وَالطَّيۡرَۚ وَاَلَنَّا لَهُ الۡحَدِيۡدَۙ","u":"اور ہم نے دی ہے داؤد کو اپنی طرف سے بڑائی اے پہاڑو خوش آوازی سے پڑھو اسکے ساتھ اور اڑتے جانوروں کو اور نرم کر دیا ہم نے اس کے آگے لوہا"},{"n":156,"l":"د","t":"دینِ اسلام کی تکمیل","p":"6","s":"المائدہ","sn":5,"r":"1","a":"3","ar":"حُرِّمَتۡ عَلَيۡكُمُ الۡمَيۡتَةُ وَالدَّمُ وَلَحۡمُ الۡخِنۡزِيۡرِ وَمَا٘ اُهِلَّ لِغَيۡرِ اللّٰهِ بِهٖ وَالۡمُنۡخَنِقَةُ وَالۡمَوۡقُوۡذَةُ وَالۡمُتَرَدِّيَةُ وَالنَّطِيۡحَةُ وَمَا٘ اَكَلَ السَّبُعُ اِلَّا مَا ذَكَّيۡتُمۡ وَمَا ذُبِحَ عَلَي النُّصُبِ وَاَنۡ تَسۡتَقۡسِمُوۡا بِالۡاَزۡلَامِؕ ذٰلِكُمۡ فِسۡقٌؕ اَلۡيَوۡمَ يَئِسَ الَّذِيۡنَ كَفَرُوۡا مِنۡ دِيۡنِكُمۡ فَلَا تَخۡشَوۡهُمۡ وَاخۡشَوۡنِؕ اَلۡيَوۡمَ اَكۡمَلۡتُ لَكُمۡ دِيۡنَكُمۡ وَاَتۡمَمۡتُ عَلَيۡكُمۡ نِعۡمَتِيۡ وَرَضِيۡتُ لَكُمُ الۡاِسۡلَامَ دِيۡنًاؕ فَمَنِ اضۡطُرَّ فِيۡ مَخۡمَصَةٍ غَيۡرَ مُتَجَانِفٍ لِّاِثۡمٍۙ فَاِنَّ اللّٰهَ غَفُوۡرٌ رَّحِيۡمٌ","u":"حرام ہوا تم پر مردہ جانور اور لہو اور گوشت سور کا اور جس جانور پر نام پکارا جائے اللہ کے سوا کسی اور کا اور جو مر گیا ہو گلا گھونٹنے سے یاچوٹ سے یا اونچے سے گر کر یا سینگ مارنے سے اور جس کو کھایا ہو درندہ نے مگر جس کو تم نےذبح کر لیا اور حرام ہے جو ذبح ہوا کسی تھان پر اور یہ کہ تقسیم کرو جوئے کے تیروں سے یہ گناہ کا کام ہے آج ناامید ہو گئے کافر تمہارے دین سے سو ان سے مت ڈرو اور مجھ سے ڈرو آج میں پورا کر چکا تمہارے لئے دین تمہارا اور پورا کیا تم پر میں نے احسان اپنا اور پسند کیا میں نے تمہارے واسطےاسلام کو دین پھر جو کوئی لاچار ہو جاوے بھوک میں لیکن گناہ پر مائل نہ ہو تو اللہ بخشنے والا مہربان ہے"},{"n":157,"l":"د","t":"دیانت داری","p":"18","s":"المؤمنون","sn":23,"r":"1","a":"8","ar":"وَالَّذِيۡنَ هُمۡ لِاَمٰنٰتِهِمۡ وَعَهۡدِهِمۡ رٰعُوۡنَۙ","u":"اور جو اپنی امانتوں سے اور اپنے قرار سے خبردار ہیں"},{"n":158,"l":"د","t":"درگزر و عفو","p":"25","s":"الشوریٰ","sn":42,"r":"4","a":"40","ar":"وَجَزٰٓؤُا سَيِّئَةٍ سَيِّئَةٌ مِّثۡلُهَاۚ فَمَنۡ عَفَا وَاَصۡلَحَ فَاَجۡرُهٗ عَلَي اللّٰهِؕ اِنَّهٗ لَا يُحِبُّ الظّٰلِمِيۡنَ","u":"اور برائی کا بدلا ہے برائی ویسی ہی پھر جو کوئی معاف کرے اور صلح کرے سو اس کا ثواب ہے اللہ کے ذمہ بیشک اللہ کو پسند نہیں آتے گنہگار"},{"n":159,"l":"د","t":"دعوتِ الی اللہ کا طریقہ","p":"14","s":"النحل","sn":16,"r":"16","a":"125","ar":"اُدۡعُ اِلٰي سَبِيۡلِ رَبِّكَ بِالۡحِكۡمَةِ وَالۡمَوۡعِظَةِ الۡحَسَنَةِ وَجَادِلۡهُمۡ بِالَّتِيۡ هِيَ اَحۡسَنُؕ اِنَّ رَبَّكَ هُوَ اَعۡلَمُ بِمَنۡ ضَلَّ عَنۡ سَبِيۡلِهٖ وَهُوَ اَعۡلَمُ بِالۡمُهۡتَدِيۡنَ","u":"بلا اپنے رب کی راہ پر پکی باتیں سمجھا کر اور نصیحت سنا کر بھلی طرح اور الزام دے انکو جس طرح بہتر ہو تیرا رب ہی بہتر جانتا ہے ان کو جو بھول گیا اس کی راہ اور وہی بہتر جانتا ہے انکو جو راہ پر ہیں"},{"n":160,"l":"د","t":"دجل و فریب کی مذمت","p":"1","s":"البقرہ","sn":2,"r":"2","a":"9","ar":"يُخٰدِعُوۡنَ اللّٰهَ وَالَّذِيۡنَ اٰمَنُوۡاۚ وَمَا يَخۡدَعُوۡنَ اِلَّا٘ اَنۡفُسَهُمۡ وَمَا يَشۡعُرُوۡنَؕ","u":"دغابازی کرتے ہیں اللہ سے اور ایمان والوں سے اور دراصل کسی کو دغا نہیں دیتے مگر اپنے آپ کو اور نہیں سوچتے"},{"n":161,"l":"د","t":"درجاتِ جنت","p":"16","s":"الکہف","sn":18,"r":"12","a":"107-108","ar":"اِنَّ الَّذِيۡنَ اٰمَنُوۡا وَعَمِلُوا الصّٰلِحٰتِ كَانَتۡ لَهُمۡ جَنّٰتُ الۡفِرۡدَوۡسِ نُزُلًاۙ خٰلِدِيۡنَ فِيۡهَا لَا يَبۡغُوۡنَ عَنۡهَا حِوَلًا","u":"جو لوگ ایمان لائے ہیں اور کئے ہیں بھلے کام انکے واسطے ہے ٹھنڈی چھاؤں کے باغ مہمانی رہا کریں ان میں نہ چاہیں وہاں سے جگہ بدلنی"},{"n":162,"l":"د","t":"دائمی نعمتوں کا تذکرہ","p":"29","s":"الانسان","sn":76,"r":"1","a":"20-22","ar":"وَاِذَا رَاَيۡتَ ثَمَّ رَاَيۡتَ نَعِيۡمًا وَّمُلۡكًا كَبِيۡرًا عٰلِيَهُمۡ ثِيَابُ سُنۡدُسٍ خُضۡرٌ وَّاِسۡتَبۡرَقٌؗ وَّحُلُّوۡ٘ا اَسَاوِرَ مِنۡ فِضَّةٍۚ وَسَقٰىهُمۡ رَبُّهُمۡ شَرَابًا طَهُوۡرًا اِنَّ هٰذَا كَانَ لَكُمۡ جَزَآءً وَّكَانَ سَعۡيُكُمۡ مَّشۡكُوۡرًا","u":"اور جب تو دیکھے وہاں تو دیکھے نعمت اور سلطنت بڑی اوپر کی پوشاک انکی کپڑے ہیں باریک ریشم کے سبز اور گاڑھے اور انکو پہنائے جائیں گے کنگن چاندی کے اور پلائے اُنکو اُنکا رب شراب جو پاک کرے دل کو یہ ہے تمہارا بدلا اور کمائی تمہاری ٹھکانے لگی"},{"n":163,"l":"د","t":"درودِ پاک کی فضیلت","p":"22","s":"الاحزاب","sn":33,"r":"7","a":"56","ar":"اِنَّ اللّٰهَ وَمَلٰٓئِكَتَهٗ يُصَلُّوۡنَ عَلَي النَّبِيِّؕ يٰ٘اَيُّهَا الَّذِيۡنَ اٰمَنُوۡا صَلُّوۡا عَلَيۡهِ وَسَلِّمُوۡا تَسۡلِيۡمًا","u":"اللہ اور اس کے فرشتے رحمت بیجھتے ہیں رسول پر اے ایمان والو رحمت بھیجو اس پر اور سلام بھیجو سلام کہہ کر"},{"n":164,"l":"د","t":"دلوں کی شفا (قرآن بطور شفا)","p":"11","s":"یونس","sn":10,"r":"6","a":"57","ar":"يٰ٘اَيُّهَا النَّاسُ قَدۡ جَآءَتۡكُمۡ مَّوۡعِظَةٌ مِّنۡ رَّبِّكُمۡ وَشِفَآءٌ لِّمَا فِي الصُّدُوۡرِ ۙ وَهُدًي وَّرَحۡمَةٌ لِّلۡمُؤۡمِنِيۡنَ","u":"اے لوگو تمہارے پاس آئی ہے نصیحت تمہارے رب سے اور شفا دلوں کے روگ کی اور ہدایت اور رحمت مسلمانوں کے واسطے"},{"n":165,"l":"ڈ","t":"ڈر اور لالچ سے بالاتر ہو کر گواہی دینا","p":"5","s":"النساء","sn":4,"r":"20","a":"135","ar":"يٰ٘اَيُّهَا الَّذِيۡنَ اٰمَنُوۡا كُوۡنُوۡا قَوّٰمِيۡنَ بِالۡقِسۡطِ شُهَدَآءَ لِلّٰهِ وَلَوۡ عَلٰ٘ي اَنۡفُسِكُمۡ اَوِ الۡوَالِدَيۡنِ وَالۡاَقۡرَبِيۡنَۚ اِنۡ يَّكُنۡ غَنِيًّا اَوۡ فَقِيۡرًا فَاللّٰهُ اَوۡلٰي بِهِمَا فَلَا تَتَّبِعُوا الۡهَوٰ٘ي اَنۡ تَعۡدِلُوۡاۚ وَاِنۡ تَلۡوٗ٘ا اَوۡ تُعۡرِضُوۡا فَاِنَّ اللّٰهَ كَانَ بِمَا تَعۡمَلُوۡنَ خَبِيۡرًا","u":"اے ایمان والو قائم رہو انصاف پر گواہی دو اللہ کی طرف کی اگرچہ نقصان ہو تمہارا یا ماں باپ کا یا قرابت والوں کا اگر کوئی مالدار ہے یا محتاج ہے تو اللہ ان کا خیرخواہ تم سے زیادہ ہے سو تم پیروی نہ کرو دل کی خواہش کی انصاف کرنے میں اور اگر تم زبان ملو گے یا بچا جاؤ گے تو اللہ تمہاے سب کاموں سے واقف ہے"},{"n":166,"l":"ذ","t":"ذکرِ الٰہی کی فضیلت","p":"13","s":"الرعد","sn":13,"r":"4","a":"28","ar":"اَلَّذِيۡنَ اٰمَنُوۡا وَتَطۡمَئِنُّ قُلُوۡبُهُمۡ بِذِكۡرِ اللّٰهِؕ اَلَا بِذِكۡرِ اللّٰهِ تَطۡمَئِنُّ الۡقُلُوۡبُؕ","u":"وہ لوگ جو ایمان لائے اور چین پاتے ہیں انکے دل اللہ کی یاد سے سنتا ہے اللہ کی یاد ہی سے چین پاتے ہیں دل"},{"n":167,"l":"ذ","t":"ذوالقرنین کا قصہ","p":"16","s":"الکہف","sn":18,"r":"11","a":"83-84","ar":"وَيَسۡـَٔلُوۡنَكَ عَنۡ ذِي الۡقَرۡنَيۡنِؕ قُلۡ سَاَتۡلُوۡا عَلَيۡكُمۡ مِّنۡهُ ذِكۡرًاؕ اِنَّا مَكَّنَّا لَهٗ فِي الۡاَرۡضِ وَاٰتَيۡنٰهُ مِنۡ كُلِّ شَيۡءٍ سَبَبًاۙ","u":"اور تجھ سے پوچھتے ہیں ذوالقرنین کو کہہ اب پڑھتا ہوں تمہارے آگے اس کا کچھ احوال ہم نے اس کو جمایا تھا ملک میں اور دیا تھا ہم نے اسکو ہر چیز کا سامان"},{"n":168,"l":"ذ","t":"ذمہ داری کا احساس (تکلیف)","p":"3","s":"البقرہ","sn":2,"r":"40","a":"286","ar":"لَا يُكَلِّفُ اللّٰهُ نَفۡسًا اِلَّا وُسۡعَهَاؕ لَهَا مَا كَسَبَتۡ وَعَلَيۡهَا مَا اكۡتَسَبَتۡؕ رَبَّنَا لَا تُؤَاخِذۡنَا٘ اِنۡ نَّسِيۡنَا٘ اَوۡ اَخۡطَاۡنَاۚ رَبَّنَا وَلَا تَحۡمِلۡ عَلَيۡنَا٘ اِصۡرًا كَمَا حَمَلۡتَهٗ عَلَي الَّذِيۡنَ مِنۡ قَبۡلِنَاۚ رَبَّنَا وَلَا تُحَمِّلۡنَا مَا لَا طَاقَةَ لَنَا بِهٖۚ وَاعۡفُ عَنَّا وَاغۡفِرۡ لَنَا وَارۡحَمۡنَا اَنۡتَ مَوۡلٰىنَا فَانۡصُرۡنَا عَلَي الۡقَوۡمِ الۡكٰفِرِيۡنَ","u":"اللہ تکلیف نہیں دیتا کسی کو مگر جس قدر اس کی گنجائش ہے اس کو ملتا ہے جو اس نے کمایا اور اسی پر پڑتا ہے جو اس نے کیا اے رب ہمارے نہ پکڑ ہم کو اگر ہم بھولیں یا چوکیں اے رب ہمارے اور نہ رکھ ہم پر بوجھ بھاری جیسا رکھا تھا ہم سے اگلے لوگوں پر اے رب ہمارے اور نہ اٹھوا ہم سے وہ بوجھ کہ جس کی ہم کو طاقت نہیں اور درگذر کر ہم سے اور بخش ہم کو اور رحم کر ہم پر تو ہی ہمارا رب ہے مدد کر ہماری کافروں پر"},{"n":169,"l":"ذ","t":"ذلت و رسوائی سے بچنے کا راستہ","p":"4","s":"آلِ عمران","sn":3,"r":"14","a":"139","ar":"وَلَا تَهِنُوۡا وَلَا تَحۡزَنُوۡا وَاَنۡتُمُ الۡاَعۡلَوۡنَ اِنۡ كُنۡتُمۡ مُّؤۡمِنِيۡنَ","u":"اور سست نہ رہو اور نہ غم کھاؤ اور تم ہی غالب رہو گے اگر تم ایمان رکھتے ہو"},{"n":170,"l":"ر","t":"رزق میں تفاوت اور اس کی حکمت","p":"14","s":"النحل","sn":16,"r":"10","a":"71","ar":"وَاللّٰهُ فَضَّلَ بَعۡضَكُمۡ عَلٰي بَعۡضٍ فِي الرِّزۡقِۚ فَمَا الَّذِيۡنَ فُضِّلُوۡا بِرَآدِّيۡ رِزۡقِهِمۡ عَلٰي مَا مَلَكَتۡ اَيۡمَانُهُمۡ فَهُمۡ فِيۡهِ سَوَآءٌؕ اَفَبِنِعۡمَةِ اللّٰهِ يَجۡحَدُوۡنَ","u":"اور اللہ نے بڑائی دی تم میں ایک کو ایک پر روزی میں سو جن کو بڑائی دی وہ نہیں پہنچا دیتے اپنی روزی ان کو جن کے مالک ان کے ہاتھ ہیں کہ وہ سب اس میں برابر ہو جائیں کیا اللہ کی نعمت کے منکر ہیں"},{"n":171,"l":"ر","t":"رحمتِ الٰہی کی وسعت","p":"9","s":"الاعراف","sn":7,"r":"19","a":"156","ar":"وَاكۡتُبۡ لَنَا فِيۡ هٰذِهِ الدُّنۡيَا حَسَنَةً وَّفِي الۡاٰخِرَةِ اِنَّا هُدۡنَا٘ اِلَيۡكَؕ قَالَ عَذَابِيۡ٘ اُصِيۡبُ بِهٖ مَنۡ اَشَآءُۚ وَرَحۡمَتِيۡ وَسِعَتۡ كُلَّ شَيۡءٍؕ فَسَاَكۡتُبُهَا لِلَّذِيۡنَ يَتَّقُوۡنَ وَيُؤۡتُوۡنَ الزَّكٰوةَ وَالَّذِيۡنَ هُمۡ بِاٰيٰتِنَا يُؤۡمِنُوۡنَۚ","u":"اور لکھ دے ہمارےلئے اس دنیا میں بھلائی اور آخرت میں ہم نے رجوع کیا تیری طرف فرمایا میرا عذاب ڈالتا ہوں میں اسکو جس پر چاہوں اور میری رحمت شامل ہے ہر چیز کو سو اس کو لکھ دوں گا ان کے لئے جو ڈر رکھتے ہیں اور دیتے ہیں زکوٰۃ اور جو ہماری باتوں پر یقین رکھتے ہیں"},{"n":172,"l":"ر","t":"ربا (سود) کی حرمت","p":"3","s":"البقرہ","sn":2,"r":"38","a":"275-276","ar":"اَلَّذِيۡنَ يَاۡكُلُوۡنَ الرِّبٰوا لَا يَقُوۡمُوۡنَ اِلَّا كَمَا يَقُوۡمُ الَّذِيۡ يَتَخَبَّطُهُ الشَّيۡطٰنُ مِنَ الۡمَسِّؕ ذٰلِكَ بِاَنَّهُمۡ قَالُوۡ٘ا اِنَّمَا الۡبَيۡعُ مِثۡلُ الرِّبٰواۘ وَاَحَلَّ اللّٰهُ الۡبَيۡعَ وَحَرَّمَ الرِّبٰواؕ فَمَنۡ جَآءَهٗ مَوۡعِظَةٌ مِّنۡ رَّبِّهٖ فَانۡتَهٰي فَلَهٗ مَا سَلَفَؕ وَاَمۡرُهٗ٘ اِلَي اللّٰهِؕ وَمَنۡ عَادَ فَاُولٰٓئِكَ اَصۡحٰبُ النَّارِۚ هُمۡ فِيۡهَا خٰلِدُوۡنَ يَمۡحَقُ اللّٰهُ الرِّبٰوا وَيُرۡبِي الصَّدَقٰتِؕ وَاللّٰهُ لَا يُحِبُّ كُلَّ كَفَّارٍ اَثِيۡمٍ","u":"جو لوگ کھاتےہیں سود نہیں اٹھیں گے قیامت کو مگر جس طرح اٹھتا ہے وہ شخص کہ جس کے حواس کھو دیے ہوں جن نے لپٹ کر یہ حالت انکی اس واسطے ہو گی کہ انہوں نے کہا کہ سوداگری بھی تو ایسی ہی ہے جیسے سود لینا حالانکہ اللہ نے حلال کیا ہے سوداگری اور حرام کیا ہے سود کو پھر جس کو پہنچی نصیحت اپنے رب کی طرف سے اور وہ باز آ گیا تو اس کے واسطے ہے جو پہلے ہو چکا اور معاملہ اس کا اللہ کے حوالہ ہے اور جو کوئی پھر سود لیوے تو وہی لوگ ہیں دوزخ والے وہ اس میں ہمیشہ رہیں گے مٹاتا ہے اللہ سود کو اور بڑھاتا ہے خیرات کو اور اللہ خوش نہیں کسی نا شکر گنہگار سے"},{"n":173,"l":"ر","t":"رشتہ داری کے حقوق","p":"4","s":"النساء","sn":4,"r":"1","a":"1","ar":"يٰ٘اَيُّهَا النَّاسُ اتَّقُوۡا رَبَّكُمُ الَّذِيۡ خَلَقَكُمۡ مِّنۡ نَّفۡسٍ وَّاحِدَةٍ وَّخَلَقَ مِنۡهَا زَوۡجَهَا وَبَثَّ مِنۡهُمَا رِجَالًا كَثِيۡرًا وَّنِسَآءًۚ وَاتَّقُوا اللّٰهَ الَّذِيۡ تَسَآءَلُوۡنَ بِهٖ وَالۡاَرۡحَامَؕ اِنَّ اللّٰهَ كَانَ عَلَيۡكُمۡ رَقِيۡبًا","u":"اے لوگو ڈرتے رہو اپنے رب سے جس نے پیدا کیا تم کو ایک جان سے اور اسی سے پیدا کیا اس کا جوڑا اور پھیلائے ان دونوں سے بہت مرد اور عورتیں اور ڈرتے رہو اللہ سے جس کے واسطے سے سوال کرتے ہو آپس میں اور خبردار رہو قرابت والوں سے بیشک اللہ تم پر نگہبان ہے"},{"n":174,"l":"ر","t":"روزہ کے احکام","p":"2","s":"البقرہ","sn":2,"r":"23","a":"183","ar":"يٰ٘اَيُّهَا الَّذِيۡنَ اٰمَنُوۡا كُتِبَ عَلَيۡكُمُ الصِّيَامُ كَمَا كُتِبَ عَلَي الَّذِيۡنَ مِنۡ قَبۡلِكُمۡ لَعَلَّكُمۡ تَتَّقُوۡنَۙ","u":"اے ایمان والو فرض کیا گیا تم پر روزہ جیسے فرض کیا گیا تھا تم سے اگلوں پر تاکہ تم پرہیز گار ہو جاؤ"},{"n":175,"l":"ر","t":"رسولوں پر ایمان","p":"24","s":"غافر","sn":40,"r":"8","a":"78","ar":"وَلَقَدۡ اَرۡسَلۡنَا رُسُلًا مِّنۡ قَبۡلِكَ مِنۡهُمۡ مَّنۡ قَصَصۡنَا عَلَيۡكَ وَمِنۡهُمۡ مَّنۡ لَّمۡ نَقۡصُصۡ عَلَيۡكَؕ وَمَا كَانَ لِرَسُوۡلٍ اَنۡ يَّاۡتِيَ بِاٰيَةٍ اِلَّا بِاِذۡنِ اللّٰهِۚ فَاِذَا جَآءَ اَمۡرُ اللّٰهِ قُضِيَ بِالۡحَقِّ وَخَسِرَ هُنَالِكَ الۡمُبۡطِلُوۡنَ","u":"اور ہم نے بھیجے ہیں رسول تجھ سے پہلے بعضے ان میں وہ ہیں کہ سنایا ہم نے تجھکو ان کا احوال اور بعضے ہیں کہ نہیں سنایا اور کسی رسول کو مقدور نہ تھا کہ لے آتا کوئی نشانی مگر اللہ کے حکم سے پھر جب آیا حکم اللہ کا فیصلہ ہو گیا انصاف سے اور ٹوٹے میں پڑے اس جگہ جھوٹے"},{"n":176,"l":"ر","t":"رحم دلی","p":"26","s":"الفتح","sn":48,"r":"4","a":"29","ar":"مُحَمَّدٌ رَّسُوۡلُ اللّٰهِؕ وَالَّذِيۡنَ مَعَهٗ٘ اَشِدَّآءُ عَلَي الۡكُفَّارِ رُحَمَآءُ بَيۡنَهُمۡ تَرٰىهُمۡ رُكَّعًا سُجَّدًا يَّبۡتَغُوۡنَ فَضۡلًا مِّنَ اللّٰهِ وَرِضۡوَانًاؗ سِيۡمَاهُمۡ فِيۡ وُجُوۡهِهِمۡ مِّنۡ اَثَرِ السُّجُوۡدِؕ ذٰلِكَ مَثَلُهُمۡ فِي التَّوۡرٰىةِۚۖۛ وَمَثَلُهُمۡ فِي الۡاِنۡجِيۡلِۚۛ كَزَرۡعٍ اَخۡرَجَ شَطۡاَهٗ فَاٰزَرَهٗ فَاسۡتَغۡلَظَ فَاسۡتَوٰي عَلٰي سُوۡقِهٖ يُعۡجِبُ الزُّرَّاعَ لِيَغِيۡظَ بِهِمُ الۡكُفَّارَؕ وَعَدَ اللّٰهُ الَّذِيۡنَ اٰمَنُوۡا وَعَمِلُوا الصّٰلِحٰتِ مِنۡهُمۡ مَّغۡفِرَةً وَّاَجۡرًا عَظِيۡمًا","u":"محمد رسول اللہ کا اور جو لوگ اسکے ساتھ ہیں زورآور ہیں کافروں پر نرم دل ہیں آپس میں تو دیکھے ان کو رکوع میں اور سجدہ میں ڈھونڈتے ہیں اللہ کا فضل اور اسکی خوشی نشانی اُنکی اُنکے منہ پر ہے سجدہ کے اثر سے یہ شان ہے انکی تورات میں اور مثال انکی انجیل میں جیسے کھیتی نے نکالا اپنا پٹھا پھر اُسکی کمر مضبوط کی پھر موٹا ہوا پھر کھڑا ہو گیا اپنی نال پر خوش لگتا ہے کھیتی والوں کو تاکہ جلائے ان سے جی کافروں کا وعدہ کیا ہے اللہ نے ان سے جو یقین لائے ہیں اور کئے ہیں بھلے کام معافی کا اور بڑے ثواب کا"},{"n":177,"l":"ر","t":"رضائے الٰہی کا حصول","p":"10","s":"التوبہ","sn":9,"r":"9","a":"72","ar":"وَعَدَ اللّٰهُ الۡمُؤۡمِنِيۡنَ وَالۡمُؤۡمِنٰتِ جَنّٰتٍ تَجۡرِيۡ مِنۡ تَحۡتِهَا الۡاَنۡهٰرُ خٰلِدِيۡنَ فِيۡهَا وَمَسٰكِنَ طَيِّبَةً فِيۡ جَنّٰتِ عَدۡنٍؕ وَرِضۡوَانٌ مِّنَ اللّٰهِ اَكۡبَرُؕ ذٰلِكَ هُوَ الۡفَوۡزُ الۡعَظِيۡمُ","u":"وعدہ دیا ہے اللہ نے ایمان والے مردوں اور ایمان والی عورتوں کو باغوں کا کہ بہتی ہیں نیچے ان کے نہریں رہا کریں انہی میں اور ستھرے مکانوں کا رہنے کے باغوں میں اور رضامندی اللہ کی ان سب سے بڑی ہے یہی ہے بڑی کامیابی"},{"n":178,"l":"ر","t":"رواداری اور برداشت","p":"3","s":"البقرہ","sn":2,"r":"34","a":"256","ar":"لَا٘ اِكۡرَاهَ فِي الدِّيۡنِۚ قَدۡ تَّبَيَّنَ الرُّشۡدُ مِنَ الۡغَيِّۚ فَمَنۡ يَّكۡفُرۡ بِالطَّاغُوۡتِ وَيُؤۡمِنۭۡ بِاللّٰهِ فَقَدِ اسۡتَمۡسَكَ بِالۡعُرۡوَةِ الۡوُثۡقٰيۚ لَا انۡفِصَامَ لَهَاؕ وَاللّٰهُ سَمِيۡعٌ عَلِيۡمٌ","u":"زبردستی نہں دین کے معاملہ میں بیشک جدا ہو چکی ہے ہدیات گمراہی سے اب جو کوئی نہ مانےگمراہ کرنےوالوں کو اور یقین لاوےاللہ پر تو اس نے پکڑ لیا حلقہ مضبوط جو ٹوٹنے والا نہیں اور اللہ سب کچھ سنتا جانتا ہے"},{"n":179,"l":"ر","t":"رفقِ بالحیوان (جانوروں سے نرمی)","p":"19","s":"النمل","sn":27,"r":"2","a":"18","ar":"حَتّٰ٘ي اِذَا٘ اَتَوۡا عَلٰي وَادِ النَّمۡلِۙ قَالَتۡ نَمۡلَةٌ يّٰ٘اَيُّهَا النَّمۡلُ ادۡخُلُوۡا مَسٰكِنَكُمۡۚ لَا يَحۡطِمَنَّكُمۡ سُلَيۡمٰنُ وَجُنُوۡدُهٗۙ وَهُمۡ لَا يَشۡعُرُوۡنَ","u":"یہاں تک کہ جب پہنچے چیونٹیوں کے میدان پر کہا ایک چیونٹی نے اے چیونٹیو گھس جاؤ اپنے گھروں میں نہ پیس ڈالے تم کو سلیمان اور اسکی فوجیں اور انکو خبر بھی نہ ہو"},{"n":180,"l":"ر","t":"رزقِ حلال کی جستجو","p":"29","s":"الملک","sn":67,"r":"2","a":"15","ar":"هُوَ الَّذِيۡ جَعَلَ لَكُمُ الۡاَرۡضَ ذَلُوۡلًا فَامۡشُوۡا فِيۡ مَنَاكِبِهَا وَكُلُوۡا مِنۡ رِّزۡقِهٖؕ وَاِلَيۡهِ النُّشُوۡرُ","u":"وہی ہے جس نے کیا تمہارے آگے زمین کو پست اب چلو پھرو اُسکے کندھوں پر اور کھاؤ کچھ اُسکی دی ہوئی روزی اور اُسی کی طرف جی اٹھنا ہے"},{"n":181,"l":"ر","t":"رہبانیت کی ممانعت","p":"27","s":"الحدید","sn":57,"r":"4","a":"27","ar":"ثُمَّ قَفَّيۡنَا عَلٰ٘ي اٰثَارِهِمۡ بِرُسُلِنَا وَقَفَّيۡنَا بِعِيۡسَي ابۡنِ مَرۡيَمَ وَاٰتَيۡنٰهُ الۡاِنۡجِيۡلَ ۙ وَجَعَلۡنَا فِيۡ قُلُوۡبِ الَّذِيۡنَ اتَّبَعُوۡهُ رَاۡفَةً وَّرَحۡمَةًؕ وَرَهۡبَانِيَّةَ اِۨبۡتَدَعُوۡهَا مَا كَتَبۡنٰهَا عَلَيۡهِمۡ اِلَّا ابۡتِغَآءَ رِضۡوَانِ اللّٰهِ فَمَا رَعَوۡهَا حَقَّ رِعَايَتِهَاۚ فَاٰتَيۡنَا الَّذِيۡنَ اٰمَنُوۡا مِنۡهُمۡ اَجۡرَهُمۡۚ وَكَثِيۡرٌ مِّنۡهُمۡ فٰسِقُوۡنَ","u":"پھر پیچھے بھیجے اُنکے قدموں پر اپنے رسول اور پیچھے بھیجا ہم نے عیسٰی مریم کے بیٹے کو اور اُسکو ہم نے دی انجیل اور رکھ دی اُس کے ساتھ چلنے والوں کے دل میں نرمی اور مہربانی اور ایک ترک کرنا دنیا کا جو انہوں نے نئی بات نکالی تھی ہم نے نہیں لکھا تھا یہ اُن پر مگر کیاچاہنے کو اللہ کی رضامندی پھر نہ نباہا اُسکو جیسا چاہئے تھا نباہنا پھر دیا ہم نے اُن لوگوں کو جو اُن میں ایماندار تھے اُنکا بدلا اور بہت اُن میں نافرمان ہں"},{"n":182,"l":"ر","t":"رحمتہ للعالمین صلی اللہ علیہ وسلم کی بعثت کا مقصد","p":"28","s":"الجمعہ","sn":62,"r":"1","a":"2","ar":"هُوَ الَّذِيۡ بَعَثَ فِي الۡاُمِّيّٖنَ رَسُوۡلًا مِّنۡهُمۡ يَتۡلُوۡا عَلَيۡهِمۡ اٰيٰتِهٖ وَيُزَكِّيۡهِمۡ وَيُعَلِّمُهُمُ الۡكِتٰبَ وَالۡحِكۡمَةَ وَاِنۡ كَانُوۡا مِنۡ قَبۡلُ لَفِيۡ ضَلٰلٍ مُّبِيۡنٍۙ","u":"وہی ہے جس نے اٹھایا ان پڑھوں میں ایک رسول انہی میں کا پڑھ کر سناتا ہے اُنکو اُسکی آیتیں اور انکو سنوارتا ہے اور سکھلاتا ہے اُنکو کتاب اور عقلمندی اور اس سے پہلے وہ پڑے ہوئے تھے صریح بھول میں"},{"n":183,"l":"ر","t":"رزقِ روحانی اور سکونِ قلب","p":"26","s":"الفتح","sn":48,"r":"1","a":"4","ar":"هُوَ الَّذِيۡ٘ اَنۡزَلَ السَّكِيۡنَةَ فِيۡ قُلُوۡبِ الۡمُؤۡمِنِيۡنَ لِيَزۡدَادُوۡ٘ا اِيۡمَانًا مَّعَ اِيۡمَانِهِمۡؕ وَلِلّٰهِ جُنُوۡدُ السَّمٰوٰتِ وَالۡاَرۡضِؕ وَكَانَ اللّٰهُ عَلِيۡمًا حَكِيۡمًاۙ","u":"وہی ہے جس نے اتارا اطمینان دل میں ایمان والوں کے تاکہ اور بڑھ جائے انکو ایمان اپنے ایمان کے ساتھ اور اللہ کے ہیں سب لشکر آسمانوں کے اور زمین کے اور اللہ ہے خبردار حکمت والا"},{"n":184,"l":"ر","t":"روحانی تزکیہ","p":"30","s":"الشمس","sn":91,"r":"1","a":"9-10","ar":"قَدۡ اَفۡلَحَ مَنۡ زَكّٰىهَاۙ وَقَدۡ خَابَ مَنۡ دَسّٰىهَاؕ","u":"تحقیق مراد کو پہنچا جس نے اُسکو سنوار لیا اور نامراد ہوا جس نے اُسکو خاک میں ملا چھوڑا"},{"n":185,"l":"ز","t":"زکوٰۃ کے احکام","p":"10","s":"التوبہ","sn":9,"r":"8","a":"60","ar":"اِنَّمَا الصَّدَقٰتُ لِلۡفُقَرَآءِ وَالۡمَسٰكِيۡنِ وَالۡعٰمِلِيۡنَ عَلَيۡهَا وَالۡمُؤَلَّفَةِ قُلُوۡبُهُمۡ وَفِي الرِّقَابِ وَالۡغٰرِمِيۡنَ وَفِيۡ سَبِيۡلِ اللّٰهِ وَابۡنِ السَّبِيۡلِؕ فَرِيۡضَةً مِّنَ اللّٰهِؕ وَاللّٰهُ عَلِيۡمٌ حَكِيۡمٌ","u":"زکوٰۃ جو ہے سو وہ حق ہے مفلسوں کا اور محتاجوں کا اور زکوٰۃ کے کام پر جانے والوں کا اور جن کا دل پرچانا منظور ہے اور گردنوں کے چھڑانے میں اور جو تاوان بھریں اور اللہ کے رستہ میں اور راہ کے مسافر کو ٹھہرایا ہوا ہے اللہ کا اور اللہ سب کچھ جاننے والا حکمت والا ہے"},{"n":186,"l":"ز","t":"زنا کی حرمت","p":"15","s":"بنی اسرائیل (الاسراء)","sn":17,"r":"4","a":"32","ar":"وَلَا تَقۡرَبُوا الزِّنٰ٘ي اِنَّهٗ كَانَ فَاحِشَةًؕ وَسَآءَ سَبِيۡلًا","u":"اور پاس نہ جاؤ زنا کے وہ ہے بے حیائی اور بری راہ ہے"},{"n":187,"l":"ز","t":"زبان کی حفاظت","p":"26","s":"قٓ","sn":50,"r":"2","a":"18","ar":"مَا يَلۡفِظُ مِنۡ قَوۡلٍ اِلَّا لَدَيۡهِ رَقِيۡبٌ عَتِيۡدٌ","u":"نہیں بولتا کچھ بات جو نہیں ہوتا اُس کے پاس ایک راہ دیکھنے والا تیار"},{"n":188,"l":"ز","t":"زوجین کے باہمی حقوق","p":"21","s":"الروم","sn":30,"r":"3","a":"21","ar":"وَمِنۡ اٰيٰتِهٖ٘ اَنۡ خَلَقَ لَكُمۡ مِّنۡ اَنۡفُسِكُمۡ اَزۡوَاجًا لِّتَسۡكُنُوۡ٘ا اِلَيۡهَا وَجَعَلَ بَيۡنَكُمۡ مَّوَدَّةً وَّرَحۡمَةًؕ اِنَّ فِيۡ ذٰلِكَ لَاٰيٰتٍ لِّقَوۡمٍ يَّتَفَكَّرُوۡنَ","u":"اور اسکی نشانیوں سے ہے یہ کہ بنا دیے تمہارے واسطے تمہاری قسم سے جوڑے کہ چین سے رہو انکے پاس اور رکھا تمہارے بیچ میں پیار اور مہربانی البتہ اس میں بہت پتے کی باتیں ہیں انکے لئے جو دھیان کرتے ہیں"},{"n":189,"l":"ز","t":"زمین و آسمان کی تخلیق","p":"17","s":"الانبیاء","sn":21,"r":"3","a":"30","ar":"اَوَلَمۡ يَرَ الَّذِيۡنَ كَفَرُوۡ٘ا اَنَّ السَّمٰوٰتِ وَالۡاَرۡضَ كَانَتَا رَتۡقًا فَفَتَقۡنٰهُمَاؕ وَجَعَلۡنَا مِنَ الۡمَآءِ كُلَّ شَيۡءٍ حَيٍّؕ اَفَلَا يُؤۡمِنُوۡنَ","u":"اور کیا نہیں دیکھا ان منکروں نے کہ آسمان اور زمین منہ بند تھے پھر ہم نے انکو کھول دیا اور بنائی ہم نے پانی سے ہر ایک چیز جس میں جان ہے پھر کیا یقین نہیں کرتے"},{"n":190,"l":"ز","t":"زیب و زینت میں اعتدال","p":"8","s":"الاعراف","sn":7,"r":"3","a":"31","ar":"يٰبَنِيۡ٘ اٰدَمَ خُذُوۡا زِيۡنَتَكُمۡ عِنۡدَ كُلِّ مَسۡجِدٍ وَّكُلُوۡا وَاشۡرَبُوۡا وَلَا تُسۡرِفُوۡاۚؕ اِنَّهٗ لَا يُحِبُّ الۡمُسۡرِفِيۡنَ","u":"اے اولاد آدم کی لے لو اپنی آرائش ہر نماز کے وقت اور کھاؤ اور پیئو اور بیجا خرچ نہ کرو اس کو خوش نہیں آتے بیجا خرچ کرنے والے"},{"n":191,"l":"ز","t":"زلزلے اور قیامت کی علامات","p":"30","s":"الزلزلہ","sn":99,"r":"1","a":"1-3","ar":"اِذَا زُلۡزِلَتِ الۡاَرۡضُ زِلۡزَالَهَاۙ وَاَخۡرَجَتِ الۡاَرۡضُ اَثۡقَالَهَاۙ وَقَالَ الۡاِنۡسَانُ مَا لَهَاۚ","u":"جب ہلا ڈالے زمین کو اُسکے بھونچال سے او ر نکال باہر کرے زمین اپنے اندر سے بوجھ اور کہے آدمی اُس کو کیا ہو گیا"},{"n":192,"l":"ز","t":"زبانِ نرم کا حکم","p":"16","s":"طٰہ","sn":20,"r":"2","a":"44","ar":"فَقُوۡلَا لَهٗ قَوۡلًا لَّيِّنًا لَّعَلَّهٗ يَتَذَكَّرُ اَوۡ يَخۡشٰي","u":"سو کہو اُس سے بات نرم شاید وہ سوچے یا ڈرے"},{"n":193,"l":"ز","t":"زبردستی نکاح کی ممانعت","p":"4","s":"النساء","sn":4,"r":"3","a":"19","ar":"يٰ٘اَيُّهَا الَّذِيۡنَ اٰمَنُوۡا لَا يَحِلُّ لَكُمۡ اَنۡ تَرِثُوا النِّسَآءَ كَرۡهًاؕ وَلَا تَعۡضُلُوۡهُنَّ لِتَذۡهَبُوۡا بِبَعۡضِ مَا٘ اٰتَيۡتُمُوۡهُنَّ اِلَّا٘ اَنۡ يَّاۡتِيۡنَ بِفَاحِشَةٍ مُّبَيِّنَةٍۚ وَعَاشِرُوۡهُنَّ بِالۡمَعۡرُوۡفِۚ فَاِنۡ كَرِهۡتُمُوۡهُنَّ فَعَسٰ٘ي اَنۡ تَكۡرَهُوۡا شَيۡـًٔا وَّيَجۡعَلَ اللّٰهُ فِيۡهِ خَيۡرًا كَثِيۡرًا","u":"اے ایمان والو حلال نہیں تم کو کہ میراث میں لے لو عورتوں کو زبردستی اور نہ روکے رکھو ان کو اس واسطے کہ لے لو ان سے کچھ اپنا دیا ہوا مگر کہ وہ کریں بے حیائی صریح اور گذران کرو عورتوں کے ساتھ اچھی طرح پھر اگر وہ تم کو نہ بھاویں تو شاید تم کو پسند نہ آوے ایک چیز اور اللہ نے رکھی ہو اس میں بہت خوبی"},{"n":194,"l":"ز","t":"زندگی بعد موت کے دلائل","p":"23","s":"یٰسٓ","sn":36,"r":"5","a":"78-79","ar":"وَضَرَبَ لَنَا مَثَلًا وَّنَسِيَ خَلۡقَهٗؕ قَالَ مَنۡ يُّحۡيِ الۡعِظَامَ وَهِيَ رَمِيۡمٌ قُلۡ يُحۡيِيۡهَا الَّذِيۡ٘ اَنۡشَاَهَا٘ اَوَّلَ مَرَّةٍؕ وَهُوَ بِكُلِّ خَلۡقٍ عَلِيۡمُۙ","u":"اور بٹھلاتا ہے ہم پر ایک مثل اور بھول گیا اپنی پیدائش کہنے لگا کون زندہ کرے گا ہڈیوں کو جب کھوکھری ہو گئیں تو کہہ ان کو زندہ کرے گا جس نے بنایا انکو پہلی بار اور وہ سب بنانا جانتا ہے"},{"n":195,"l":"ز","t":"اعجازِ قرآن (فصاحتِ کلام)","p":"1","s":"البقرہ","sn":2,"r":"3","a":"23","ar":"وَاِنۡ كُنۡتُمۡ فِيۡ رَيۡبٍ مِّمَّا نَزَّلۡنَا عَلٰي عَبۡدِنَا فَاۡتُوۡا بِسُوۡرَةٍ مِّنۡ مِّثۡلِهٖ وَادۡعُوۡا شُهَدَآءَكُمۡ مِّنۡ دُوۡنِ اللّٰهِ اِنۡ كُنۡتُمۡ صٰدِقِيۡنَ","u":"اور اگر تم شک میں ہو اس کلام سےجو اتارا ہم نے اپنے بندہ پر تو لے آؤ ایک سورت اس جیسی اور بلاؤ اس کو جو تمہارا مددگار ہو اللہ کے سوا اگر تم سچے ہو"},{"n":196,"l":"ز","t":"زینتِ دنیا کی حقیقت","p":"15","s":"الکہف","sn":18,"r":"6","a":"46","ar":"اَلۡمَالُ وَالۡبَنُوۡنَ زِيۡنَةُ الۡحَيٰوةِ الدُّنۡيَاۚ وَالۡبٰقِيٰتُ الصّٰلِحٰتُ خَيۡرٌ عِنۡدَ رَبِّكَ ثَوَابًا وَّخَيۡرٌ اَمَلًا","u":"مال اور بیٹے رونق ہیں دنیا کی زندگی میں اور باقی رہنے والی نیکیوں کا بہتر ہے تیرے رب کے یہاں بدلا اور بہتر ہے توقع"},{"n":197,"l":"ژ","t":"ژولیدہ حالی میں صبر کا سبق","p":"15","s":"الکہف","sn":18,"r":"4","a":"28","ar":"وَاصۡبِرۡ نَفۡسَكَ مَعَ الَّذِيۡنَ يَدۡعُوۡنَ رَبَّهُمۡ بِالۡغَدٰوةِ وَالۡعَشِيِّ يُرِيۡدُوۡنَ وَجۡهَهٗ وَلَا تَعۡدُ عَيۡنٰكَ عَنۡهُمۡۚ تُرِيۡدُ زِيۡنَةَ الۡحَيٰوةِ الدُّنۡيَاۚ وَلَا تُطِعۡ مَنۡ اَغۡفَلۡنَا قَلۡبَهٗ عَنۡ ذِكۡرِنَا وَاتَّبَعَ هَوٰىهُ وَكَانَ اَمۡرُهٗ فُرُطًا","u":"اور روکے رکھ اپنے آپ کو ان کے ساتھ جو پکارتے ہیں اپنے رب کو صبح اور شام طالب ہیں اسکے منہ کے اور نہ دوڑیں تیری آنکھیں انکو چھوڑ کر تلاش میں رونق زندگانی دنیا کی اور نہ کہا مان اس کا جس کا دل غافل کیا ہم نے اپنی یاد سے اور پیچھے پڑا ہوا ہے اپنی خوشی کے اور اس کا کام ہے حد پر نہ رہنا"},{"n":198,"l":"س","t":"سچائی کی اہمیت","p":"11","s":"التوبہ","sn":9,"r":"15","a":"119","ar":"يٰ٘اَيُّهَا الَّذِيۡنَ اٰمَنُوا اتَّقُوا اللّٰهَ وَكُوۡنُوۡا مَعَ الصّٰدِقِيۡنَ","u":"اے ایمان والو ڈرتے رہو اللہ سے اور رہو ساتھ سچوں کے"},{"n":199,"l":"س","t":"سلام کو عام کرنا","p":"5","s":"النساء","sn":4,"r":"11","a":"86","ar":"وَاِذَا حُيِّيۡتُمۡ بِتَحِيَّةٍ فَحَيُّوۡا بِاَحۡسَنَ مِنۡهَا٘ اَوۡ رُدُّوۡهَاؕ اِنَّ اللّٰهَ كَانَ عَلٰي كُلِّ شَيۡءٍ حَسِيۡبًا","u":"اور جب تم کو دعا دیوے کوئی تو تم بھی دعا دو اس سے بہتر یا وہی کہو الٹ کر بیشک اللہ ہے ہر چیز کا حساب کرنے والا"},{"n":200,"l":"س","t":"سلیمان علیہ السلام کا قصہ","p":"19","s":"النمل","sn":27,"r":"3","a":"38-40","ar":"قَالَ يٰ٘اَيُّهَا الۡمَلَؤُا اَيُّكُمۡ يَاۡتِيۡنِيۡ بِعَرۡشِهَا قَبۡلَ اَنۡ يَّاۡتُوۡنِيۡ مُسۡلِمِيۡنَ قَالَ عِفۡرِيۡتٌ مِّنَ الۡجِنِّ اَنَا اٰتِيۡكَ بِهٖ قَبۡلَ اَنۡ تَقُوۡمَ مِنۡ مَّقَامِكَۚ وَاِنِّيۡ عَلَيۡهِ لَقَوِيٌّ اَمِيۡنٌ قَالَ الَّذِيۡ عِنۡدَهٗ عِلۡمٌ مِّنَ الۡكِتٰبِ اَنَا اٰتِيۡكَ بِهٖ قَبۡلَ اَنۡ يَّرۡتَدَّ اِلَيۡكَ طَرۡفُكَؕ فَلَمَّا رَاٰهُ مُسۡتَقِرًّا عِنۡدَهٗ قَالَ هٰذَا مِنۡ فَضۡلِ رَبِّيۡ لِيَبۡلُوَنِيۡ٘ ءَاَشۡكُرُ اَمۡ اَكۡفُرُؕ وَمَنۡ شَكَرَ فَاِنَّمَا يَشۡكُرُ لِنَفۡسِهٖۚ وَمَنۡ كَفَرَ فَاِنَّ رَبِّيۡ غَنِيٌّ كَرِيۡمٌ","u":"بولا اے دربار والو تم میں کوئی ہے کہ لے آوے میرے پاس اس کا تخت پہلے اس سے کہ وہ آئیں میرے پاس حکم بردار ہو کر بولا ایک دیو جنوں میں سے میں لائے دیتا ہوں وہ تجھکو پہلے اس سے کہ تو اٹھے اپنی جگہ سے اور میں اس پر زورآور ہوں معتبر بولا وہ شخص جس کے پاس تھا ایک علم کتاب کا میں لائے دیتا ہوں تیرے پاس اسکو پہلے اس سے کہ پھر آئے تیری طرف تیری آنکھ پھر جب دیکھا اسکو دھرا ہوا اپنے پاس کہا یہ میرے رب کا فضل ہے میرے جانچنے کو کہ میں شکر کرتا ہوں یا ناشکری اور جو کوئی شکر کرے سو شکر کرے اپنے واسطے اور جو کوئی ناشکری کرے سو میرا رب بے پروا ہے کرم والا"},{"n":201,"l":"س","t":"سفر کے آداب","p":"5","s":"النساء","sn":4,"r":"15","a":"101","ar":"وَاِذَا ضَرَبۡتُمۡ فِي الۡاَرۡضِ فَلَيۡسَ عَلَيۡكُمۡ جُنَاحٌ اَنۡ تَقۡصُرُوۡا مِنَ الصَّلٰوةِۖ اِنۡ خِفۡتُمۡ اَنۡ يَّفۡتِنَكُمُ الَّذِيۡنَ كَفَرُوۡاؕ اِنَّ الۡكٰفِرِيۡنَ كَانُوۡا لَكُمۡ عَدُوًّا مُّبِيۡنًا","u":"اور جب تم سفر کرو ملک میں تو تم پر گناہ نہیں کہ کچھ کم کرو نماز میں سےاگر تم کو ڈر ہو کہ ستاویں گے تم کو کافر البتہ کافر تمہارے صریح دشمن ہیں"},{"n":202,"l":"س","t":"سود کی ممانعت","p":"3","s":"البقرہ","sn":2,"r":"38","a":"278-279","ar":"يٰ٘اَيُّهَا الَّذِيۡنَ اٰمَنُوا اتَّقُوا اللّٰهَ وَذَرُوۡا مَا بَقِيَ مِنَ الرِّبٰ٘وا اِنۡ كُنۡتُمۡ مُّؤۡمِنِيۡنَ فَاِنۡ لَّمۡ تَفۡعَلُوۡا فَاۡذَنُوۡا بِحَرۡبٍ مِّنَ اللّٰهِ وَرَسُوۡلِهٖۚ وَاِنۡ تُبۡتُمۡ فَلَكُمۡ رُءُوۡسُ اَمۡوَالِكُمۡۚ لَا تَظۡلِمُوۡنَ وَلَا تُظۡلَمُوۡنَ","u":"اے ایمان والو ڈرو اللہ سے اور چھوڑ دو جو کچھ باقی رہ گیا ہے سود اگر تم کو یقین ہے اللہ کے فرمانے کا پھر اگر نہیں چھوڑتے تو تیار ہو جاؤ لڑنے کو اللہ سے اور اس کے رسول سے اور اگر توبہ کرتے ہو تو تمہارے واسطے ہے اصل مال تمہارا نہ تم کسی پر ظلم کرو اور نہ کوئی تم پر"},{"n":203,"l":"س","t":"ستر و حجاب کے احکام","p":"18","s":"النور","sn":24,"r":"4","a":"31","ar":"وَقُلۡ لِّلۡمُؤۡمِنٰتِ يَغۡضُضۡنَ مِنۡ اَبۡصَارِهِنَّ وَيَحۡفَظۡنَ فُرُوۡجَهُنَّ وَلَا يُبۡدِيۡنَ زِيۡنَتَهُنَّ اِلَّا مَا ظَهَرَ مِنۡهَا وَلۡيَضۡرِبۡنَ بِخُمُرِهِنَّ عَلٰي جُيُوۡبِهِنَّ وَلَا يُبۡدِيۡنَ زِيۡنَتَهُنَّ اِلَّا لِبُعُوۡلَتِهِنَّ اَوۡ اٰبَآئِهِنَّ اَوۡ اٰبَآءِ بُعُوۡلَتِهِنَّ اَوۡ اَبۡنَآئِهِنَّ اَوۡ اَبۡنَآءِ بُعُوۡلَتِهِنَّ اَوۡ اِخۡوَانِهِنَّ اَوۡ بَنِيۡ٘ اِخۡوَانِهِنَّ اَوۡ بَنِيۡ٘ اَخَوٰتِهِنَّ اَوۡ نِسَآئِهِنَّ اَوۡ مَا مَلَكَتۡ اَيۡمَانُهُنَّ اَوِ التّٰبِعِيۡنَ غَيۡرِ اُولِي الۡاِرۡبَةِ مِنَ الرِّجَالِ اَوِ الطِّفۡلِ الَّذِيۡنَ لَمۡ يَظۡهَرُوۡا عَلٰي عَوۡرٰتِ النِّسَآءِ وَلَا يَضۡرِبۡنَ بِاَرۡجُلِهِنَّ لِيُعۡلَمَ مَا يُخۡفِيۡنَ مِنۡ زِيۡنَتِهِنَّؕ وَتُوۡبُوۡ٘ا اِلَي اللّٰهِ جَمِيۡعًا اَيُّهَ الۡمُؤۡمِنُوۡنَ لَعَلَّكُمۡ تُفۡلِحُوۡنَ","u":"اور کہہ دے ایمان والیوں کو نیچی رکھیں ذرا اپنی آنکھیں اور تھامتی رہیں اپنے ستر کو اور نہ دکھائیں اپنا سنگار مگر جو کھلی چیز ہے اس میں سے اور ڈال لیں اپنی اوڑھنی اپنے گریبان پر اور نہ کھولیں اپنا سنگار مگر اپنے خاوند کے آگے یا اپنے باپ کے یا پنے خاوند کے باپ کے یا اپنے بیٹے کے یا اپنے خاوند کے بیٹے کے یا اپنے بھائی کے یا اپنے بھتیجوں کے یا اپنے بھانجوں کے یا اپنی عورتوں کے یا اپنے ہاتھ کے مال کے یا کاربار کرنے والوں کے (خدمت میں مشغول رہنے والوں کے) جو مرد کہ کچھ غرض نہیں رکھتے یا لڑکوں کے جنہوں نے ابھی نہیں پہچانا عورتوں کے بھید کو اور نہ ماریں زمین پر اپنے پاؤں کو کہ جانا جائے جو چھپاتی ہیں اپنا سنگار اور توبہ کرو اللہ کے آگے سب مل کر اے ایمان والو تاکہ تم بھلائی پاؤ"},{"n":204,"l":"س","t":"سیرتِ صالحین","p":"19","s":"الفرقان","sn":25,"r":"6","a":"63-67","ar":"وَعِبَادُ الرَّحۡمٰنِ الَّذِيۡنَ يَمۡشُوۡنَ عَلَي الۡاَرۡضِ هَوۡنًا وَّاِذَا خَاطَبَهُمُ الۡجٰهِلُوۡنَ قَالُوۡا سَلٰمًا وَالَّذِيۡنَ يَبِيۡتُوۡنَ لِرَبِّهِمۡ سُجَّدًا وَّقِيَامًا وَالَّذِيۡنَ يَقُوۡلُوۡنَ رَبَّنَا اصۡرِفۡ عَنَّا عَذَابَ جَهَنَّمَۖ اِنَّ عَذَابَهَا كَانَ غَرَامًاۖ اِنَّهَا سَآءَتۡ مُسۡتَقَرًّا وَّمُقَامًا وَالَّذِيۡنَ اِذَا٘ اَنۡفَقُوۡا لَمۡ يُسۡرِفُوۡا وَلَمۡ يَقۡتُرُوۡا وَكَانَ بَيۡنَ ذٰلِكَ قَوَامًا","u":"اور بندے رحمٰن کے وہ ہیں جو چلتے ہیں زمین پر دبے پاؤں اور جب بات کرنے لگیں ان سے بے سمجھ لوگ تو کہیں صاحب سلامت اور وہ لوگ جو رات کاٹتے ہیں اپنے رب کے آگے سجدہ میں اور کھڑے اور وہ لوگ کہ کہتے ہیں اے رب ہٹا ہم سے دوزخ کا عذاب بیشک اس کا عذاب چمٹنے والا ہے وہ بری جگہ ہے ٹھہرنے کی اور بری جگہ رہنے کی اور وہ لوگ کہ جب خرچ کرنے لگیں نہ بیجا اڑائیں اور نہ تنگی کریں اور ہے اس کے بیچ ایک سیدھی گذران"},{"n":205,"l":"س","t":"سود خوروں کا انجام","p":"3","s":"البقرہ","sn":2,"r":"38","a":"275","ar":"اَلَّذِيۡنَ يَاۡكُلُوۡنَ الرِّبٰوا لَا يَقُوۡمُوۡنَ اِلَّا كَمَا يَقُوۡمُ الَّذِيۡ يَتَخَبَّطُهُ الشَّيۡطٰنُ مِنَ الۡمَسِّؕ ذٰلِكَ بِاَنَّهُمۡ قَالُوۡ٘ا اِنَّمَا الۡبَيۡعُ مِثۡلُ الرِّبٰواۘ وَاَحَلَّ اللّٰهُ الۡبَيۡعَ وَحَرَّمَ الرِّبٰواؕ فَمَنۡ جَآءَهٗ مَوۡعِظَةٌ مِّنۡ رَّبِّهٖ فَانۡتَهٰي فَلَهٗ مَا سَلَفَؕ وَاَمۡرُهٗ٘ اِلَي اللّٰهِؕ وَمَنۡ عَادَ فَاُولٰٓئِكَ اَصۡحٰبُ النَّارِۚ هُمۡ فِيۡهَا خٰلِدُوۡنَ","u":"جو لوگ کھاتےہیں سود نہیں اٹھیں گے قیامت کو مگر جس طرح اٹھتا ہے وہ شخص کہ جس کے حواس کھو دیے ہوں جن نے لپٹ کر یہ حالت انکی اس واسطے ہو گی کہ انہوں نے کہا کہ سوداگری بھی تو ایسی ہی ہے جیسے سود لینا حالانکہ اللہ نے حلال کیا ہے سوداگری اور حرام کیا ہے سود کو پھر جس کو پہنچی نصیحت اپنے رب کی طرف سے اور وہ باز آ گیا تو اس کے واسطے ہے جو پہلے ہو چکا اور معاملہ اس کا اللہ کے حوالہ ہے اور جو کوئی پھر سود لیوے تو وہی لوگ ہیں دوزخ والے وہ اس میں ہمیشہ رہیں گے"},{"n":206,"l":"س","t":"سود اور تجارت میں فرق","p":"3","s":"البقرہ","sn":2,"r":"38","a":"275","ar":"اَلَّذِيۡنَ يَاۡكُلُوۡنَ الرِّبٰوا لَا يَقُوۡمُوۡنَ اِلَّا كَمَا يَقُوۡمُ الَّذِيۡ يَتَخَبَّطُهُ الشَّيۡطٰنُ مِنَ الۡمَسِّؕ ذٰلِكَ بِاَنَّهُمۡ قَالُوۡ٘ا اِنَّمَا الۡبَيۡعُ مِثۡلُ الرِّبٰواۘ وَاَحَلَّ اللّٰهُ الۡبَيۡعَ وَحَرَّمَ الرِّبٰواؕ فَمَنۡ جَآءَهٗ مَوۡعِظَةٌ مِّنۡ رَّبِّهٖ فَانۡتَهٰي فَلَهٗ مَا سَلَفَؕ وَاَمۡرُهٗ٘ اِلَي اللّٰهِؕ وَمَنۡ عَادَ فَاُولٰٓئِكَ اَصۡحٰبُ النَّارِۚ هُمۡ فِيۡهَا خٰلِدُوۡنَ","u":"جو لوگ کھاتےہیں سود نہیں اٹھیں گے قیامت کو مگر جس طرح اٹھتا ہے وہ شخص کہ جس کے حواس کھو دیے ہوں جن نے لپٹ کر یہ حالت انکی اس واسطے ہو گی کہ انہوں نے کہا کہ سوداگری بھی تو ایسی ہی ہے جیسے سود لینا حالانکہ اللہ نے حلال کیا ہے سوداگری اور حرام کیا ہے سود کو پھر جس کو پہنچی نصیحت اپنے رب کی طرف سے اور وہ باز آ گیا تو اس کے واسطے ہے جو پہلے ہو چکا اور معاملہ اس کا اللہ کے حوالہ ہے اور جو کوئی پھر سود لیوے تو وہی لوگ ہیں دوزخ والے وہ اس میں ہمیشہ رہیں گے"},{"n":207,"l":"س","t":"ستاروں اور کہکشاؤں کی نشانیاں","p":"29","s":"الملک","sn":67,"r":"1","a":"5","ar":"وَلَقَدۡ زَيَّنَّا السَّمَآءَ الدُّنۡيَا بِمَصَابِيۡحَ وَجَعَلۡنٰهَا رُجُوۡمًا لِّلشَّيٰطِيۡنِ وَاَعۡتَدۡنَا لَهُمۡ عَذَابَ السَّعِيۡرِ","u":"اور ہم نے رونق دی سب سے ورلے آسمان کو چراغوں سے اور اُن سے کر رکھی ہے ہم نے پھینک مار شیطانوں کے واسطے اور رکھا ہے اُنکے واسطے عذاب دہکتی آگ کا"},{"n":208,"l":"س","t":"سچی گواہی کا حکم","p":"3","s":"البقرہ","sn":2,"r":"39","a":"283","ar":"وَاِنۡ كُنۡتُمۡ عَلٰي سَفَرٍ وَّلَمۡ تَجِدُوۡا كَاتِبًا فَرِهٰنٌ مَّقۡبُوۡضَةٌؕ فَاِنۡ اَمِنَ بَعۡضُكُمۡ بَعۡضًا فَلۡيُؤَدِّ الَّذِي اؤۡتُمِنَ اَمَانَتَهٗ وَلۡيَتَّقِ اللّٰهَ رَبَّهٗؕ وَلَا تَكۡتُمُوا الشَّهَادَةَؕ وَمَنۡ يَّكۡتُمۡهَا فَاِنَّهٗ٘ اٰثِمٌ قَلۡبُهٗؕ وَاللّٰهُ بِمَا تَعۡمَلُوۡنَ عَلِيۡمٌ","u":"اور اگر تم سفر میں ہو اور نہ پاؤ کوئی لکھنے والا تو گرو ہاتھ میں رکھنی چاہیئے پھر اگر اعتبار کرے ایک دوسرے کا تو چاہئے کہ پورا ادا کرے وہ شخص کہ جس پر اعتبار کیا اپنی امانت کو اور ڈرتا رہے اللہ سے جو رب ہے اس کا اور مت چھپاؤ گواہی کو اور جو شخص اس کو چھپاوے تو بیشک گنہگار ہے دل اس کا اور اللہ تمہارے کاموں کو خوب جانتا ہے"},{"n":209,"l":"س","t":"سات آسمانوں کی تخلیق","p":"1","s":"البقرہ","sn":2,"r":"3","a":"29","ar":"هُوَ الَّذِيۡ خَلَقَ لَكُمۡ مَّا فِي الۡاَرۡضِ جَمِيۡعًا ثُمَّ اسۡتَوٰ٘ي اِلَي السَّمَآءِ فَسَوّٰىهُنَّ سَبۡعَ سَمٰوٰتٍؕ وَهُوَ بِكُلِّ شَيۡءٍ عَلِيۡمٌ","u":"وہی ہے جس نے پیدا کیا تمہارے واسطے جو کچھ زمین میں ہے سب پھر قصد کیا آسمان کی طرف سو ٹھیک کر دیا انکو سات آسمان اور خدا تعالیٰ ہر چیز سے خبردار ہے"},{"n":210,"l":"س","t":"سمندر اور کشتیوں میں نشانیاں","p":"14","s":"النحل","sn":16,"r":"2","a":"14","ar":"وَهُوَ الَّذِيۡ سَخَّرَ الۡبَحۡرَ لِتَاۡكُلُوۡا مِنۡهُ لَحۡمًا طَرِيًّا وَّتَسۡتَخۡرِجُوۡا مِنۡهُ حِلۡيَةً تَلۡبَسُوۡنَهَاۚ وَتَرَي الۡفُلۡكَ مَوَاخِرَ فِيۡهِ وَلِتَبۡتَغُوۡا مِنۡ فَضۡلِهٖ وَلَعَلَّكُمۡ تَشۡكُرُوۡنَ","u":"اور وہی ہے جس نے کام میں لگا دیا دریا کو کہ کھاؤ اس میں سے گوشت تازہ اور نکالو اس میں سے گہنا جو پہنتے ہو اور دیکھتا ہے تو کشتیوں کو چلتی ہیں پانی پھاڑ کر اسمیں (دریا میں) اور اس واسطے کہ تلاش کرو اسکے فضل سے اور تاکہ احسان مانو"},{"n":211,"l":"س","t":"سود کے معاشرتی نقصانات","p":"3","s":"البقرہ","sn":2,"r":"38","a":"276","ar":"يَمۡحَقُ اللّٰهُ الرِّبٰوا وَيُرۡبِي الصَّدَقٰتِؕ وَاللّٰهُ لَا يُحِبُّ كُلَّ كَفَّارٍ اَثِيۡمٍ","u":"مٹاتا ہے اللہ سود کو اور بڑھاتا ہے خیرات کو اور اللہ خوش نہیں کسی نا شکر گنہگار سے"},{"n":212,"l":"س","t":"سفرِ آخرت کی تیاری","p":"28","s":"الحشر","sn":59,"r":"3","a":"18","ar":"يٰ٘اَيُّهَا الَّذِيۡنَ اٰمَنُوا اتَّقُوا اللّٰهَ وَلۡتَنۡظُرۡ نَفۡسٌ مَّا قَدَّمَتۡ لِغَدٍۚ وَاتَّقُوا اللّٰهَؕ اِنَّ اللّٰهَ خَبِيۡرٌۭ بِمَا تَعۡمَلُوۡنَ","u":"اے ایمان والو ڈرتے رہو اللہ سے اور چاہیے کہ دیکھ لے ہر ایک جی کیا بھیجتا ہے کل کے واسطے اور ڈرتے رہو اللہ سے بیشک اللہ کو خبر ہے جو تم کرتے ہو"},{"n":213,"l":"س","t":"ستاروں سے راستہ معلوم کرنا","p":"14","s":"النحل","sn":16,"r":"2","a":"16","ar":"وَعَلٰمٰتٍؕ وَبِالنَّجۡمِ هُمۡ يَهۡتَدُوۡنَ","u":"اور بنائیں (رکھیں) علامتیں اور ستاروں سے لوگ راہ پاتے ہیں"},{"n":214,"l":"ش","t":"شکر گزاری","p":"13","s":"ابراہیم","sn":14,"r":"2","a":"7","ar":"وَاِذۡ تَاَذَّنَ رَبُّكُمۡ لَئِنۡ شَكَرۡتُمۡ لَاَزِيۡدَنَّكُمۡ وَلَئِنۡ كَفَرۡتُمۡ اِنَّ عَذَابِيۡ لَشَدِيۡدٌ","u":"اور جب سنا دیا تمہارے رب نے اگر احسان مانو گے تو اور بھی دوں گا تم کو اور اگر ناشکری کرو گے تو میرا عذاب البتہ سخت ہے"},{"n":215,"l":"ش","t":"شرک کی مذمت","p":"5","s":"النساء","sn":4,"r":"7","a":"48","ar":"اِنَّ اللّٰهَ لَا يَغۡفِرُ اَنۡ يُّشۡرَكَ بِهٖ وَيَغۡفِرُ مَا دُوۡنَ ذٰلِكَ لِمَنۡ يَّشَآءُۚ وَمَنۡ يُّشۡرِكۡ بِاللّٰهِ فَقَدِ افۡتَرٰ٘ي اِثۡمًا عَظِيۡمًا","u":"بیشک اللہ نہیں بخشتا اس کو جو اس کا شریک کرے اور بخشتا ہے اس سے نیچے کے گناہ جس کے چاہے اور جس نے شریک ٹھہرایا اللہ کا اس نے بڑا طوفان باندھا"},{"n":216,"l":"ش","t":"شفاعت کا تصور","p":"3","s":"البقرہ","sn":2,"r":"34","a":"255","ar":"اَللّٰهُ لَا٘ اِلٰهَ اِلَّا هُوَۚ اَلۡحَيُّ الۡقَيُّوۡمُ ۚ لَا تَاۡخُذُهٗ سِنَةٌ وَّلَا نَوۡمٌؕ لَهٗ مَا فِي السَّمٰوٰتِ وَمَا فِي الۡاَرۡضِؕ مَنۡ ذَا الَّذِيۡ يَشۡفَعُ عِنۡدَهٗ٘ اِلَّا بِاِذۡنِهٖؕ يَعۡلَمُ مَا بَيۡنَ اَيۡدِيۡهِمۡ وَمَا خَلۡفَهُمۡۚ وَلَا يُحِيۡطُوۡنَ بِشَيۡءٍ مِّنۡ عِلۡمِهٖ٘ اِلَّا بِمَا شَآءَۚ وَسِعَ كُرۡسِيُّهُ السَّمٰوٰتِ وَالۡاَرۡضَۚ وَلَا يَـُٔوۡدُهٗ حِفۡظُهُمَاۚ وَهُوَ الۡعَلِيُّ الۡعَظِيۡمُ","u":"اللہ اس کے سوا کوئی معبود نہں زندہ ہے سب کا تھامنے والا نہیں پکڑ سکتی اس کو اونگھ اور نہ نیند اسی کا ہے جو کچھ آسمانوں اور زمین میں ہے ایسا کون ہے جو سفارش کرے اس کے پاس مگر اجازت سے جانتا ہے جو کچھ خلقت کے روبرو ہے اور جو کچھ انکے پیچھے ہے اور وہ سب احاطہ نہیں کر سکتے کسی چیز کا اس کی معلومات میں سے مگر جتنا کہ وہی چاہے گنجائش ہے اس کی کرسی میں تمام آسمانوں اور زمین کو اور گراں نہیں اس کو تھامنا ان کا اور وہی ہے سب سے برتر عظمت والا"},{"n":217,"l":"ش","t":"شیطان سے پناہ مانگنا","p":"9","s":"الاعراف","sn":7,"r":"24","a":"200","ar":"وَاِمَّا يَنۡزَغَنَّكَ مِنَ الشَّيۡطٰنِ نَزۡغٌ فَاسۡتَعِذۡ بِاللّٰهِؕ اِنَّهٗ سَمِيۡعٌ عَلِيۡمٌ","u":"اور اگر ابھارے تجھ کو شیطان کی چھیڑ تو پناہ مانگ اللہ سے وہی ہےسننے والا جاننے والا"},{"n":218,"l":"ش","t":"شعائرِ اللہ کی تعظیم","p":"17","s":"الحج","sn":22,"r":"4","a":"32","ar":"ذٰلِكَ وَمَنۡ يُّعَظِّمۡ شَعَآئِرَ اللّٰهِ فَاِنَّهَا مِنۡ تَقۡوَي الۡقُلُوۡبِ","u":"یہ سن چکے اور جو کوئی ادب رکھے اللہ کے نام لگی چیزوں کا سو وہ دل کی پرہیزگاری کی بات ہے"},{"n":219,"l":"ش","t":"شعیب علیہ السلام کا قصہ","p":"12","s":"ھود","sn":11,"r":"8","a":"84-85","ar":"وَاِلٰي مَدۡيَنَ اَخَاهُمۡ شُعَيۡبًاؕ قَالَ يٰقَوۡمِ اعۡبُدُوا اللّٰهَ مَا لَكُمۡ مِّنۡ اِلٰهٍ غَيۡرُهٗؕ وَلَا تَنۡقُصُوا الۡمِكۡيَالَ وَالۡمِيۡزَانَ اِنِّيۡ٘ اَرٰىكُمۡ بِخَيۡرٍ وَّاِنِّيۡ٘ اَخَافُ عَلَيۡكُمۡ عَذَابَ يَوۡمٍ مُّحِيۡطٍ وَيٰقَوۡمِ اَوۡفُوا الۡمِكۡيَالَ وَالۡمِيۡزَانَ بِالۡقِسۡطِ وَلَا تَبۡخَسُوا النَّاسَ اَشۡيَآءَهُمۡ وَلَا تَعۡثَوۡا فِي الۡاَرۡضِ مُفۡسِدِيۡنَ","u":"اور مدین کی طرف بھیجا ان کے بھائی شعیب کو بولا اے میری قوم بندگی کرو اللہ کی کوئی نہیں تمہارا معبود اس کے سوائے اور نہ گھٹاؤ ماپ اور تول کو میں دیکھتا ہوں تم کو آسودہ حال اور ڈرتا ہوں تم پر عذاب سے ایک گھیر لینے والے دن کے اور اے قوم پورا کرو ماپ اور تول کو انصاف سے اور نہ گھٹا دو لوگوں کو ان کی چیزیں اور مت مچاؤ زمین میں فساد"},{"n":220,"l":"ش","t":"شوریٰ (باہمی مشورہ)","p":"4","s":"آلِ عمران","sn":3,"r":"17","a":"159","ar":"فَبِمَا رَحۡمَةٍ مِّنَ اللّٰهِ لِنۡتَ لَهُمۡۚ وَلَوۡ كُنۡتَ فَظًّا غَلِيۡظَ الۡقَلۡبِ لَانۡفَضُّوۡا مِنۡ حَوۡلِكَ فَاعۡفُ عَنۡهُمۡ وَاسۡتَغۡفِرۡ لَهُمۡ وَشَاوِرۡهُمۡ فِي الۡاَمۡرِۚ فَاِذَا عَزَمۡتَ فَتَوَكَّلۡ عَلَي اللّٰهِؕ اِنَّ اللّٰهَ يُحِبُّ الۡمُتَوَكِّلِيۡنَ","u":"سو کچھ اللہ ہی کی رحمت ہے جو تو نرم دل مل گیا ان کو اور اگر تو ہوتا تندخو سخت دل تو متفرق ہو جاتے تیرے پاس سے سو تو ان کو معاف کر اور ان کے واسطے بخشش مانگ اور ان سے مشورہ لے کام میں پھر جب قصد کر چکا تو اس کام کا تو پھر بھروسہ کر اللہ پر اللہ کو محبت ہے توکل والوں سے"},{"n":221,"l":"ش","t":"شادی بیاہ کے احکام","p":"18","s":"النور","sn":24,"r":"4","a":"32","ar":"وَاَنۡكِحُوا الۡاَيَامٰي مِنۡكُمۡ وَالصّٰلِحِيۡنَ مِنۡ عِبَادِكُمۡ وَاِمَآئِكُمۡؕ اِنۡ يَّكُوۡنُوۡا فُقَرَآءَ يُغۡنِهِمُ اللّٰهُ مِنۡ فَضۡلِهٖؕ وَاللّٰهُ وَاسِعٌ عَلِيۡمٌ","u":"اور نکاح کر دو رانڈوں کا اپنے اندر اور جو نیک ہوں تمہارے غلام اور لونڈیاں اگر وہ ہوں گے مفلس اللہ ان کو غنی کر دے گا اپنے فضل سے اور اللہ کشائش والا ہے سب کچھ جانتا ہے"},{"n":222,"l":"ش","t":"شراکت داری کے احکام","p":"23","s":"صٓ","sn":38,"r":"2","a":"24","ar":"قَالَ لَقَدۡ ظَلَمَكَ بِسُؤَالِ نَعۡجَتِكَ اِلٰي نِعَاجِهٖؕ وَاِنَّ كَثِيۡرًا مِّنَ الۡخُلَطَآءِ لَيَبۡغِيۡ بَعۡضُهُمۡ عَلٰي بَعۡضٍ اِلَّا الَّذِيۡنَ اٰمَنُوۡا وَعَمِلُوا الصّٰلِحٰتِ وَقَلِيۡلٌ مَّا هُمۡؕ وَظَنَّ دَاوٗدُ اَنَّمَا فَتَنّٰهُ فَاسۡتَغۡفَرَ رَبَّهٗ وَخَرَّ رَاكِعًا وَّاَنَابَ","u":"بولا وہ بے انصافی کرتا ہے تجھ پر کہ مانگتا ہے تیری دنبی ملانے کو اپنی دنبیوں میں اور اکثر شریک زیادتی کرتے ہیں ایک دوسرے پر مگر جو یقین لائے ہیں اور کام کئے نیک اور تھوڑے لوگ ہیں ایسے اور خیال میں آیا داؤد کے کہ ہم نے اس کو جانچا پھر گناہ بخشوانے لگا اپنے رب سے اور گر پڑا جھک کر اور رجوع ہوا"},{"n":223,"l":"ش","t":"شب قدر کی فضیلت","p":"30","s":"القدر","sn":97,"r":"1","a":"1-5","ar":"اِنَّا٘ اَنۡزَلۡنٰهُ فِيۡ لَيۡلَةِ الۡقَدۡرِۚۙ وَمَا٘ اَدۡرٰىكَ مَا لَيۡلَةُ الۡقَدۡرِؕ لَيۡلَةُ الۡقَدۡرِ ۙ خَيۡرٌ مِّنۡ اَلۡفِ شَهۡرٍؕؔ تَنَزَّلُ الۡمَلٰٓئِكَةُ وَالرُّوۡحُ فِيۡهَا بِاِذۡنِ رَبِّهِمۡ مِّنۡ كُلِّ اَمۡرٍۙۛ سَلٰمٌۛ هِيَ حَتّٰي مَطۡلَعِ الۡفَجۡرِ","u":"ہم نے اُسکو اتارا شب قدر میں اور تو نے کیا سمجھا کہ کیا ہے شب قدر شب قدر بہتر ہے ہزار مہینے سے اترتے ہیں فرشتے اور روح اُس میں اپنے رب کے حکم سے ہر کام پر امان ہے وہ رات صبح کے نکلنے تک"},{"n":224,"l":"ش","t":"شجاعت و بہادری","p":"21","s":"الاحزاب","sn":33,"r":"3","a":"23","ar":"مِنَ الۡمُؤۡمِنِيۡنَ رِجَالٌ صَدَقُوۡا مَا عَاهَدُوا اللّٰهَ عَلَيۡهِۚ فَمِنۡهُمۡ مَّنۡ قَضٰي نَحۡبَهٗ وَمِنۡهُمۡ مَّنۡ يَّنۡتَظِرُؗۖ وَمَا بَدَّلُوۡا تَبۡدِيۡلًاۙ","u":"ایمان والوں میں کتنے مرد ہیں کہ سچ کر دکھلایا جس بات کا عہد کیا تھا اللہ سے پھر کوئی تو ان میں پورا کر چکا اپنا ذمہ اور کوئی ہے ان میں راہ دیکھ رہا اور بدلا نہیں ایک ذرہ"},{"n":225,"l":"ش","t":"شرعی پردہ کی حکمت","p":"18","s":"النور","sn":24,"r":"8","a":"60","ar":"وَالۡقَوَاعِدُ مِنَ النِّسَآءِ الّٰتِيۡ لَا يَرۡجُوۡنَ نِكَاحًا فَلَيۡسَ عَلَيۡهِنَّ جُنَاحٌ اَنۡ يَّضَعۡنَ ثِيَابَهُنَّ غَيۡرَ مُتَبَرِّجٰتٍۭ بِزِيۡنَةٍؕ وَاَنۡ يَّسۡتَعۡفِفۡنَ خَيۡرٌ لَّهُنَّؕ وَاللّٰهُ سَمِيۡعٌ عَلِيۡمٌ","u":"اور جو بیٹھ رہی ہیں گھروں میں تمہاری عورتوں میں سے جنکو توقع نہیں رہی نکاح کی ان پرگناہ نہیں کہ اتار رکھیں اپنے کپڑے یہ نہیں کہ دکھاتی پھریں اپنا سنگار اور اس سے بھی بچیں تو بہتر ہے انکے لئے اور اللہ سب باتیں سنتا جانتا ہے"},{"n":226,"l":"ش","t":"شراکتِ حیات میں مودت و رحمت","p":"2","s":"البقرہ","sn":2,"r":"23","a":"187","ar":"اُحِلَّ لَكُمۡ لَيۡلَةَ الصِّيَامِ الرَّفَثُ اِلٰي نِسَآئِكُمۡؕ هُنَّ لِبَاسٌ لَّكُمۡ وَاَنۡتُمۡ لِبَاسٌ لَّهُنَّؕ عَلِمَ اللّٰهُ اَنَّكُمۡ كُنۡتُمۡ تَخۡتَانُوۡنَ اَنۡفُسَكُمۡ فَتَابَ عَلَيۡكُمۡ وَعَفَا عَنۡكُمۡۚ فَالۡـٰٔنَ بَاشِرُوۡهُنَّ وَابۡتَغُوۡا مَا كَتَبَ اللّٰهُ لَكُمۡ وَكُلُوۡا وَاشۡرَبُوۡا حَتّٰي يَتَبَيَّنَ لَكُمُ الۡخَيۡطُ الۡاَبۡيَضُ مِنَ الۡخَيۡطِ الۡاَسۡوَدِ مِنَ الۡفَجۡرِ ثُمَّ اَتِمُّوا الصِّيَامَ اِلَي الَّيۡلِۚ وَلَا تُبَاشِرُوۡهُنَّ وَاَنۡتُمۡ عٰكِفُوۡنَ فِي الۡمَسٰجِدِؕ تِلۡكَ حُدُوۡدُ اللّٰهِ فَلَا تَقۡرَبُوۡهَاؕ كَذٰلِكَ يُبَيِّنُ اللّٰهُ اٰيٰتِهٖ لِلنَّاسِ لَعَلَّهُمۡ يَتَّقُوۡنَ","u":"حلال ہوا تم کو روزہ کی رات میں بے حجاب ہونا اپنی عورتوں سے وہ پوشاک ہیں تمہاری اور تم پوشاک ہو انکی اللہ کو معلوم ہے کہ تم خیانت کرتے تھے اپنی جانوں سے سو معاف کیا تم کو اور درگذر کی تم سے پھر ملو اپنی عورتوں سے اور طلب کرو اس کو جو لکھ دیا ہے اللہ نے تمہارے لئے اور کھاؤ اور پیو جب تک کہ صاف نظر آئے تم کو دھاری سفید صبح کی جدا دھاری سیاہ سے پھر پورا کرو روزہ کو رات تک اور نہ ملو عورتوں سے جب تک تم اعتکاف کرو مسجدوں میں یہ حدیں باندھی ہوئی ہیں اللہ کی سو انکے نزدیک نہ جاؤ اسی طرح بیان فرماتا ہے اللہ اپنی آیتیں لوگوں کے واسطے تاکہ وہ بچتے رہیں"},{"n":227,"l":"ش","t":"شانِ نزولِ قرآن","p":"2","s":"البقرہ","sn":2,"r":"23","a":"185","ar":"شَهۡرُ رَمَضَانَ الَّذِيۡ٘ اُنۡزِلَ فِيۡهِ الۡقُرۡاٰنُ هُدًي لِّلنَّاسِ وَبَيِّنٰتٍ مِّنَ الۡهُدٰي وَالۡفُرۡقَانِۚ فَمَنۡ شَهِدَ مِنۡكُمُ الشَّهۡرَ فَلۡيَصُمۡهُؕ وَمَنۡ كَانَ مَرِيۡضًا اَوۡ عَلٰي سَفَرٍ فَعِدَّةٌ مِّنۡ اَيَّامٍ اُخَرَؕ يُرِيۡدُ اللّٰهُ بِكُمُ الۡيُسۡرَ وَلَا يُرِيۡدُ بِكُمُ الۡعُسۡرَؗ وَلِتُكۡمِلُوا الۡعِدَّةَ وَلِتُكَبِّرُوا اللّٰهَ عَلٰي مَا هَدٰىكُمۡ وَلَعَلَّكُمۡ تَشۡكُرُوۡنَ","u":"مہینہ رمضان کا ہے جس میں نازل ہوا قرآن ہدایت ہے واسطے لوگوں کو اور دلیلیں روشن راہ پانے کی اور حق کو باطل سے جدا کرنے کی سو جو کوئی پائے تم میں سے اس مہینہ کو تو ضرور روزے رکھے اسکے اور جو کوئی ہو بیمار یا مسافر تو اس کو گنتی پوری کرنی چاہیئے اور دنوں سے اللہ چاہتا ہے تم پر آسانی اور نہیں چاہتا تم پر دشواری اور اس واسطے کہ تم پوری کرو گنتی اور تاکہ بڑائی کرو اللہ کی اس بات پر کہ تم کو ہدایت کی اور تاکہ تم احسان مانو"},{"n":228,"l":"ص","t":"صبر کی فضیلت","p":"23","s":"الزمر","sn":39,"r":"2","a":"10","ar":"قُلۡ يٰعِبَادِ الَّذِيۡنَ اٰمَنُوا اتَّقُوۡا رَبَّكُمۡؕ لِلَّذِيۡنَ اَحۡسَنُوۡا فِيۡ هٰذِهِ الدُّنۡيَا حَسَنَةٌؕ وَاَرۡضُ اللّٰهِ وَاسِعَةٌؕ اِنَّمَا يُوَفَّي الصّٰبِرُوۡنَ اَجۡرَهُمۡ بِغَيۡرِ حِسَابٍ","u":"تو کہہ اے بندو میرے جو یقین لائے ہو ڈرو اپنے رب سے جنہوں نے نیکی کی اس دنیا میں انکے لئے ہی ہے بھلائی اور زمین اللہ کی کشادہ ہے صبر کرنے والوں ہی کو ملتا ہے ان کا ثواب بے شمار"},{"n":229,"l":"ص","t":"صدقہ و خیرات کی ترغیب","p":"3","s":"البقرہ","sn":2,"r":"37","a":"271","ar":"اِنۡ تُبۡدُوا الصَّدَقٰتِ فَنِعِمَّا هِيَۚ وَاِنۡ تُخۡفُوۡهَا وَتُؤۡتُوۡهَا الۡفُقَرَآءَ فَهُوَ خَيۡرٌ لَّكُمۡؕ وَيُكَفِّرُ عَنۡكُمۡ مِّنۡ سَيِّاٰتِكُمۡؕ وَاللّٰهُ بِمَا تَعۡمَلُوۡنَ خَبِيۡرٌ","u":"اگر ظاہر کر کے دو خیرات تو کیا اچھی بات اور اگر اس کو چھپاؤ اور فقیروں کو پہنچاؤ تو وہ بہتر ہے تمہارے حق میں اور دور کرے گا کچھ گناہ تمہارے اور اللہ تمہارے کاموں سے خوب خبردار ہے"},{"n":230,"l":"ص","t":"صلہ رحمی","p":"26","s":"محمد","sn":47,"r":"3","a":"22-23","ar":"فَهَلۡ عَسَيۡتُمۡ اِنۡ تَوَلَّيۡتُمۡ اَنۡ تُفۡسِدُوۡا فِي الۡاَرۡضِ وَتُقَطِّعُوۡ٘ا اَرۡحَامَكُمۡ اُولٰٓئِكَ الَّذِيۡنَ لَعَنَهُمُ اللّٰهُ فَاَصَمَّهُمۡ وَاَعۡمٰ٘ي اَبۡصَارَهُمۡ","u":"پھر تم سے یہ بھی توقع ہے کہ اگر تمکو حکومت مل جائے تو خرابی ڈالو ملک میں اور قطع کرو اپنی قرابتیں ایسے لوگ ہیں جن پر لعنت کی اللہ نے پھر کردیا انکو بہرا اور اندھی کردیں اُنکی آنکھیں"},{"n":231,"l":"ص","t":"صدق و امانت","p":"14","s":"النحل","sn":16,"r":"13","a":"91","ar":"وَاَوۡفُوۡا بِعَهۡدِ اللّٰهِ اِذَا عٰهَدۡتُّمۡ وَلَا تَنۡقُضُوا الۡاَيۡمَانَ بَعۡدَ تَوۡكِيۡدِهَا وَقَدۡ جَعَلۡتُمُ اللّٰهَ عَلَيۡكُمۡ كَفِيۡلًاؕ اِنَّ اللّٰهَ يَعۡلَمُ مَا تَفۡعَلُوۡنَ","u":"اور پورا کرو عہد اللہ کا جب آپس میں عہد کرو اور نہ توڑو قسموں کو پکا کرنے کے بعد اور تم نے کیا ہے اللہ کو اپنا ضامن اللہ جانتا ہے جو تم کرتےہو"},{"n":232,"l":"ص","t":"صالحین کا حسنِ انجام","p":"12","s":"ھود","sn":11,"r":"2","a":"23","ar":"اِنَّ الَّذِيۡنَ اٰمَنُوۡا وَعَمِلُوا الصّٰلِحٰتِ وَاَخۡبَتُوۡ٘ا اِلٰي رَبِّهِمۡۙ اُولٰٓئِكَ اَصۡحٰبُ الۡجَنَّةِۚ هُمۡ فِيۡهَا خٰلِدُوۡنَ","u":"البتہ جو لوگ ایمان لائے اور کام کئے نیک اور عاجزی کی اپنے رب کے سامنے وہ ہیں جنت کے رہنے والے وہ اسی میں رہا کریں گے"},{"n":233,"l":"ص","t":"نماز (صلوٰۃ) کا حکم","p":"2","s":"البقرہ","sn":2,"r":"31","a":"238","ar":"حَافِظُوۡا عَلَي الصَّلَوٰتِ وَالصَّلٰوةِ الۡوُسۡطٰي وَقُوۡمُوۡا لِلّٰهِ قٰنِتِيۡنَ","u":"خبردار رہو سب نمازوں سے اور بیچ والی نماز سے اور کھڑے رہو اللہ کے آگے ادب سے"},{"n":234,"l":"ص","t":"صالح علیہ السلام کا قصہ","p":"8","s":"الاعراف","sn":7,"r":"10","a":"73","ar":"وَاِلٰي ثَمُوۡدَ اَخَاهُمۡ صٰلِحًاۘ قَالَ يٰقَوۡمِ اعۡبُدُوا اللّٰهَ مَا لَكُمۡ مِّنۡ اِلٰهٍ غَيۡرُهٗؕ قَدۡ جَآءَتۡكُمۡ بَيِّنَةٌ مِّنۡ رَّبِّكُمۡؕ هٰذِهٖ نَاقَةُ اللّٰهِ لَكُمۡ اٰيَةً فَذَرُوۡهَا تَاۡكُلۡ فِيۡ٘ اَرۡضِ اللّٰهِ وَلَا تَمَسُّوۡهَا بِسُوۡٓءٍ فَيَاۡخُذَكُمۡ عَذَابٌ اَلِيۡمٌ","u":"اور ثمود کی طرف بھیجا انکے بھائی صالح کو بولا اے میری قوم بندگی کرو اللہ کی کوئی نہیں تمہارا معبود اسکے سوا تم کو پہنچ چکی ہے دلیل تمہارے رب کی طرف سے یہ اونٹنی اللہ کی ہے تمہارے لئے نشانی سو اس کو چھوڑ دو کہ کھائے اللہ کی زمین میں اور اس کو ہاتھ نہ لگاؤ بری طرح پھر تم کو پکڑے گا عذاب دردناک"},{"n":235,"l":"ص","t":"صفِ جہاد میں استقامت","p":"28","s":"الصف","sn":61,"r":"1","a":"4","ar":"اِنَّ اللّٰهَ يُحِبُّ الَّذِيۡنَ يُقَاتِلُوۡنَ فِيۡ سَبِيۡلِهٖ صَفًّا كَاَنَّهُمۡ بُنۡيَانٌ مَّرۡصُوۡصٌ","u":"اللہ چاہتا ہے اُن لوگوں کو جو لڑتے ہیں اُسکی راہ میں قطار باندھ کر گویا وہ دیوار ہیں سیسہ پلائی ہوئی"},{"n":236,"l":"ص","t":"صبرِ جمیل","p":"12","s":"یوسف","sn":12,"r":"2","a":"18","ar":"وَجَآءُوۡ عَلٰي قَمِيۡصِهٖ بِدَمٍ كَذِبٍؕ قَالَ بَلۡ سَوَّلَتۡ لَكُمۡ اَنۡفُسُكُمۡ اَمۡرًاؕ فَصَبۡرٌ جَمِيۡلٌؕ وَاللّٰهُ الۡمُسۡتَعَانُ عَلٰي مَا تَصِفُوۡنَ","u":"اور لائے اس کے کرتے پر لہو لگا کر جھوٹ بولا یہ ہر گز نہیں بلکہ بنا دی ہے تم کو تمہارے جیوں نےایک بات اب صبر ہی بہتر ہے اور اللہ ہی سے مدد مانگتا ہوں اس بات پر جو تم ظاہر کرتے ہو"},{"n":237,"l":"ص","t":"صنعت و حرفت کی ترغیب (حضرت داؤد علیہ السلام)","p":"22","s":"سبأ","sn":34,"r":"2","a":"10-11","ar":"وَلَقَدۡ اٰتَيۡنَا دَاوٗدَ مِنَّا فَضۡلًاؕ يٰجِبَالُ اَوِّبِيۡ مَعَهٗ وَالطَّيۡرَۚ وَاَلَنَّا لَهُ الۡحَدِيۡدَۙ اَنِ اعۡمَلۡ سٰبِغٰتٍ وَّقَدِّرۡ فِي السَّرۡدِ وَاعۡمَلُوۡا صَالِحًاؕ اِنِّيۡ بِمَا تَعۡمَلُوۡنَ بَصِيۡرٌ","u":"اور ہم نے دی ہے داؤد کو اپنی طرف سے بڑائی اے پہاڑو خوش آوازی سے پڑھو اسکے ساتھ اور اڑتے جانوروں کو اور نرم کر دیا ہم نے اس کے آگے لوہا کہ بنا زرہیں کشادہ اور اندازے سے جوڑ کڑیاں اور کرو تم سب کام بھلا میں جو کچھ تم کرتے ہو دیکھتا ہوں"},{"n":238,"l":"ص","t":"صراطِ مستقیم کی دعا","p":"1","s":"الفاتحہ","sn":1,"r":"1","a":"6","ar":"اِهۡدِنَا الصِّرَاطَ الۡمُسۡتَقِيۡمَۙ","u":"بتلا ہم کو راہ سیدھی"},{"n":239,"l":"ص","t":"کھانے پینے کے آداب","p":"30","s":"عبس","sn":80,"r":"1","a":"24","ar":"فَلۡيَنۡظُرِ الۡاِنۡسَانُ اِلٰي طَعَامِهٖ٘ۙ","u":"اب دیکھ لے آدمی اپنے کھانے کو"},{"n":240,"l":"ص","t":"صدقہ جاریہ کا تصور","p":"3","s":"البقرہ","sn":2,"r":"36","a":"265","ar":"وَمَثَلُ الَّذِيۡنَ يُنۡفِقُوۡنَ اَمۡوَالَهُمُ ابۡتِغَآءَ مَرۡضَاتِ اللّٰهِ وَتَثۡبِيۡتًا مِّنۡ اَنۡفُسِهِمۡ كَمَثَلِ جَنَّةٍۭ بِرَبۡوَةٍ اَصَابَهَا وَابِلٌ فَاٰتَتۡ اُكُلَهَا ضِعۡفَيۡنِۚ فَاِنۡ لَّمۡ يُصِبۡهَا وَابِلٌ فَطَلٌّؕ وَاللّٰهُ بِمَا تَعۡمَلُوۡنَ بَصِيۡرٌ","u":"اور مثال ان کی جو خرچ کرتے ہیں اپنے مال اللہ کی خوشی حاصل کرنے کو اور اپنے دلوں کو ثابت کر کر ایسی ہے جیسے ایک باغ ہے بلند زمین پر اس پر پڑا زور کا مینہ تو لایا وہ باغ اپنا پھل دو چند اور اگر نہ پڑا اس پر مینہ تو پھورا ہی کافی ہے اور اللہ تمہارے کاموں کو خوب دیکھتا ہے"},{"n":241,"l":"ص","t":"صلحِ حدیبیہ کا تذکرہ","p":"26","s":"الفتح","sn":48,"r":"1","a":"1","ar":"اِنَّا فَتَحۡنَا لَكَ فَتۡحًا مُّبِيۡنًاۙ","u":"ہم نے فیصلہ کر دیا تیرے واسطے صریح فیصلہ"},{"n":242,"l":"ص","t":"صلہ رحمی کا اجر","p":"13","s":"الرعد","sn":13,"r":"3","a":"21","ar":"وَالَّذِيۡنَ يَصِلُوۡنَ مَا٘ اَمَرَ اللّٰهُ بِهٖ٘ اَنۡ يُّوۡصَلَ وَيَخۡشَوۡنَ رَبَّهُمۡ وَيَخَافُوۡنَ سُوۡٓءَ الۡحِسَابِؕ","u":"اور وہ لوگ جو ملاتے ہیں جس کو اللہ نے فرمایا ملانا اور ڈرتے ہیں اپنے رب سے اور اندیشہ رکھتے ہیں برے حساب کا"},{"n":243,"l":"ض","t":"ضعیفوں اور کمزوروں کی مدد","p":"5","s":"النساء","sn":4,"r":"10","a":"75","ar":"وَمَا لَكُمۡ لَا تُقَاتِلُوۡنَ فِيۡ سَبِيۡلِ اللّٰهِ وَالۡمُسۡتَضۡعَفِيۡنَ مِنَ الرِّجَالِ وَالنِّسَآءِ وَالۡوِلۡدَانِ الَّذِيۡنَ يَقُوۡلُوۡنَ رَبَّنَا٘ اَخۡرِجۡنَا مِنۡ هٰذِهِ الۡقَرۡيَةِ الظَّالِمِ اَهۡلُهَاۚ وَاجۡعَلۡ لَّنَا مِنۡ لَّدُنۡكَ وَلِيًّاۚۙ وَّاجۡعَلۡ لَّنَا مِنۡ لَّدُنۡكَ نَصِيۡرًاؕ","u":"اور تم کو کیا ہوا کہ نہیں لڑتے اللہ کی راہ میں اور ان کے واسطے جو مغلوب ہیں مرد اور عورتیں اور بچے جو کہتے ہیں اے رب ہمارے نکال ہم کو اس بستی سے کہ ظالم ہیں یہاں کےلوگ اور کر دے ہمارے واسطے اپنے پاس سےکوئی حمایتی اور کر دے ہمارے واسطے اپنے پاس سے مددگار"},{"n":244,"l":"ض","t":"ضرورت مندوں کا حق","p":"26","s":"الذاریات","sn":51,"r":"1","a":"19","ar":"وَفِيۡ٘ اَمۡوَالِهِمۡ حَقٌّ لِّلسَّآئِلِ وَالۡمَحۡرُوۡمِ","u":"اور اُنکے مال میں حصہ تھا مانگنے والوں کا اور ہارے ہوئے کا"},{"n":245,"l":"ض","t":"ضمانت اور کفالت کے احکام","p":"13","s":"یوسف","sn":12,"r":"9","a":"72","ar":"قَالُوۡا نَفۡقِدُ صُوَاعَ الۡمَلِكِ وَلِمَنۡ جَآءَ بِهٖ حِمۡلُ بَعِيۡرٍ وَّاَنَا بِهٖ زَعِيۡمٌ","u":"بولے ہم نہیں پاتے بادشاہ کا پیمانہ اور جو کوئی اس کو لائے اسکو ملے ایک بوجھ اونٹ کا اور میں ہوں اس کا ضامن"},{"n":246,"l":"ط","t":"طلاق کے احکام","p":"28","s":"الطلاق","sn":65,"r":"1","a":"1","ar":"يٰ٘اَيُّهَا النَّبِيُّ اِذَا طَلَّقۡتُمُ النِّسَآءَ فَطَلِّقُوۡهُنَّ لِعِدَّتِهِنَّ وَاَحۡصُوا الۡعِدَّةَۚ وَاتَّقُوا اللّٰهَ رَبَّكُمۡۚ لَا تُخۡرِجُوۡهُنَّ مِنۭۡ بُيُوۡتِهِنَّ وَلَا يَخۡرُجۡنَ اِلَّا٘ اَنۡ يَّاۡتِيۡنَ بِفَاحِشَةٍ مُّبَيِّنَةٍؕ وَتِلۡكَ حُدُوۡدُ اللّٰهِؕ وَمَنۡ يَّتَعَدَّ حُدُوۡدَ اللّٰهِ فَقَدۡ ظَلَمَ نَفۡسَهٗؕ لَا تَدۡرِيۡ لَعَلَّ اللّٰهَ يُحۡدِثُ بَعۡدَ ذٰلِكَ اَمۡرًا","u":"اے نبی جب تم طلاق دو عورتوں کو تو انکو طلاق دو اُنکی عدت پر اور گنتے رہو عدت کو اور ڈرو اللہ سے جو رب ہے تمہارا مت نکالو اُنکو اُنکے گھروں سے اور وہ بھی نہ نکلیں مگر جو کریں صریح بے حیائی اور یہ حدیں ہیں باندھی ہوئی اللہ کی اور جو کوئی بڑھے اللہ کی حدوں سے تو اُس نے برا کیا اپنا اُسکو خبر نہیں شاید اللہ پیدا کر دے اُس طلاق کے بعد نئی صورت"},{"n":247,"l":"ط","t":"طہارت کے احکام","p":"6","s":"المائدہ","sn":5,"r":"2","a":"6","ar":"يٰ٘اَيُّهَا الَّذِيۡنَ اٰمَنُوۡ٘ا اِذَا قُمۡتُمۡ اِلَي الصَّلٰوةِ فَاغۡسِلُوۡا وُجُوۡهَكُمۡ وَاَيۡدِيَكُمۡ اِلَي الۡمَرَافِقِ وَامۡسَحُوۡا بِرُءُوۡسِكُمۡ وَاَرۡجُلَكُمۡ اِلَي الۡكَعۡبَيۡنِؕ وَاِنۡ كُنۡتُمۡ جُنُبًا فَاطَّهَّرُوۡاؕ وَاِنۡ كُنۡتُمۡ مَّرۡضٰ٘ي اَوۡ عَلٰي سَفَرٍ اَوۡ جَآءَ اَحَدٌ مِّنۡكُمۡ مِّنَ الۡغَآئِطِ اَوۡ لٰمَسۡتُمُ النِّسَآءَ فَلَمۡ تَجِدُوۡا مَآءً فَتَيَمَّمُوۡا صَعِيۡدًا طَيِّبًا فَامۡسَحُوۡا بِوُجُوۡهِكُمۡ وَاَيۡدِيۡكُمۡ مِّنۡهُؕ مَا يُرِيۡدُ اللّٰهُ لِيَجۡعَلَ عَلَيۡكُمۡ مِّنۡ حَرَجٍ وَّلٰكِنۡ يُّرِيۡدُ لِيُطَهِّرَكُمۡ وَلِيُتِمَّ نِعۡمَتَهٗ عَلَيۡكُمۡ لَعَلَّكُمۡ تَشۡكُرُوۡنَ","u":"اے ایمان والو جب تم اٹھو نماز کو تو دھو لو اپنے منہ اور ہاتھ کہنیوں تک اور مل لو اپنے سر کو اور پاؤں ٹخنوں تک اور اگر تم کو جنابت ہو تو خوب طرح پاک ہو اور اگر تم بیمار ہو یا سفر میں یا کوئی تم میں آیا ہے جائے ضرور سے یا پاس گئے ہو عورتوں کے پھر نہ پاؤ تم پانی تو قصد کرو مٹی پاک کا اور مل لو اپنے منہ اور ہاتھ اس سے اللہ نہیں چاہتا کہ تم پر تنگی کرے لیکن چاہتا ہے کہ تم کو پاک کرے اور پورا کرے اپنا احسان تم پر تاکہ تم احسان مانو"},{"n":248,"l":"ط","t":"طاغوت سے اجتناب","p":"3","s":"البقرہ","sn":2,"r":"34","a":"256","ar":"لَا٘ اِكۡرَاهَ فِي الدِّيۡنِۚ قَدۡ تَّبَيَّنَ الرُّشۡدُ مِنَ الۡغَيِّۚ فَمَنۡ يَّكۡفُرۡ بِالطَّاغُوۡتِ وَيُؤۡمِنۭۡ بِاللّٰهِ فَقَدِ اسۡتَمۡسَكَ بِالۡعُرۡوَةِ الۡوُثۡقٰيۚ لَا انۡفِصَامَ لَهَاؕ وَاللّٰهُ سَمِيۡعٌ عَلِيۡمٌ","u":"زبردستی نہں دین کے معاملہ میں بیشک جدا ہو چکی ہے ہدیات گمراہی سے اب جو کوئی نہ مانےگمراہ کرنےوالوں کو اور یقین لاوےاللہ پر تو اس نے پکڑ لیا حلقہ مضبوط جو ٹوٹنے والا نہیں اور اللہ سب کچھ سنتا جانتا ہے"},{"n":249,"l":"ط","t":"طالوت اور جالوت کا واقعہ","p":"2","s":"البقرہ","sn":2,"r":"33","a":"250-251","ar":"وَلَمَّا بَرَزُوۡا لِجَالُوۡتَ وَجُنُوۡدِهٖ قَالُوۡا رَبَّنَا٘ اَفۡرِغۡ عَلَيۡنَا صَبۡرًا وَّثَبِّتۡ اَقۡدَامَنَا وَانۡصُرۡنَا عَلَي الۡقَوۡمِ الۡكٰفِرِيۡنَؕ فَهَزَمُوۡهُمۡ بِاِذۡنِ اللّٰهِۙ وَقَتَلَ دَاوٗدُ جَالُوۡتَ وَاٰتٰىهُ اللّٰهُ الۡمُلۡكَ وَالۡحِكۡمَةَ وَعَلَّمَهٗ مِمَّا يَشَآءُؕ وَلَوۡلَا دَفۡعُ اللّٰهِ النَّاسَ بَعۡضَهُمۡ بِبَعۡضٍ لَّفَسَدَتِ الۡاَرۡضُ وَلٰكِنَّ اللّٰهَ ذُوۡ فَضۡلٍ عَلَي الۡعٰلَمِيۡنَ","u":"اور جب سامنے ہوئے جالوت کے اور اس کی فوجوں کے تو بولے اے رب ہمارےڈال دے ہمارے دلوں میں صبر اور جمائے رکھ ہمارے پاؤں اور مدد کر ہماری اس کافر قوم پر پھر شکست دی مومنوں نے جالوت کے لشکر کو اللہ کے حکم سے اور مار ڈالا داؤد نے جالوت کو اور دی داؤد کو اللہ نے سلطنت اور حکمت اور سکھایا ان کو جو چاہاا اور اگر نہ ہوتا دفع کرا دینا اللہ کا ایک کو دوسرے سے تو خراب ہو جاتا ملک لیکن اللہ بہت مہربان ہے جہان کے لوگوں پر"},{"n":250,"l":"ط","t":"طمع و حرص کی مذمت","p":"30","s":"التکاثر","sn":102,"r":"1","a":"1-2","ar":"اَلۡهٰىكُمُ التَّكَاثُرُۙ حَتّٰي زُرۡتُمُ الۡمَقَابِرَؕ","u":"غفلت میں رکھا تم کو بہتایت کی حرص نے یہاں تک کہ جا دیکھیں قبریں"},{"n":251,"l":"ط","t":"طبقاتی تفاخر کی نفی","p":"26","s":"الحجرات","sn":49,"r":"2","a":"13","ar":"يٰ٘اَيُّهَا النَّاسُ اِنَّا خَلَقۡنٰكُمۡ مِّنۡ ذَكَرٍ وَّاُنۡثٰي وَجَعَلۡنٰكُمۡ شُعُوۡبًا وَّقَبَآئِلَ لِتَعَارَفُوۡاؕ اِنَّ اَكۡرَمَكُمۡ عِنۡدَ اللّٰهِ اَتۡقٰىكُمۡؕ اِنَّ اللّٰهَ عَلِيۡمٌ خَبِيۡرٌ","u":"اے آدمیو ہم نے تم کو بنایا ایک مرد اور ایک عورت سےاور رکھیں تمہاری ذاتیں اور قبیلے تاکہ آپس کی پہچان ہو تحقیق عزت اللہ کے یہاں اسکی کو بڑی جسکو ادب بڑا اللہ سب کچھ جانتا ہے خبردار"},{"n":252,"l":"ط","t":"طوفانِ نوح کا تذکرہ","p":"12","s":"ھود","sn":11,"r":"4","a":"42-44","ar":"وَهِيَ تَجۡرِيۡ بِهِمۡ فِيۡ مَوۡجٍ كَالۡجِبَالِ وَنَادٰي نُوۡحُ اِۨبۡنَهٗ وَكَانَ فِيۡ مَعۡزِلٍ يّٰبُنَيَّ ارۡكَبۡ مَّعَنَا وَلَا تَكُنۡ مَّعَ الۡكٰفِرِيۡنَ قَالَ سَاٰوِيۡ٘ اِلٰي جَبَلٍ يَّعۡصِمُنِيۡ مِنَ الۡمَآءِؕ قَالَ لَا عَاصِمَ الۡيَوۡمَ مِنۡ اَمۡرِ اللّٰهِ اِلَّا مَنۡ رَّحِمَۚ وَحَالَ بَيۡنَهُمَا الۡمَوۡجُ فَكَانَ مِنَ الۡمُغۡرَقِيۡنَ وَقِيۡلَ يٰ٘اَرۡضُ ابۡلَعِيۡ مَآءَكِ وَيٰسَمَآءُ اَقۡلِعِيۡ وَغِيۡضَ الۡمَآءُ وَقُضِيَ الۡاَمۡرُ وَاسۡتَوَتۡ عَلَي الۡجُوۡدِيِّ وَقِيۡلَ بُعۡدًا لِّلۡقَوۡمِ الظّٰلِمِيۡنَ","u":"اور وہ لئے جارہی تھی انکو لہروں میں جیسے پہاڑ اور پکارا نوح نے اپنے بیٹے کو اور وہ ہو رہا تھا کنارے اے بیٹے سوار ہو جا ساتھ ہمارے اور مت رہ ساتھ کافروں کے بولا جا لگوں گا کسی پہاڑ کو جو بچا لے گا مجھ کو پانی سے کہا کوئی بچانے والا نہیں آ ج اللہ کے حکم سے مگر جس پر وہی رحم کرے اور حائل ہو گئ دونوں میں موج پھر ہو گیا ڈوبنے والوں میں اور حکم آیا اے زمین نگل جا اپنا پانی اور اے آسمان تھم جا اور سکھا دیا گیا پانی اور ہو چکا کام اور کشتی ٹھہری جودی پہاڑ پر اور حکم ہوا کہ دور ہو قوم ظالم"},{"n":253,"l":"ظ","t":"ظلم کی مذمت","p":"25","s":"الشوریٰ","sn":42,"r":"4","a":"42","ar":"اِنَّمَا السَّبِيۡلُ عَلَي الَّذِيۡنَ يَظۡلِمُوۡنَ النَّاسَ وَيَبۡغُوۡنَ فِي الۡاَرۡضِ بِغَيۡرِ الۡحَقِّؕ اُولٰٓئِكَ لَهُمۡ عَذَابٌ اَلِيۡمٌ","u":"الزام تو ان پر ہے جو ظلم کرتے ہیں لوگوں پر اور دھوم اٹھاتے ہیں ملک میں ناحق ان لوگوں کے لئے ہے عذاب دردناک"},{"n":254,"l":"ظ","t":"ظالموں کا انجام","p":"13","s":"ابراہیم","sn":14,"r":"7","a":"42","ar":"وَلَا تَحۡسَبَنَّ اللّٰهَ غَافِلًا عَمَّا يَعۡمَلُ الظّٰلِمُوۡنَ ؕ اِنَّمَا يُؤَخِّرُهُمۡ لِيَوۡمٍ تَشۡخَصُ فِيۡهِ الۡاَبۡصَارُۙ","u":"اور ہرگز مت خیال کر کہ اللہ بیخبر ہے ان کاموں سے جو کرتے ہیں بے انصاف ان کو تو ڈھیل دے رکھی ہے (چھوڑ رکھا ہے) اس دن کے لئے کہ پتھرا جائیں گی (کھلی رہ جائیں گی) آنکھیں"},{"n":255,"l":"ظ","t":"ظاہر و باطن کی پاکیزگی","p":"29","s":"الملک","sn":67,"r":"1","a":"13","ar":"وَاَسِرُّوۡا قَوۡلَكُمۡ اَوِ اجۡهَرُوۡا بِهٖؕ اِنَّهٗ عَلِيۡمٌۭ بِذَاتِ الصُّدُوۡرِ","u":"اور تم چھپا کر کہو اپنی بات یا کھول کر وہ خوب جانتا ہے جیوں کے بھید"},{"n":256,"l":"ع","t":"عدل و انصاف","p":"6","s":"المائدہ","sn":5,"r":"2","a":"8","ar":"يٰ٘اَيُّهَا الَّذِيۡنَ اٰمَنُوۡا كُوۡنُوۡا قَوّٰمِيۡنَ لِلّٰهِ شُهَدَآءَ بِالۡقِسۡطِؗ وَلَا يَجۡرِمَنَّكُمۡ شَنَاٰنُ قَوۡمٍ عَلٰ٘ي اَلَّا تَعۡدِلُوۡاؕ اِعۡدِلُوۡا هُوَ اَقۡرَبُ لِلتَّقۡوٰيؗ وَاتَّقُوا اللّٰهَؕ اِنَّ اللّٰهَ خَبِيۡرٌۭ بِمَا تَعۡمَلُوۡنَ","u":"اے ایمان والو کھڑے ہو جایا کرو اللہ کے واسطے گواہی دینے کو انصاف کی اور کسی قوم کی دشمنی کے باعث انصاف کو ہر گز نہ چھوڑو عدل کرو یہ بات زیادہ نزدیک ہے تقویٰ سے اور ڈرتے رہو اللہ سے اللہ کو خوب خبر ہے جو تم کرتے ہو"},{"n":257,"l":"ع","t":"عبادت کی حقیقت و مقصد","p":"27","s":"الذاریات","sn":51,"r":"3","a":"56","ar":"وَمَا خَلَقۡتُ الۡجِنَّ وَالۡاِنۡسَ اِلَّا لِيَعۡبُدُوۡنِ","u":"اور میں نے جو بنائے جن اور آدمی سو اپنی بندگی کو"},{"n":258,"l":"ع","t":"علم کی فضیلت","p":"28","s":"المجادلہ","sn":58,"r":"2","a":"11","ar":"يٰ٘اَيُّهَا الَّذِيۡنَ اٰمَنُوۡ٘ا اِذَا قِيۡلَ لَكُمۡ تَفَسَّحُوۡا فِي الۡمَجٰلِسِ فَافۡسَحُوۡا يَفۡسَحِ اللّٰهُ لَكُمۡۚ وَاِذَا قِيۡلَ انۡشُزُوۡا فَانۡشُزُوۡا يَرۡفَعِ اللّٰهُ الَّذِيۡنَ اٰمَنُوۡا مِنۡكُمۡۙ وَالَّذِيۡنَ اُوۡتُوا الۡعِلۡمَ دَرَجٰتٍؕ وَاللّٰهُ بِمَا تَعۡمَلُوۡنَ خَبِيۡرٌ","u":"اے ایمان والو جب کوئی تم کو کہے کہ کھل کر بیٹھو مجلسوں میں تو کھل جاؤ اللہ کشادگی دے تم کو اور جب کوئی کہے کہ اٹھ کھڑے ہو تو اٹھ کھڑے ہو اللہ بلند کرے گا اُنکے لئے جو کہ ایمان رکھتے ہیں تم میں سے اور علم انکے درجے اور اللہ کو خبر ہے جو کچھ تم کرتے ہو"},{"n":259,"l":"ع","t":"عہد کی پاسداری","p":"6","s":"المائدہ","sn":5,"r":"1","a":"1","ar":"يٰ٘اَيُّهَا الَّذِيۡنَ اٰمَنُوۡ٘ا اَوۡفُوۡا بِالۡعُقُوۡدِ ؕ اُحِلَّتۡ لَكُمۡ بَهِيۡمَةُ الۡاَنۡعَامِ اِلَّا مَا يُتۡلٰي عَلَيۡكُمۡ غَيۡرَ مُحِلِّي الصَّيۡدِ وَاَنۡتُمۡ حُرُمٌؕ اِنَّ اللّٰهَ يَحۡكُمُ مَا يُرِيۡدُ","u":"اے ایمان والو پورا کرو عہدوں کو حلا ل ہوئے تمہارے لئے چوپائے مویشی سو اے انکے جو تم کو آگے سنائےجاویں گے مگر حلال نہ جانو شکار کو احرام کی حالت میں اللہ حکم کرتا ہے جو چاہے"},{"n":260,"l":"ع","t":"عورتوں کے حقوق","p":"4","s":"النساء","sn":4,"r":"1","a":"7","ar":"لِلرِّجَالِ نَصِيۡبٌ مِّمَّا تَرَكَ الۡوَالِدٰنِ وَالۡاَقۡرَبُوۡنَ وَلِلنِّسَآءِ نَصِيۡبٌ مِّمَّا تَرَكَ الۡوَالِدٰنِ وَالۡاَقۡرَبُوۡنَ مِمَّا قَلَّ مِنۡهُ اَوۡ كَثُرَؕ نَصِيۡبًا مَّفۡرُوۡضًا","u":"مردوں کا بھی حصہ ہے اس میں جو چھوڑ مریں ماں باپ او رقرابت والے اور عورتوں کا بھی حصہ ہے اس میں جو چھوڑ مریں ماں باپ اور قرابت والے تھوڑا ہو یا بہت ہو حصہ مقرر کیا ہوا ہے"},{"n":261,"l":"ع","t":"عذابِ آخرت کی تفصیل","p":"13","s":"ابراہیم","sn":14,"r":"7","a":"49-50","ar":"وَتَرَي الۡمُجۡرِمِيۡنَ يَوۡمَئِذٍ مُّقَرَّنِيۡنَ فِي الۡاَصۡفَادِۚ سَرَابِيۡلُهُمۡ مِّنۡ قَطِرَانٍ وَّتَغۡشٰي وُجُوۡهَهُمُ النَّارُۙ","u":"اور دیکھے تو گنہگاروں کو اس دن باہم جکڑے ہوئے زنجیروں میں کرتے ان کے ہیں گندھک کے اور ڈھانکے لیتی ہے انکے منہ کو آگ"},{"n":262,"l":"ع","t":"عیسیٰ علیہ السلام کا تذکرہ و معجزات","p":"3","s":"آلِ عمران","sn":3,"r":"5","a":"49","ar":"وَرَسُوۡلًا اِلٰي بَنِيۡ٘ اِسۡرَآءِيۡلَ ۙ اَنِّيۡ قَدۡ جِئۡتُكُمۡ بِاٰيَةٍ مِّنۡ رَّبِّكُمۡۚۙ اَنِّيۡ٘ اَخۡلُقُ لَكُمۡ مِّنَ الطِّيۡنِ كَهَيۡـَٔةِ الطَّيۡرِ فَاَنۡفُخُ فِيۡهِ فَيَكُوۡنُ طَيۡرًاۭ بِاِذۡنِ اللّٰهِۚ وَاُبۡرِئُ الۡاَكۡمَهَ وَالۡاَبۡرَصَ وَاُحۡيِ الۡمَوۡتٰي بِاِذۡنِ اللّٰهِۚ وَاُنَبِّئُكُمۡ بِمَا تَاۡكُلُوۡنَ وَمَا تَدَّخِرُوۡنَۙ فِيۡ بُيُوۡتِكُمۡؕ اِنَّ فِيۡ ذٰلِكَ لَاٰيَةً لَّكُمۡ اِنۡ كُنۡتُمۡ مُّؤۡمِنِيۡنَۚ","u":"اور کرے گا اس کو پیغمبر بنی اسرائیل کی طرف بیشک میں آیا ہوں تمہارےپاس نشانیاں لے کر تمہارے رب کی طرف سے کہ میں بنا دیتا ہوں تم کو گارے سے پرندہ کی شکل پھر اس میں پھونک مارتا ہوں تو ہو جاتا ہے وہ اڑتا جانور اللہ کے حکم سے اور اچھا کرتا ہوں مادر زاد اندھے کو اور کوڑھی کو اور جلاتا ہوں مردے اللہ کے حکم سے اور بتا دیتا ہوں تم کو جو کھا کر آؤ اور جو رکھ آؤ اپنے گھر میں اس میں نشانی پوری ہے تم کو اگر تم یقین رکھتے ہو"},{"n":263,"l":"ع","t":"عفو و درگزر","p":"18","s":"النور","sn":24,"r":"3","a":"22","ar":"وَلَا يَاۡتَلِ اُولُوا الۡفَضۡلِ مِنۡكُمۡ وَالسَّعَةِ اَنۡ يُّؤۡتُوۡ٘ا اُولِي الۡقُرۡبٰي وَالۡمَسٰكِيۡنَ وَالۡمُهٰجِرِيۡنَ فِيۡ سَبِيۡلِ اللّٰهِۖ وَلۡيَعۡفُوۡا وَلۡيَصۡفَحُوۡاؕ اَلَا تُحِبُّوۡنَ اَنۡ يَّغۡفِرَ اللّٰهُ لَكُمۡؕ وَاللّٰهُ غَفُوۡرٌ رَّحِيۡمٌ","u":"اور قسم نہ کھائیں بڑے درجہ والے تم میں سے اور کشائش والے اس پر کہ دیں قرابتیوں کو اور محتاجوں کو اور وطن چھوڑنے والوں کو اللہ کی راہ میں اور چاہئے کہ معاف کریں اور درگزر کریں کیا تم نہیں چاہتے کہ اللہ تم کو معاف کرے اور اللہ بخشنے والا مہربان ہے"},{"n":264,"l":"ع","t":"عاجزی و انکساری","p":"15","s":"بنی اسرائیل (الاسراء)","sn":17,"r":"4","a":"37","ar":"وَلَا تَمۡشِ فِي الۡاَرۡضِ مَرَحًاۚ اِنَّكَ لَنۡ تَخۡرِقَ الۡاَرۡضَ وَلَنۡ تَبۡلُغَ الۡجِبَالَ طُوۡلًا","u":"اور مت چل زمین پر اتراتا ہوا تو پھاڑ نہ ڈالے گا زمین کو اور نہ ہنچے گا پہاڑوں تک لمبا ہو کر"},{"n":265,"l":"ع","t":"عمرہ کے احکام","p":"2","s":"البقرہ","sn":2,"r":"24","a":"196","ar":"وَاَتِمُّوا الۡحَجَّ وَالۡعُمۡرَةَ لِلّٰهِؕ فَاِنۡ اُحۡصِرۡتُمۡ فَمَا اسۡتَيۡسَرَ مِنَ الۡهَدۡيِۚ وَلَا تَحۡلِقُوۡا رُءُوۡسَكُمۡ حَتّٰي يَبۡلُغَ الۡهَدۡيُ مَحِلَّهٗؕ فَمَنۡ كَانَ مِنۡكُمۡ مَّرِيۡضًا اَوۡ بِهٖ٘ اَذًي مِّنۡ رَّاۡسِهٖ فَفِدۡيَةٌ مِّنۡ صِيَامٍ اَوۡ صَدَقَةٍ اَوۡ نُسُكٍۚ فَاِذَا٘ اَمِنۡتُمۡ فَمَنۡ تَمَتَّعَ بِالۡعُمۡرَةِ اِلَي الۡحَجِّ فَمَا اسۡتَيۡسَرَ مِنَ الۡهَدۡيِۚ فَمَنۡ لَّمۡ يَجِدۡ فَصِيَامُ ثَلٰثَةِ اَيَّامٍ فِي الۡحَجِّ وَسَبۡعَةٍ اِذَا رَجَعۡتُمۡؕ تِلۡكَ عَشَرَةٌ كَامِلَةٌؕ ذٰلِكَ لِمَنۡ لَّمۡ يَكُنۡ اَهۡلُهٗ حَاضِرِي الۡمَسۡجِدِ الۡحَرَامِؕ وَاتَّقُوا اللّٰهَ وَاعۡلَمُوۡ٘ا اَنَّ اللّٰهَ شَدِيۡدُ الۡعِقَابِ","u":"اورپورا کرو حج اور عمرہ اللہ کے واسطے پھر اگر تم روک دیے جاؤ تو تم پر ہے جو کچھ کہ میسر ہو قربانی سے اور حجامت نہ کرو اپنے سروں کی جب تک پہنچ نہ چکے قربانی اپنے ٹھکانے پر پھر جو کوئی تم میں سے بیمار ہو یا اس کو تکلیف ہو سر کی تو بدلا دیوے روزے یا خیرات یا قربانی پھر جب تمہاری خاطر جمع ہو تو جو کوئی فائدہ اٹھائے عمرہ کو ملا کر حج کے ساتھ تو اس پر ہے جو کچھ میسر ہو قربانی سے پھر جس کو قربانی نہ ملے تو روزے رکھے تین حج کےدنوں میں اور سات روزے جب لوٹو یہ دس روزےہو ئے پورے یہ حکم اس کے لئے ہے جسکے گھر والے نہ رہتے ہوں مسجد الحرام کے پاس اور ڈرتے رہو اللہ سے اور جان لو کہ بیشک اللہ کا عذاب سخت ہے"},{"n":266,"l":"ع","t":"عقیقہ و قربانی","p":"30","s":"الکوثر","sn":108,"r":"1","a":"1-2","ar":"اِنَّا٘ اَعۡطَيۡنٰكَ الۡكَوۡثَرَؕ فَصَلِّ لِرَبِّكَ وَانۡحَرۡؕ","u":"بیشک ہم نے دی تجھ کو کوثر سو نماز پڑھ اپنے رب کے آگے اور قربانی کر"},{"n":267,"l":"ع","t":"عذرِ شرعی کا اعتبار","p":"3","s":"البقرہ","sn":2,"r":"40","a":"286","ar":"لَا يُكَلِّفُ اللّٰهُ نَفۡسًا اِلَّا وُسۡعَهَاؕ لَهَا مَا كَسَبَتۡ وَعَلَيۡهَا مَا اكۡتَسَبَتۡؕ رَبَّنَا لَا تُؤَاخِذۡنَا٘ اِنۡ نَّسِيۡنَا٘ اَوۡ اَخۡطَاۡنَاۚ رَبَّنَا وَلَا تَحۡمِلۡ عَلَيۡنَا٘ اِصۡرًا كَمَا حَمَلۡتَهٗ عَلَي الَّذِيۡنَ مِنۡ قَبۡلِنَاۚ رَبَّنَا وَلَا تُحَمِّلۡنَا مَا لَا طَاقَةَ لَنَا بِهٖۚ وَاعۡفُ عَنَّا وَاغۡفِرۡ لَنَا وَارۡحَمۡنَا اَنۡتَ مَوۡلٰىنَا فَانۡصُرۡنَا عَلَي الۡقَوۡمِ الۡكٰفِرِيۡنَ","u":"اللہ تکلیف نہیں دیتا کسی کو مگر جس قدر اس کی گنجائش ہے اس کو ملتا ہے جو اس نے کمایا اور اسی پر پڑتا ہے جو اس نے کیا اے رب ہمارے نہ پکڑ ہم کو اگر ہم بھولیں یا چوکیں اے رب ہمارے اور نہ رکھ ہم پر بوجھ بھاری جیسا رکھا تھا ہم سے اگلے لوگوں پر اے رب ہمارے اور نہ اٹھوا ہم سے وہ بوجھ کہ جس کی ہم کو طاقت نہیں اور درگذر کر ہم سے اور بخش ہم کو اور رحم کر ہم پر تو ہی ہمارا رب ہے مدد کر ہماری کافروں پر"},{"n":268,"l":"ع","t":"علم و عقل کا استعمال","p":"23","s":"الزمر","sn":39,"r":"1","a":"9","ar":"اَمَّنۡ هُوَ قَانِتٌ اٰنَآءَ الَّيۡلِ سَاجِدًا وَّقَآئِمًا يَّحۡذَرُ الۡاٰخِرَةَ وَيَرۡجُوۡا رَحۡمَةَ رَبِّهٖؕ قُلۡ هَلۡ يَسۡتَوِي الَّذِيۡنَ يَعۡلَمُوۡنَ وَالَّذِيۡنَ لَا يَعۡلَمُوۡنَؕ اِنَّمَا يَتَذَكَّرُ اُولُوا الۡاَلۡبَابِ","u":"بھلا ایک جو بندگی میں لگا ہوا ہے رات کی گھڑیوں میں سجدے کرتا ہوا اور کھڑا ہو اخطرہ رکھتا ہے آخرت کا اور امید رکھتا ہے اپنے رب کی مہربانی کی تو کہہ کوئی برابر ہوتے ہیں سمجھ والے اور بے سمجھ سوچتے وہی ہیں جن کو عقل ہے"},{"n":269,"l":"ع","t":"عبادالرحمٰن کی صفات","p":"19","s":"الفرقان","sn":25,"r":"6","a":"72-74","ar":"وَالَّذِيۡنَ لَا يَشۡهَدُوۡنَ الزُّوۡرَۙ وَاِذَا مَرُّوۡا بِاللَّغۡوِ مَرُّوۡا كِرَامًا وَالَّذِيۡنَ اِذَا ذُكِّرُوۡا بِاٰيٰتِ رَبِّهِمۡ لَمۡ يَخِرُّوۡا عَلَيۡهَا صُمًّا وَّعُمۡيَانًا وَالَّذِيۡنَ يَقُوۡلُوۡنَ رَبَّنَا هَبۡ لَنَا مِنۡ اَزۡوَاجِنَا وَذُرِّيّٰتِنَا قُرَّةَ اَعۡيُنٍ وَّاجۡعَلۡنَا لِلۡمُتَّقِيۡنَ اِمَامًا","u":"اور جو لوگ شامل نہیں ہوتے جھوٹے کام میں اور جب گزرتے ہیں کھیل کی باتوں پر نکل جائیں بزرگانہ اور وہ لوگ کہ جب انکو سمجھائیں انکے رب کی باتیں نہ پڑیں ان پر بہرے اندھے ہو کر اور وہ لوگ جو کہتے ہیں اے رب دے ہم کو ہماری عورتوں کی طرف سے اور اولاد کی طرف سے آنکھ کی ٹھنڈک اور کر ہم کو پرہیزگاروں کا پیشوا"},{"n":270,"l":"ع","t":"علمِ نافع کی دعا","p":"16","s":"طٰہ","sn":20,"r":"6","a":"114","ar":"فَتَعٰلَي اللّٰهُ الۡمَلِكُ الۡحَقُّۚ وَلَا تَعۡجَلۡ بِالۡقُرۡاٰنِ مِنۡ قَبۡلِ اَنۡ يُّقۡضٰ٘ي اِلَيۡكَ وَحۡيُهٗؗ وَقُلۡ رَّبِّ زِدۡنِيۡ عِلۡمًا","u":"سو بلند درجہ اللہ کا اُس سچے بادشاہ کا اور تو جلدی نہ کر قرآن کے لینے میں جب تک کہ پورا نہ ہو چکے اُس کا اترنا اور کہہ اے رب زیادہ کر میری سمجھ"},{"n":271,"l":"ع","t":"عہدِ الست کا تذکرہ","p":"9","s":"الاعراف","sn":7,"r":"22","a":"172","ar":"وَاِذۡ اَخَذَ رَبُّكَ مِنۭۡ بَنِيۡ٘ اٰدَمَ مِنۡ ظُهُوۡرِهِمۡ ذُرِّيَّتَهُمۡ وَاَشۡهَدَهُمۡ عَلٰ٘ي اَنۡفُسِهِمۡۚ اَلَسۡتُ بِرَبِّكُمۡؕ قَالُوۡا بَلٰيۚۛ شَهِدۡنَاۚۛ اَنۡ تَقُوۡلُوۡا يَوۡمَ الۡقِيٰمَةِ اِنَّا كُنَّا عَنۡ هٰذَا غٰفِلِيۡنَۙ","u":"اور جب نکالا تیرے رب نے بنی آدم کی پیٹھوں سے ان کی اولاد کو اور اقرار کرایا ان سے ان کی جانوں پر کیا میں نہیں ہوں تمہارا رب بولے ہاں ہے ہم اقرار کرتے ہیں کبھی کہنے لگو قیامت کے دن ہم کو تو اس کی خبر نہ تھی"},{"n":272,"l":"ع","t":"عزتِ نفسِ مومن","p":"28","s":"المنافقون","sn":63,"r":"1","a":"8","ar":"يَقُوۡلُوۡنَ لَئِنۡ رَّجَعۡنَا٘ اِلَي الۡمَدِيۡنَةِ لَيُخۡرِجَنَّ الۡاَعَزُّ مِنۡهَا الۡاَذَلَّؕ وَلِلّٰهِ الۡعِزَّةُ وَلِرَسُوۡلِهٖ وَلِلۡمُؤۡمِنِيۡنَ وَلٰكِنَّ الۡمُنٰفِقِيۡنَ لَا يَعۡلَمُوۡنَ","u":"کہتے ہیں البتہ اگر ہم پھر گئے مدینہ کو تو نکال دے گا جس کا زور ہے وہاں سے کمزور لوگوں کو اور زور تو اللہ کا ہے اور اُسکے رسول کا اور ایمان والوں کا لیکن منافق نہیں جانتے"},{"n":273,"l":"ع","t":"عذابِ الٰہی سے پہلے انذار کا اصول","p":"15","s":"بنی اسرائیل (الاسراء)","sn":17,"r":"2","a":"15","ar":"مَنِ اهۡتَدٰي فَاِنَّمَا يَهۡتَدِيۡ لِنَفۡسِهٖۚ وَمَنۡ ضَلَّ فَاِنَّمَا يَضِلُّ عَلَيۡهَاؕ وَلَا تَزِرُ وَازِرَةٌ وِّزۡرَ اُخۡرٰيؕ وَمَا كُنَّا مُعَذِّبِيۡنَ حَتّٰي نَبۡعَثَ رَسُوۡلًا","u":"جو کوئی راہ پر آیا تو آیا اپنے ہی بھلے کو اور جو کوئی بہکا رہا تو بہکا رہا اپنے ہی برے کو اور کسی پر نہیں پڑتا بوجھ دوسرے کا اور ہم نہیں ڈالتے بلا جب تک نہ بھیجیں کوئی رسول"},{"n":274,"l":"ع","t":"علاماتِ قیامتِ صغریٰ و کبریٰ","p":"26","s":"محمد","sn":47,"r":"2","a":"18","ar":"فَهَلۡ يَنۡظُرُوۡنَ اِلَّا السَّاعَةَ اَنۡ تَاۡتِيَهُمۡ بَغۡتَةًۚ فَقَدۡ جَآءَ اَشۡرَاطُهَاۚ فَاَنّٰي لَهُمۡ اِذَا جَآءَتۡهُمۡ ذِكۡرٰىهُمۡ","u":"اب یہی انتظار کرتے ہیں قیامت کا کہ آ کھڑی ہو ان پر اچانک سو آچکی ہیں اسکی نشانیاں پھر کہاں نصیب ہو گا انکو جب وہ آ پہنچے ان پر سمجھ پکڑنا"},{"n":275,"l":"غ","t":"غیبت کی مذمت","p":"26","s":"الحجرات","sn":49,"r":"2","a":"12","ar":"يٰ٘اَيُّهَا الَّذِيۡنَ اٰمَنُوا اجۡتَنِبُوۡا كَثِيۡرًا مِّنَ الظَّنِّؗ اِنَّ بَعۡضَ الظَّنِّ اِثۡمٌ وَّلَا تَجَسَّسُوۡا وَلَا يَغۡتَبۡ بَّعۡضُكُمۡ بَعۡضًاؕ اَيُحِبُّ اَحَدُكُمۡ اَنۡ يَّاۡكُلَ لَحۡمَ اَخِيۡهِ مَيۡتًا فَكَرِهۡتُمُوۡهُؕ وَاتَّقُوا اللّٰهَؕ اِنَّ اللّٰهَ تَوَّابٌ رَّحِيۡمٌ","u":"اے ایمان والو بچتے رہو بہت تہمتیں کرنے سے مقرر بعضی تہمت گناہ ہے اور بھید نہ ٹٹولو کسی کا اور برا نہ کہیو پیٹھ پیچھے ایک دوسرے کو بھلا خوش لگتا ہے تم میں کسی کو کہ کھائے گوشت اپنے بھائی کا جو مردہ ہو سو گھن آتا ہے تم کو اس سے اور ڈرتے رہو اللہ سے بیشک اللہ معاف کرنے والا ہے مہربان"},{"n":276,"l":"غ","t":"غصے پر قابو پانا","p":"4","s":"آلِ عمران","sn":3,"r":"14","a":"134","ar":"الَّذِيۡنَ يُنۡفِقُوۡنَ فِي السَّرَّآءِ وَالضَّرَّآءِ وَالۡكٰظِمِيۡنَ الۡغَيۡظَ وَالۡعَافِيۡنَ عَنِ النَّاسِؕ وَاللّٰهُ يُحِبُّ الۡمُحۡسِنِيۡنَۚ","u":"جو خرچ کئے جاتے ہیں خوشی میں اور تکلیف میں اور دبا لیتےہیں غصہ اور معاف کرتے ہیں لوگوں کو اور اللہ چاہتا ہے نیکی کرنے والوں کو"},{"n":277,"l":"غ","t":"غلامی سے آزادی کی ترغیب","p":"30","s":"البلد","sn":90,"r":"1","a":"11-13","ar":"فَلَا اقۡتَحَمَ الۡعَقَبَةَؗۖ وَمَا٘ اَدۡرٰىكَ مَا الۡعَقَبَةُؕ فَكُّ رَقَبَةٍۙ","u":"سو نہ دھمک سکا گھاٹی پر اور توکیا سمجھا کیا ہے وہ گھاٹی چھڑانا گردن کا"},{"n":278,"l":"غ","t":"غزواتِ نبوی صلی اللہ علیہ وسلم کا تذکرہ","p":"4","s":"آلِ عمران","sn":3,"r":"13","a":"121","ar":"وَاِذۡ غَدَوۡتَ مِنۡ اَهۡلِكَ تُبَوِّئُ الۡمُؤۡمِنِيۡنَ مَقَاعِدَ لِلۡقِتَالِؕ وَاللّٰهُ سَمِيۡعٌ عَلِيۡمٌۙ","u":"اور جب صبح کو نکلا تو اپنے گھر سے بٹھلانے لگا مسلمانوں کو لڑائی کے ٹھکانوں پر اور اللہ سب کچھ سنتا جانتا ہے"},{"n":279,"l":"غ","t":"غفلت سے بچنے کی تلقین","p":"17","s":"الانبیاء","sn":21,"r":"1","a":"1","ar":"اِقۡتَرَبَ لِلنَّاسِ حِسَابُهُمۡ وَهُمۡ فِيۡ غَفۡلَةٍ مُّعۡرِضُوۡنَۚ","u":"نزدیک آ گیا لوگوں کے اُنکے حساب کا وقت اور وہ بیخبر ٹلا رہے ہیں"},{"n":280,"l":"غ","t":"غرورِ نفس کی مذمت","p":"20","s":"القصص","sn":28,"r":"8","a":"76","ar":"اِنَّ قَارُوۡنَ كَانَ مِنۡ قَوۡمِ مُوۡسٰي فَبَغٰي عَلَيۡهِمۡ وَاٰتَيۡنٰهُ مِنَ الۡكُنُوۡزِ مَا٘ اِنَّ مَفَاتِحَهٗ لَتَنُوۡٓاُ بِالۡعُصۡبَةِ اُولِي الۡقُوَّةِ اِذۡ قَالَ لَهٗ قَوۡمُهٗ لَا تَفۡرَحۡ اِنَّ اللّٰهَ لَا يُحِبُّ الۡفَرِحِيۡنَ","u":"قارون جو تھا سو موسٰی کی قوم سے پھر شرارت کرنے لگا ان پر اور ہم نے دیے تھے اسکو خزانے اتنے کہ اسکی کنجیاں اٹھانے سے تھک جاتے کئ مرد زور آور جب کہا اس کو اسکی قوم نے اترا مت اللہ کو نہیں بھاتے اترانے والے"},{"n":281,"l":"غ","t":"غریبوں کا حق بیت المال میں","p":"28","s":"الحشر","sn":59,"r":"1","a":"7","ar":"مَا٘ اَفَآءَ اللّٰهُ عَلٰي رَسُوۡلِهٖ مِنۡ اَهۡلِ الۡقُرٰي فَلِلّٰهِ وَلِلرَّسُوۡلِ وَلِذِي الۡقُرۡبٰي وَالۡيَتٰمٰي وَالۡمَسٰكِيۡنِ وَابۡنِ السَّبِيۡلِۙ كَيۡ لَا يَكُوۡنَ دُوۡلَةًۭ بَيۡنَ الۡاَغۡنِيَآءِ مِنۡكُمۡؕ وَمَا٘ اٰتٰىكُمُ الرَّسُوۡلُ فَخُذُوۡهُۚ وَمَا نَهٰىكُمۡ عَنۡهُ فَانۡتَهُوۡاۚ وَاتَّقُوا اللّٰهَؕ اِنَّ اللّٰهَ شَدِيۡدُ الۡعِقَابِۘ","u":"جو مال لوٹایا اللہ نے اپنے رسول پر بستیوں والوں سے سو اللہ کے واسطے اور رسول کے اور قرابت والے کے اور یتیموں کے اور محتاجوں کے اور مسافر کے تاکہ نہ آئے لینے دینے میں دولتمندوں کے تم میں سے اور جو دے تم کو رسول سو لے لو اور جس سے منع کرے سو چھوڑ دو اور ڈرتے رہو اللہ سے بیشک اللہ کا عذاب سخت ہے"},{"n":282,"l":"غ","t":"غزوۂ احزاب کا تذکرہ","p":"21","s":"الاحزاب","sn":33,"r":"2","a":"9-11","ar":"يٰ٘اَيُّهَا الَّذِيۡنَ اٰمَنُوا اذۡكُرُوۡا نِعۡمَةَ اللّٰهِ عَلَيۡكُمۡ اِذۡ جَآءَتۡكُمۡ جُنُوۡدٌ فَاَرۡسَلۡنَا عَلَيۡهِمۡ رِيۡحًا وَّجُنُوۡدًا لَّمۡ تَرَوۡهَاؕ وَكَانَ اللّٰهُ بِمَا تَعۡمَلُوۡنَ بَصِيۡرًاۚ اِذۡ جَآءُوۡكُمۡ مِّنۡ فَوۡقِكُمۡ وَمِنۡ اَسۡفَلَ مِنۡكُمۡ وَاِذۡ زَاغَتِ الۡاَبۡصَارُ وَبَلَغَتِ الۡقُلُوۡبُ الۡحَنَاجِرَ وَتَظُنُّوۡنَ بِاللّٰهِ الظُّنُوۡنَاؕ هُنَالِكَ ابۡتُلِيَ الۡمُؤۡمِنُوۡنَ وَزُلۡزِلُوۡا زِلۡزَالًا شَدِيۡدًا","u":"اے ایمان والو یاد کرو احسان اللہ کا اپنے اوپر جب چڑھ آئیں تم پر فوجیں پھر ہم نے بھیجدی ان پر ہوا اور وہ فوجیں جو تم نے نہیں دیکھیں اور ہے اللہ جو کچھ کرتے ہو دیکھنے والا جب چڑھ آئے تم پر اوپر کی طرف سے اور نیچے سے اور جب بدلنے لگیں آنکھیں اور پہنچے دل گلوں تک اور اٹکلنے لگے تم اللہ پر طرح طرح کی اٹکلیں وہاں جانچے گئے ایمان والے اور جھڑ جھڑائے گئے زور کا جھڑ جھڑانا"},{"n":283,"l":"غ","t":"غارِ حرا کا تذکرہ","p":"30","s":"العلق","sn":96,"r":"1","a":"1-5","ar":"اِقۡرَاۡ بِاسۡمِ رَبِّكَ الَّذِيۡ خَلَقَۚ خَلَقَ الۡاِنۡسَانَ مِنۡ عَلَقٍۚ اِقۡرَاۡ وَرَبُّكَ الۡاَكۡرَمُۙ الَّذِيۡ عَلَّمَ بِالۡقَلَمِۙ عَلَّمَ الۡاِنۡسَانَ مَا لَمۡ يَعۡلَمۡؕ","u":"پڑھ اپنے رب کے نام سے جو سب کا بنانے والا ہے بنایا آدمی کو جمے ہوئے لہو سے پڑھ اور تیرا رب بڑا کریم ہے جس نے علم سکھایا قلم سے سکھلایا آدمی کو جو وہ نہ جانتا تھا"},{"n":284,"l":"غ","t":"غریب پروری","p":"30","s":"الماعون","sn":107,"r":"1","a":"1-3","ar":"اَرَءَيۡتَ الَّذِيۡ يُكَذِّبُ بِالدِّيۡنِؕ فَذٰلِكَ الَّذِيۡ يَدُعُّ الۡيَتِيۡمَۙ وَلَا يَحُضُّ عَلٰي طَعَامِ الۡمِسۡكِيۡنِؕ","u":"تو نے دیکھا اُسکو جو جھٹلاتا ہے انصاف ہونے کو سو یہ وہی ہے جو دھکے دیتا ہے یتیم کو اور نہیں تاکید کرتا محتاج کے کھانے پر"},{"n":285,"l":"غ","t":"غیب پر ایمان","p":"1","s":"البقرہ","sn":2,"r":"1","a":"3","ar":"الَّذِيۡنَ يُؤۡمِنُوۡنَ بِالۡغَيۡبِ وَيُقِيۡمُوۡنَ الصَّلٰوةَ وَمِمَّا رَزَقۡنٰهُمۡ يُنۡفِقُوۡنَۙ","u":"جو کہ یقین کرتے ہیں بن دیکھی چیزوں کا اور قائم رکھتے ہیں نماز کو اور جو ہم نے روزی دی ہے ان کو اسمیں سے خرچ کرتے ہیں"},{"n":286,"l":"غ","t":"غمگین دلوں کے لیے تسلی","p":"10","s":"التوبہ","sn":9,"r":"6","a":"40","ar":"اِلَّا تَنۡصُرُوۡهُ فَقَدۡ نَصَرَهُ اللّٰهُ اِذۡ اَخۡرَجَهُ الَّذِيۡنَ كَفَرُوۡا ثَانِيَ اثۡنَيۡنِ اِذۡ هُمَا فِي الۡغَارِ اِذۡ يَقُوۡلُ لِصَاحِبِهٖ لَا تَحۡزَنۡ اِنَّ اللّٰهَ مَعَنَاۚ فَاَنۡزَلَ اللّٰهُ سَكِيۡنَتَهٗ عَلَيۡهِ وَاَيَّدَهٗ بِجُنُوۡدٍ لَّمۡ تَرَوۡهَا وَجَعَلَ كَلِمَةَ الَّذِيۡنَ كَفَرُوا السُّفۡلٰيؕ وَكَلِمَةُ اللّٰهِ هِيَ الۡعُلۡيَاؕ وَاللّٰهُ عَزِيۡزٌ حَكِيۡمٌ","u":"اگر تم نہ مدد کرو گے رسول کی تو اس کی مدد کی ہے اللہ نے جس وقت اس کو نکالا تھا کافروں نے کہ وہ دوسرا تھا دو میں کا جب وہ دونوں تھے غار میں جب وہ کہہ رہا تھا اپنے رفیق سے تو غم نہ کھا بیشک اللہ ہمارے ساتھ ہے پھر اللہ نے اتاری اپنی طرف سے اس پر تسکین اور اسکی مدد کو وہ فوجیں بھیجیں کہ تم نے نہیں دیکھیں اور نیچے ڈالی کافروں کی اور اللہ کی بات ہمیشہ اوپر ہے اور اللہ زبردست ہے حکمت والا"},{"n":287,"l":"غ","t":"غضبِ الٰہی سے بچنے کی تدبیر","p":"3","s":"آلِ عمران","sn":3,"r":"2","a":"16","ar":"اَلَّذِيۡنَ يَقُوۡلُوۡنَ رَبَّنَا٘ اِنَّنَا٘ اٰمَنَّا فَاغۡفِرۡ لَنَا ذُنُوۡبَنَا وَقِنَا عَذَابَ النَّارِۚ","u":"وہ جو کہتے ہیں اے رب ہمارے ہم ایمان لائے ہیں سو بخش دے ہم کو گناہ ہمارے اور بچا ہم کو دوزخ کے عذب سے"},{"n":288,"l":"ف","t":"فرشتوں پر ایمان","p":"22","s":"فاطر","sn":35,"r":"1","a":"1","ar":"اَلۡحَمۡدُ لِلّٰهِ فَاطِرِ السَّمٰوٰتِ وَالۡاَرۡضِ جَاعِلِ الۡمَلٰٓئِكَةِ رُسُلًا اُولِيۡ٘ اَجۡنِحَةٍ مَّثۡنٰي وَثُلٰثَ وَرُبٰعَؕ يَزِيۡدُ فِي الۡخَلۡقِ مَا يَشَآءُؕ اِنَّ اللّٰهَ عَلٰي كُلِّ شَيۡءٍ قَدِيۡرٌ","u":"سب خوبی اللہ کو ہے جس نے بنا نکالے آسمان اور زمین جس نے ٹھہرایا فرشتوں کو پیغام لانے والے جن کے پر ہیں دو دو اور تین تین اور چار چار بڑھا دیتا ہے پیدائش میں جو چاہے بیشک اللہ ہر چیز کر سکتا ہے"},{"n":289,"l":"ف","t":"فرعون کا تکبر اور انجام","p":"20","s":"القصص","sn":28,"r":"4","a":"39-40","ar":"وَاسۡتَكۡبَرَ هُوَ وَجُنُوۡدُهٗ فِي الۡاَرۡضِ بِغَيۡرِ الۡحَقِّ وَظَنُّوۡ٘ا اَنَّهُمۡ اِلَيۡنَا لَا يُرۡجَعُوۡنَ فَاَخَذۡنٰهُ وَجُنُوۡدَهٗ فَنَبَذۡنٰهُمۡ فِي الۡيَمِّۚ فَانۡظُرۡ كَيۡفَ كَانَ عَاقِبَةُ الظّٰلِمِيۡنَ","u":"اور بڑائی کرنے لگے وہ اور اس کے لشکر ملک میں ناحق اور سمجھے کہ وہ ہماری طرف پھر کر نہ آئیں گے پھر پکڑ اہم نے اسکو اور اسکے لشکروں کو پھر پھینک دیا ہم نے انکو دریا میں سو دیکھ لے کیسا ہوا انجام گنہگاروں کا"},{"n":290,"l":"ف","t":"فحاشی کی ممانعت","p":"8","s":"الاعراف","sn":7,"r":"4","a":"33","ar":"قُلۡ اِنَّمَا حَرَّمَ رَبِّيَ الۡفَوَاحِشَ مَا ظَهَرَ مِنۡهَا وَمَا بَطَنَ وَالۡاِثۡمَ وَالۡبَغۡيَ بِغَيۡرِ الۡحَقِّ وَاَنۡ تُشۡرِكُوۡا بِاللّٰهِ مَا لَمۡ يُنَزِّلۡ بِهٖ سُلۡطٰنًا وَّاَنۡ تَقُوۡلُوۡا عَلَي اللّٰهِ مَا لَا تَعۡلَمُوۡنَ","u":"تو کہہ دے میرے رب نے حرام کیا ہے صرف بیحیائی کی باتوں کو جو ان میں کھلی ہوئی ہیں اور جو چھپی ہوئی ہیں اور گناہ کو اور ناحق زیادتی کو اور اس بات کو کہ شریک کرو اللہ کا ایسی چیز کو کہ جس کی اس نے سند نہیں اتاری اور اس بات کو کہ لگاؤ اللہ کے ذمہ وہ باتیں جو تم کو معلوم نہیں"},{"n":291,"l":"ف","t":"فضول خرچی کی ممانعت","p":"19","s":"الفرقان","sn":25,"r":"6","a":"67","ar":"وَالَّذِيۡنَ اِذَا٘ اَنۡفَقُوۡا لَمۡ يُسۡرِفُوۡا وَلَمۡ يَقۡتُرُوۡا وَكَانَ بَيۡنَ ذٰلِكَ قَوَامًا","u":"اور وہ لوگ کہ جب خرچ کرنے لگیں نہ بیجا اڑائیں اور نہ تنگی کریں اور ہے اس کے بیچ ایک سیدھی گذران"},{"n":292,"l":"ف","t":"فلاح کا راستہ","p":"30","s":"الاعلیٰ","sn":87,"r":"1","a":"14-15","ar":"قَدۡ اَفۡلَحَ مَنۡ تَزَكّٰيۙ وَذَكَرَ اسۡمَ رَبِّهٖ فَصَلّٰيؕ","u":"بیشک بھلا ہوا اُس کا جو سنورا اورلیا اُس نے نام اپنے رب کا پھر نماز پڑھی"},{"n":293,"l":"ف","t":"فدیہ کا تصور","p":"2","s":"البقرہ","sn":2,"r":"23","a":"184","ar":"اَيَّامًا مَّعۡدُوۡدٰتٍؕ فَمَنۡ كَانَ مِنۡكُمۡ مَّرِيۡضًا اَوۡ عَلٰي سَفَرٍ فَعِدَّةٌ مِّنۡ اَيَّامٍ اُخَرَؕ وَعَلَي الَّذِيۡنَ يُطِيۡقُوۡنَهٗ فِدۡيَةٌ طَعَامُ مِسۡكِيۡنٍؕ فَمَنۡ تَطَوَّعَ خَيۡرًا فَهُوَ خَيۡرٌ لَّهٗؕ وَاَنۡ تَصُوۡمُوۡا خَيۡرٌ لَّكُمۡ اِنۡ كُنۡتُمۡ تَعۡلَمُوۡنَ","u":"چند روز ہیں گنتی کے پھر جو کوئی تم میں سے بیمار ہو یا مسافر تو اس پر ان کی گنتی ہے اور دنوں سے اور جن کو طاقت ہے روزہ کی انکے ذمہ بدلا ہے ایک فقیر کا کھانا پھر جو کوئی خوشی سے کرے نیکی تو اچھا ہےاسکے واسطے اور روزہ رکھو تو بہتر ہے تمہارے لئے اگر تم سمجھ رکھتے ہو"},{"n":294,"l":"ف","t":"فرائضِ اسلام","p":"30","s":"البینہ","sn":98,"r":"1","a":"5","ar":"وَمَا٘ اُمِرُوۡ٘ا اِلَّا لِيَعۡبُدُوا اللّٰهَ مُخۡلِصِيۡنَ لَهُ الدِّيۡنَ ۙ حُنَفَآءَ وَيُقِيۡمُوا الصَّلٰوةَ وَيُؤۡتُوا الزَّكٰوةَ وَذٰلِكَ دِيۡنُ الۡقَيِّمَةِؕ","u":"اور انکو حکم یہی ہوا کہ بندگی کریں اللہ کی خالص کر کے اُسکے واسطے بندگی ابراہیم کی راہ پر اور قائم رکھیں نماز اور دیں زکوٰۃ اور یہ ہے راہ مضبوط لوگوں کی"},{"n":295,"l":"ف","t":"فیصلہ صرف اللہ کی شریعت سے","p":"6","s":"المائدہ","sn":5,"r":"7","a":"44","ar":"اِنَّا٘ اَنۡزَلۡنَا التَّوۡرٰىةَ فِيۡهَا هُدًي وَّنُوۡرٌۚ يَحۡكُمُ بِهَا النَّبِيُّوۡنَ الَّذِيۡنَ اَسۡلَمُوۡا لِلَّذِيۡنَ هَادُوۡا وَالرَّبّٰنِيُّوۡنَ وَالۡاَحۡبَارُ بِمَا اسۡتُحۡفِظُوۡا مِنۡ كِتٰبِ اللّٰهِ وَكَانُوۡا عَلَيۡهِ شُهَدَآءَۚ فَلَا تَخۡشَوُا النَّاسَ وَاخۡشَوۡنِ وَلَا تَشۡتَرُوۡا بِاٰيٰتِيۡ ثَمَنًا قَلِيۡلًاؕ وَمَنۡ لَّمۡ يَحۡكُمۡ بِمَا٘ اَنۡزَلَ اللّٰهُ فَاُولٰٓئِكَ هُمُ الۡكٰفِرُوۡنَ","u":"ہم نےنازل کی توریت کہ اس میں ہدایت اور روشنی ہے اس پر حکم کرتے تھے پیغمبر جو کہ حکم بردار تھے اللہ کے یہود کو اور حکم کرتے تھے درویش اور عالم اس واسطے کہ وہ نگہبان ٹھہرائے گئے تھے اللہ کی کتاب پر اور اس کی خبر گیری پر مقرر تھے سو تم نہ ڈرو لوگوں سے اور مجھ سے ڈرو اور مت خریدو میری آیتوں پر مول تھوڑا اور جو کوئی حکم نہ کرے اس کے موافق جو کہ اللہ نے اتارا سو وہی لوگ ہیں کافر"},{"n":296,"l":"ف","t":"فاحشہ کاموں سے اجتناب","p":"8","s":"الانعام","sn":6,"r":"19","a":"151","ar":"قُلۡ تَعَالَوۡا اَتۡلُ مَا حَرَّمَ رَبُّكُمۡ عَلَيۡكُمۡ اَلَّا تُشۡرِكُوۡا بِهٖ شَيۡـًٔا وَّبِالۡوَالِدَيۡنِ اِحۡسَانًاۚ وَلَا تَقۡتُلُوۡ٘ا اَوۡلَادَكُمۡ مِّنۡ اِمۡلَاقٍؕ نَحۡنُ نَرۡزُقُكُمۡ وَاِيَّاهُمۡۚ وَلَا تَقۡرَبُوا الۡفَوَاحِشَ مَا ظَهَرَ مِنۡهَا وَمَا بَطَنَۚ وَلَا تَقۡتُلُوا النَّفۡسَ الَّتِيۡ حَرَّمَ اللّٰهُ اِلَّا بِالۡحَقِّؕ ذٰلِكُمۡ وَصّٰىكُمۡ بِهٖ لَعَلَّكُمۡ تَعۡقِلُوۡنَ","u":"تو کہہ تم آؤ میں سنا دوں جو حرام کیا ہے تم پر تمہارے رب نے کہ شریک نہ کرو اسکے ساتھ کسی چیز کو اور ماں باپ کے ساتھ نیکی کرو اور مار نہ ڈالو اپنی اولاد کو مفلسی سے ہم رزق دیتے ہیں تم کو اور ان کو اور پاس نہ جاؤ بیحیائی کے کام کے جو ظاہر ہو اس میں سے اور جو پوشیدہ ہو اور مار نہ ڈالو اس جان کو جس کو حرام کیا ہے اللہ نے مگر حق پر تم کو یہ حکم کیا ہے تاکہ تم سمجھو"},{"n":297,"l":"ف","t":"فطرت پر پیدائش کا تصور","p":"21","s":"الروم","sn":30,"r":"4","a":"30","ar":"فَاَقِمۡ وَجۡهَكَ لِلدِّيۡنِ حَنِيۡفًاؕ فِطۡرَتَ اللّٰهِ الَّتِيۡ فَطَرَ النَّاسَ عَلَيۡهَاؕ لَا تَبۡدِيۡلَ لِخَلۡقِ اللّٰهِؕ ذٰلِكَ الدِّيۡنُ الۡقَيِّمُۙ وَلٰكِنَّ اَكۡثَرَ النَّاسِ لَا يَعۡلَمُوۡنَۙ","u":"سو تو سیدھا رکھ اپنا منہ دین پر ایک طرف کا ہو کر وہی تراش اللہ کی جس پر تراشا لوگوں کو بدلنا نہیں اللہ کے بنائے کو یہی ہے دین سیدھا و لیکن اکثر لوگ نہیں سمجھتے"},{"n":298,"l":"ف","t":"فتح مکہ کا تذکرہ","p":"30","s":"النصر","sn":110,"r":"1","a":"1-3","ar":"اِذَا جَآءَ نَصۡرُ اللّٰهِ وَالۡفَتۡحُۙ وَرَاَيۡتَ النَّاسَ يَدۡخُلُوۡنَ فِيۡ دِيۡنِ اللّٰهِ اَفۡوَاجًاۙ فَسَبِّحۡ بِحَمۡدِ رَبِّكَ وَاسۡتَغۡفِرۡهُؕؔ اِنَّهٗ كَانَ تَوَّابًا","u":"جب پہنچ چکے مدد اللہ کی اور فیصلہ اور تو دیکھے لوگوں کو داخل ہوتے دین میں غول کے غول تو پاکی بول اپنے رب کی خوبیاں اور گناہ بخشوا اس سے بیشک وہ معاف کرنے والا ہے"},{"n":299,"l":"ف","t":"فہم و تدبر کی دعوت","p":"26","s":"محمد","sn":47,"r":"3","a":"24","ar":"اَفَلَا يَتَدَبَّرُوۡنَ الۡقُرۡاٰنَ اَمۡ عَلٰي قُلُوۡبٍ اَقۡفَالُهَا","u":"کیا دھیان نہیں کرتے قرآن میں یا دلوں پر لگ رہے ہیں انکے قفل"},{"n":300,"l":"ف","t":"فہمِ دین میں تدریج","p":"19","s":"الفرقان","sn":25,"r":"3","a":"32","ar":"وَقَالَ الَّذِيۡنَ كَفَرُوۡا لَوۡلَا نُزِّلَ عَلَيۡهِ الۡقُرۡاٰنُ جُمۡلَةً وَّاحِدَةًۚۛ كَذٰلِكَۚۛ لِنُثَبِّتَ بِهٖ فُؤَادَكَ وَرَتَّلۡنٰهُ تَرۡتِيۡلًا","u":"اور کہنے لگے وہ لوگ جو منکر ہیں کیوں نہ اترا اس پر قرآن سارا ایک جگہ ہو کر اسی طرح اتارا تاکہ ثابت رکھیں ہم اس سےتیرا دل اور پڑھ سنایا ہم نے اسکو ٹھہر ٹھہر کر"},{"n":301,"l":"ف","t":"فاسق کی صحبت سے اجتناب","p":"7","s":"الانعام","sn":6,"r":"8","a":"68","ar":"وَاِذَا رَاَيۡتَ الَّذِيۡنَ يَخُوۡضُوۡنَ فِيۡ٘ اٰيٰتِنَا فَاَعۡرِضۡ عَنۡهُمۡ حَتّٰي يَخُوۡضُوۡا فِيۡ حَدِيۡثٍ غَيۡرِهٖؕ وَاِمَّا يُنۡسِيَنَّكَ الشَّيۡطٰنُ فَلَا تَقۡعُدۡ بَعۡدَ الذِّكۡرٰي مَعَ الۡقَوۡمِ الظّٰلِمِيۡنَ","u":"اور جب تو دیکھے ان لوگوں کہ کہ جھگڑتے ہیں ہماری آیتوں میں تو ان سے کنارہ کر یہاں تک کہ مشغول ہو جاویں کسی اور بات میں اور اگر بھلا دے تجھ کو شیطان تو مت بیٹھ یاد آجانے کے بعد ظالموں کےساتھ"},{"n":302,"l":"ف","t":"فطری دین (دینِ حنیف)","p":"3","s":"آلِ عمران","sn":3,"r":"7","a":"67","ar":"مَا كَانَ اِبۡرٰهِيۡمُ يَهُوۡدِيًّا وَّلَا نَصۡرَانِيًّا وَّلٰكِنۡ كَانَ حَنِيۡفًا مُّسۡلِمًاؕ وَمَا كَانَ مِنَ الۡمُشۡرِكِيۡنَ","u":"نہ تھا ابراہیم یہودی اور نہ تھا نصرانی لیکن تھا حنیف یعنی سب جھوٹے مذہبوں سے بیزار اور حکم بردار اور نہ تھا مشرک"},{"n":303,"l":"ق","t":"قرآن کی عظمت و حفاظت","p":"14","s":"الحجر","sn":15,"r":"1","a":"9","ar":"اِنَّا نَحۡنُ نَزَّلۡنَا الذِّكۡرَ وَاِنَّا لَهٗ لَحٰفِظُوۡنَ","u":"ہم نے آپ اتاری ہے یہ نصیحت اور ہم آپ اس کے نگہبان ہیں"},{"n":304,"l":"ق","t":"قیامت کے دلائل","p":"17","s":"الحج","sn":22,"r":"1","a":"5-7","ar":"يٰ٘اَيُّهَا النَّاسُ اِنۡ كُنۡتُمۡ فِيۡ رَيۡبٍ مِّنَ الۡبَعۡثِ فَاِنَّا خَلَقۡنٰكُمۡ مِّنۡ تُرَابٍ ثُمَّ مِنۡ نُّطۡفَةٍ ثُمَّ مِنۡ عَلَقَةٍ ثُمَّ مِنۡ مُّضۡغَةٍ مُّخَلَّقَةٍ وَّغَيۡرِ مُخَلَّقَةٍ لِّنُبَيِّنَ لَكُمۡؕ وَنُقِرُّ فِي الۡاَرۡحَامِ مَا نَشَآءُ اِلٰ٘ي اَجَلٍ مُّسَمًّي ثُمَّ نُخۡرِجُكُمۡ طِفۡلًا ثُمَّ لِتَبۡلُغُوۡ٘ا اَشُدَّكُمۡۚ وَمِنۡكُمۡ مَّنۡ يُّتَوَفّٰي وَمِنۡكُمۡ مَّنۡ يُّرَدُّ اِلٰ٘ي اَرۡذَلِ الۡعُمُرِ لِكَيۡلَا يَعۡلَمَ مِنۭۡ بَعۡدِ عِلۡمٍ شَيۡـًٔاؕ وَتَرَي الۡاَرۡضَ هَامِدَةً فَاِذَا٘ اَنۡزَلۡنَا عَلَيۡهَا الۡمَآءَ اهۡتَزَّتۡ وَرَبَتۡ وَاَنۭۡ بَتَتۡ مِنۡ كُلِّ زَوۡجٍۭ بَهِيۡجٍ ذٰلِكَ بِاَنَّ اللّٰهَ هُوَ الۡحَقُّ وَاَنَّهٗ يُحۡيِ الۡمَوۡتٰي وَاَنَّهٗ عَلٰي كُلِّ شَيۡءٍ قَدِيۡرٌۙ وَّاَنَّ السَّاعَةَ اٰتِيَةٌ لَّا رَيۡبَ فِيۡهَاۙ وَاَنَّ اللّٰهَ يَبۡعَثُ مَنۡ فِي الۡقُبُوۡرِ","u":"اے لوگو اگر تمکو دھوکا ہے جی اٹھنے میں تو ہم نے تمکو بنایا مٹی سے پھر قطرہ سے پھر جمے ہوئے خون سے پھر گوشت کی بوٹی نقشہ بنی ہوئی سے اور بدون نقشہ بنی ہوئی سے اس واسطے کہ تم کو کھول کر سنا دیں اور ٹھہرا رکھتے ہیں ہم پیٹ میں جو کچھ چاہیں ایک وقت معین تک پھر تم کو نکالتے ہیں لڑکا پھر جب تک کہ پہنچو اپنی جوانی کے زور کو اورکوئی تم میں سے قبضہ کر لیا جاتا ہے اور کوئی تم میں سے پھر چلایا جاتا ہے نکمی عمر تک تاکہ سمجھنے کے پیچھے کچھ نہ سمجھنے لگے اور تو دیکھتا ہے زمین خراب پڑی ہوئی پھر جہاں ہم نے اتارا اُس پر پانی تازی ہو گئ اور ابھری اور اگائیں ہر قسم قسم رونق کی چیزیں یہ سب کچھ اس واسطے کہ اللہ وہی ہے محقق اور وہ جِلاتا ہے مُردوں کو اور وہ ہر چیز کر سکتا ہے اور یہ کہ قیامت آنی ہے اُس میں دھوکا نہیں اور یہ کہ اللہ اٹھائے گا قبروں میں پڑے ہوؤں کو"},{"n":305,"l":"ق","t":"قناعت کی فضیلت","p":"16","s":"طٰہ","sn":20,"r":"8","a":"131","ar":"وَلَا تَمُدَّنَّ عَيۡنَيۡكَ اِلٰي مَا مَتَّعۡنَا بِهٖ٘ اَزۡوَاجًا مِّنۡهُمۡ زَهۡرَةَ الۡحَيٰوةِ الدُّنۡيَا ۙ لِنَفۡتِنَهُمۡ فِيۡهِؕ وَرِزۡقُ رَبِّكَ خَيۡرٌ وَّاَبۡقٰي","u":"اور مت پسار اپنی آنکھیں اُس چیز پر جو فائدہ اٹھانے کو دی ہم نے ان طرح طرح کے لوگوں کو رونق دنیا کی زندگی کی اُنکے جانچے کو اور تیرے رب کی دی ہوئی روزی بہتر ہے اور بہت باقی رہنے والی"},{"n":306,"l":"ق","t":"قتلِ ناحق کی حرمت","p":"6","s":"المائدہ","sn":5,"r":"5","a":"32","ar":"مِنۡ اَجۡلِ ذٰلِكَۚۛؔ كَتَبۡنَا عَلٰي بَنِيۡ٘ اِسۡرَآءِيۡلَ اَنَّهٗ مَنۡ قَتَلَ نَفۡسًاۭ بِغَيۡرِ نَفۡسٍ اَوۡ فَسَادٍ فِي الۡاَرۡضِ فَكَاَنَّمَا قَتَلَ النَّاسَ جَمِيۡعًاؕ وَمَنۡ اَحۡيَاهَا فَكَاَنَّمَا٘ اَحۡيَا النَّاسَ جَمِيۡعًاؕ وَلَقَدۡ جَآءَتۡهُمۡ رُسُلُنَا بِالۡبَيِّنٰتِؗ ثُمَّ اِنَّ كَثِيۡرًا مِّنۡهُمۡ بَعۡدَ ذٰلِكَ فِي الۡاَرۡضِ لَمُسۡرِفُوۡنَ","u":"اسی سبب سے لکھا ہم نے بنی اسرائیل پر کہ جو کوئی قتل کرے ایک جان کو بلاعوض جان کے یا بغیر فساد کرنے کے ملک میں تو گویا قتل کر ڈالا اس نے سب لوگوں کو اور جس نے زندہ رکھا ایک جان کو تو گویا زندہ کر دیا سب لوگوں کو اور لا چکے ہیں انکے پاس رسول ہمارے کھلے ہوئے حکم پھر بہت لوگ ان میں سے اس پر بھی ملک میں دست درازی کرتے ہیں"},{"n":307,"l":"ق","t":"قارون کا تکبر اور انجام","p":"20","s":"القصص","sn":28,"r":"8","a":"81","ar":"فَخَسَفۡنَا بِهٖ وَبِدَارِهِ الۡاَرۡضَ فَمَا كَانَ لَهٗ مِنۡ فِئَةٍ يَّنۡصُرُوۡنَهٗ مِنۡ دُوۡنِ اللّٰهِؗ وَمَا كَانَ مِنَ الۡمُنۡتَصِرِيۡنَ","u":"پھر دھنسا دیا ہم نے اس کو اور اسکے گھر کو زمین میں پھر نہ ہوئی س کی کوئی جماعت جو مدد کرتی اسکی اللہ کے سوائے اور نہ وہ خود مدد لا سکا"},{"n":308,"l":"ق","t":"قسم کھانے کے احکام","p":"7","s":"المائدہ","sn":5,"r":"12","a":"89","ar":"لَا يُؤَاخِذُكُمُ اللّٰهُ بِاللَّغۡوِ فِيۡ٘ اَيۡمَانِكُمۡ وَلٰكِنۡ يُّؤَاخِذُكُمۡ بِمَا عَقَّدۡتُّمُ الۡاَيۡمَانَۚ فَكَفَّارَتُهٗ٘ اِطۡعَامُ عَشَرَةِ مَسٰكِيۡنَ مِنۡ اَوۡسَطِ مَا تُطۡعِمُوۡنَ اَهۡلِيۡكُمۡ اَوۡ كِسۡوَتُهُمۡ اَوۡ تَحۡرِيۡرُ رَقَبَةٍؕ فَمَنۡ لَّمۡ يَجِدۡ فَصِيَامُ ثَلٰثَةِ اَيَّامٍؕ ذٰلِكَ كَفَّارَةُ اَيۡمَانِكُمۡ اِذَا حَلَفۡتُمۡؕ وَاحۡفَظُوۡ٘ا اَيۡمَانَكُمۡؕ كَذٰلِكَ يُبَيِّنُ اللّٰهُ لَكُمۡ اٰيٰتِهٖ لَعَلَّكُمۡ تَشۡكُرُوۡنَ","u":"نہیں پکڑتا اللہ تم کو تمہاری بیہودہ قسموں پر لیکن پکڑتا ہے اس پر جس قسم کو تم نے مضبوط باندھا سو اس کا کفارہ کھانا دینا ہے دس محتاجوں کو اوسط درجہ کا کھانا جو دیتے ہو اپنے گھر والوں کو یا کپڑا پہنا دینا دس محتاجوں کو یا ایک گردن آزاد کرنی پھر جس کو میسر نہ ہوتو روزے رکھنے ہیں تین دن کے یہ کفارہ ہے تمہاری قسموں کا جب قسم کھا بیٹھو اور حفاطت رکھو اپنی قسموں کی اسی طرح بیان کرتا ہے اللہ تمہارے لئے اپنے حکم تاکہ تم احسان مانو"},{"n":309,"l":"ق","t":"قصاص کا حکم","p":"2","s":"البقرہ","sn":2,"r":"22","a":"178","ar":"يٰ٘اَيُّهَا الَّذِيۡنَ اٰمَنُوۡا كُتِبَ عَلَيۡكُمُ الۡقِصَاصُ فِي الۡقَتۡلٰيؕ اَلۡحُرُّ بِالۡحُرِّ وَالۡعَبۡدُ بِالۡعَبۡدِ وَالۡاُنۡثٰي بِالۡاُنۡثٰيؕ فَمَنۡ عُفِيَ لَهٗ مِنۡ اَخِيۡهِ شَيۡءٌ فَاتِّبَاعٌۭ بِالۡمَعۡرُوۡفِ وَاَدَآءٌ اِلَيۡهِ بِاِحۡسَانٍؕ ذٰلِكَ تَخۡفِيۡفٌ مِّنۡ رَّبِّكُمۡ وَرَحۡمَةٌؕ فَمَنِ اعۡتَدٰي بَعۡدَ ذٰلِكَ فَلَهٗ عَذَابٌ اَلِيۡمٌۚ","u":"اے ایمان والو فرض ہوا تم پر [قصاص] برابری کرنا مقتولوں میں آزاد کے بدلے آزاد اور غلام کے بدلے غلام اور عورت کےبدلے عورت پھر جس کو معاف کیا جائے اس کے بھائی کی طرف سے کچھ بھی تو تابعداری کرنی چاہیئے موافق دستور کے اور ادا کرنا چاہئے اس کو خوبی کے ساتھ یہ آسانی ہوئی تمہارے رب کی طرف سے اور مہربانی پھر جو زیادتی کرے اس فیصلہ کے بعد تو اس کے لئے ہے عذاب دردناک"},{"n":310,"l":"ق","t":"قربِ الٰہی کے ذرائع","p":"26","s":"قٓ","sn":50,"r":"2","a":"16","ar":"وَلَقَدۡ خَلَقۡنَا الۡاِنۡسَانَ وَنَعۡلَمُ مَا تُوَسۡوِسُ بِهٖ نَفۡسُهٗۚۖ وَنَحۡنُ اَقۡرَبُ اِلَيۡهِ مِنۡ حَبۡلِ الۡوَرِيۡدِ","u":"اور البتہ ہم نے بنایا انسان کو اور ہم جانتےہیں جو باتیں آتی رہتی ہیں اُسکے جی میں اور ہم اُس سے نزدیک ہیں دھڑکتی رگ سے زیادہ"},{"n":311,"l":"ق","t":"قرضِ حسنہ کی ترغیب","p":"2","s":"البقرہ","sn":2,"r":"32","a":"245","ar":"مَنۡ ذَا الَّذِيۡ يُقۡرِضُ اللّٰهَ قَرۡضًا حَسَنًا فَيُضٰعِفَهٗ لَهٗ٘ اَضۡعَافًا كَثِيۡرَةًؕ وَاللّٰهُ يَقۡبِضُ وَيَبۡصُۜطُ وَاِلَيۡهِ تُرۡجَعُوۡنَ","u":"کو ن شخص ہے ایسا جو کہ قرض دے اللہ کو اچھا قرض پھر دوگنا کر دے اللہ اس کو کئ گنا اور اللہ ہی تنگی کردیتا ہے اور وہی کشائش کرتا ہے اور اسی کی طرف تم لوٹائے جاؤ گے"},{"n":312,"l":"ق","t":"قرآن میں امثال (تمثیلات)","p":"20","s":"العنکبوت","sn":29,"r":"4","a":"43","ar":"وَتِلۡكَ الۡاَمۡثَالُ نَضۡرِبُهَا لِلنَّاسِۚ وَمَا يَعۡقِلُهَا٘ اِلَّا الۡعٰلِمُوۡنَ","u":"اور یہ مثالیں بٹھلاتے ہیں ہم لوگوں کے واسطے اور ان کو سمجھتے وہی ہیں جن کو سمجھ ہے"},{"n":313,"l":"ق","t":"قوتِ ایمانی","p":"26","s":"الحجرات","sn":49,"r":"2","a":"15","ar":"اِنَّمَا الۡمُؤۡمِنُوۡنَ الَّذِيۡنَ اٰمَنُوۡا بِاللّٰهِ وَرَسُوۡلِهٖ ثُمَّ لَمۡ يَرۡتَابُوۡا وَجٰهَدُوۡا بِاَمۡوَالِهِمۡ وَاَنۡفُسِهِمۡ فِيۡ سَبِيۡلِ اللّٰهِؕ اُولٰٓئِكَ هُمُ الصّٰدِقُوۡنَ","u":"ایمان والے وہ لوگ ہیں جو ایمان لائے اللہ پر اور اسکے رسول پر پھر شبہ نہ لائے اور لڑے اللہ کی راہ میں اپنے مال اور اپنی جان سے وہ لوگ جو ہیں وہی ہیں سچے"},{"n":314,"l":"ق","t":"قرآن کا چیلنج (تحدی)","p":"12","s":"ھود","sn":11,"r":"2","a":"13","ar":"اَمۡ يَقُوۡلُوۡنَ افۡتَرٰىهُؕ قُلۡ فَاۡتُوۡا بِعَشۡرِ سُوَرٍ مِّثۡلِهٖ مُفۡتَرَيٰتٍ وَّادۡعُوۡا مَنِ اسۡتَطَعۡتُمۡ مِّنۡ دُوۡنِ اللّٰهِ اِنۡ كُنۡتُمۡ صٰدِقِيۡنَ","u":"کیا کہتے ہیں کہ بنا لیا ہے تو قرآن کو کہہ دے تم بھی لے آؤ ایک دس سورتیں ایسی بنا کر اور بلا لو جس کو بلا سکو اللہ کے سوا اگر ہو تم سچے"},{"n":315,"l":"ق","t":"قوتِ برداشت","p":"2","s":"البقرہ","sn":2,"r":"19","a":"153","ar":"يٰ٘اَيُّهَا الَّذِيۡنَ اٰمَنُوا اسۡتَعِيۡنُوۡا بِالصَّبۡرِ وَالصَّلٰوةِؕ اِنَّ اللّٰهَ مَعَ الصّٰبِرِيۡنَ","u":"اے مسلمانو مدد لو صبر اور نماز سے بیشک اللہ صبر کرنے والوں کے ساتھ ہے"},{"n":316,"l":"ق","t":"قربانی کی روح","p":"17","s":"الحج","sn":22,"r":"5","a":"37","ar":"لَنۡ يَّنَالَ اللّٰهَ لُحُوۡمُهَا وَلَا دِمَآؤُهَا وَلٰكِنۡ يَّنَالُهُ التَّقۡوٰي مِنۡكُمۡؕ كَذٰلِكَ سَخَّرَهَا لَكُمۡ لِتُكَبِّرُوا اللّٰهَ عَلٰي مَا هَدٰىكُمۡؕ وَبَشِّرِ الۡمُحۡسِنِيۡنَ","u":"اللہ کو نہیں پہنچتا اُن کا گوشت اور نہ اُن کا لہو لیکن اُسکو پہنچتا ہے تمہارے دل کا ادب اسی طرح اُنکو بس میں کر دیا تمہارے کہ اللہ کی بڑائی پڑھو اس بات پر کہ تم کو راہ سجھائی اور بشارت سنا دے نیکی والوں کو"},{"n":317,"l":"ق","t":"قرآن کا اسلوبِ تربیت","p":"15","s":"بنی اسرائیل (الاسراء)","sn":17,"r":"1","a":"9","ar":"اِنَّ هٰذَا الۡقُرۡاٰنَ يَهۡدِيۡ لِلَّتِيۡ هِيَ اَقۡوَمُ وَيُبَشِّرُ الۡمُؤۡمِنِيۡنَ الَّذِيۡنَ يَعۡمَلُوۡنَ الصّٰلِحٰتِ اَنَّ لَهُمۡ اَجۡرًا كَبِيۡرًاۙ","u":"یہ قرآن بتلاتا ہے وہ راہ جو سب سے سیدھی ہے اور خوشخبری سناتا ہے ایمان والوں کو جو عمل کرتے ہیں اچھے کہ ان کے لئے ہے ثواب بڑا"},{"n":318,"l":"ق","t":"قلبِ سلیم کی فضیلت","p":"23","s":"الصافات","sn":37,"r":"3","a":"84","ar":"اِذۡ جَآءَ رَبَّهٗ بِقَلۡبٍ سَلِيۡمٍ","u":"جب آیا اپنے رب کے پاس لیکر دل نروگا"},{"n":319,"l":"ک","t":"کفر کی حقیقت اور اس کا انجام","p":"1","s":"البقرہ","sn":2,"r":"1","a":"6-7","ar":"اِنَّ الَّذِيۡنَ كَفَرُوۡا سَوَآءٌ عَلَيۡهِمۡ ءَاَنۡذَرۡتَهُمۡ اَمۡ لَمۡ تُنۡذِرۡهُمۡ لَا يُؤۡمِنُوۡنَ خَتَمَ اللّٰهُ عَلٰي قُلُوۡبِهِمۡ وَعَلٰي سَمۡعِهِمۡؕ وَعَلٰ٘ي اَبۡصَارِهِمۡ غِشَاوَةٌؗ وَّلَهُمۡ عَذَابٌ عَظِيۡمٌ","u":"بیشک جو لوگ کافر ہو چکے برابر ہے ان کو تو ڈرائے یا نہ ڈرائے وہ ایمان نہیں لائیں گے مہر کر دی اللہ نے ان کےدلوں پر اور انکے کانوں پر اور ان کی آنکھوں پر پردہ ہے اور ان کے لئے بڑا عذاب ہے"},{"n":320,"l":"ک","t":"کبیرہ گناہوں سے اجتناب","p":"5","s":"النساء","sn":4,"r":"5","a":"31","ar":"اِنۡ تَجۡتَنِبُوۡا كَبَآئِرَ مَا تُنۡهَوۡنَ عَنۡهُ نُكَفِّرۡ عَنۡكُمۡ سَيِّاٰتِكُمۡ وَنُدۡخِلۡكُمۡ مُّدۡخَلًا كَرِيۡمًا","u":"اگر تم بچتے رہو گے ان چیزوں سے جو گناہوں میں بڑی ہیں تو ہم معاف کر دیں گے تم سے چھوٹے گناہ تمہارے اور داخل کریں گے تم کو عزت کے مقام میں"},{"n":321,"l":"ک","t":"کسبِ حلال کی اہمیت","p":"28","s":"الجمعہ","sn":62,"r":"2","a":"10","ar":"فَاِذَا قُضِيَتِ الصَّلٰوةُ فَانۡتَشِرُوۡا فِي الۡاَرۡضِ وَابۡتَغُوۡا مِنۡ فَضۡلِ اللّٰهِ وَاذۡكُرُوا اللّٰهَ كَثِيۡرًا لَّعَلَّكُمۡ تُفۡلِحُوۡنَ","u":"پھر جب تمام ہو چکے نماز تو پھیل پڑو زمین میں اور ڈھونڈو فضل اللہ کا اور یاد کرو اللہ کو بہت سا تاکہ تمہارا بھلا ہو"},{"n":322,"l":"ک","t":"کعبہ کی تعمیر و فضیلت","p":"1","s":"البقرہ","sn":2,"r":"15","a":"125","ar":"وَاِذۡ جَعَلۡنَا الۡبَيۡتَ مَثَابَةً لِّلنَّاسِ وَاَمۡنًاؕ وَاتَّخِذُوۡا مِنۡ مَّقَامِ اِبۡرٰهٖمَ مُصَلًّيؕ وَعَهِدۡنَا٘ اِلٰ٘ي اِبۡرٰهٖمَ وَاِسۡمٰعِيۡلَ اَنۡ طَهِّرَا بَيۡتِيَ لِلطَّآئِفِيۡنَ وَالۡعٰكِفِيۡنَ وَالرُّكَّعِ السُّجُوۡدِ","u":"اور جب مقرر کیا ہم نے خانہ کعبہ کو اجتماع کی جگہ لوگوں کے واسطے اور جگہ امن کی اور بناؤ ابراہیم کے کھڑے ہونے کی جگہ کو نماز کی جگہ اور حکم کیا ہم نے ابراہیم اور اسمٰعیل کو کہ پاک کر رکھو میرے گھر کو واسطے طواف کرنے والوں کے اور اعتکاف کرنے والوں کے اور رکوع او رسجدہ کرنے والوں کے"},{"n":323,"l":"ک","t":"کتاب اللہ کی پیروی","p":"8","s":"الانعام","sn":6,"r":"20","a":"155","ar":"وَهٰذَا كِتٰبٌ اَنۡزَلۡنٰهُ مُبٰرَكٌ فَاتَّبِعُوۡهُ وَاتَّقُوۡا لَعَلَّكُمۡ تُرۡحَمُوۡنَۙ","u":"اور ایک یہ کتاب ہے کہ ہم نے اتاری برکت والی سو اس پر چلو اور ڈرتے رہو تاکہ تم پر رحمت ہو"},{"n":324,"l":"ک","t":"کائنات میں تفکر کی دعوت","p":"30","s":"الغاشیہ","sn":88,"r":"1","a":"17-20","ar":"اَفَلَا يَنۡظُرُوۡنَ اِلَي الۡاِبِلِ كَيۡفَ خُلِقَتۡ وَاِلَي السَّمَآءِ كَيۡفَ رُفِعَتۡ وَاِلَي الۡجِبَالِ كَيۡفَ نُصِبَتۡ وَاِلَي الۡاَرۡضِ كَيۡفَ سُطِحَتۡ","u":"بھلا کیا نظر نہیں کرتے اونٹوں پر کہ کیسے بنائے ہیں اور آسمان پر کہ کیسا اُس کو بلند کیا ہے اور پہاڑوں پر کہ کیسے کھڑے کر دیے ہیں اور زمین پر کہ کیسی صاف بچھائی ہے"},{"n":325,"l":"ک","t":"کم تولنے کی ممانعت (اصحابِ مدین)","p":"30","s":"المطففین","sn":83,"r":"1","a":"1-3","ar":"وَيۡلٌ لِّلۡمُطَفِّفِيۡنَۙ الَّذِيۡنَ اِذَا اكۡتَالُوۡا عَلَي النَّاسِ يَسۡتَوۡفُوۡنَؗۖ وَاِذَا كَالُوۡهُمۡ اَوۡ وَّزَنُوۡهُمۡ يُخۡسِرُوۡنَؕ","u":"خرابی ہے گھٹانے والوں کی وہ لوگ کہ جب ماپ کر لیں لوگوں سے تو پورا بھر لیں اور جب ماپ کر دیں اُنکو یا تول کر تو گھٹا کر دیں"},{"n":326,"l":"ک","t":"کائنات کے نظام میں توازن","p":"27","s":"الرحمٰن","sn":55,"r":"1","a":"7-9","ar":"وَالسَّمَآءَ رَفَعَهَا وَوَضَعَ الۡمِيۡزَانَۙ اَلَّا تَطۡغَوۡا فِي الۡمِيۡزَانِ وَاَقِيۡمُوا الۡوَزۡنَ بِالۡقِسۡطِ وَلَا تُخۡسِرُوا الۡمِيۡزَانَ","u":"اور آسمان کو اونچا کیا اور رکھی ترازو کہ زیادتی نہ کرو ترازو میں اور سیدھی ترازو تولو انصاف سے اور مت گھٹاؤ تول کو"},{"n":327,"l":"ک","t":"کم سنی میں نبوت کی مثالیں","p":"16","s":"مریم","sn":19,"r":"2","a":"29-30","ar":"فَاَشَارَتۡ اِلَيۡهِؕ قَالُوۡا كَيۡفَ نُكَلِّمُ مَنۡ كَانَ فِي الۡمَهۡدِ صَبِيًّا قَالَ اِنِّيۡ عَبۡدُ اللّٰهِؕ اٰتٰىنِيَ الۡكِتٰبَ وَجَعَلَنِيۡ نَبِيًّاۙ","u":"پھر ہاتھ سے بتلایا اُس لڑکے کو بولے ہم کیونکر بات کریں اُس شخص سے کہ وہ ہے گود میں لڑکا وہ بولا میں بندہ ہوں اللہ کا مجھ کو اُس نے کتاب دی ہے اور مجھ کو اُس نے نبی کیا"},{"n":328,"l":"ک","t":"کامیابی کا حقیقی معیار","p":"28","s":"الحشر","sn":59,"r":"3","a":"20","ar":"لَا يَسۡتَوِيۡ٘ اَصۡحٰبُ النَّارِ وَاَصۡحٰبُ الۡجَنَّةِؕ اَصۡحٰبُ الۡجَنَّةِ هُمُ الۡفَآئِزُوۡنَ","u":"برابر نہیں دوزخ والے اور بہشت والے بہشت والے جو ہیں وہی ہیں مراد پانے والے"},{"n":329,"l":"ک","t":"کفرانِ نعمت کی مذمت","p":"13","s":"ابراہیم","sn":14,"r":"2","a":"7","ar":"وَاِذۡ تَاَذَّنَ رَبُّكُمۡ لَئِنۡ شَكَرۡتُمۡ لَاَزِيۡدَنَّكُمۡ وَلَئِنۡ كَفَرۡتُمۡ اِنَّ عَذَابِيۡ لَشَدِيۡدٌ","u":"اور جب سنا دیا تمہارے رب نے اگر احسان مانو گے تو اور بھی دوں گا تم کو اور اگر ناشکری کرو گے تو میرا عذاب البتہ سخت ہے"},{"n":330,"l":"ک","t":"کلمہ طیبہ کی برکت","p":"13","s":"ابراہیم","sn":14,"r":"4","a":"24-25","ar":"اَلَمۡ تَرَ كَيۡفَ ضَرَبَ اللّٰهُ مَثَلًا كَلِمَةً طَيِّبَةً كَشَجَرَةٍ طَيِّبَةٍ اَصۡلُهَا ثَابِتٌ وَّفَرۡعُهَا فِي السَّمَآءِۙ تُؤۡتِيۡ٘ اُكُلَهَا كُلَّ حِيۡنٍۭ بِاِذۡنِ رَبِّهَاؕ وَيَضۡرِبُ اللّٰهُ الۡاَمۡثَالَ لِلنَّاسِ لَعَلَّهُمۡ يَتَذَكَّرُوۡنَ","u":"تو نے نہ دیکھا کیسی بیان کی اللہ نے ایک مثال بات ستھری جیسے ایک درخت ستھرا اسکی جڑ مضبوط ہے اور ٹہنے (شاخیں) ہیں آسمان میں لاتا ہے پھل اپنا ہر وقت پر اپنے رب کے حکم سے اور بیان کرتا ہے اللہ مثالیں لوگوں کے واسطے تاکہ وہ فکر کریں (سوچیں)"},{"n":331,"l":"گ","t":"گناہوں سے توبہ","p":"5","s":"النساء","sn":4,"r":"16","a":"110","ar":"وَمَنۡ يَّعۡمَلۡ سُوۡٓءًا اَوۡ يَظۡلِمۡ نَفۡسَهٗ ثُمَّ يَسۡتَغۡفِرِ اللّٰهَ يَجِدِ اللّٰهَ غَفُوۡرًا رَّحِيۡمًا","u":"اور جو کوئی کرے گناہ یا اپنا برا کرے پھر اللہ سے بخشوا دے تو پاوے اللہ کو بخشنے والا مہربان"},{"n":332,"l":"گ","t":"گمراہی کے اسباب","p":"25","s":"الجاثیہ","sn":45,"r":"3","a":"23","ar":"اَفَرَءَيۡتَ مَنِ اتَّخَذَ اِلٰهَهٗ هَوٰىهُ وَاَضَلَّهُ اللّٰهُ عَلٰي عِلۡمٍ وَّخَتَمَ عَلٰي سَمۡعِهٖ وَقَلۡبِهٖ وَجَعَلَ عَلٰي بَصَرِهٖ غِشٰوَةًؕ فَمَنۡ يَّهۡدِيۡهِ مِنۭۡ بَعۡدِ اللّٰهِؕ اَفَلَا تَذَكَّرُوۡنَ","u":"بھلا دیکھ تو جس نے ٹھہرا لیا اپنا حاکم اپنی خواہش کو اور راہ سے بچلا دیا اسکو اللہ نے جانتا بوجھتا اور مہر لگا دی اسکے کان پر اوردل پر اور ڈالدی اسکی آنکھ پر اندھیری پھر کون راہ پر لائے اسکو اللہ کے سوائے سو کیا تم غور نہیں کرتے"},{"n":333,"l":"گ","t":"گواہی میں دیانت داری","p":"28","s":"الطلاق","sn":65,"r":"1","a":"2","ar":"فَاِذَا بَلَغۡنَ اَجَلَهُنَّ فَاَمۡسِكُوۡهُنَّ بِمَعۡرُوۡفٍ اَوۡ فَارِقُوۡهُنَّ بِمَعۡرُوۡفٍ وَّاَشۡهِدُوۡا ذَوَيۡ عَدۡلٍ مِّنۡكُمۡ وَاَقِيۡمُوا الشَّهَادَةَ لِلّٰهِؕ ذٰلِكُمۡ يُوۡعَظُ بِهٖ مَنۡ كَانَ يُؤۡمِنُ بِاللّٰهِ وَالۡيَوۡمِ الۡاٰخِرِ ؕ وَمَنۡ يَّتَّقِ اللّٰهَ يَجۡعَلۡ لَّهٗ مَخۡرَجًاۙ","u":"پھر جب پہنچیں اپنے وعدہ کو تو رکھ لو اُنکو دستور کے موافق یا چھوڑ دو اُنکو دستور کے موافق اور گواہ کر لو دو معتبر اپنے میں کے اور سیدھی ادا کرو گواہی اللہ کے واسطے یہ بات جو ہے اس سے سمجھ جائے گا جو کوئی یقین رکھتا ہو گا اللہ پر اور پچھلے دن پر اور جو کوئی ڈرتا ہے اللہ سے وہ کر دے اُس کا گذارہ"},{"n":334,"l":"گ","t":"گزشتہ امتوں کی عبرت","p":"20","s":"العنکبوت","sn":29,"r":"4","a":"40","ar":"فَكُلًّا اَخَذۡنَا بِذَنۭۡ بِهٖۚ فَمِنۡهُمۡ مَّنۡ اَرۡسَلۡنَا عَلَيۡهِ حَاصِبًاۚ وَمِنۡهُمۡ مَّنۡ اَخَذَتۡهُ الصَّيۡحَةُۚ وَمِنۡهُمۡ مَّنۡ خَسَفۡنَا بِهِ الۡاَرۡضَۚ وَمِنۡهُمۡ مَّنۡ اَغۡرَقۡنَاۚ وَمَا كَانَ اللّٰهُ لِيَظۡلِمَهُمۡ وَلٰكِنۡ كَانُوۡ٘ا اَنۡفُسَهُمۡ يَظۡلِمُوۡنَ","u":"پھر سب کو پکڑ ا ہم نے اپنے اپنے گناہ پر پھر کوئی تھا کہ اس پر ہم نے بھیجا پتھراؤ ہوا سے اور کوئی تھا کہ اس کو پکڑا چنگھاڑ نے اور کوئی تھا کہ اس کو دھنسا دیا ہم نے زمین میں اور کوئی تھا کہ اس کو ڈبا دیا ہم نے اور اللہ ایسا نہ تھا کہ ان پر ظلم کرے پر تھے وہ اپنا آپ ہی برا کرتے"},{"n":335,"l":"گ","t":"گمراہ رہنماؤں کی پیروی سے اجتناب","p":"22","s":"الاحزاب","sn":33,"r":"8","a":"67","ar":"وَقَالُوۡا رَبَّنَا٘ اِنَّا٘ اَطَعۡنَا سَادَتَنَا وَكُبَرَآءَنَا فَاَضَلُّوۡنَا السَّبِيۡلَا","u":"اور کہیں گے اے رب ہم نے کہا مانا اپنے سرداروں کا اور اپنے بڑوں کا پھر انہوں نے چکا دیا ہم کو راہ سے"},{"n":336,"l":"ل","t":"لقمان حکیم کی نصیحتیں","p":"21","s":"لقمان","sn":31,"r":"2","a":"13","ar":"وَاِذۡ قَالَ لُقۡمٰنُ لِابۡنِهٖ وَهُوَ يَعِظُهٗ يٰبُنَيَّ لَا تُشۡرِكۡ بِاللّٰهِؕؔ اِنَّ الشِّرۡكَ لَظُلۡمٌ عَظِيۡمٌ","u":"اور جب کہا لقمان نے اپنے بیٹے کو جب اس کو سمجھانے لگا اے بیٹے شریک نہ ٹھہرائیو اللہ کا بیشک شریک بنانا بھاری بے انصافی ہے"},{"n":337,"l":"ل","t":"لوط علیہ السلام کا قصہ","p":"8","s":"الاعراف","sn":7,"r":"10","a":"80-81","ar":"وَلُوۡطًا اِذۡ قَالَ لِقَوۡمِهٖ٘ اَتَاۡتُوۡنَ الۡفَاحِشَةَ مَا سَبَقَكُمۡ بِهَا مِنۡ اَحَدٍ مِّنَ الۡعٰلَمِيۡنَ اِنَّكُمۡ لَتَاۡتُوۡنَ الرِّجَالَ شَهۡوَةً مِّنۡ دُوۡنِ النِّسَآءِؕ بَلۡ اَنۡتُمۡ قَوۡمٌ مُّسۡرِفُوۡنَ","u":"اور بھیجا لوط کو جب کہا اس نے اپنی قوم کو کیا تم کرتے ہو ایسی بے حیائی کہ تم سے پہلے نہیں کیا اس کو کسی نے جہان میں تم تو دوڑتے ہو مردوں پر شہوت کے مارے عورتوں کو چھوڑ کر بلکہ تم لوگ ہو حد سے گذرنے والے"},{"n":338,"l":"ل","t":"لہو و لعب سے اجتناب","p":"21","s":"لقمان","sn":31,"r":"1","a":"6","ar":"وَمِنَ النَّاسِ مَنۡ يَّشۡتَرِيۡ لَهۡوَ الۡحَدِيۡثِ لِيُضِلَّ عَنۡ سَبِيۡلِ اللّٰهِ بِغَيۡرِ عِلۡمٍۖ وَّيَتَّخِذَهَا هُزُوًاؕ اُولٰٓئِكَ لَهُمۡ عَذَابٌ مُّهِيۡنٌ","u":"اور ایک وہ لوگ ہیں کہ خریدارا ہیں کھیل کی باتوں کے تاکہ بچلائیں اللہ کی راہ سے بن سمجھے اور ٹھہرائیں اسی کو ہنسی وہ جو ہیں ان کو ذلت کا عذاب ہے"},{"n":339,"l":"ل","t":"لباسِ تقویٰ","p":"8","s":"الاعراف","sn":7,"r":"3","a":"26","ar":"يٰبَنِيۡ٘ اٰدَمَ قَدۡ اَنۡزَلۡنَا عَلَيۡكُمۡ لِبَاسًا يُّوَارِيۡ سَوۡاٰتِكُمۡ وَرِيۡشًاؕ وَلِبَاسُ التَّقۡوٰي ذٰلِكَ خَيۡرٌؕ ذٰلِكَ مِنۡ اٰيٰتِ اللّٰهِ لَعَلَّهُمۡ يَذَّكَّرُوۡنَ","u":"اےاولاد آدم کی ہم نے اتاری تم پر پوشاک جو ڈھانکے تمہاری شرمگاہیں اور اتارے آرائش کے کپڑے اور لباس پرہیزگاری کا وہ سب سے بہتر ہے یہ نشانیاں ہیں اللہ کی قدرت کی تاکہ وہ لوگ غور کریں"},{"n":340,"l":"ل","t":"لذتِ ایمان","p":"26","s":"الحجرات","sn":49,"r":"1","a":"7","ar":"وَاعۡلَمُوۡ٘ا اَنَّ فِيۡكُمۡ رَسُوۡلَ اللّٰهِؕ لَوۡ يُطِيۡعُكُمۡ فِيۡ كَثِيۡرٍ مِّنَ الۡاَمۡرِ لَعَنِتُّمۡ وَلٰكِنَّ اللّٰهَ حَبَّبَ اِلَيۡكُمُ الۡاِيۡمَانَ وَزَيَّنَهٗ فِيۡ قُلُوۡبِكُمۡ وَكَرَّهَ اِلَيۡكُمُ الۡكُفۡرَ وَالۡفُسُوۡقَ وَالۡعِصۡيَانَؕ اُولٰٓئِكَ هُمُ الرّٰشِدُوۡنَۙ","u":"اور جان لو کہ تم میں رسول ہے اللہ کا اگر وہ تمہاری بات مان لیا کرے بہت کاموں میں تو تم پر مشکل پڑے پر اللہ نے محبت ڈال دی تمہارے دل میں ایمان کی اور کھبا دیا اسکو تمہارے دلوں میں اور نفرت ڈال دی تمہارے دل میں کفر اور گناہ اور نافرمانی کی وہ لوگ وہی ہیں نیک راہ پر"},{"n":341,"l":"ل","t":"لغو باتوں سے اجتناب","p":"18","s":"المؤمنون","sn":23,"r":"1","a":"3","ar":"وَالَّذِيۡنَ هُمۡ عَنِ اللَّغۡوِ مُعۡرِضُوۡنَۙ","u":"اور جو نکمی بات پر دھیان نہیں کرتے"},{"n":342,"l":"ل","t":"لوحِ محفوظ کا تذکرہ","p":"30","s":"البروج","sn":85,"r":"1","a":"21-22","ar":"بَلۡ هُوَ قُرۡاٰنٌ مَّجِيۡدٌۙ فِيۡ لَوۡحٍ مَّحۡفُوۡظٍ","u":"کوئی نہیں یہ قرآن ہے بڑی شان کا لکھا ہو الوح محفوظ میں"},{"n":343,"l":"م","t":"محبتِ الٰہی","p":"6","s":"المائدہ","sn":5,"r":"8","a":"54","ar":"يٰ٘اَيُّهَا الَّذِيۡنَ اٰمَنُوۡا مَنۡ يَّرۡتَدَّ مِنۡكُمۡ عَنۡ دِيۡنِهٖ فَسَوۡفَ يَاۡتِي اللّٰهُ بِقَوۡمٍ يُّحِبُّهُمۡ وَيُحِبُّوۡنَهٗ٘ۙ اَذِلَّةٍ عَلَي الۡمُؤۡمِنِيۡنَ اَعِزَّةٍ عَلَي الۡكٰفِرِيۡنَؗ يُجَاهِدُوۡنَ فِيۡ سَبِيۡلِ اللّٰهِ وَلَا يَخَافُوۡنَ لَوۡمَةَ لَآئِمٍؕ ذٰلِكَ فَضۡلُ اللّٰهِ يُؤۡتِيۡهِ مَنۡ يَّشَآءُؕ وَاللّٰهُ وَاسِعٌ عَلِيۡمٌ","u":"اے ایمان والو جو کوئی تم میں پھرے گا اپنے دین سے تو اللہ عنقریب لاوے گا ایسی قوم کو کہ اللہ انکو چاہتا ہے اور وہ اس کو چاہتے ہیں نرم دل ہیں مسلمانوں پر زبردست ہیں کافروں پر لڑتے ہیں اللہ کی راہ میں اور ڈرتے نہیں کسی کے الزام سے یہ فضل ہے اللہ کا دے گا جس کو چاہے اور اللہ کشائش والا ہے خبردار"},{"n":344,"l":"م","t":"ملائکہ کا تذکرہ و ذمہ داریاں","p":"17","s":"الانبیاء","sn":21,"r":"2","a":"19-20","ar":"وَلَهٗ مَنۡ فِي السَّمٰوٰتِ وَالۡاَرۡضِؕ وَمَنۡ عِنۡدَهٗ لَا يَسۡتَكۡبِرُوۡنَ عَنۡ عِبَادَتِهٖ وَلَا يَسۡتَحۡسِرُوۡنَۚ يُسَبِّحُوۡنَ الَّيۡلَ وَالنَّهَارَ لَا يَفۡتُرُوۡنَ","u":"اور اُسی کا ہے جو کوئی ہے آسمان اور زمین میں اور جو اُسکے نزدیک رہتے ہیں سرکشی نہیں کرتے اُسکی عبادت سے اور نہیں کرتے کاہلی یاد کرتےہیں رات اور دن نہیں تھکتے"},{"n":345,"l":"م","t":"موت کی حقیقت","p":"4","s":"آلِ عمران","sn":3,"r":"19","a":"185","ar":"كُلُّ نَفۡسٍ ذَآئِقَةُ الۡمَوۡتِؕ وَاِنَّمَا تُوَفَّوۡنَ اُجُوۡرَكُمۡ يَوۡمَ الۡقِيٰمَةِؕ فَمَنۡ زُحۡزِحَ عَنِ النَّارِ وَاُدۡخِلَ الۡجَنَّةَ فَقَدۡ فَازَؕ وَمَا الۡحَيٰوةُ الدُّنۡيَا٘ اِلَّا مَتَاعُ الۡغُرُوۡرِ","u":"ہر جی کو چکھنی ہے موت اور تم کو پورے بدلے ملیں گے قیامت کے دن پھر جو کوئی دور کیا گیا دوزخ سے اور داخل کیا گیا جنت میں اس کا کام تو بن گیا اور نہیں زندگانی دنیا کی مگر پونجی دھوکے کی"},{"n":346,"l":"م","t":"منافقین کی علامات","p":"1","s":"البقرہ","sn":2,"r":"2","a":"14","ar":"وَاِذَا لَقُوا الَّذِيۡنَ اٰمَنُوۡا قَالُوۡ٘ا اٰمَنَّاۚۖ وَاِذَا خَلَوۡا اِلٰي شَيٰطِيۡنِهِمۡۙ قَالُوۡ٘ا اِنَّا مَعَكُمۡۙ اِنَّمَا نَحۡنُ مُسۡتَهۡزِءُوۡنَ","u":"اور جب ملاقات کرتے ہیں مسلمانوں سے تو کہتے ہیں ہم ایمان لے آئے ہیں اور جب تنہا ہوتے ہیں اپنے شیطانوں کے پاس تو کہتےہیں کہ بیشک ہم تمہارے ساتھ ہیں ہم تو ہنسی کرتے ہیں (یعنی مسلمانوں سے)"},{"n":347,"l":"م","t":"موسیٰ علیہ السلام کا قصہ","p":"16","s":"طٰہ","sn":20,"r":"1","a":"11-14","ar":"فَلَمَّا٘ اَتٰىهَا نُوۡدِيَ يٰمُوۡسٰيؕ اِنِّيۡ٘ اَنَا رَبُّكَ فَاخۡلَعۡ نَعۡلَيۡكَۚ اِنَّكَ بِالۡوَادِ الۡمُقَدَّسِ طُوًيؕ وَاَنَا اخۡتَرۡتُكَ فَاسۡتَمِعۡ لِمَا يُوۡحٰي اِنَّنِيۡ٘ اَنَا اللّٰهُ لَا٘ اِلٰهَ اِلَّا٘ اَنَا فَاعۡبُدۡنِيۡۙ وَاَقِمِ الصَّلٰوةَ لِذِكۡرِيۡ","u":"پھر جب پہنچا آگ کے پاس آواز آئی اے موسٰی میں ہوں تیرا رب سو اتار ڈال اپنی جوتیاں تو ہے پاک میدان طویٰ میں اور میں نے تجھ کو پسند کیا ہے سو تو سنتا رہ جو حکم ہو میں جو ہوں اللہ ہوں کسی کی بندگی نہیں سوا میرے سو میری بندگی کر اور نماز قائم رکھ میری یادگاری کو"},{"n":348,"l":"م","t":"مریم علیہا السلام کا تذکرہ","p":"16","s":"مریم","sn":19,"r":"2","a":"17-19","ar":"فَاتَّخَذَتۡ مِنۡ دُوۡنِهِمۡ حِجَابًا فَاَرۡسَلۡنَا٘ اِلَيۡهَا رُوۡحَنَا فَتَمَثَّلَ لَهَا بَشَرًا سَوِيًّا قَالَتۡ اِنِّيۡ٘ اَعُوۡذُ بِالرَّحۡمٰنِ مِنۡكَ اِنۡ كُنۡتَ تَقِيًّا قَالَ اِنَّمَا٘ اَنَا رَسُوۡلُ رَبِّكِۖ لِاَهَبَ لَكِ غُلٰمًا زَكِيًّا","u":"پھر پکڑ لیا اُن سے ورے ایک پردہ پھر بھیجا ہم نے اُسکے پاس اپنا فرشتہ پھر بن کر آیا اُسکے آگے آدمی پورا بولی مجھ کو رحمٰن کی پناہ تجھ سے اگر ہے تو ڈر رکھنے والا بولا میں تو بھیجا ہوا ہوں تیرے رب کا کہ دے جاؤں تجھ کو ایک لڑکا ستھرا"},{"n":349,"l":"م","t":"میراث کی تقسیم کے احکام","p":"4","s":"النساء","sn":4,"r":"2","a":"11","ar":"يُوۡصِيۡكُمُ اللّٰهُ فِيۡ٘ اَوۡلَادِكُمۡ لِلذَّكَرِ مِثۡلُ حَظِّ الۡاُنۡثَيَيۡنِۚ فَاِنۡ كُنَّ نِسَآءً فَوۡقَ اثۡنَتَيۡنِ فَلَهُنَّ ثُلُثَا مَا تَرَكَۚ وَاِنۡ كَانَتۡ وَاحِدَةً فَلَهَا النِّصۡفُؕ وَلِاَبَوَيۡهِ لِكُلِّ وَاحِدٍ مِّنۡهُمَا السُّدُسُ مِمَّا تَرَكَ اِنۡ كَانَ لَهٗ وَلَدٌۚ فَاِنۡ لَّمۡ يَكُنۡ لَّهٗ وَلَدٌ وَّوَرِثَهٗ٘ اَبَوٰهُ فَلِاُمِّهِ الثُّلُثُۚ فَاِنۡ كَانَ لَهٗ٘ اِخۡوَةٌ فَلِاُمِّهِ السُّدُسُ مِنۭۡ بَعۡدِ وَصِيَّةٍ يُّوۡصِيۡ بِهَا٘ اَوۡ دَيۡنٍؕ اٰبَآؤُكُمۡ وَاَبۡنَآؤُكُمۡۚ لَا تَدۡرُوۡنَ اَيُّهُمۡ اَقۡرَبُ لَكُمۡ نَفۡعًاؕ فَرِيۡضَةً مِّنَ اللّٰهِؕ اِنَّ اللّٰهَ كَانَ عَلِيۡمًا حَكِيۡمًا","u":"حکم کرتا ہے تم کو اللہ تمہاری اولاد کے حق میں کہ ایک مرد کا حصہ ہے برابر ہے دو عورتوں کے پھر اگر صرف عورتیں ہی ہوں دو سے زیادہ تو ان کے لئے ہے دو تہائی اس مال سےجو چھوڑ مرا اور اگر ایک ہی ہو تو اس کے لئے آدھا ہے اور میت کے ماں باپ کو ہر ایک کے لئے دونوں میں سے چھٹا حصہ ہے اس مال سے جو کہ چھوڑ مرا اگر میت کے اولاد ہے اور اگر اس کے اولاد نہیں اور وارث ہیں اسکے ماں باپ تو اس کی ماں کا ہے تہائی پھر اگر میت کے کئ بھائی ہیں تو اس کی ماں کا ہے چھٹا حصہ بعد وصیت کے جو کر مرا یا بعد ادائے قرض کے تمہارے باپ اور بیٹے تم کو معلوم نہیں کون نفع پہنچائے تم کو زیادہ حصہ مقرر کیا ہوا اللہ کا ہے بیشک اللہ خبردار ہے حکمت والا"},{"n":350,"l":"م","t":"معاہدوں کی پاسداری","p":"10","s":"التوبہ","sn":9,"r":"1","a":"4","ar":"اِلَّا الَّذِيۡنَ عٰهَدۡتُّمۡ مِّنَ الۡمُشۡرِكِيۡنَ ثُمَّ لَمۡ يَنۡقُصُوۡكُمۡ شَيۡـًٔا وَّلَمۡ يُظَاهِرُوۡا عَلَيۡكُمۡ اَحَدًا فَاَتِمُّوۡ٘ا اِلَيۡهِمۡ عَهۡدَهُمۡ اِلٰي مُدَّتِهِمۡؕ اِنَّ اللّٰهَ يُحِبُّ الۡمُتَّقِيۡنَ","u":"مگر جن مشرکوں سے تم نے عہد کیا تھا پھر انہوں نے کچھ قصور نہ کیا تمہارے ساتھ اور مدد نہ کی تمہارے مقابلہ میں کسی کی سو ان سے پورا کر دو ان کا عہد ان کے وعدہ تک بیشک اللہ کو پسند ہیں احتیاط والے"},{"n":351,"l":"م","t":"ماں باپ کے حقوق","p":"20","s":"العنکبوت","sn":29,"r":"1","a":"8","ar":"وَوَصَّيۡنَا الۡاِنۡسَانَ بِوَالِدَيۡهِ حُسۡنًاؕ وَاِنۡ جٰهَدٰكَ لِتُشۡرِكَ بِيۡ مَا لَيۡسَ لَكَ بِهٖ عِلۡمٌ فَلَا تُطِعۡهُمَاؕ اِلَيَّ مَرۡجِعُكُمۡ فَاُنَبِّئُكُمۡ بِمَا كُنۡتُمۡ تَعۡمَلُوۡنَ","u":"اور ہم نے تاکید کر دی انسان کو اپنے ماں باپ سے بھلائی سے رہنے کی اور اگر وہ تجھ سے زور کریں کہ تو شریک کرے میرا جس کی تجھ کو خبر نہیں تو انکا کہنا مت مان مجھی تک پھر آنا ہے تم کو سو میں بتلا دوں گا تمکو جو کچھ تم کرتے تھے"},{"n":352,"l":"م","t":"مساواتِ انسانیت","p":"4","s":"النساء","sn":4,"r":"1","a":"1","ar":"يٰ٘اَيُّهَا النَّاسُ اتَّقُوۡا رَبَّكُمُ الَّذِيۡ خَلَقَكُمۡ مِّنۡ نَّفۡسٍ وَّاحِدَةٍ وَّخَلَقَ مِنۡهَا زَوۡجَهَا وَبَثَّ مِنۡهُمَا رِجَالًا كَثِيۡرًا وَّنِسَآءًۚ وَاتَّقُوا اللّٰهَ الَّذِيۡ تَسَآءَلُوۡنَ بِهٖ وَالۡاَرۡحَامَؕ اِنَّ اللّٰهَ كَانَ عَلَيۡكُمۡ رَقِيۡبًا","u":"اے لوگو ڈرتے رہو اپنے رب سے جس نے پیدا کیا تم کو ایک جان سے اور اسی سے پیدا کیا اس کا جوڑا اور پھیلائے ان دونوں سے بہت مرد اور عورتیں اور ڈرتے رہو اللہ سے جس کے واسطے سے سوال کرتے ہو آپس میں اور خبردار رہو قرابت والوں سے بیشک اللہ تم پر نگہبان ہے"},{"n":353,"l":"م","t":"معراج النبی صلی اللہ علیہ وسلم کا تذکرہ","p":"27","s":"النجم","sn":53,"r":"1","a":"13-18","ar":"وَلَقَدۡ رَاٰهُ نَزۡلَةً اُخۡرٰيۙ عِنۡدَ سِدۡرَةِ الۡمُنۡتَهٰي عِنۡدَهَا جَنَّةُ الۡمَاۡوٰيؕ اِذۡ يَغۡشَي السِّدۡرَةَ مَا يَغۡشٰيۙ مَا زَاغَ الۡبَصَرُ وَمَا طَغٰي لَقَدۡ رَاٰي مِنۡ اٰيٰتِ رَبِّهِ الۡكُبۡرٰي","u":"اور اُسکو اُس نے دیکھا ہے اترتے ہوئے ایک بار اور بھی سدرۃ المنتہٰی کے پاس اُس کے پاس ہے بہشت آرام سے رہنے کی جب چھا رہا تھا اُس بیری پر جو کچھ چھا رہا تھا بہکی نہیں نگاہ اور نہ حد سے بڑھی بیشک دیکھے اُس نے اپنے رب کے بڑے نمونے"},{"n":354,"l":"م","t":"مہر کے احکام","p":"4","s":"النساء","sn":4,"r":"1","a":"4","ar":"وَاٰتُوا النِّسَآءَ صَدُقٰتِهِنَّ نِحۡلَةًؕ فَاِنۡ طِبۡنَ لَكُمۡ عَنۡ شَيۡءٍ مِّنۡهُ نَفۡسًا فَكُلُوۡهُ هَنِيۡٓـًٔا مَّرِيۡٓـًٔا","u":"اور دے ڈالو عورتوں کو مہر ان کے خوشی سے پھر اگر وہ اس میں سے کچھ چھوڑ دیں تم کو اپنی خوشی سے تو اس کو کھاؤ رچتا پچتا"},{"n":355,"l":"م","t":"مشاورت کا حکم","p":"4","s":"آلِ عمران","sn":3,"r":"17","a":"159","ar":"فَبِمَا رَحۡمَةٍ مِّنَ اللّٰهِ لِنۡتَ لَهُمۡۚ وَلَوۡ كُنۡتَ فَظًّا غَلِيۡظَ الۡقَلۡبِ لَانۡفَضُّوۡا مِنۡ حَوۡلِكَ فَاعۡفُ عَنۡهُمۡ وَاسۡتَغۡفِرۡ لَهُمۡ وَشَاوِرۡهُمۡ فِي الۡاَمۡرِۚ فَاِذَا عَزَمۡتَ فَتَوَكَّلۡ عَلَي اللّٰهِؕ اِنَّ اللّٰهَ يُحِبُّ الۡمُتَوَكِّلِيۡنَ","u":"سو کچھ اللہ ہی کی رحمت ہے جو تو نرم دل مل گیا ان کو اور اگر تو ہوتا تندخو سخت دل تو متفرق ہو جاتے تیرے پاس سے سو تو ان کو معاف کر اور ان کے واسطے بخشش مانگ اور ان سے مشورہ لے کام میں پھر جب قصد کر چکا تو اس کام کا تو پھر بھروسہ کر اللہ پر اللہ کو محبت ہے توکل والوں سے"},{"n":356,"l":"م","t":"مال و دولت کا صحیح استعمال","p":"20","s":"القصص","sn":28,"r":"8","a":"77","ar":"وَابۡتَغِ فِيۡمَا٘ اٰتٰىكَ اللّٰهُ الدَّارَ الۡاٰخِرَةَ وَلَا تَنۡسَ نَصِيۡبَكَ مِنَ الدُّنۡيَا وَاَحۡسِنۡ كَمَا٘ اَحۡسَنَ اللّٰهُ اِلَيۡكَ وَلَا تَبۡغِ الۡفَسَادَ فِي الۡاَرۡضِؕ اِنَّ اللّٰهَ لَا يُحِبُّ الۡمُفۡسِدِيۡنَ","u":"اور جو تجھ کو اللہ نے دیا ہے اس سے کما لے پچھلا گھر اور نہ بھول اپنا حصہ دنیا سے اور بھلائی کر جیسے اللہ نے بھلائی کی تجھ سے اور مت چاہ خرابی ڈالنی ملک میں اللہ کو بھاتے نہیں خرابی ڈالنے والے"},{"n":357,"l":"م","t":"مساجد کی تعمیر و آداب","p":"10","s":"التوبہ","sn":9,"r":"3","a":"18","ar":"اِنَّمَا يَعۡمُرُ مَسٰجِدَ اللّٰهِ مَنۡ اٰمَنَ بِاللّٰهِ وَالۡيَوۡمِ الۡاٰخِرِ وَاَقَامَ الصَّلٰوةَ وَاٰتَي الزَّكٰوةَ وَلَمۡ يَخۡشَ اِلَّا اللّٰهَ فَعَسٰ٘ي اُولٰٓئِكَ اَنۡ يَّكُوۡنُوۡا مِنَ الۡمُهۡتَدِيۡنَ","u":"وہی آباد کرتا ہے مسجدیں اللہ کی جو یقین لایا اللہ پر اور آخرت کے دن پر اور قائم کیا نماز کو اور دیتا رہا زکوٰۃ اور نہ ڈرا سوائے اللہ کے کسی سے سو امیدوار ہیں وہ لوگ کہ ہوویں ہدایت والوں میں"},{"n":358,"l":"م","t":"معذوروں کے حقوق","p":"30","s":"عبس","sn":80,"r":"1","a":"1-2","ar":"عَبَسَ وَتَوَلّٰ٘يۙ اَنۡ جَآءَهُ الۡاَعۡمٰيؕ","u":"تیوری چڑھائی اور منہ موڑھا اس بات سے کہ آیا اُسکے پاس اندھا"},{"n":359,"l":"م","t":"مسافر کے حقوق","p":"10","s":"التوبہ","sn":9,"r":"8","a":"60","ar":"اِنَّمَا الصَّدَقٰتُ لِلۡفُقَرَآءِ وَالۡمَسٰكِيۡنِ وَالۡعٰمِلِيۡنَ عَلَيۡهَا وَالۡمُؤَلَّفَةِ قُلُوۡبُهُمۡ وَفِي الرِّقَابِ وَالۡغٰرِمِيۡنَ وَفِيۡ سَبِيۡلِ اللّٰهِ وَابۡنِ السَّبِيۡلِؕ فَرِيۡضَةً مِّنَ اللّٰهِؕ وَاللّٰهُ عَلِيۡمٌ حَكِيۡمٌ","u":"زکوٰۃ جو ہے سو وہ حق ہے مفلسوں کا اور محتاجوں کا اور زکوٰۃ کے کام پر جانے والوں کا اور جن کا دل پرچانا منظور ہے اور گردنوں کے چھڑانے میں اور جو تاوان بھریں اور اللہ کے رستہ میں اور راہ کے مسافر کو ٹھہرایا ہوا ہے اللہ کا اور اللہ سب کچھ جاننے والا حکمت والا ہے"},{"n":360,"l":"م","t":"مشرکینِ مکہ کے اعتراضات کے جوابات","p":"18","s":"الفرقان","sn":25,"r":"1","a":"7-8","ar":"وَقَالُوۡا مَالِ هٰذَا الرَّسُوۡلِ يَاۡكُلُ الطَّعَامَ وَيَمۡشِيۡ فِي الۡاَسۡوَاقِؕ لَوۡلَا٘ اُنۡزِلَ اِلَيۡهِ مَلَكٌ فَيَكُوۡنَ مَعَهٗ نَذِيۡرًاۙ اَوۡ يُلۡقٰ٘ي اِلَيۡهِ كَنۡزٌ اَوۡ تَكُوۡنُ لَهٗ جَنَّةٌ يَّاۡكُلُ مِنۡهَاؕ وَقَالَ الظّٰلِمُوۡنَ اِنۡ تَتَّبِعُوۡنَ اِلَّا رَجُلًا مَّسۡحُوۡرًا","u":"اور کہنے لگے یہ کیسا رسول ہے کھاتا ہے کھانا اور پھرتا ہے بازاروں میں کیوں نہ اترا اسکی طرف کوئی فرشتہ کہ رہتا اس کے ساتھ ڈرانے کو یا آ پڑتا اسکے پاس خزانہ یا ہو جاتا اس کے لئے ایک باغ کہ کھایا کرتا اس میں سے اور کہنے لگے بے انصاف تم پیروی کرتے ہو اس ایک مرد جادو مارے کی"},{"n":361,"l":"م","t":"مومنوں کی صفات (سورۃ المومنون کی روشنی میں)","p":"18","s":"المؤمنون","sn":23,"r":"1","a":"4-6","ar":"وَالَّذِيۡنَ هُمۡ لِلزَّكٰوةِ فٰعِلُوۡنَۙ وَالَّذِيۡنَ هُمۡ لِفُرُوۡجِهِمۡ حٰفِظُوۡنَۙ اِلَّا عَلٰ٘ي اَزۡوَاجِهِمۡ اَوۡ مَا مَلَكَتۡ اَيۡمَانُهُمۡ فَاِنَّهُمۡ غَيۡرُ مَلُوۡمِيۡنَۚ","u":"اور جو زکوٰۃ دیا کرتے ہیں اور جو اپنی شہوت کی جگہ کو تھامتے ہیں مگر اپنی عورتوں پر یا اپنے ہاتھ کے مال باندیوں پر سو اُن پر نہیں کچھ الزام"},{"n":362,"l":"م","t":"مہاجرین و انصار کا تعاون","p":"28","s":"الحشر","sn":59,"r":"1","a":"8-9","ar":"لِلۡفُقَرَآءِ الۡمُهٰجِرِيۡنَ الَّذِيۡنَ اُخۡرِجُوۡا مِنۡ دِيَارِهِمۡ وَاَمۡوَالِهِمۡ يَبۡتَغُوۡنَ فَضۡلًا مِّنَ اللّٰهِ وَرِضۡوَانًا وَّيَنۡصُرُوۡنَ اللّٰهَ وَرَسُوۡلَهٗؕ اُولٰٓئِكَ هُمُ الصّٰدِقُوۡنَۚ وَالَّذِيۡنَ تَبَوَّءُو الدَّارَ وَالۡاِيۡمَانَ مِنۡ قَبۡلِهِمۡ يُحِبُّوۡنَ مَنۡ هَاجَرَ اِلَيۡهِمۡ وَلَا يَجِدُوۡنَ فِيۡ صُدُوۡرِهِمۡ حَاجَةً مِّمَّا٘ اُوۡتُوۡا وَيُؤۡثِرُوۡنَ عَلٰ٘ي اَنۡفُسِهِمۡ وَلَوۡ كَانَ بِهِمۡ خَصَاصَةٌؕ وَمَنۡ يُّوۡقَ شُحَّ نَفۡسِهٖ فَاُولٰٓئِكَ هُمُ الۡمُفۡلِحُوۡنَۚ","u":"واسطے ان مفلسوں وطن چھوڑنے والوں کے جو نکالے ہوئے آتے ہیں اپنے گھروں سے اور اپنے مالوں سے ڈھونڈتے آئے ہیں اللہ کا فضل اور اُسکی رضامندی اور مدد کرنے کو اللہ کی اور اسکے رسول کی وہ لوگ وہی ہیں سچے اور جو لوگ جگہ پکڑ رہے ہیں اس گھر میں اور ایمان میں ان سے پہلے سے وہ محبت کرتے ہیں اس سے جو وطن چھوڑ کر آئے انکے پاس اور نہیں پاتے اپنے دل میں تنگی اس چیز سے جو مہاجرین کو دی جائے اور مقدم رکھتے ہیں اُنکو اپنی جان سے اور اگر چہ ہو اپنے اوپر فاقہ اور جو بچایا گیا اپنے جی کے لالچ سے تو وہ لوگ ہیں مراد پانے والے"},{"n":363,"l":"م","t":"معجزاتِ انبیاء","p":"17","s":"الانبیاء","sn":21,"r":"5","a":"69","ar":"قُلۡنَا يٰنَارُ كُوۡنِيۡ بَرۡدًا وَّسَلٰمًا عَلٰ٘ي اِبۡرٰهِيۡمَۙ","u":"ہم نے کہا اے آگ ٹھنڈی ہو جا اور آرام کر ابراہیم پر"},{"n":364,"l":"م","t":"مومن کی پہچان","p":"10","s":"التوبہ","sn":9,"r":"9","a":"71","ar":"وَالۡمُؤۡمِنُوۡنَ وَالۡمُؤۡمِنٰتُ بَعۡضُهُمۡ اَوۡلِيَآءُ بَعۡضٍۘ يَاۡمُرُوۡنَ بِالۡمَعۡرُوۡفِ وَيَنۡهَوۡنَ عَنِ الۡمُنۡكَرِ وَيُقِيۡمُوۡنَ الصَّلٰوةَ وَيُؤۡتُوۡنَ الزَّكٰوةَ وَيُطِيۡعُوۡنَ اللّٰهَ وَرَسُوۡلَهٗؕ اُولٰٓئِكَ سَيَرۡحَمُهُمُ اللّٰهُؕ اِنَّ اللّٰهَ عَزِيۡزٌ حَكِيۡمٌ","u":"اور ایمان والے مرد اور ایمان والی عورتیں ایک دوسرے کی مددگار ہیں سکھلاتے ہیں نیک بات اور منع کرتے ہیں بری بات سے اور قائم رکھتے ہیں نماز اور دیتے ہیں زکوٰۃ اور حکم پر چلتے ہیں اللہ کے اور اسکے رسول کے وہی لوگ ہیں جن پر رحم کرے گا اللہ بیشک اللہ زبردست ہے حکمت والا"},{"n":365,"l":"م","t":"میزانِ اعمال","p":"8","s":"الاعراف","sn":7,"r":"1","a":"8-9","ar":"وَالۡوَزۡنُ يَوۡمَئِذِ اِۨلۡحَقُّۚ فَمَنۡ ثَقُلَتۡ مَوَازِيۡنُهٗ فَاُولٰٓئِكَ هُمُ الۡمُفۡلِحُوۡنَ وَمَنۡ خَفَّتۡ مَوَازِيۡنُهٗ فَاُولٰٓئِكَ الَّذِيۡنَ خَسِرُوۡ٘ا اَنۡفُسَهُمۡ بِمَا كَانُوۡا بِاٰيٰتِنَا يَظۡلِمُوۡنَ","u":"اور تول اس دن ٹھیک ہو گی پھر جس کی تولیں بھاری ہوئیں سو وہی ہیں نجات پانے والے اور جس کی تولیں ہلکی ہوئیں سو وہی ہیں جنہوں نے اپنا نقصان کیا اس واسطے کہ ہماری آیتوں کا انکار کرتے تھے"},{"n":366,"l":"م","t":"مہمان نوازی کی ترغیب","p":"26","s":"الذاریات","sn":51,"r":"2","a":"24-27","ar":"هَلۡ اَتٰىكَ حَدِيۡثُ ضَيۡفِ اِبۡرٰهِيۡمَ الۡمُكۡرَمِيۡنَۘ اِذۡ دَخَلُوۡا عَلَيۡهِ فَقَالُوۡا سَلٰمًاؕ قَالَ سَلٰمٌۚ قَوۡمٌ مُّنۡكَرُوۡنَ فَرَاغَ اِلٰ٘ي اَهۡلِهٖ فَجَآءَ بِعِجۡلٍ سَمِيۡنٍۙ فَقَرَّبَهٗ٘ اِلَيۡهِمۡ قَالَ اَلَا تَاۡكُلُوۡنَؗ","u":"کیا پہنچی ہے تجھ کو بات ابراہیم کے مہمانوں کی جو عزت والے تھے جب اندر پہنچے اُسکے پاس تو بولے سلام وہ بولا سلام ہے یہ لوگ ہیں اوپرے پھر دوڑا اپنے گھر کو تو لے آیا ایک بچھڑا گھی میں تلا ہوا پھر اُنکے سامنے رکھا کہا کیوں تم کھاتے نہیں"},{"n":367,"l":"م","t":"ماحول اور وسائلِ زمین میں اعتدال","p":"21","s":"الروم","sn":30,"r":"5","a":"41","ar":"ظَهَرَ الۡفَسَادُ فِي الۡبَرِّ وَالۡبَحۡرِ بِمَا كَسَبَتۡ اَيۡدِي النَّاسِ لِيُذِيۡقَهُمۡ بَعۡضَ الَّذِيۡ عَمِلُوۡا لَعَلَّهُمۡ يَرۡجِعُوۡنَ","u":"پھیل پڑی ہے خرابی جنگل میں اور دریا میں لوگوں کے ہاتھ کی کمائی سے چکھانا چاہیے ان کو کچھ مزہ ان کے کام کا تاکہ وہ پھر آئیں"},{"n":368,"l":"م","t":"مغفرت کے اسباب","p":"12","s":"ھود","sn":11,"r":"10","a":"114","ar":"وَاَقِمِ الصَّلٰوةَ طَرَفَيِ النَّهَارِ وَزُلَفًا مِّنَ الَّيۡلِؕ اِنَّ الۡحَسَنٰتِ يُذۡهِبۡنَ السَّيِّاٰتِؕ ذٰلِكَ ذِكۡرٰي لِلذّٰكِرِيۡنَۚ","u":"اور قائم کر نماز کو دونوں طرف دن کے اورکچھ ٹکڑوں میں رات کے البتہ نیکیاں دور کرتی ہیں برائیوں کو یہ یادگاری ہے یاد رکھنے والوں کو"},{"n":369,"l":"م","t":"متقین کی صفات","p":"26","s":"الذاریات","sn":51,"r":"1","a":"15-18","ar":"اِنَّ الۡمُتَّقِيۡنَ فِيۡ جَنّٰتٍ وَّعُيُوۡنٍۙ اٰخِذِيۡنَ مَا٘ اٰتٰىهُمۡ رَبُّهُمۡؕ اِنَّهُمۡ كَانُوۡا قَبۡلَ ذٰلِكَ مُحۡسِنِيۡنَؕ كَانُوۡا قَلِيۡلًا مِّنَ الَّيۡلِ مَا يَهۡجَعُوۡنَ وَبِالۡاَسۡحَارِ هُمۡ يَسۡتَغۡفِرُوۡنَ","u":"البتہ ڈرنے والے باغوں میں ہیں اور چشموں میں لیتے ہیں جو دیا اُنکو اُنکے رب نے وہ تھے اس سے پہلے نیکی والے وہ تھے رات کو تھوڑا سوتے اور صبح کے وقتوں میں معافی مانگنے والے"},{"n":370,"l":"ن","t":"نماز کی اہمیت و فضیلت","p":"20","s":"العنکبوت","sn":29,"r":"5","a":"45","ar":"اُتۡلُ مَا٘ اُوۡحِيَ اِلَيۡكَ مِنَ الۡكِتٰبِ وَاَقِمِ الصَّلٰوةَؕ اِنَّ الصَّلٰوةَ تَنۡهٰي عَنِ الۡفَحۡشَآءِ وَالۡمُنۡكَرِؕ وَلَذِكۡرُ اللّٰهِ اَكۡبَرُؕ وَاللّٰهُ يَعۡلَمُ مَا تَصۡنَعُوۡنَ","u":"تو پڑھ جو اتری تیری طرف کتاب اور قائم رکھ نماز بیشک نماز روکتی ہے بیحیائی اور بری بات سے اور اللہ کی یاد ہے سب سے بڑی اور اللہ کو خبر ہے جو تم کرتے ہو"},{"n":371,"l":"ن","t":"نکاح کے احکام","p":"2","s":"البقرہ","sn":2,"r":"27","a":"221","ar":"وَلَا تَنۡكِحُوا الۡمُشۡرِكٰتِ حَتّٰي يُؤۡمِنَّؕ وَلَاَمَةٌ مُّؤۡمِنَةٌ خَيۡرٌ مِّنۡ مُّشۡرِكَةٍ وَّلَوۡ اَعۡجَبَتۡكُمۡۚ وَلَا تُنۡكِحُوا الۡمُشۡرِكِيۡنَ حَتّٰي يُؤۡمِنُوۡاؕ وَلَعَبۡدٌ مُّؤۡمِنٌ خَيۡرٌ مِّنۡ مُّشۡرِكٍ وَّلَوۡ اَعۡجَبَكُمۡؕ اُولٰٓئِكَ يَدۡعُوۡنَ اِلَي النَّارِۚۖ وَاللّٰهُ يَدۡعُوۡ٘ا اِلَي الۡجَنَّةِ وَالۡمَغۡفِرَةِ بِاِذۡنِهٖۚ وَيُبَيِّنُ اٰيٰتِهٖ لِلنَّاسِ لَعَلَّهُمۡ يَتَذَكَّرُوۡنَ","u":"اور نکاح مت کرو مشرک عورتوں سے جب تک ایمان نہ لے آئیں اور البتہ لونڈی مسلمان بہتر ہے مشرک بی بی سے اگرچہ وہ تم کو بھلی لگے اور نکاح نہ کر دو مشرکین سے جب تک وہ ایمان نے لے آویں اور البتہ غلام مسلمان بہتر ہے مشرک سے اگرچہ وہ تم کو بھلا لگے وہ بلاتےہیں دوزخ کی طرف اور اللہ بلاتا ہے جنت کی اور بخشش کی طرف اپنے حکم سے اور بتلاتا ہے اپنے حکم لوگوں کو تاکہ وہ نصیحت قبول کریں"},{"n":372,"l":"ن","t":"نوح علیہ السلام کا قصہ","p":"29","s":"نوح","sn":71,"r":"1","a":"5-7","ar":"قَالَ رَبِّ اِنِّيۡ دَعَوۡتُ قَوۡمِيۡ لَيۡلًا وَّنَهَارًاۙ فَلَمۡ يَزِدۡهُمۡ دُعَآءِيۡ٘ اِلَّا فِرَارًا وَاِنِّيۡ كُلَّمَا دَعَوۡتُهُمۡ لِتَغۡفِرَ لَهُمۡ جَعَلُوۡ٘ا اَصَابِعَهُمۡ فِيۡ٘ اٰذَانِهِمۡ وَاسۡتَغۡشَوۡا ثِيَابَهُمۡ وَاَصَرُّوۡا وَاسۡتَكۡبَرُوا اسۡتِكۡبَارًاۚ","u":"بولا اے رب میں بلاتا رہا اپنی قوم کو رات اور دن پھرمیرے بلانے سے اور زیادہ بھاگنے لگے اور میں نے جب کبھی اُنکو بلایا تاکہ تو اُنکو بخشے ڈالنے لگے انگلیاں اپنے کانوں میں اور لپیٹنے لگے اپنے اوپر کپڑے اور ضد کی اور غرور کیا بڑا غرور"},{"n":373,"l":"ن","t":"نفاق کی علامات","p":"28","s":"المنافقون","sn":63,"r":"1","a":"1-2","ar":"اِذَا جَآءَكَ الۡمُنٰفِقُوۡنَ قَالُوۡا نَشۡهَدُ اِنَّكَ لَرَسُوۡلُ اللّٰهِۘ وَاللّٰهُ يَعۡلَمُ اِنَّكَ لَرَسُوۡلُهٗؕ وَاللّٰهُ يَشۡهَدُ اِنَّ الۡمُنٰفِقِيۡنَ لَكٰذِبُوۡنَۚ اِتَّخَذُوۡ٘ا اَيۡمَانَهُمۡ جُنَّةً فَصَدُّوۡا عَنۡ سَبِيۡلِ اللّٰهِؕ اِنَّهُمۡ سَآءَ مَا كَانُوۡا يَعۡمَلُوۡنَ","u":"جب آئیں تیرے پاس منافق کہیں ہم قائل ہیں تو رسول ہے اللہ کا اور اللہ جانتا ہے کہ تو اُس کا رسول ہے اور اللہ گواہی دیتا ہے کہ یہ منافق جھوٹے ہیں انہوں نے رکھا ہے اپنی قسموں کو ڈھال بنا کر پھر روکتے ہیں اللہ کی راہ سے یہ لوگ برے کام ہیں جو کر رہے ہیں"},{"n":374,"l":"ن","t":"نیکی کا حکم اور برائی سے روکنا","p":"4","s":"آلِ عمران","sn":3,"r":"11","a":"104","ar":"وَلۡتَكُنۡ مِّنۡكُمۡ اُمَّةٌ يَّدۡعُوۡنَ اِلَي الۡخَيۡرِ وَيَاۡمُرُوۡنَ بِالۡمَعۡرُوۡفِ وَيَنۡهَوۡنَ عَنِ الۡمُنۡكَرِؕ وَاُولٰٓئِكَ هُمُ الۡمُفۡلِحُوۡنَ","u":"اور چاہیئے کہ رہے تم میں ایک جماعت ایسی جو بلاتی رہے نیک کام کی طرف اور حکم کرتی رہے اچھے کاموں کا اور منع کریں برائی سے اور وہی پہنچے اپنی مراد کو"},{"n":375,"l":"ن","t":"نذر کے احکام","p":"29","s":"الانسان","sn":76,"r":"1","a":"7","ar":"يُوۡفُوۡنَ بِالنَّذۡرِ وَيَخَافُوۡنَ يَوۡمًا كَانَ شَرُّهٗ مُسۡتَطِيۡرًا","u":"پورا کرتے ہیں منت کو اور ڈرتے ہیں اس دن سے کہ اُسکی برائی پھیل پڑے گی"},{"n":376,"l":"ن","t":"نبوت کا تسلسل","p":"18","s":"المؤمنون","sn":23,"r":"3","a":"44","ar":"ثُمَّ اَرۡسَلۡنَا رُسُلَنَا تَتۡرَاؕ كُلَّمَا جَآءَ اُمَّةً رَّسُوۡلُهَا كَذَّبُوۡهُ فَاَتۡبَعۡنَا بَعۡضَهُمۡ بَعۡضًا وَّجَعَلۡنٰهُمۡ اَحَادِيۡثَۚ فَبُعۡدًا لِّقَوۡمٍ لَّا يُؤۡمِنُوۡنَ","u":"پھر بھیجتے رہے ہم اپنے رسول لگاتار جہاں پہنچا کسی امت کے پاس اُن کا رسول اُسکو جھٹلا دیا پھر چلاتے گئے ہیں ہم ایک کے پیچھے دوسرے اور کر ڈالا اُنکو کہانیاں سو دو ہو جائیں جو لوگ نہیں مانتے"},{"n":377,"l":"ن","t":"نعمتوں کا شکر","p":"14","s":"النحل","sn":16,"r":"2","a":"18","ar":"وَاِنۡ تَعُدُّوۡا نِعۡمَةَ اللّٰهِ لَا تُحۡصُوۡهَاؕ اِنَّ اللّٰهَ لَغَفُوۡرٌ رَّحِيۡمٌ","u":"اور اگر شمار (گنو) کرو اللہ کی نعمتوں کو نہ پورا کر سکو گے ان کو بیشک اللہ بخشنے والا مہربان ہے"},{"n":378,"l":"ن","t":"نسب اور رشتوں کا احترام","p":"19","s":"الفرقان","sn":25,"r":"5","a":"54","ar":"وَهُوَ الَّذِيۡ خَلَقَ مِنَ الۡمَآءِ بَشَرًا فَجَعَلَهٗ نَسَبًا وَّصِهۡرًاؕ وَكَانَ رَبُّكَ قَدِيۡرًا","u":"اور ہی ہے جس نے بنایا پانی سے آدمی پھر ٹھہرایا اس کے لئے جد اور سسرال اور تیرا رب سب کچھ کر سکتا ہے"},{"n":379,"l":"ن","t":"نباتات اور زراعت میں نشانیاں","p":"7","s":"الانعام","sn":6,"r":"12","a":"99","ar":"وَهُوَ الَّذِيۡ٘ اَنۡزَلَ مِنَ السَّمَآءِ مَآءًۚ فَاَخۡرَجۡنَا بِهٖ نَبَاتَ كُلِّ شَيۡءٍ فَاَخۡرَجۡنَا مِنۡهُ خَضِرًا نُّخۡرِجُ مِنۡهُ حَبًّا مُّتَرَاكِبًاۚ وَمِنَ النَّخۡلِ مِنۡ طَلۡعِهَا قِنۡوَانٌ دَانِيَةٌۙ وَّجَنّٰتٍ مِّنۡ اَعۡنَابٍ وَّالزَّيۡتُوۡنَ وَالرُّمَّانَ مُشۡتَبِهًا وَّغَيۡرَ مُتَشَابِهٍؕ اُنۡظُرُوۡ٘ا اِلٰي ثَمَرِهٖ٘ اِذَا٘ اَثۡمَرَ وَيَنۡعِهٖؕ اِنَّ فِيۡ ذٰلِكُمۡ لَاٰيٰتٍ لِّقَوۡمٍ يُّؤۡمِنُوۡنَ","u":"اور اسی نے اتارا آسمان سے پانی پھر نکالی ہم نے اس سے اگنے والی ہر چیز پھر نکالی اس میں سے سبز کھیتی جس سے ہم نکالتے ہیں دانے ایک پر ایک چڑھا ہوا اور کھجور کے گابھے میں سے پھل کے گچھے جھکے ہوئے اور باغ انگور کے اور زیتون کے اور انار کے آپس میں ملتے جلتے اور جدا جدا بھی دیکھو ہر ایک درخت کے پھل کو جب وہ پھل لاتا ہے اور اسکے پکنے کو ان چیزوں میں نشانیاں ہیں واسطے ایمان والوں کے"},{"n":380,"l":"ن","t":"نرمی اور حسنِ خلق سے دعوت","p":"4","s":"آلِ عمران","sn":3,"r":"17","a":"159","ar":"فَبِمَا رَحۡمَةٍ مِّنَ اللّٰهِ لِنۡتَ لَهُمۡۚ وَلَوۡ كُنۡتَ فَظًّا غَلِيۡظَ الۡقَلۡبِ لَانۡفَضُّوۡا مِنۡ حَوۡلِكَ فَاعۡفُ عَنۡهُمۡ وَاسۡتَغۡفِرۡ لَهُمۡ وَشَاوِرۡهُمۡ فِي الۡاَمۡرِۚ فَاِذَا عَزَمۡتَ فَتَوَكَّلۡ عَلَي اللّٰهِؕ اِنَّ اللّٰهَ يُحِبُّ الۡمُتَوَكِّلِيۡنَ","u":"سو کچھ اللہ ہی کی رحمت ہے جو تو نرم دل مل گیا ان کو اور اگر تو ہوتا تندخو سخت دل تو متفرق ہو جاتے تیرے پاس سے سو تو ان کو معاف کر اور ان کے واسطے بخشش مانگ اور ان سے مشورہ لے کام میں پھر جب قصد کر چکا تو اس کام کا تو پھر بھروسہ کر اللہ پر اللہ کو محبت ہے توکل والوں سے"},{"n":381,"l":"ن","t":"نیک اعمال کی قبولیت کی شرائط","p":"16","s":"الکہف","sn":18,"r":"12","a":"110","ar":"قُلۡ اِنَّمَا٘ اَنَا بَشَرٌ مِّثۡلُكُمۡ يُوۡحٰ٘ي اِلَيَّ اَنَّمَا٘ اِلٰهُكُمۡ اِلٰهٌ وَّاحِدٌۚ فَمَنۡ كَانَ يَرۡجُوۡا لِقَآءَ رَبِّهٖ فَلۡيَعۡمَلۡ عَمَلًا صَالِحًا وَّلَا يُشۡرِكۡ بِعِبَادَةِ رَبِّهٖ٘ اَحَدًا","u":"تو کہہ میں بھی ایک آدمی ہوں جیسے تم حکم آتا ہے مجھ کو کہ معبود تمہارا ایک معبود ہے سو پھر جس کو امید ہو ملنے کی اپنے رب سے سوہ وہ کرے کچھ کام نیک اور شریک نہ کرے اپنے رب کی بندگی میں کسی کو"},{"n":382,"l":"ن","t":"نسلِ انسانی کی وحدت","p":"4","s":"النساء","sn":4,"r":"1","a":"1","ar":"يٰ٘اَيُّهَا النَّاسُ اتَّقُوۡا رَبَّكُمُ الَّذِيۡ خَلَقَكُمۡ مِّنۡ نَّفۡسٍ وَّاحِدَةٍ وَّخَلَقَ مِنۡهَا زَوۡجَهَا وَبَثَّ مِنۡهُمَا رِجَالًا كَثِيۡرًا وَّنِسَآءًۚ وَاتَّقُوا اللّٰهَ الَّذِيۡ تَسَآءَلُوۡنَ بِهٖ وَالۡاَرۡحَامَؕ اِنَّ اللّٰهَ كَانَ عَلَيۡكُمۡ رَقِيۡبًا","u":"اے لوگو ڈرتے رہو اپنے رب سے جس نے پیدا کیا تم کو ایک جان سے اور اسی سے پیدا کیا اس کا جوڑا اور پھیلائے ان دونوں سے بہت مرد اور عورتیں اور ڈرتے رہو اللہ سے جس کے واسطے سے سوال کرتے ہو آپس میں اور خبردار رہو قرابت والوں سے بیشک اللہ تم پر نگہبان ہے"},{"n":383,"l":"ن","t":"نورِ ہدایت","p":"18","s":"النور","sn":24,"r":"5","a":"35","ar":"اَللّٰهُ نُوۡرُ السَّمٰوٰتِ وَالۡاَرۡضِؕ مَثَلُ نُوۡرِهٖ كَمِشۡكٰوةٍ فِيۡهَا مِصۡبَاحٌؕ اَلۡمِصۡبَاحُ فِيۡ زُجَاجَةٍؕ اَلزُّجَاجَةُ كَاَنَّهَا كَوۡكَبٌ دُرِّيٌّ يُّوۡقَدُ مِنۡ شَجَرَةٍ مُّبٰرَكَةٍ زَيۡتُوۡنَةٍ لَّا شَرۡقِيَّةٍ وَّلَا غَرۡبِيَّةٍۙ يَّكَادُ زَيۡتُهَا يُضِيۡٓءُ وَلَوۡ لَمۡ تَمۡسَسۡهُ نَارٌؕ نُوۡرٌ عَلٰي نُوۡرٍؕ يَهۡدِي اللّٰهُ لِنُوۡرِهٖ مَنۡ يَّشَآءُؕ وَيَضۡرِبُ اللّٰهُ الۡاَمۡثَالَ لِلنَّاسِؕ وَاللّٰهُ بِكُلِّ شَيۡءٍ عَلِيۡمٌۙ","u":"اللہ روشنی ہے آسمانوں اور زمین کی مثال اس کی روشنی کی جیسے ایک طاق اس میں ہو ایک چراغ وہ چراغ دھرا ہو ایک شیشہ میں وہ شیشہ ہے جیسے ایک تارہ چمکتا ہوا تیل جلتا ہے اس میں ایک برکت کے درخت کا وہ زیتون ہے نہ مشرق کی طرف ہے اور نہ مغرب کی طرف قریب ہے اس کا تیل کہ روشن ہو جائے اگرچہ نہ لگی ہو اس میں آگ روشنی پر روشنی اللہ راہ دکھلا دیتا ہے اپنی روشنی کی جس کو چاہے اور بیان کرتا ہے اللہ مثالیں لوگوں کے واسطے اور اللہ سب چیز کو جانتا ہے"},{"n":384,"l":"ن","t":"نیتوں کا اعتبار","p":"30","s":"البینہ","sn":98,"r":"1","a":"5","ar":"وَمَا٘ اُمِرُوۡ٘ا اِلَّا لِيَعۡبُدُوا اللّٰهَ مُخۡلِصِيۡنَ لَهُ الدِّيۡنَ ۙ حُنَفَآءَ وَيُقِيۡمُوا الصَّلٰوةَ وَيُؤۡتُوا الزَّكٰوةَ وَذٰلِكَ دِيۡنُ الۡقَيِّمَةِؕ","u":"اور انکو حکم یہی ہوا کہ بندگی کریں اللہ کی خالص کر کے اُسکے واسطے بندگی ابراہیم کی راہ پر اور قائم رکھیں نماز اور دیں زکوٰۃ اور یہ ہے راہ مضبوط لوگوں کی"},{"n":385,"l":"ن","t":"ناپ تول میں کمی کی ممانعت","p":"27","s":"الرحمٰن","sn":55,"r":"1","a":"8-9","ar":"اَلَّا تَطۡغَوۡا فِي الۡمِيۡزَانِ وَاَقِيۡمُوا الۡوَزۡنَ بِالۡقِسۡطِ وَلَا تُخۡسِرُوا الۡمِيۡزَانَ","u":"کہ زیادتی نہ کرو ترازو میں اور سیدھی ترازو تولو انصاف سے اور مت گھٹاؤ تول کو"},{"n":386,"l":"ن","t":"نیکی میں سبقت لے جانا","p":"27","s":"الحدید","sn":57,"r":"3","a":"21","ar":"سَابِقُوۡ٘ا اِلٰي مَغۡفِرَةٍ مِّنۡ رَّبِّكُمۡ وَجَنَّةٍ عَرۡضُهَا كَعَرۡضِ السَّمَآءِ وَالۡاَرۡضِۙ اُعِدَّتۡ لِلَّذِيۡنَ اٰمَنُوۡا بِاللّٰهِ وَرُسُلِهٖؕ ذٰلِكَ فَضۡلُ اللّٰهِ يُؤۡتِيۡهِ مَنۡ يَّشَآءُؕ وَاللّٰهُ ذُو الۡفَضۡلِ الۡعَظِيۡمِ","u":"دوڑو اپنے رب کی معافی کی طرف کو اور بہشت کو جس کا پھیلاؤ ہے جیسے پھیلاؤ آسمان اور زمین کا تیار رکھی ہے واسطے اُنکے جو یقین لائے اللہ پر اور اسکے رسولوں پر یہ فضل اللہ کا ہے دے اُسکو جسکو چاہے اور اللہ کا فضل بڑا ہے"},{"n":387,"l":"ن","t":"نیک ساتھیوں کی صحبت","p":"15","s":"الکہف","sn":18,"r":"4","a":"28","ar":"وَاصۡبِرۡ نَفۡسَكَ مَعَ الَّذِيۡنَ يَدۡعُوۡنَ رَبَّهُمۡ بِالۡغَدٰوةِ وَالۡعَشِيِّ يُرِيۡدُوۡنَ وَجۡهَهٗ وَلَا تَعۡدُ عَيۡنٰكَ عَنۡهُمۡۚ تُرِيۡدُ زِيۡنَةَ الۡحَيٰوةِ الدُّنۡيَاۚ وَلَا تُطِعۡ مَنۡ اَغۡفَلۡنَا قَلۡبَهٗ عَنۡ ذِكۡرِنَا وَاتَّبَعَ هَوٰىهُ وَكَانَ اَمۡرُهٗ فُرُطًا","u":"اور روکے رکھ اپنے آپ کو ان کے ساتھ جو پکارتے ہیں اپنے رب کو صبح اور شام طالب ہیں اسکے منہ کے اور نہ دوڑیں تیری آنکھیں انکو چھوڑ کر تلاش میں رونق زندگانی دنیا کی اور نہ کہا مان اس کا جس کا دل غافل کیا ہم نے اپنی یاد سے اور پیچھے پڑا ہوا ہے اپنی خوشی کے اور اس کا کام ہے حد پر نہ رہنا"},{"n":388,"l":"و","t":"وراثت کی منصفانہ تقسیم","p":"4","s":"النساء","sn":4,"r":"2","a":"12","ar":"وَلَكُمۡ نِصۡفُ مَا تَرَكَ اَزۡوَاجُكُمۡ اِنۡ لَّمۡ يَكُنۡ لَّهُنَّ وَلَدٌۚ فَاِنۡ كَانَ لَهُنَّ وَلَدٌ فَلَكُمُ الرُّبُعُ مِمَّا تَرَكۡنَ مِنۭۡ بَعۡدِ وَصِيَّةٍ يُّوۡصِيۡنَ بِهَا٘ اَوۡ دَيۡنٍؕ وَلَهُنَّ الرُّبُعُ مِمَّا تَرَكۡتُمۡ اِنۡ لَّمۡ يَكُنۡ لَّكُمۡ وَلَدٌۚ فَاِنۡ كَانَ لَكُمۡ وَلَدٌ فَلَهُنَّ الثُّمُنُ مِمَّا تَرَكۡتُمۡ مِّنۭۡ بَعۡدِ وَصِيَّةٍ تُوۡصُوۡنَ بِهَا٘ اَوۡ دَيۡنٍؕ وَاِنۡ كَانَ رَجُلٌ يُّوۡرَثُ كَلٰلَةً اَوِ امۡرَاَةٌ وَّلَهٗ٘ اَخٌ اَوۡ اُخۡتٌ فَلِكُلِّ وَاحِدٍ مِّنۡهُمَا السُّدُسُۚ فَاِنۡ كَانُوۡ٘ا اَكۡثَرَ مِنۡ ذٰلِكَ فَهُمۡ شُرَكَآءُ فِي الثُّلُثِ مِنۭۡ بَعۡدِ وَصِيَّةٍ يُّوۡصٰي بِهَا٘ اَوۡ دَيۡنٍۙ غَيۡرَ مُضَآرٍّۚ وَصِيَّةً مِّنَ اللّٰهِؕ وَاللّٰهُ عَلِيۡمٌ حَلِيۡمٌؕ","u":"اور تمہارا ہے آدھا مال جو کہ چھوڑ مریں تمہاری عورتیں اگر نہ ہو ان کے اولاد اور اگر ان کےاولاد ہے تو تمہارے واسطے چوتھائی ہے اس میں سے جو چھوڑ گئیں بعد وصیت کے جو کر گئیں یا بعد قرض کے اور عورتوں کے لئے چوتھائی مال ہے اس میں سے جو چھوڑ مرو تم اگر نہ ہو تمہارے اولاد اور اگر تمہارے اولاد ہے تو ان کے لئے آٹھواں حصہ ہے اس میں سے کہ جو کچھ تم نے چھوڑا بعد وصیت کے جو تم کر مرو یا قرض کے اور اگر وہ مرد کہ جس کی میراث ہے باپ بیٹا کچھ نہیں رکھتا یا عورت ہو ایسی ہی اور اس میت کے ایک بھائی ہے یا بہن ہے تودونوں میں سے ہر ایک کا چھٹا حصہ ہے اور اگر زیادہ ہوں اس سے تو سب شریک ہیں ایک تہائی میں بعد وصیت کے جو ہو چکی ہے یا قرض کے جب اوروں کا نقصان نہ کیا ہو یہ حکم ہے اللہ کا اور اللہ ہی سب کچھ جاننے والا تحمل کرنے والا"},{"n":389,"l":"و","t":"وعدہ خلافی کی ممانعت","p":"1","s":"البقرہ","sn":2,"r":"3","a":"27","ar":"الَّذِيۡنَ يَنۡقُضُوۡنَ عَهۡدَ اللّٰهِ مِنۭۡ بَعۡدِ مِيۡثَاقِهٖ وَيَقۡطَعُوۡنَ مَا٘ اَمَرَ اللّٰهُ بِهٖ٘ اَنۡ يُّوۡصَلَ وَيُفۡسِدُوۡنَ فِي الۡاَرۡضِؕ اُولٰٓئِكَ هُمُ الۡخٰسِرُوۡنَ","u":"جو توڑتے ہیں خدا کے معاہدہ کو مضبوط کرنے کے بعد اور قطع کرتے ہیں اس چیز کو جس کو اللہ نے فرمایا ملانے کو اور فساد کرتے ہیں ملک میں وہی ہیں ٹوٹے والے"},{"n":390,"l":"و","t":"وحدتِ امت کی دعوت","p":"4","s":"آلِ عمران","sn":3,"r":"11","a":"103","ar":"وَاعۡتَصِمُوۡا بِحَبۡلِ اللّٰهِ جَمِيۡعًا وَّلَا تَفَرَّقُوۡا وَاذۡكُرُوۡا نِعۡمَتَ اللّٰهِ عَلَيۡكُمۡ اِذۡ كُنۡتُمۡ اَعۡدَآءً فَاَلَّفَ بَيۡنَ قُلُوۡبِكُمۡ فَاَصۡبَحۡتُمۡ بِنِعۡمَتِهٖ٘ اِخۡوَانًاۚ وَكُنۡتُمۡ عَلٰي شَفَا حُفۡرَةٍ مِّنَ النَّارِ فَاَنۡقَذَكُمۡ مِّنۡهَاؕ كَذٰلِكَ يُبَيِّنُ اللّٰهُ لَكُمۡ اٰيٰتِهٖ لَعَلَّكُمۡ تَهۡتَدُوۡنَ","u":"اور مضبوط پکڑو رسی اللہ کی سب مل کر اور پھوٹ نہ ڈالو اور یاد کرو احسان اللہ کا اپنے اوپر جب کہ تھے تم آپس میں دشمن پھر الفت دی تمہارے دلوں میں اب ہو گئے اس کے فضل سے بھائی اور تم تھے کنارے پر ایک آگ کے گڑھے کے پھر تم کو اس سے نجات دی اسی طرح کھولتا ہے اللہ تم پر آیتیں تاکہ تم راہ پاؤ"},{"n":391,"l":"و","t":"وضو کے احکام","p":"6","s":"المائدہ","sn":5,"r":"2","a":"6","ar":"يٰ٘اَيُّهَا الَّذِيۡنَ اٰمَنُوۡ٘ا اِذَا قُمۡتُمۡ اِلَي الصَّلٰوةِ فَاغۡسِلُوۡا وُجُوۡهَكُمۡ وَاَيۡدِيَكُمۡ اِلَي الۡمَرَافِقِ وَامۡسَحُوۡا بِرُءُوۡسِكُمۡ وَاَرۡجُلَكُمۡ اِلَي الۡكَعۡبَيۡنِؕ وَاِنۡ كُنۡتُمۡ جُنُبًا فَاطَّهَّرُوۡاؕ وَاِنۡ كُنۡتُمۡ مَّرۡضٰ٘ي اَوۡ عَلٰي سَفَرٍ اَوۡ جَآءَ اَحَدٌ مِّنۡكُمۡ مِّنَ الۡغَآئِطِ اَوۡ لٰمَسۡتُمُ النِّسَآءَ فَلَمۡ تَجِدُوۡا مَآءً فَتَيَمَّمُوۡا صَعِيۡدًا طَيِّبًا فَامۡسَحُوۡا بِوُجُوۡهِكُمۡ وَاَيۡدِيۡكُمۡ مِّنۡهُؕ مَا يُرِيۡدُ اللّٰهُ لِيَجۡعَلَ عَلَيۡكُمۡ مِّنۡ حَرَجٍ وَّلٰكِنۡ يُّرِيۡدُ لِيُطَهِّرَكُمۡ وَلِيُتِمَّ نِعۡمَتَهٗ عَلَيۡكُمۡ لَعَلَّكُمۡ تَشۡكُرُوۡنَ","u":"اے ایمان والو جب تم اٹھو نماز کو تو دھو لو اپنے منہ اور ہاتھ کہنیوں تک اور مل لو اپنے سر کو اور پاؤں ٹخنوں تک اور اگر تم کو جنابت ہو تو خوب طرح پاک ہو اور اگر تم بیمار ہو یا سفر میں یا کوئی تم میں آیا ہے جائے ضرور سے یا پاس گئے ہو عورتوں کے پھر نہ پاؤ تم پانی تو قصد کرو مٹی پاک کا اور مل لو اپنے منہ اور ہاتھ اس سے اللہ نہیں چاہتا کہ تم پر تنگی کرے لیکن چاہتا ہے کہ تم کو پاک کرے اور پورا کرے اپنا احسان تم پر تاکہ تم احسان مانو"},{"n":392,"l":"و","t":"وقت کی اہمیت (سورۃ العصر کی روشنی میں)","p":"30","s":"العصر","sn":103,"r":"1","a":"1-3","ar":"وَالۡعَصۡرِۙ اِنَّ الۡاِنۡسَانَ لَفِيۡ خُسۡرٍۙ اِلَّا الَّذِيۡنَ اٰمَنُوۡا وَعَمِلُوا الصّٰلِحٰتِ وَتَوَاصَوۡا بِالۡحَقِّ ۙ وَتَوَاصَوۡا بِالصَّبۡرِ","u":"قسم ہے عصر کی مقرر انسان ٹوٹے میں ہے مگر جو لوگ کہ یقین لائے اور کئے بھلے کام اور آپس میں تاکید کرتے رہے سچے دین کی اور آپس میں تاکید کرتے رہے تحمل کی"},{"n":393,"l":"و","t":"وصیت کے احکام","p":"2","s":"البقرہ","sn":2,"r":"22","a":"180","ar":"كُتِبَ عَلَيۡكُمۡ اِذَا حَضَرَ اَحَدَكُمُ الۡمَوۡتُ اِنۡ تَرَكَ خَيۡرَاۚۖ اِۨلۡوَصِيَّةُ لِلۡوَالِدَيۡنِ وَالۡاَقۡرَبِيۡنَ بِالۡمَعۡرُوۡفِۚ حَقًّا عَلَي الۡمُتَّقِيۡنَؕ","u":"فرض کر دیا گیا تم پر جب حاضر ہو کسی کو تم میں موت بشرطیکہ چھوڑے کچھ مال وصیت کرنا ماں باپ کے واسطے اور رشتہ داروں کےلئے انصاف کے ساتھ یہ حکم لازم ہے پرہیز گاروں پر"},{"n":394,"l":"و","t":"والدین کی نافرمانی کی مذمت","p":"15","s":"بنی اسرائیل (الاسراء)","sn":17,"r":"3","a":"23","ar":"وَقَضٰي رَبُّكَ اَلَّا تَعۡبُدُوۡ٘ا اِلَّا٘ اِيَّاهُ وَبِالۡوَالِدَيۡنِ اِحۡسَانًاؕ اِمَّا يَبۡلُغَنَّ عِنۡدَكَ الۡكِبَرَ اَحَدُهُمَا٘ اَوۡ كِلٰهُمَا فَلَا تَقُلۡ لَّهُمَا٘ اُفٍّ وَّلَا تَنۡهَرۡهُمَا وَقُلۡ لَّهُمَا قَوۡلًا كَرِيۡمًا","u":"اور حکم کر چکا تیرا رب کہ نہ پوجو اس کے سوائے اور ماں باپ کے ساتھ بھلائی کرو اگر پہنچ جائے تیرے سامنے بڑھاپے کو ایک ان میں سے یا دونوں تو نہ کہہ ان کو ہوں اور نہ جھڑک ان کو اور کہہ ان سے بات ادب کی"},{"n":395,"l":"و","t":"وعدہ پورا کرنے کی تاکید","p":"15","s":"بنی اسرائیل (الاسراء)","sn":17,"r":"4","a":"34","ar":"وَلَا تَقۡرَبُوۡا مَالَ الۡيَتِيۡمِ اِلَّا بِالَّتِيۡ هِيَ اَحۡسَنُ حَتّٰي يَبۡلُغَ اَشُدَّهٗ وَاَوۡفُوۡا بِالۡعَهۡدِۚ اِنَّ الۡعَهۡدَ كَانَ مَسۡـُٔوۡلًا","u":"اور پاس نہ جاؤ یتیم کے مال کے مگر جس طرح کہ بہتر ہو جب تک کہ وہ پہنچے اپنی جوانی کو اور پورا کرو عہد کو بیشک عہد کی پوچھ ہو گی"},{"n":396,"l":"و","t":"وقتِ نزاع میں صبر","p":"5","s":"النساء","sn":4,"r":"8","a":"59","ar":"يٰ٘اَيُّهَا الَّذِيۡنَ اٰمَنُوۡ٘ا اَطِيۡعُوا اللّٰهَ وَاَطِيۡعُوا الرَّسُوۡلَ وَاُولِي الۡاَمۡرِ مِنۡكُمۡۚ فَاِنۡ تَنَازَعۡتُمۡ فِيۡ شَيۡءٍ فَرُدُّوۡهُ اِلَي اللّٰهِ وَالرَّسُوۡلِ اِنۡ كُنۡتُمۡ تُؤۡمِنُوۡنَ بِاللّٰهِ وَالۡيَوۡمِ الۡاٰخِرِؕ ذٰلِكَ خَيۡرٌ وَّاَحۡسَنُ تَاۡوِيۡلًا","u":"اے ایمان والو حکم مانو اللہ کا اور حکم مانو رسول کا اور حاکموں کا جو تم میں سے ہوں پھر اگر جھگڑ پڑو کسی چیز میں تو اس کو رجوع کرو طرف اللہ کے اور رسول کے اگر یقین رکھتے ہو اللہ پر اور قیامت کے دن پر یہ بات اچھی ہے اور بہت بہتر ہے اس کا انجام"},{"n":397,"l":"و","t":"وفاتِ انبیاء کا تذکرہ","p":"4","s":"آلِ عمران","sn":3,"r":"15","a":"144","ar":"وَمَا مُحَمَّدٌ اِلَّا رَسُوۡلٌۚ قَدۡ خَلَتۡ مِنۡ قَبۡلِهِ الرُّسُلُؕ اَفَا۠ئِنۡ مَّاتَ اَوۡ قُتِلَ انۡقَلَبۡتُمۡ عَلٰ٘ي اَعۡقَابِكُمۡؕ وَمَنۡ يَّنۡقَلِبۡ عَلٰي عَقِبَيۡهِ فَلَنۡ يَّضُرَّ اللّٰهَ شَيۡـًٔاؕ وَسَيَجۡزِي اللّٰهُ الشّٰكِرِيۡنَ","u":"اور محمد تو ایک رسول ہے ہو چکے اس سے پہلے بہت رسول پھر کیا اگر وہ مر گیا یا مارا گیا تو تم پھر جاؤ گے الٹے پاؤں اور جو کوئی پھر جائے گا الٹے پاؤں تو ہر گز نہ بگاڑے گا اللہ کا کچھ اور اللہ ثواب دے گا شکر گذاروں کو"},{"n":398,"l":"و","t":"وحی کا نزول اور مقصد","p":"25","s":"الشوریٰ","sn":42,"r":"5","a":"51-52","ar":"وَمَا كَانَ لِبَشَرٍ اَنۡ يُّكَلِّمَهُ اللّٰهُ اِلَّا وَحۡيًا اَوۡ مِنۡ وَّرَآئِ حِجَابٍ اَوۡ يُرۡسِلَ رَسُوۡلًا فَيُوۡحِيَ بِاِذۡنِهٖ مَا يَشَآءُؕ اِنَّهٗ عَلِيٌّ حَكِيۡمٌ وَكَذٰلِكَ اَوۡحَيۡنَا٘ اِلَيۡكَ رُوۡحًا مِّنۡ اَمۡرِنَاؕ مَا كُنۡتَ تَدۡرِيۡ مَا الۡكِتٰبُ وَلَا الۡاِيۡمَانُ وَلٰكِنۡ جَعَلۡنٰهُ نُوۡرًا نَّهۡدِيۡ بِهٖ مَنۡ نَّشَآءُ مِنۡ عِبَادِنَاؕ وَاِنَّكَ لَتَهۡدِيۡ٘ اِلٰي صِرَاطٍ مُّسۡتَقِيۡمٍۙ","u":"اور کسی آدمی کی طاقت نہیں کہ اس سے باتیں کرے اللہ مگر اشارہ سے یا پردہ کے پیچھے سے یا بھیجے کوئی پیغما لانے والا پھر پہنچا دے اسکے حکم سے جو ہو چاہے تحقیقی وہ سب سے اوپر ہے حکمتوں والا اور اسی طح بھیجا ہم نے تیری طف ایک فرشتہ اپجے حکم سے تو نہ جانتا تھا کہ کیا ہے کتاب اور نہ ایمان ولیکن ہم نے رکھی ہے یہ روشنی اس سے راہ سجھا دیتے ہیں جسکو چاہیں اپنے بندوں میں اور بیشک تو سجھاتا ہے سیدھی راہ"},{"n":399,"l":"و","t":"وعدۂ آخرت پر یقین","p":"26","s":"قٓ","sn":50,"r":"2","a":"20-22","ar":"وَنُفِخَ فِي الصُّوۡرِؕ ذٰلِكَ يَوۡمُ الۡوَعِيۡدِ وَجَآءَتۡ كُلُّ نَفۡسٍ مَّعَهَا سَآئِقٌ وَّشَهِيۡدٌ لَقَدۡ كُنۡتَ فِيۡ غَفۡلَةٍ مِّنۡ هٰذَا فَكَشَفۡنَا عَنۡكَ غِطَآءَكَ فَبَصَرُكَ الۡيَوۡمَ حَدِيۡدٌ","u":"اور پھونکا گیا صور یہ ہے دن ڈرانے کا اور آیا ہر ایک جی اس کے ساتھ ہے ایک ہانکنے والا ایک احوال بتانے والا تو بیخبر رہا اس دن سے اب کھول دی ہے ہم نے تجھ پر سے تیری اندھیری سو تیری نگاہ آج تیز ہے"},{"n":400,"l":"و","t":"وسوسۂ شیطانی سے بچاؤ","p":"9","s":"الاعراف","sn":7,"r":"24","a":"201","ar":"اِنَّ الَّذِيۡنَ اتَّقَوۡا اِذَا مَسَّهُمۡ طٰٓئِفٌ مِّنَ الشَّيۡطٰنِ تَذَكَّرُوۡا فَاِذَا هُمۡ مُّبۡصِرُوۡنَۚ","u":"جن کے دل میں ڈر ہے جہاں پڑ گیا ان پر شیطان کا گذر چونک گئے پھر اسی وقت ان کو سوجھ آ جاتی ہے"},{"n":401,"l":"ہ","t":"ہجرت کا حکم اور فضیلت","p":"5","s":"النساء","sn":4,"r":"14","a":"100","ar":"وَمَنۡ يُّهَاجِرۡ فِيۡ سَبِيۡلِ اللّٰهِ يَجِدۡ فِي الۡاَرۡضِ مُرٰغَمًا كَثِيۡرًا وَّسَعَةًؕ وَمَنۡ يَّخۡرُجۡ مِنۭۡ بَيۡتِهٖ مُهَاجِرًا اِلَي اللّٰهِ وَرَسُوۡلِهٖ ثُمَّ يُدۡرِكۡهُ الۡمَوۡتُ فَقَدۡ وَقَعَ اَجۡرُهٗ عَلَي اللّٰهِؕ وَكَانَ اللّٰهُ غَفُوۡرًا رَّحِيۡمًا","u":"اور جو کوئی وطن چھوڑے اللہ کی راہ میں پاوے گا اس کے مقابلہ میں جگہ بہت اور کشائش اور جو کوئی نکلے اپنے گھر سے ہجرت کر کے اللہ اور رسول کی طرف پھر آ پکڑے اس کو موت تو مقرر ہو چکا اس کا ثواب اللہ کے ہاں اور ہے اللہ بخشنے والا مہربان"},{"n":402,"l":"ہ","t":"ہاروت و ماروت کا تذکرہ","p":"1","s":"البقرہ","sn":2,"r":"12","a":"102","ar":"وَاتَّبَعُوۡا مَا تَتۡلُوا الشَّيٰطِيۡنُ عَلٰي مُلۡكِ سُلَيۡمٰنَۚ وَمَا كَفَرَ سُلَيۡمٰنُ وَلٰكِنَّ الشَّيٰطِيۡنَ كَفَرُوۡا يُعَلِّمُوۡنَ النَّاسَ السِّحۡرَ وَمَا٘ اُنۡزِلَ عَلَي الۡمَلَكَيۡنِ بِبَابِلَ هَارُوۡتَ وَمَارُوۡتَؕ وَمَا يُعَلِّمٰنِ مِنۡ اَحَدٍ حَتّٰي يَقُوۡلَا٘ اِنَّمَا نَحۡنُ فِتۡنَةٌ فَلَا تَكۡفُرۡؕ فَيَتَعَلَّمُوۡنَ مِنۡهُمَا مَا يُفَرِّقُوۡنَ بِهٖ بَيۡنَ الۡمَرۡءِ وَزَوۡجِهٖؕ وَمَا هُمۡ بِضَآرِّيۡنَ بِهٖ مِنۡ اَحَدٍ اِلَّا بِاِذۡنِ اللّٰهِؕ وَيَتَعَلَّمُوۡنَ مَا يَضُرُّهُمۡ وَلَا يَنۡفَعُهُمۡؕ وَلَقَدۡ عَلِمُوۡا لَمَنِ اشۡتَرٰىهُ مَا لَهٗ فِي الۡاٰخِرَةِ مِنۡ خَلَاقٍؕ وَلَبِئۡسَ مَا شَرَوۡا بِهٖ٘ اَنۡفُسَهُمۡؕ لَوۡ كَانُوۡا يَعۡلَمُوۡنَ","u":"اور پیچھے ہو لئے اس علم کے جو پڑتے تھے شیطان سلیمان کی بادشاہت کے وقت اور کفر نہیں کیا سلیمان نے لیکن شیطانوں نے کفر کیا کہ سکھلاتے تھے لوگوں کو جادو اور اس علم کے پیچھے ہو لئے جو اترا دو فرشتوں پر شہر بابل میں جن کا نام ہاروت اور ماروت ہے اور نہیں سکھاتے تھے وہ دونوں فرشتے کسی کو جب تک یہ نہ کہدیتے کہ ہم تو آزمائش کے لئے ہیں سو تو کافر مت ہو پھر ان سے سیکھتے وہ جادو جس سے جدائی ڈالتے ہیں مرد میں اور اسکی عورت میں اور وہ اس سے نقصان نہیں کر سکتے کس کا بغیر حکم اللہ کے اور سیکھتے ہیں وہ چیز جو نقصان کرے ان کا اور فائدہ نہ کرے اور وہ خوب جان چکے ہیں کہ جس نے اختیار کیا جادو کو نہیں اس کے لئے آخرت میں کچھ حصہ اور بہت ہی بری چیز ہے جسکے بدلے بیچا انہوں نے اپنے آپکو اگر ان کو سمجھ ہوتی"},{"n":403,"l":"ہ","t":"ہدایت کا راستہ","p":"1","s":"البقرہ","sn":2,"r":"1","a":"2","ar":"ذٰلِكَ الۡكِتٰبُ لَا رَيۡبَۛۚۖ فِيۡهِۛۚ هُدًي لِّلۡمُتَّقِيۡنَۙ","u":"اس کتاب میں کچھ شک نہیں راہ بتلاتی ہے ڈرنے والوں کو"},{"n":404,"l":"ہ","t":"ہود علیہ السلام کا قصہ","p":"8","s":"الاعراف","sn":7,"r":"9","a":"65","ar":"وَاِلٰي عَادٍ اَخَاهُمۡ هُوۡدًاؕ قَالَ يٰقَوۡمِ اعۡبُدُوا اللّٰهَ مَا لَكُمۡ مِّنۡ اِلٰهٍ غَيۡرُهٗؕ اَفَلَا تَتَّقُوۡنَ","u":"اور قوم عاد کی طرف بھیجا انکے بھائی ہود کو بولا اے میری قوم بندگی کرو اللہ کی کوئی نہیں تمہارا معبود اسکے سوا سو کیا تم ڈرتے نہیں"},{"n":405,"l":"ہ","t":"ہمسائیگی کے حقوق","p":"5","s":"النساء","sn":4,"r":"6","a":"36","ar":"وَاعۡبُدُوا اللّٰهَ وَلَا تُشۡرِكُوۡا بِهٖ شَيۡـًٔا وَّبِالۡوَالِدَيۡنِ اِحۡسَانًا وَّبِذِي الۡقُرۡبٰي وَالۡيَتٰمٰي وَالۡمَسٰكِيۡنِ وَالۡجَارِ ذِي الۡقُرۡبٰي وَالۡجَارِ الۡجُنُبِ وَالصَّاحِبِ بِالۡجَنۭۡ بِ وَابۡنِ السَّبِيۡلِۙ وَمَا مَلَكَتۡ اَيۡمَانُكُمۡؕ اِنَّ اللّٰهَ لَا يُحِبُّ مَنۡ كَانَ مُخۡتَالًا فَخُوۡرَاۙ","u":"اور بندگی کرو اللہ کی اور شریک نہ کرو اس کا کسی کو اور ماں باپ کے ساتھ نیکی کرو اور قرابت والوں کے ساتھ اور یتیموں اور فقیروں اور ہمسایہ قریب اور ہمسایہ اجنبی اور پاس بیٹھنے والےاور مسافر کے ساتھ اور اپنے ہاتھ کے مال یعنی غلام باندیوں کے ساتھ بیشک اللہ کو پسند نہیں آتا اترانے والا بڑائی کرنے والا"},{"n":406,"l":"ہ","t":"ہجرتِ حبشہ کا پسِ منظر","p":"14","s":"النحل","sn":16,"r":"6","a":"41","ar":"وَالَّذِيۡنَ هَاجَرُوۡا فِي اللّٰهِ مِنۭۡ بَعۡدِ مَا ظُلِمُوۡا لَنُبَوِّئَنَّهُمۡ فِي الدُّنۡيَا حَسَنَةًؕ وَلَاَجۡرُ الۡاٰخِرَةِ اَكۡبَرُۘ لَوۡ كَانُوۡا يَعۡلَمُوۡنَۙ","u":"اور جنہوں نے گھر چھوڑا اللہ کے واسطے بعد اس کے کہ ظلم اٹھایا البتہ انکو ہم ٹھکانا دیں گے دنیا میں اچھا اور ثواب آخرت کا تو بہت بڑا ہے اگر ان کو معلوم ہوتا"},{"n":407,"l":"ہ","t":"ہلاکت خیز اقوام کا انجام (عاد و ثمود)","p":"29","s":"الحاقہ","sn":69,"r":"1","a":"6-8","ar":"وَاَمَّا عَادٌ فَاُهۡلِكُوۡا بِرِيۡحٍ صَرۡصَرٍ عَاتِيَةٍۙ سَخَّرَهَا عَلَيۡهِمۡ سَبۡعَ لَيَالٍ وَّثَمٰنِيَةَ اَيَّامٍۙ حُسُوۡمًا فَتَرَي الۡقَوۡمَ فِيۡهَا صَرۡعٰيۙ كَاَنَّهُمۡ اَعۡجَازُ نَخۡلٍ خَاوِيَةٍۚ فَهَلۡ تَرٰي لَهُمۡ مِّنۭۡ بَاقِيَةٍ","u":"اور وہ جو عاد تھے سو برباد ہوئے ٹھنڈی سناٹے کی ہوا سے نکلی جائے ہاتھوں سے مقرر کر دیا اُسکو اُن پر سات رات اور آٹھ دن تک لگاتار پھر تو دیکھے کہ وہ لوگ اُس میں بچھڑ گئے گویا وہ ڈھنڈ ہیں کھجور کے کھوکھلے پھر تو دیکھتا ہے کوئی اُن میں کا بچا"},{"n":408,"l":"ہ","t":"ہمت اور حوصلہ","p":"4","s":"آلِ عمران","sn":3,"r":"14","a":"139","ar":"وَلَا تَهِنُوۡا وَلَا تَحۡزَنُوۡا وَاَنۡتُمُ الۡاَعۡلَوۡنَ اِنۡ كُنۡتُمۡ مُّؤۡمِنِيۡنَ","u":"اور سست نہ رہو اور نہ غم کھاؤ اور تم ہی غالب رہو گے اگر تم ایمان رکھتے ہو"},{"n":409,"l":"ہ","t":"ہر دور میں ہدایت کا تسلسل","p":"3","s":"آلِ عمران","sn":3,"r":"4","a":"33-34","ar":"اِنَّ اللّٰهَ اصۡطَفٰ٘ي اٰدَمَ وَنُوۡحًا وَّاٰلَ اِبۡرٰهِيۡمَ وَاٰلَ عِمۡرٰنَ عَلَي الۡعٰلَمِيۡنَۙ ذُرِّيَّةًۭ بَعۡضُهَا مِنۭۡ بَعۡضٍؕ وَاللّٰهُ سَمِيۡعٌ عَلِيۡمٌۚ","u":"بیشک اللہ نے پسند کیا آدم کو اور نوح کو اور ابراہیم کے گھر کو اور عمران کے گھر کو سارے جہان سے جو اولاد تھے ایک دوسرے کی اور اللہ سننے والا جاننے والا ہے"},{"n":410,"l":"ہ","t":"ہر امت کے لیے رسول کا اصول","p":"14","s":"النحل","sn":16,"r":"5","a":"36","ar":"وَلَقَدۡ بَعَثۡنَا فِيۡ كُلِّ اُمَّةٍ رَّسُوۡلًا اَنِ اعۡبُدُوا اللّٰهَ وَاجۡتَنِبُوا الطَّاغُوۡتَۚ فَمِنۡهُمۡ مَّنۡ هَدَي اللّٰهُ وَمِنۡهُمۡ مَّنۡ حَقَّتۡ عَلَيۡهِ الضَّلٰلَةُؕ فَسِيۡرُوۡا فِي الۡاَرۡضِ فَانۡظُرُوۡا كَيۡفَ كَانَ عَاقِبَةُ الۡمُكَذِّبِيۡنَ","u":"اور ہم نے اٹھائے ہیں (بھیجے ہیں) ہر امت میں رسول کہ بندگی کرو اللہ کی اور بچو ہڑونگے سے (جھوٹے معبودوں سے) پھر کسی کو ان میں سے ہدایت کی (راہ سمجھائی) اللہ نے اور کسی پر ثابت ہوئی گمراہی سو سفر کرو (چلو پھرو زمین میں) ملکوں میں پھر دیکھو کیا ہوا انجام جھٹلانے والوں کا"},{"n":411,"l":"ہ","t":"ہدایت اور ضلالت میں اللہ کی مشیت","p":"7","s":"الانعام","sn":6,"r":"4","a":"39","ar":"وَالَّذِيۡنَ كَذَّبُوۡا بِاٰيٰتِنَا صُمٌّ وَّبُكۡمٌ فِي الظُّلُمٰتِؕ مَنۡ يَّشَاِ اللّٰهُ يُضۡلِلۡهُؕ وَمَنۡ يَّشَاۡ يَجۡعَلۡهُ عَلٰي صِرَاطٍ مُّسۡتَقِيۡمٍ","u":"اور جو جھٹلاتے ہیں ہماری آیتوں کو وہ بہرے اور گونگے ہیں اندھیروں میں جسکو چاہے اللہ گمراہ کرے اور جس کو چاہے ڈال دے سیدھی راہ پر"},{"n":412,"l":"ی","t":"یتیموں کے حقوق","p":"4","s":"النساء","sn":4,"r":"1","a":"2","ar":"وَاٰتُوا الۡيَتٰمٰ٘ي اَمۡوَالَهُمۡ وَلَا تَتَبَدَّلُوا الۡخَبِيۡثَ بِالطَّيِّبِ وَلَا تَاۡكُلُوۡ٘ا اَمۡوَالَهُمۡ اِلٰ٘ي اَمۡوَالِكُمۡؕ اِنَّهٗ كَانَ حُوۡبًا كَبِيۡرًا","u":"اور دے ڈالو یتیموں کو ان کا مال اور بدل نہ لو برے مال کو اچھے مال سے اور نہ کھاؤ ان کے مال اپنے مالوں کے ساتھ یہ ہے بڑا وبال"},{"n":413,"l":"ی","t":"یوسف علیہ السلام کا قصہ","p":"12","s":"یوسف","sn":12,"r":"1","a":"3","ar":"نَحۡنُ نَقُصُّ عَلَيۡكَ اَحۡسَنَ الۡقَصَصِ بِمَا٘ اَوۡحَيۡنَا٘ اِلَيۡكَ هٰذَا الۡقُرۡاٰنَۖ وَاِنۡ كُنۡتَ مِنۡ قَبۡلِهٖ لَمِنَ الۡغٰفِلِيۡنَ","u":"ہم بیان کرتے ہیں تیرے پاس بہت اچھا بیان اس واسطے کہ بھیجا ہم نے تیری طرف یہ قرآن اور تو تھا اس سے پہلے البتہ بیخبروں میں"},{"n":414,"l":"ی","t":"یونس علیہ السلام کا قصہ","p":"23","s":"الصافات","sn":37,"r":"5","a":"142-144","ar":"فَالۡتَقَمَهُ الۡحُوۡتُ وَهُوَ مُلِيۡمٌ فَلَوۡلَا٘ اَنَّهٗ كَانَ مِنَ الۡمُسَبِّحِيۡنَۙ لَلَبِثَ فِيۡ بَطۡنِهٖ٘ اِلٰي يَوۡمِ يُبۡعَثُوۡنَۚ","u":"پھر لقمہ کیا اس کو مچھلی نے اور وہ الزام کھایا ہوا تھا پھر اگر نہ ہوتی یہ بات کہ وہ یاد کرتا تھا پاک ذات کو تو رہتا اسی کے پیٹ میں جس دن تک مردے زندہ ہوں"},{"n":415,"l":"ی","t":"یومِ آخرت کی تفصیلات","p":"30","s":"القارعہ","sn":101,"r":"1","a":"1-5","ar":"اَلۡقَارِعَةُۙ مَا الۡقَارِعَةُۚ وَمَا٘ اَدۡرٰىكَ مَا الۡقَارِعَةُؕ يَوۡمَ يَكُوۡنُ النَّاسُ كَالۡفَرَاشِ الۡمَبۡثُوۡثِۙ وَتَكُوۡنُ الۡجِبَالُ كَالۡعِهۡنِ الۡمَنۡفُوۡشِؕ","u":"وہ کھڑکھڑا ڈالنے والی کیا ہے وہ کھڑ کھڑا ڈالنے والی اور تو کیا سمجھا کیا ہے وہ کھڑ کھڑا ڈالنے والی جس دن ہوویں لوگ جیسے پتنگے بکھرے ہوئے اور ہوویں پہاڑ جیسے رنگی ہوئی اون دُھنی ہوئی"},{"n":416,"l":"ی","t":"یادِ الٰہی کی برکات","p":"2","s":"البقرہ","sn":2,"r":"18","a":"152","ar":"فَاذۡكُرُوۡنِيۡ٘ اَذۡكُرۡكُمۡ وَاشۡكُرُوۡا لِيۡ وَلَا تَكۡفُرُوۡنِ","u":"سو تم یاد رکھو مجھ کو میں یاد رکھوں تم کو اور احسان مانو میرا اور ناشکری مت کرو"},{"n":417,"l":"ی","t":"یاجوج ماجوج کا تذکرہ","p":"16","s":"الکہف","sn":18,"r":"11","a":"94","ar":"قَالُوۡا يٰذَا الۡقَرۡنَيۡنِ اِنَّ يَاۡجُوۡجَ وَمَاۡجُوۡجَ مُفۡسِدُوۡنَ فِي الۡاَرۡضِ فَهَلۡ نَجۡعَلُ لَكَ خَرۡجًا عَلٰ٘ي اَنۡ تَجۡعَلَ بَيۡنَنَا وَبَيۡنَهُمۡ سَدًّا","u":"بولے اے ذوالقرنین یہ یاجوج و ماجوج دھوم اٹھاتے ہیں ملک میں سو تو کہے تو ہم مقرر کر دیں تیرے واسطے کچھ محصول اس شرط پر کہ بنا دےتو ہم میں ان میں ایک آڑ"},{"n":418,"l":"ی","t":"یہود و نصاریٰ کے ساتھ معاملات کے اصول","p":"21","s":"العنکبوت","sn":29,"r":"5","a":"46","ar":"وَلَا تُجَادِلُوۡ٘ا اَهۡلَ الۡكِتٰبِ اِلَّا بِالَّتِيۡ هِيَ اَحۡسَنُؗ اِلَّا الَّذِيۡنَ ظَلَمُوۡا مِنۡهُمۡ وَقُوۡلُوۡ٘ا اٰمَنَّا بِالَّذِيۡ٘ اُنۡزِلَ اِلَيۡنَا وَاُنۡزِلَ اِلَيۡكُمۡ وَاِلٰهُنَا وَاِلٰهُكُمۡ وَاحِدٌ وَّنَحۡنُ لَهٗ مُسۡلِمُوۡنَ","u":"اور جھگڑا نہ کرو اہل کتاب سے مگر اس طرح پر جو بہتر ہو مگر جو ان میں بے انصاف ہیں اور یوں کہو کہ ہم مانتے ہیں جو اترا ہم کو اور اترا تم کو اور بندگی ہماری اور تمہاری ایک ہی کو ہے اور ہم اسی کے حکم پر چلتے ہیں"},{"n":419,"l":"ی","t":"یادِ آخرت سے دل کی نرمی","p":"23","s":"الزمر","sn":39,"r":"3","a":"23","ar":"اَللّٰهُ نَزَّلَ اَحۡسَنَ الۡحَدِيۡثِ كِتٰبًا مُّتَشَابِهًا مَّثَانِيَ تَقۡشَعِرُّ مِنۡهُ جُلُوۡدُ الَّذِيۡنَ يَخۡشَوۡنَ رَبَّهُمۡۚ ثُمَّ تَلِيۡنُ جُلُوۡدُهُمۡ وَقُلُوۡبُهُمۡ اِلٰي ذِكۡرِ اللّٰهِؕ ذٰلِكَ هُدَي اللّٰهِ يَهۡدِيۡ بِهٖ مَنۡ يَّشَآءُؕ وَمَنۡ يُّضۡلِلِ اللّٰهُ فَمَا لَهٗ مِنۡ هَادٍ","u":"اللہ نے اتاری بہتر بات کتاب کی آپس میں ملتی دہرائی ہوئی بال کھڑے ہوئے ہیں اس سے کھال پر ان لوگوں کے جو ڈرتے ہیں اپنے رب سے پھر نرم ہوتی ہیں ان کی کھالیں اور ان کے دل اللہ کی یاد پر یہ ہے راہ دینا اللہ کا اس طرح راہ دیتا ہے جس کو چاہے اور جس کو راہ بھلائے اللہ اسکو کوئی نہیں سجھانے والا"},{"n":420,"l":"ی","t":"یکسوئی فی العبادت","p":"8","s":"الانعام","sn":6,"r":"20","a":"162","ar":"قُلۡ اِنَّ صَلَاتِيۡ وَنُسُكِيۡ وَمَحۡيَايَ وَمَمَاتِيۡ لِلّٰهِ رَبِّ الۡعٰلَمِيۡنَۙ","u":"تو کہہ کہ میری نماز اور میری قربانی اور میرا جینا اور مرنا اللہ ہی کے لئے ہے جو پالنے والا سارے جہان کا ہے"},{"n":421,"l":"ی","t":"یقینِ کامل کی برکات","p":"27","s":"الواقعہ","sn":56,"r":"3","a":"95","ar":"اِنَّ هٰذَا لَهُوَ حَقُّ الۡيَقِيۡنِۚ","u":"بیشک یہ بات یہی ہے لائق یقین کے"},{"n":422,"l":"ی","t":"یادِ موت سے دل کی اصلاح","p":"4","s":"آلِ عمران","sn":3,"r":"19","a":"185","ar":"كُلُّ نَفۡسٍ ذَآئِقَةُ الۡمَوۡتِؕ وَاِنَّمَا تُوَفَّوۡنَ اُجُوۡرَكُمۡ يَوۡمَ الۡقِيٰمَةِؕ فَمَنۡ زُحۡزِحَ عَنِ النَّارِ وَاُدۡخِلَ الۡجَنَّةَ فَقَدۡ فَازَؕ وَمَا الۡحَيٰوةُ الدُّنۡيَا٘ اِلَّا مَتَاعُ الۡغُرُوۡرِ","u":"ہر جی کو چکھنی ہے موت اور تم کو پورے بدلے ملیں گے قیامت کے دن پھر جو کوئی دور کیا گیا دوزخ سے اور داخل کیا گیا جنت میں اس کا کام تو بن گیا اور نہیں زندگانی دنیا کی مگر پونجی دھوکے کی"},{"n":423,"l":"ی","t":"یوم الفصل کا تذکرہ","p":"30","s":"النبأ","sn":78,"r":"1","a":"17-20","ar":"اِنَّ يَوۡمَ الۡفَصۡلِ كَانَ مِيۡقَاتًاۙ يَّوۡمَ يُنۡفَخُ فِي الصُّوۡرِ فَتَاۡتُوۡنَ اَفۡوَاجًاۙ وَّفُتِحَتِ السَّمَآءُ فَكَانَتۡ اَبۡوَابًاۙ وَّسُيِّرَتِ الۡجِبَالُ فَكَانَتۡ سَرَابًاؕ","u":"بیشک دن فیصلے کا ہے ایک وقت ٹھہرا ہوا جس دن پھونکی جائے صور پھر تم چلے آؤ جٹ کے جٹ اور کھولا جائے آسمان تو ہو جائیں اس میں دروازے اور چلائے جائیں گے پہاڑ تو ہو جائیں گے چمکتا ریتا"}];
